insert into control_room_bible (version, book, book_num, chapter, verse, text) values
  ('KJV', 'Psalms', 19, 71, 24, 'My tongue also shall talk of thy righteousness all the day long: for they are confounded, for they are brought unto shame, that seek my hurt.'),
  ('KJV', 'Psalms', 19, 72, 1, 'A Psalm for Solomon. Give the king thy judgments, O God, and thy righteousness unto the king''s son.'),
  ('KJV', 'Psalms', 19, 72, 2, 'He shall judge thy people with righteousness, and thy poor with judgment.'),
  ('KJV', 'Psalms', 19, 72, 3, 'The mountains shall bring peace to the people, and the little hills, by righteousness.'),
  ('KJV', 'Psalms', 19, 72, 4, 'He shall judge the poor of the people, he shall save the children of the needy, and shall break in pieces the oppressor.'),
  ('KJV', 'Psalms', 19, 72, 5, 'They shall fear thee as long as the sun and moon endure, throughout all generations.'),
  ('KJV', 'Psalms', 19, 72, 6, 'He shall come down like rain upon the mown grass: as showers that water the earth.'),
  ('KJV', 'Psalms', 19, 72, 7, 'In his days shall the righteous flourish; and abundance of peace so long as the moon endureth.'),
  ('KJV', 'Psalms', 19, 72, 8, 'He shall have dominion also from sea to sea, and from the river unto the ends of the earth.'),
  ('KJV', 'Psalms', 19, 72, 9, 'They that dwell in the wilderness shall bow before him; and his enemies shall lick the dust.'),
  ('KJV', 'Psalms', 19, 72, 10, 'The kings of Tarshish and of the isles shall bring presents: the kings of Sheba and Seba shall offer gifts.'),
  ('KJV', 'Psalms', 19, 72, 11, 'Yea, all kings shall fall down before him: all nations shall serve him.'),
  ('KJV', 'Psalms', 19, 72, 12, 'For he shall deliver the needy when he crieth; the poor also, and him that hath no helper.'),
  ('KJV', 'Psalms', 19, 72, 13, 'He shall spare the poor and needy, and shall save the souls of the needy.'),
  ('KJV', 'Psalms', 19, 72, 14, 'He shall redeem their soul from deceit and violence: and precious shall their blood be in his sight.'),
  ('KJV', 'Psalms', 19, 72, 15, 'And he shall live, and to him shall be given of the gold of Sheba: prayer also shall be made for him continually; and daily shall he be praised.'),
  ('KJV', 'Psalms', 19, 72, 16, 'There shall be an handful of corn in the earth upon the top of the mountains; the fruit thereof shall shake like Lebanon: and they of the city shall flourish like grass of the earth.'),
  ('KJV', 'Psalms', 19, 72, 17, 'His name shall endure for ever: his name shall be continued as long as the sun: and men shall be blessed in him: all nations shall call him blessed.'),
  ('KJV', 'Psalms', 19, 72, 18, 'Blessed be the LORD God, the God of Israel, who only doeth wondrous things.'),
  ('KJV', 'Psalms', 19, 72, 19, 'And blessed be his glorious name for ever: and let the whole earth be filled with his glory; Amen, and Amen.'),
  ('KJV', 'Psalms', 19, 72, 20, 'The prayers of David the son of Jesse are ended.'),
  ('KJV', 'Psalms', 19, 73, 1, 'A Psalm of Asaph. Truly God is good to Israel, even to such as are of a clean heart.'),
  ('KJV', 'Psalms', 19, 73, 2, 'But as for me, my feet were almost gone; my steps had well nigh slipped.'),
  ('KJV', 'Psalms', 19, 73, 3, 'For I was envious at the foolish, when I saw the prosperity of the wicked.'),
  ('KJV', 'Psalms', 19, 73, 4, 'For there are no bands in their death: but their strength is firm.'),
  ('KJV', 'Psalms', 19, 73, 5, 'They are not in trouble as other men; neither are they plagued like other men.'),
  ('KJV', 'Psalms', 19, 73, 6, 'Therefore pride compasseth them about as a chain; violence covereth them as a garment.'),
  ('KJV', 'Psalms', 19, 73, 7, 'Their eyes stand out with fatness: they have more than heart could wish.'),
  ('KJV', 'Psalms', 19, 73, 8, 'They are corrupt, and speak wickedly concerning oppression: they speak loftily.'),
  ('KJV', 'Psalms', 19, 73, 9, 'They set their mouth against the heavens, and their tongue walketh through the earth.'),
  ('KJV', 'Psalms', 19, 73, 10, 'Therefore his people return hither: and waters of a full cup are wrung out to them.'),
  ('KJV', 'Psalms', 19, 73, 11, 'And they say, How doth God know? and is there knowledge in the most High?'),
  ('KJV', 'Psalms', 19, 73, 12, 'Behold, these are the ungodly, who prosper in the world; they increase in riches.'),
  ('KJV', 'Psalms', 19, 73, 13, 'Verily I have cleansed my heart in vain, and washed my hands in innocency.'),
  ('KJV', 'Psalms', 19, 73, 14, 'For all the day long have I been plagued, and chastened every morning.'),
  ('KJV', 'Psalms', 19, 73, 15, 'If I say, I will speak thus; behold, I should offend against the generation of thy children.'),
  ('KJV', 'Psalms', 19, 73, 16, 'When I thought to know this, it was too painful for me;'),
  ('KJV', 'Psalms', 19, 73, 17, 'Until I went into the sanctuary of God; then understood I their end.'),
  ('KJV', 'Psalms', 19, 73, 18, 'Surely thou didst set them in slippery places: thou castedst them down into destruction.'),
  ('KJV', 'Psalms', 19, 73, 19, 'How are they brought into desolation, as in a moment! they are utterly consumed with terrors.'),
  ('KJV', 'Psalms', 19, 73, 20, 'As a dream when one awaketh; so, O Lord, when thou awakest, thou shalt despise their image.'),
  ('KJV', 'Psalms', 19, 73, 21, 'Thus my heart was grieved, and I was pricked in my reins.'),
  ('KJV', 'Psalms', 19, 73, 22, 'So foolish was I, and ignorant: I was as a beast before thee.'),
  ('KJV', 'Psalms', 19, 73, 23, 'Nevertheless I am continually with thee: thou hast holden me by my right hand.'),
  ('KJV', 'Psalms', 19, 73, 24, 'Thou shalt guide me with thy counsel, and afterward receive me to glory.'),
  ('KJV', 'Psalms', 19, 73, 25, 'Whom have I in heaven but thee? and there is none upon earth that I desire beside thee.'),
  ('KJV', 'Psalms', 19, 73, 26, 'My flesh and my heart faileth: but God is the strength of my heart, and my portion for ever.'),
  ('KJV', 'Psalms', 19, 73, 27, 'For, lo, they that are far from thee shall perish: thou hast destroyed all them that go a whoring from thee.'),
  ('KJV', 'Psalms', 19, 73, 28, 'But it is good for me to draw near to God: I have put my trust in the Lord GOD, that I may declare all thy works.'),
  ('KJV', 'Psalms', 19, 74, 1, 'Maschil of Asaph. O God, why hast thou cast us off for ever? why doth thine anger smoke against the sheep of thy pasture?'),
  ('KJV', 'Psalms', 19, 74, 2, 'Remember thy congregation, which thou hast purchased of old; the rod of thine inheritance, which thou hast redeemed; this mount Zion, wherein thou hast dwelt.'),
  ('KJV', 'Psalms', 19, 74, 3, 'Lift up thy feet unto the perpetual desolations; even all that the enemy hath done wickedly in the sanctuary.'),
  ('KJV', 'Psalms', 19, 74, 4, 'Thine enemies roar in the midst of thy congregations; they set up their ensigns for signs.'),
  ('KJV', 'Psalms', 19, 74, 5, 'A man was famous according as he had lifted up axes upon the thick trees.'),
  ('KJV', 'Psalms', 19, 74, 6, 'But now they break down the carved work thereof at once with axes and hammers.'),
  ('KJV', 'Psalms', 19, 74, 7, 'They have cast fire into thy sanctuary, they have defiled by casting down the dwelling place of thy name to the ground.'),
  ('KJV', 'Psalms', 19, 74, 8, 'They said in their hearts, Let us destroy them together: they have burned up all the synagogues of God in the land.'),
  ('KJV', 'Psalms', 19, 74, 9, 'We see not our signs: there is no more any prophet: neither is there among us any that knoweth how long.'),
  ('KJV', 'Psalms', 19, 74, 10, 'O God, how long shall the adversary reproach? shall the enemy blaspheme thy name for ever?'),
  ('KJV', 'Psalms', 19, 74, 11, 'Why withdrawest thou thy hand, even thy right hand? pluck it out of thy bosom.'),
  ('KJV', 'Psalms', 19, 74, 12, 'For God is my King of old, working salvation in the midst of the earth.'),
  ('KJV', 'Psalms', 19, 74, 13, 'Thou didst divide the sea by thy strength: thou brakest the heads of the dragons in the waters.'),
  ('KJV', 'Psalms', 19, 74, 14, 'Thou brakest the heads of leviathan in pieces, and gavest him to be meat to the people inhabiting the wilderness.'),
  ('KJV', 'Psalms', 19, 74, 15, 'Thou didst cleave the fountain and the flood: thou driedst up mighty rivers.'),
  ('KJV', 'Psalms', 19, 74, 16, 'The day is thine, the night also is thine: thou hast prepared the light and the sun.'),
  ('KJV', 'Psalms', 19, 74, 17, 'Thou hast set all the borders of the earth: thou hast made summer and winter.'),
  ('KJV', 'Psalms', 19, 74, 18, 'Remember this, that the enemy hath reproached, O LORD, and that the foolish people have blasphemed thy name.'),
  ('KJV', 'Psalms', 19, 74, 19, 'O deliver not the soul of thy turtledove unto the multitude of the wicked: forget not the congregation of thy poor for ever.'),
  ('KJV', 'Psalms', 19, 74, 20, 'Have respect unto the covenant: for the dark places of the earth are full of the habitations of cruelty.'),
  ('KJV', 'Psalms', 19, 74, 21, 'O let not the oppressed return ashamed: let the poor and needy praise thy name.'),
  ('KJV', 'Psalms', 19, 74, 22, 'Arise, O God, plead thine own cause: remember how the foolish man reproacheth thee daily.'),
  ('KJV', 'Psalms', 19, 74, 23, 'Forget not the voice of thine enemies: the tumult of those that rise up against thee increaseth continually.'),
  ('KJV', 'Psalms', 19, 75, 1, 'To the chief Musician, Altaschith, A Psalm or Song of Asaph. Unto thee, O God, do we give thanks, unto thee do we give thanks: for that thy name is near thy wondrous works declare.'),
  ('KJV', 'Psalms', 19, 75, 2, 'When I shall receive the congregation I will judge uprightly.'),
  ('KJV', 'Psalms', 19, 75, 3, 'The earth and all the inhabitants thereof are dissolved: I bear up the pillars of it. Selah.'),
  ('KJV', 'Psalms', 19, 75, 4, 'I said unto the fools, Deal not foolishly: and to the wicked, Lift not up the horn:'),
  ('KJV', 'Psalms', 19, 75, 5, 'Lift not up your horn on high: speak not with a stiff neck.'),
  ('KJV', 'Psalms', 19, 75, 6, 'For promotion cometh neither from the east, nor from the west, nor from the south.'),
  ('KJV', 'Psalms', 19, 75, 7, 'But God is the judge: he putteth down one, and setteth up another.'),
  ('KJV', 'Psalms', 19, 75, 8, 'For in the hand of the LORD there is a cup, and the wine is red; it is full of mixture; and he poureth out of the same: but the dregs thereof, all the wicked of the earth shall wring them out, and drink them.'),
  ('KJV', 'Psalms', 19, 75, 9, 'But I will declare for ever; I will sing praises to the God of Jacob.'),
  ('KJV', 'Psalms', 19, 75, 10, 'All the horns of the wicked also will I cut off; but the horns of the righteous shall be exalted.'),
  ('KJV', 'Psalms', 19, 76, 1, 'To the chief Musician on Neginoth, A Psalm or Song of Asaph. In Judah is God known: his name is great in Israel.'),
  ('KJV', 'Psalms', 19, 76, 2, 'In Salem also is his tabernacle, and his dwelling place in Zion.'),
  ('KJV', 'Psalms', 19, 76, 3, 'There brake he the arrows of the bow, the shield, and the sword, and the battle. Selah.'),
  ('KJV', 'Psalms', 19, 76, 4, 'Thou art more glorious and excellent than the mountains of prey.'),
  ('KJV', 'Psalms', 19, 76, 5, 'The stouthearted are spoiled, they have slept their sleep: and none of the men of might have found their hands.'),
  ('KJV', 'Psalms', 19, 76, 6, 'At thy rebuke, O God of Jacob, both the chariot and horse are cast into a dead sleep.'),
  ('KJV', 'Psalms', 19, 76, 7, 'Thou, even thou, art to be feared: and who may stand in thy sight when once thou art angry?'),
  ('KJV', 'Psalms', 19, 76, 8, 'Thou didst cause judgment to be heard from heaven; the earth feared, and was still,'),
  ('KJV', 'Psalms', 19, 76, 9, 'When God arose to judgment, to save all the meek of the earth. Selah.'),
  ('KJV', 'Psalms', 19, 76, 10, 'Surely the wrath of man shall praise thee: the remainder of wrath shalt thou restrain.'),
  ('KJV', 'Psalms', 19, 76, 11, 'Vow, and pay unto the LORD your God: let all that be round about him bring presents unto him that ought to be feared.'),
  ('KJV', 'Psalms', 19, 76, 12, 'He shall cut off the spirit of princes: he is terrible to the kings of the earth.'),
  ('KJV', 'Psalms', 19, 77, 1, 'To the chief Musician, to Jeduthun, A Psalm of Asaph. I cried unto God with my voice, even unto God with my voice; and he gave ear unto me.'),
  ('KJV', 'Psalms', 19, 77, 2, 'In the day of my trouble I sought the Lord: my sore ran in the night, and ceased not: my soul refused to be comforted.'),
  ('KJV', 'Psalms', 19, 77, 3, 'I remembered God, and was troubled: I complained, and my spirit was overwhelmed. Selah.'),
  ('KJV', 'Psalms', 19, 77, 4, 'Thou holdest mine eyes waking: I am so troubled that I cannot speak.'),
  ('KJV', 'Psalms', 19, 77, 5, 'I have considered the days of old, the years of ancient times.'),
  ('KJV', 'Psalms', 19, 77, 6, 'I call to remembrance my song in the night: I commune with mine own heart: and my spirit made diligent search.'),
  ('KJV', 'Psalms', 19, 77, 7, 'Will the Lord cast off for ever? and will he be favourable no more?'),
  ('KJV', 'Psalms', 19, 77, 8, 'Is his mercy clean gone for ever? doth his promise fail for evermore?'),
  ('KJV', 'Psalms', 19, 77, 9, 'Hath God forgotten to be gracious? hath he in anger shut up his tender mercies? Selah.'),
  ('KJV', 'Psalms', 19, 77, 10, 'And I said, This is my infirmity: but I will remember the years of the right hand of the most High.'),
  ('KJV', 'Psalms', 19, 77, 11, 'I will remember the works of the LORD: surely I will remember thy wonders of old.'),
  ('KJV', 'Psalms', 19, 77, 12, 'I will meditate also of all thy work, and talk of thy doings.'),
  ('KJV', 'Psalms', 19, 77, 13, 'Thy way, O God, is in the sanctuary: who is so great a God as our God?'),
  ('KJV', 'Psalms', 19, 77, 14, 'Thou art the God that doest wonders: thou hast declared thy strength among the people.'),
  ('KJV', 'Psalms', 19, 77, 15, 'Thou hast with thine arm redeemed thy people, the sons of Jacob and Joseph. Selah.'),
  ('KJV', 'Psalms', 19, 77, 16, 'The waters saw thee, O God, the waters saw thee; they were afraid: the depths also were troubled.'),
  ('KJV', 'Psalms', 19, 77, 17, 'The clouds poured out water: the skies sent out a sound: thine arrows also went abroad.'),
  ('KJV', 'Psalms', 19, 77, 18, 'The voice of thy thunder was in the heaven: the lightnings lightened the world: the earth trembled and shook.'),
  ('KJV', 'Psalms', 19, 77, 19, 'Thy way is in the sea, and thy path in the great waters, and thy footsteps are not known.'),
  ('KJV', 'Psalms', 19, 77, 20, 'Thou leddest thy people like a flock by the hand of Moses and Aaron.'),
  ('KJV', 'Psalms', 19, 78, 1, 'Maschil of Asaph. Give ear, O my people, to my law: incline your ears to the words of my mouth.'),
  ('KJV', 'Psalms', 19, 78, 2, 'I will open my mouth in a parable: I will utter dark sayings of old:'),
  ('KJV', 'Psalms', 19, 78, 3, 'Which we have heard and known, and our fathers have told us.'),
  ('KJV', 'Psalms', 19, 78, 4, 'We will not hide them from their children, shewing to the generation to come the praises of the LORD, and his strength, and his wonderful works that he hath done.'),
  ('KJV', 'Psalms', 19, 78, 5, 'For he established a testimony in Jacob, and appointed a law in Israel, which he commanded our fathers, that they should make them known to their children:'),
  ('KJV', 'Psalms', 19, 78, 6, 'That the generation to come might know them, even the children which should be born; who should arise and declare them to their children:'),
  ('KJV', 'Psalms', 19, 78, 7, 'That they might set their hope in God, and not forget the works of God, but keep his commandments:'),
  ('KJV', 'Psalms', 19, 78, 8, 'And might not be as their fathers, a stubborn and rebellious generation; a generation that set not their heart aright, and whose spirit was not stedfast with God.'),
  ('KJV', 'Psalms', 19, 78, 9, 'The children of Ephraim, being armed, and carrying bows, turned back in the day of battle.'),
  ('KJV', 'Psalms', 19, 78, 10, 'They kept not the covenant of God, and refused to walk in his law;'),
  ('KJV', 'Psalms', 19, 78, 11, 'And forgat his works, and his wonders that he had shewed them.'),
  ('KJV', 'Psalms', 19, 78, 12, 'Marvellous things did he in the sight of their fathers, in the land of Egypt, in the field of Zoan.'),
  ('KJV', 'Psalms', 19, 78, 13, 'He divided the sea, and caused them to pass through; and he made the waters to stand as an heap.'),
  ('KJV', 'Psalms', 19, 78, 14, 'In the daytime also he led them with a cloud, and all the night with a light of fire.'),
  ('KJV', 'Psalms', 19, 78, 15, 'He clave the rocks in the wilderness, and gave them drink as out of the great depths.'),
  ('KJV', 'Psalms', 19, 78, 16, 'He brought streams also out of the rock, and caused waters to run down like rivers.'),
  ('KJV', 'Psalms', 19, 78, 17, 'And they sinned yet more against him by provoking the most High in the wilderness.'),
  ('KJV', 'Psalms', 19, 78, 18, 'And they tempted God in their heart by asking meat for their lust.'),
  ('KJV', 'Psalms', 19, 78, 19, 'Yea, they spake against God; they said, Can God furnish a table in the wilderness?'),
  ('KJV', 'Psalms', 19, 78, 20, 'Behold, he smote the rock, that the waters gushed out, and the streams overflowed; can he give bread also? can he provide flesh for his people?'),
  ('KJV', 'Psalms', 19, 78, 21, 'Therefore the LORD heard this, and was wroth: so a fire was kindled against Jacob, and anger also came up against Israel;'),
  ('KJV', 'Psalms', 19, 78, 22, 'Because they believed not in God, and trusted not in his salvation:'),
  ('KJV', 'Psalms', 19, 78, 23, 'Though he had commanded the clouds from above, and opened the doors of heaven,'),
  ('KJV', 'Psalms', 19, 78, 24, 'And had rained down manna upon them to eat, and had given them of the corn of heaven.'),
  ('KJV', 'Psalms', 19, 78, 25, 'Man did eat angels'' food: he sent them meat to the full.'),
  ('KJV', 'Psalms', 19, 78, 26, 'He caused an east wind to blow in the heaven: and by his power he brought in the south wind.'),
  ('KJV', 'Psalms', 19, 78, 27, 'He rained flesh also upon them as dust, and feathered fowls like as the sand of the sea:'),
  ('KJV', 'Psalms', 19, 78, 28, 'And he let it fall in the midst of their camp, round about their habitations.'),
  ('KJV', 'Psalms', 19, 78, 29, 'So they did eat, and were well filled: for he gave them their own desire;'),
  ('KJV', 'Psalms', 19, 78, 30, 'They were not estranged from their lust. But while their meat was yet in their mouths,'),
  ('KJV', 'Psalms', 19, 78, 31, 'The wrath of God came upon them, and slew the fattest of them, and smote down the chosen men of Israel.'),
  ('KJV', 'Psalms', 19, 78, 32, 'For all this they sinned still, and believed not for his wondrous works.'),
  ('KJV', 'Psalms', 19, 78, 33, 'Therefore their days did he consume in vanity, and their years in trouble.'),
  ('KJV', 'Psalms', 19, 78, 34, 'When he slew them, then they sought him: and they returned and enquired early after God.'),
  ('KJV', 'Psalms', 19, 78, 35, 'And they remembered that God was their rock, and the high God their redeemer.'),
  ('KJV', 'Psalms', 19, 78, 36, 'Nevertheless they did flatter him with their mouth, and they lied unto him with their tongues.'),
  ('KJV', 'Psalms', 19, 78, 37, 'For their heart was not right with him, neither were they stedfast in his covenant.'),
  ('KJV', 'Psalms', 19, 78, 38, 'But he, being full of compassion, forgave their iniquity, and destroyed them not: yea, many a time turned he his anger away, and did not stir up all his wrath.'),
  ('KJV', 'Psalms', 19, 78, 39, 'For he remembered that they were but flesh; a wind that passeth away, and cometh not again.'),
  ('KJV', 'Psalms', 19, 78, 40, 'How oft did they provoke him in the wilderness, and grieve him in the desert!'),
  ('KJV', 'Psalms', 19, 78, 41, 'Yea, they turned back and tempted God, and limited the Holy One of Israel.'),
  ('KJV', 'Psalms', 19, 78, 42, 'They remembered not his hand, nor the day when he delivered them from the enemy.'),
  ('KJV', 'Psalms', 19, 78, 43, 'How he had wrought his signs in Egypt, and his wonders in the field of Zoan:'),
  ('KJV', 'Psalms', 19, 78, 44, 'And had turned their rivers into blood; and their floods, that they could not drink.'),
  ('KJV', 'Psalms', 19, 78, 45, 'He sent divers sorts of flies among them, which devoured them; and frogs, which destroyed them.'),
  ('KJV', 'Psalms', 19, 78, 46, 'He gave also their increase unto the caterpiller, and their labour unto the locust.'),
  ('KJV', 'Psalms', 19, 78, 47, 'He destroyed their vines with hail, and their sycomore trees with frost.'),
  ('KJV', 'Psalms', 19, 78, 48, 'He gave up their cattle also to the hail, and their flocks to hot thunderbolts.'),
  ('KJV', 'Psalms', 19, 78, 49, 'He cast upon them the fierceness of his anger, wrath, and indignation, and trouble, by sending evil angels among them.'),
  ('KJV', 'Psalms', 19, 78, 50, 'He made a way to his anger; he spared not their soul from death, but gave their life over to the pestilence;'),
  ('KJV', 'Psalms', 19, 78, 51, 'And smote all the firstborn in Egypt; the chief of their strength in the tabernacles of Ham:'),
  ('KJV', 'Psalms', 19, 78, 52, 'But made his own people to go forth like sheep, and guided them in the wilderness like a flock.'),
  ('KJV', 'Psalms', 19, 78, 53, 'And he led them on safely, so that they feared not: but the sea overwhelmed their enemies.'),
  ('KJV', 'Psalms', 19, 78, 54, 'And he brought them to the border of his sanctuary, even to this mountain, which his right hand had purchased.'),
  ('KJV', 'Psalms', 19, 78, 55, 'He cast out the heathen also before them, and divided them an inheritance by line, and made the tribes of Israel to dwell in their tents.'),
  ('KJV', 'Psalms', 19, 78, 56, 'Yet they tempted and provoked the most high God, and kept not his testimonies:'),
  ('KJV', 'Psalms', 19, 78, 57, 'But turned back, and dealt unfaithfully like their fathers: they were turned aside like a deceitful bow.'),
  ('KJV', 'Psalms', 19, 78, 58, 'For they provoked him to anger with their high places, and moved him to jealousy with their graven images.'),
  ('KJV', 'Psalms', 19, 78, 59, 'When God heard this, he was wroth, and greatly abhorred Israel:'),
  ('KJV', 'Psalms', 19, 78, 60, 'So that he forsook the tabernacle of Shiloh, the tent which he placed among men;'),
  ('KJV', 'Psalms', 19, 78, 61, 'And delivered his strength into captivity, and his glory into the enemy''s hand.'),
  ('KJV', 'Psalms', 19, 78, 62, 'He gave his people over also unto the sword; and was wroth with his inheritance.'),
  ('KJV', 'Psalms', 19, 78, 63, 'The fire consumed their young men; and their maidens were not given to marriage.'),
  ('KJV', 'Psalms', 19, 78, 64, 'Their priests fell by the sword; and their widows made no lamentation.'),
  ('KJV', 'Psalms', 19, 78, 65, 'Then the Lord awaked as one out of sleep, and like a mighty man that shouteth by reason of wine.'),
  ('KJV', 'Psalms', 19, 78, 66, 'And he smote his enemies in the hinder parts: he put them to a perpetual reproach.'),
  ('KJV', 'Psalms', 19, 78, 67, 'Moreover he refused the tabernacle of Joseph, and chose not the tribe of Ephraim:'),
  ('KJV', 'Psalms', 19, 78, 68, 'But chose the tribe of Judah, the mount Zion which he loved.'),
  ('KJV', 'Psalms', 19, 78, 69, 'And he built his sanctuary like high palaces, like the earth which he hath established for ever.'),
  ('KJV', 'Psalms', 19, 78, 70, 'He chose David also his servant, and took him from the sheepfolds:'),
  ('KJV', 'Psalms', 19, 78, 71, 'From following the ewes great with young he brought him to feed Jacob his people, and Israel his inheritance.'),
  ('KJV', 'Psalms', 19, 78, 72, 'So he fed them according to the integrity of his heart; and guided them by the skilfulness of his hands.'),
  ('KJV', 'Psalms', 19, 79, 1, 'A Psalm of Asaph. O God, the heathen are come into thine inheritance; thy holy temple have they defiled; they have laid Jerusalem on heaps.'),
  ('KJV', 'Psalms', 19, 79, 2, 'The dead bodies of thy servants have they given to be meat unto the fowls of the heaven, the flesh of thy saints unto the beasts of the earth.'),
  ('KJV', 'Psalms', 19, 79, 3, 'Their blood have they shed like water round about Jerusalem; and there was none to bury them.'),
  ('KJV', 'Psalms', 19, 79, 4, 'We are become a reproach to our neighbours, a scorn and derision to them that are round about us.'),
  ('KJV', 'Psalms', 19, 79, 5, 'How long, LORD? wilt thou be angry for ever? shall thy jealousy burn like fire?'),
  ('KJV', 'Psalms', 19, 79, 6, 'Pour out thy wrath upon the heathen that have not known thee, and upon the kingdoms that have not called upon thy name.'),
  ('KJV', 'Psalms', 19, 79, 7, 'For they have devoured Jacob, and laid waste his dwelling place.'),
  ('KJV', 'Psalms', 19, 79, 8, 'O remember not against us former iniquities: let thy tender mercies speedily prevent us: for we are brought very low.'),
  ('KJV', 'Psalms', 19, 79, 9, 'Help us, O God of our salvation, for the glory of thy name: and deliver us, and purge away our sins, for thy name''s sake.'),
  ('KJV', 'Psalms', 19, 79, 10, 'Wherefore should the heathen say, Where is their God? let him be known among the heathen in our sight by the revenging of the blood of thy servants which is shed.'),
  ('KJV', 'Psalms', 19, 79, 11, 'Let the sighing of the prisoner come before thee; according to the greatness of thy power preserve thou those that are appointed to die;'),
  ('KJV', 'Psalms', 19, 79, 12, 'And render unto our neighbours sevenfold into their bosom their reproach, wherewith they have reproached thee, O Lord.'),
  ('KJV', 'Psalms', 19, 79, 13, 'So we thy people and sheep of thy pasture will give thee thanks for ever: we will shew forth thy praise to all generations.'),
  ('KJV', 'Psalms', 19, 80, 1, 'To the chief Musician upon Shoshannimeduth, A Psalm of Asaph. Give ear, O Shepherd of Israel, thou that leadest Joseph like a flock; thou that dwellest between the cherubims, shine forth.'),
  ('KJV', 'Psalms', 19, 80, 2, 'Before Ephraim and Benjamin and Manasseh stir up thy strength, and come and save us.'),
  ('KJV', 'Psalms', 19, 80, 3, 'Turn us again, O God, and cause thy face to shine; and we shall be saved.'),
  ('KJV', 'Psalms', 19, 80, 4, 'O LORD God of hosts, how long wilt thou be angry against the prayer of thy people?'),
  ('KJV', 'Psalms', 19, 80, 5, 'Thou feedest them with the bread of tears; and givest them tears to drink in great measure.'),
  ('KJV', 'Psalms', 19, 80, 6, 'Thou makest us a strife unto our neighbours: and our enemies laugh among themselves.'),
  ('KJV', 'Psalms', 19, 80, 7, 'Turn us again, O God of hosts, and cause thy face to shine; and we shall be saved.'),
  ('KJV', 'Psalms', 19, 80, 8, 'Thou hast brought a vine out of Egypt: thou hast cast out the heathen, and planted it.'),
  ('KJV', 'Psalms', 19, 80, 9, 'Thou preparedst room before it, and didst cause it to take deep root, and it filled the land.'),
  ('KJV', 'Psalms', 19, 80, 10, 'The hills were covered with the shadow of it, and the boughs thereof were like the goodly cedars.'),
  ('KJV', 'Psalms', 19, 80, 11, 'She sent out her boughs unto the sea, and her branches unto the river.'),
  ('KJV', 'Psalms', 19, 80, 12, 'Why hast thou then broken down her hedges, so that all they which pass by the way do pluck her?'),
  ('KJV', 'Psalms', 19, 80, 13, 'The boar out of the wood doth waste it, and the wild beast of the field doth devour it.'),
  ('KJV', 'Psalms', 19, 80, 14, 'Return, we beseech thee, O God of hosts: look down from heaven, and behold, and visit this vine;'),
  ('KJV', 'Psalms', 19, 80, 15, 'And the vineyard which thy right hand hath planted, and the branch that thou madest strong for thyself.'),
  ('KJV', 'Psalms', 19, 80, 16, 'It is burned with fire, it is cut down: they perish at the rebuke of thy countenance.'),
  ('KJV', 'Psalms', 19, 80, 17, 'Let thy hand be upon the man of thy right hand, upon the son of man whom thou madest strong for thyself.'),
  ('KJV', 'Psalms', 19, 80, 18, 'So will not we go back from thee: quicken us, and we will call upon thy name.'),
  ('KJV', 'Psalms', 19, 80, 19, 'Turn us again, O LORD God of hosts, cause thy face to shine; and we shall be saved.'),
  ('KJV', 'Psalms', 19, 81, 1, 'To the chief Musician upon Gittith, A Psalm of Asaph. Sing aloud unto God our strength: make a joyful noise unto the God of Jacob.'),
  ('KJV', 'Psalms', 19, 81, 2, 'Take a psalm, and bring hither the timbrel, the pleasant harp with the psaltery.'),
  ('KJV', 'Psalms', 19, 81, 3, 'Blow up the trumpet in the new moon, in the time appointed, on our solemn feast day.'),
  ('KJV', 'Psalms', 19, 81, 4, 'For this was a statute for Israel, and a law of the God of Jacob.'),
  ('KJV', 'Psalms', 19, 81, 5, 'This he ordained in Joseph for a testimony, when he went out through the land of Egypt: where I heard a language that I understood not.'),
  ('KJV', 'Psalms', 19, 81, 6, 'I removed his shoulder from the burden: his hands were delivered from the pots.'),
  ('KJV', 'Psalms', 19, 81, 7, 'Thou calledst in trouble, and I delivered thee; I answered thee in the secret place of thunder: I proved thee at the waters of Meribah. Selah.'),
  ('KJV', 'Psalms', 19, 81, 8, 'Hear, O my people, and I will testify unto thee: O Israel, if thou wilt hearken unto me;'),
  ('KJV', 'Psalms', 19, 81, 9, 'There shall no strange god be in thee; neither shalt thou worship any strange god.'),
  ('KJV', 'Psalms', 19, 81, 10, 'I am the LORD thy God, which brought thee out of the land of Egypt: open thy mouth wide, and I will fill it.'),
  ('KJV', 'Psalms', 19, 81, 11, 'But my people would not hearken to my voice; and Israel would none of me.'),
  ('KJV', 'Psalms', 19, 81, 12, 'So I gave them up unto their own hearts'' lust: and they walked in their own counsels.'),
  ('KJV', 'Psalms', 19, 81, 13, 'Oh that my people had hearkened unto me, and Israel had walked in my ways!'),
  ('KJV', 'Psalms', 19, 81, 14, 'I should soon have subdued their enemies, and turned my hand against their adversaries.'),
  ('KJV', 'Psalms', 19, 81, 15, 'The haters of the LORD should have submitted themselves unto him: but their time should have endured for ever.'),
  ('KJV', 'Psalms', 19, 81, 16, 'He should have fed them also with the finest of the wheat: and with honey out of the rock should I have satisfied thee.'),
  ('KJV', 'Psalms', 19, 82, 1, 'A Psalm of Asaph. God standeth in the congregation of the mighty; he judgeth among the gods.'),
  ('KJV', 'Psalms', 19, 82, 2, 'How long will ye judge unjustly, and accept the persons of the wicked? Selah.'),
  ('KJV', 'Psalms', 19, 82, 3, 'Defend the poor and fatherless: do justice to the afflicted and needy.'),
  ('KJV', 'Psalms', 19, 82, 4, 'Deliver the poor and needy: rid them out of the hand of the wicked.'),
  ('KJV', 'Psalms', 19, 82, 5, 'They know not, neither will they understand; they walk on in darkness: all the foundations of the earth are out of course.'),
  ('KJV', 'Psalms', 19, 82, 6, 'I have said, Ye are gods; and all of you are children of the most High.'),
  ('KJV', 'Psalms', 19, 82, 7, 'But ye shall die like men, and fall like one of the princes.'),
  ('KJV', 'Psalms', 19, 82, 8, 'Arise, O God, judge the earth: for thou shalt inherit all nations.'),
  ('KJV', 'Psalms', 19, 83, 1, 'A Song or Psalm of Asaph. Keep not thou silence, O God: hold not thy peace, and be not still, O God.'),
  ('KJV', 'Psalms', 19, 83, 2, 'For, lo, thine enemies make a tumult: and they that hate thee have lifted up the head.'),
  ('KJV', 'Psalms', 19, 83, 3, 'They have taken crafty counsel against thy people, and consulted against thy hidden ones.'),
  ('KJV', 'Psalms', 19, 83, 4, 'They have said, Come, and let us cut them off from being a nation; that the name of Israel may be no more in remembrance.'),
  ('KJV', 'Psalms', 19, 83, 5, 'For they have consulted together with one consent: they are confederate against thee:'),
  ('KJV', 'Psalms', 19, 83, 6, 'The tabernacles of Edom, and the Ishmaelites; of Moab, and the Hagarenes;'),
  ('KJV', 'Psalms', 19, 83, 7, 'Gebal, and Ammon, and Amalek; the Philistines with the inhabitants of Tyre;'),
  ('KJV', 'Psalms', 19, 83, 8, 'Assur also is joined with them: they have holpen the children of Lot. Selah.'),
  ('KJV', 'Psalms', 19, 83, 9, 'Do unto them as unto the Midianites; as to Sisera, as to Jabin, at the brook of Kison:'),
  ('KJV', 'Psalms', 19, 83, 10, 'Which perished at Endor: they became as dung for the earth.'),
  ('KJV', 'Psalms', 19, 83, 11, 'Make their nobles like Oreb, and like Zeeb: yea, all their princes as Zebah, and as Zalmunna:'),
  ('KJV', 'Psalms', 19, 83, 12, 'Who said, Let us take to ourselves the houses of God in possession.'),
  ('KJV', 'Psalms', 19, 83, 13, 'O my God, make them like a wheel; as the stubble before the wind.'),
  ('KJV', 'Psalms', 19, 83, 14, 'As the fire burneth a wood, and as the flame setteth the mountains on fire;'),
  ('KJV', 'Psalms', 19, 83, 15, 'So persecute them with thy tempest, and make them afraid with thy storm.'),
  ('KJV', 'Psalms', 19, 83, 16, 'Fill their faces with shame; that they may seek thy name, O LORD.'),
  ('KJV', 'Psalms', 19, 83, 17, 'Let them be confounded and troubled for ever; yea, let them be put to shame, and perish:'),
  ('KJV', 'Psalms', 19, 83, 18, 'That men may know that thou, whose name alone is JEHOVAH, art the most high over all the earth.'),
  ('KJV', 'Psalms', 19, 84, 1, 'To the chief Musician upon Gittith, A Psalm for the sons of Korah. How amiable are thy tabernacles, O LORD of hosts!'),
  ('KJV', 'Psalms', 19, 84, 2, 'My soul longeth, yea, even fainteth for the courts of the LORD: my heart and my flesh crieth out for the living God.'),
  ('KJV', 'Psalms', 19, 84, 3, 'Yea, the sparrow hath found an house, and the swallow a nest for herself, where she may lay her young, even thine altars, O LORD of hosts, my King, and my God.'),
  ('KJV', 'Psalms', 19, 84, 4, 'Blessed are they that dwell in thy house: they will be still praising thee. Selah.'),
  ('KJV', 'Psalms', 19, 84, 5, 'Blessed is the man whose strength is in thee; in whose heart are the ways of them.'),
  ('KJV', 'Psalms', 19, 84, 6, 'Who passing through the valley of Baca make it a well; the rain also filleth the pools.'),
  ('KJV', 'Psalms', 19, 84, 7, 'They go from strength to strength, every one of them in Zion appeareth before God.'),
  ('KJV', 'Psalms', 19, 84, 8, 'O LORD God of hosts, hear my prayer: give ear, O God of Jacob. Selah.'),
  ('KJV', 'Psalms', 19, 84, 9, 'Behold, O God our shield, and look upon the face of thine anointed.'),
  ('KJV', 'Psalms', 19, 84, 10, 'For a day in thy courts is better than a thousand. I had rather be a doorkeeper in the house of my God, than to dwell in the tents of wickedness.'),
  ('KJV', 'Psalms', 19, 84, 11, 'For the LORD God is a sun and shield: the LORD will give grace and glory: no good thing will he withhold from them that walk uprightly.'),
  ('KJV', 'Psalms', 19, 84, 12, 'O LORD of hosts, blessed is the man that trusteth in thee.'),
  ('KJV', 'Psalms', 19, 85, 1, 'To the chief Musician, A Psalm for the sons of Korah. LORD, thou hast been favourable unto thy land: thou hast brought back the captivity of Jacob.'),
  ('KJV', 'Psalms', 19, 85, 2, 'Thou hast forgiven the iniquity of thy people, thou hast covered all their sin. Selah.'),
  ('KJV', 'Psalms', 19, 85, 3, 'Thou hast taken away all thy wrath: thou hast turned thyself from the fierceness of thine anger.'),
  ('KJV', 'Psalms', 19, 85, 4, 'Turn us, O God of our salvation, and cause thine anger toward us to cease.'),
  ('KJV', 'Psalms', 19, 85, 5, 'Wilt thou be angry with us for ever? wilt thou draw out thine anger to all generations?'),
  ('KJV', 'Psalms', 19, 85, 6, 'Wilt thou not revive us again: that thy people may rejoice in thee?'),
  ('KJV', 'Psalms', 19, 85, 7, 'Shew us thy mercy, O LORD, and grant us thy salvation.'),
  ('KJV', 'Psalms', 19, 85, 8, 'I will hear what God the LORD will speak: for he will speak peace unto his people, and to his saints: but let them not turn again to folly.'),
  ('KJV', 'Psalms', 19, 85, 9, 'Surely his salvation is nigh them that fear him; that glory may dwell in our land.'),
  ('KJV', 'Psalms', 19, 85, 10, 'Mercy and truth are met together; righteousness and peace have kissed each other.'),
  ('KJV', 'Psalms', 19, 85, 11, 'Truth shall spring out of the earth; and righteousness shall look down from heaven.'),
  ('KJV', 'Psalms', 19, 85, 12, 'Yea, the LORD shall give that which is good; and our land shall yield her increase.'),
  ('KJV', 'Psalms', 19, 85, 13, 'Righteousness shall go before him; and shall set us in the way of his steps.'),
  ('KJV', 'Psalms', 19, 86, 1, 'A Prayer of David. Bow down thine ear, O LORD, hear me: for I am poor and needy.'),
  ('KJV', 'Psalms', 19, 86, 2, 'Preserve my soul; for I am holy: O thou my God, save thy servant that trusteth in thee.'),
  ('KJV', 'Psalms', 19, 86, 3, 'Be merciful unto me, O Lord: for I cry unto thee daily.'),
  ('KJV', 'Psalms', 19, 86, 4, 'Rejoice the soul of thy servant: for unto thee, O Lord, do I lift up my soul.'),
  ('KJV', 'Psalms', 19, 86, 5, 'For thou, Lord, art good, and ready to forgive; and plenteous in mercy unto all them that call upon thee.'),
  ('KJV', 'Psalms', 19, 86, 6, 'Give ear, O LORD, unto my prayer; and attend to the voice of my supplications.'),
  ('KJV', 'Psalms', 19, 86, 7, 'In the day of my trouble I will call upon thee: for thou wilt answer me.'),
  ('KJV', 'Psalms', 19, 86, 8, 'Among the gods there is none like unto thee, O Lord; neither are there any works like unto thy works.'),
  ('KJV', 'Psalms', 19, 86, 9, 'All nations whom thou hast made shall come and worship before thee, O Lord; and shall glorify thy name.'),
  ('KJV', 'Psalms', 19, 86, 10, 'For thou art great, and doest wondrous things: thou art God alone.'),
  ('KJV', 'Psalms', 19, 86, 11, 'Teach me thy way, O LORD; I will walk in thy truth: unite my heart to fear thy name.'),
  ('KJV', 'Psalms', 19, 86, 12, 'I will praise thee, O Lord my God, with all my heart: and I will glorify thy name for evermore.'),
  ('KJV', 'Psalms', 19, 86, 13, 'For great is thy mercy toward me: and thou hast delivered my soul from the lowest hell.'),
  ('KJV', 'Psalms', 19, 86, 14, 'O God, the proud are risen against me, and the assemblies of violent men have sought after my soul; and have not set thee before them.'),
  ('KJV', 'Psalms', 19, 86, 15, 'But thou, O Lord, art a God full of compassion, and gracious, longsuffering, and plenteous in mercy and truth.'),
  ('KJV', 'Psalms', 19, 86, 16, 'O turn unto me, and have mercy upon me; give thy strength unto thy servant, and save the son of thine handmaid.'),
  ('KJV', 'Psalms', 19, 86, 17, 'Shew me a token for good; that they which hate me may see it, and be ashamed: because thou, LORD, hast holpen me, and comforted me.'),
  ('KJV', 'Psalms', 19, 87, 1, 'A Psalm or Song for the sons of Korah. His foundation is in the holy mountains.'),
  ('KJV', 'Psalms', 19, 87, 2, 'The LORD loveth the gates of Zion more than all the dwellings of Jacob.'),
  ('KJV', 'Psalms', 19, 87, 3, 'Glorious things are spoken of thee, O city of God. Selah.'),
  ('KJV', 'Psalms', 19, 87, 4, 'I will make mention of Rahab and Babylon to them that know me: behold Philistia, and Tyre, with Ethiopia; this man was born there.'),
  ('KJV', 'Psalms', 19, 87, 5, 'And of Zion it shall be said, This and that man was born in her: and the highest himself shall establish her.'),
  ('KJV', 'Psalms', 19, 87, 6, 'The LORD shall count, when he writeth up the people, that this man was born there. Selah.'),
  ('KJV', 'Psalms', 19, 87, 7, 'As well the singers as the players on instruments shall be there: all my springs are in thee.'),
  ('KJV', 'Psalms', 19, 88, 1, 'A Song or Psalm for the sons of Korah, to the chief Musician upon Mahalath Leannoth, Maschil of Heman the Ezrahite. O LORD God of my salvation, I have cried day and night before thee:'),
  ('KJV', 'Psalms', 19, 88, 2, 'Let my prayer come before thee: incline thine ear unto my cry;'),
  ('KJV', 'Psalms', 19, 88, 3, 'For my soul is full of troubles: and my life draweth nigh unto the grave.'),
  ('KJV', 'Psalms', 19, 88, 4, 'I am counted with them that go down into the pit: I am as a man that hath no strength:'),
  ('KJV', 'Psalms', 19, 88, 5, 'Free among the dead, like the slain that lie in the grave, whom thou rememberest no more: and they are cut off from thy hand.'),
  ('KJV', 'Psalms', 19, 88, 6, 'Thou hast laid me in the lowest pit, in darkness, in the deeps.'),
  ('KJV', 'Psalms', 19, 88, 7, 'Thy wrath lieth hard upon me, and thou hast afflicted me with all thy waves. Selah.'),
  ('KJV', 'Psalms', 19, 88, 8, 'Thou hast put away mine acquaintance far from me; thou hast made me an abomination unto them: I am shut up, and I cannot come forth.'),
  ('KJV', 'Psalms', 19, 88, 9, 'Mine eye mourneth by reason of affliction: LORD, I have called daily upon thee, I have stretched out my hands unto thee.'),
  ('KJV', 'Psalms', 19, 88, 10, 'Wilt thou shew wonders to the dead? shall the dead arise and praise thee? Selah.'),
  ('KJV', 'Psalms', 19, 88, 11, 'Shall thy lovingkindness be declared in the grave? or thy faithfulness in destruction?'),
  ('KJV', 'Psalms', 19, 88, 12, 'Shall thy wonders be known in the dark? and thy righteousness in the land of forgetfulness?'),
  ('KJV', 'Psalms', 19, 88, 13, 'But unto thee have I cried, O LORD; and in the morning shall my prayer prevent thee.'),
  ('KJV', 'Psalms', 19, 88, 14, 'LORD, why castest thou off my soul? why hidest thou thy face from me?'),
  ('KJV', 'Psalms', 19, 88, 15, 'I am afflicted and ready to die from my youth up: while I suffer thy terrors I am distracted.'),
  ('KJV', 'Psalms', 19, 88, 16, 'Thy fierce wrath goeth over me; thy terrors have cut me off.'),
  ('KJV', 'Psalms', 19, 88, 17, 'They came round about me daily like water; they compassed me about together.'),
  ('KJV', 'Psalms', 19, 88, 18, 'Lover and friend hast thou put far from me, and mine acquaintance into darkness.'),
  ('KJV', 'Psalms', 19, 89, 1, 'Maschil of Ethan the Ezrahite. I will sing of the mercies of the LORD for ever: with my mouth will I make known thy faithfulness to all generations.'),
  ('KJV', 'Psalms', 19, 89, 2, 'For I have said, Mercy shall be built up for ever: thy faithfulness shalt thou establish in the very heavens.'),
  ('KJV', 'Psalms', 19, 89, 3, 'I have made a covenant with my chosen, I have sworn unto David my servant,'),
  ('KJV', 'Psalms', 19, 89, 4, 'Thy seed will I establish for ever, and build up thy throne to all generations. Selah.'),
  ('KJV', 'Psalms', 19, 89, 5, 'And the heavens shall praise thy wonders, O LORD: thy faithfulness also in the congregation of the saints.'),
  ('KJV', 'Psalms', 19, 89, 6, 'For who in the heaven can be compared unto the LORD? who among the sons of the mighty can be likened unto the LORD?'),
  ('KJV', 'Psalms', 19, 89, 7, 'God is greatly to be feared in the assembly of the saints, and to be had in reverence of all them that are about him.'),
  ('KJV', 'Psalms', 19, 89, 8, 'O LORD God of hosts, who is a strong LORD like unto thee? or to thy faithfulness round about thee?'),
  ('KJV', 'Psalms', 19, 89, 9, 'Thou rulest the raging of the sea: when the waves thereof arise, thou stillest them.'),
  ('KJV', 'Psalms', 19, 89, 10, 'Thou hast broken Rahab in pieces, as one that is slain; thou hast scattered thine enemies with thy strong arm.'),
  ('KJV', 'Psalms', 19, 89, 11, 'The heavens are thine, the earth also is thine: as for the world and the fulness thereof, thou hast founded them.'),
  ('KJV', 'Psalms', 19, 89, 12, 'The north and the south thou hast created them: Tabor and Hermon shall rejoice in thy name.'),
  ('KJV', 'Psalms', 19, 89, 13, 'Thou hast a mighty arm: strong is thy hand, and high is thy right hand.'),
  ('KJV', 'Psalms', 19, 89, 14, 'Justice and judgment are the habitation of thy throne: mercy and truth shall go before thy face.'),
  ('KJV', 'Psalms', 19, 89, 15, 'Blessed is the people that know the joyful sound: they shall walk, O LORD, in the light of thy countenance.'),
  ('KJV', 'Psalms', 19, 89, 16, 'In thy name shall they rejoice all the day: and in thy righteousness shall they be exalted.'),
  ('KJV', 'Psalms', 19, 89, 17, 'For thou art the glory of their strength: and in thy favour our horn shall be exalted.'),
  ('KJV', 'Psalms', 19, 89, 18, 'For the LORD is our defence; and the Holy One of Israel is our king.'),
  ('KJV', 'Psalms', 19, 89, 19, 'Then thou spakest in vision to thy holy one, and saidst, I have laid help upon one that is mighty; I have exalted one chosen out of the people.'),
  ('KJV', 'Psalms', 19, 89, 20, 'I have found David my servant; with my holy oil have I anointed him:'),
  ('KJV', 'Psalms', 19, 89, 21, 'With whom my hand shall be established: mine arm also shall strengthen him.'),
  ('KJV', 'Psalms', 19, 89, 22, 'The enemy shall not exact upon him; nor the son of wickedness afflict him.'),
  ('KJV', 'Psalms', 19, 89, 23, 'And I will beat down his foes before his face, and plague them that hate him.'),
  ('KJV', 'Psalms', 19, 89, 24, 'But my faithfulness and my mercy shall be with him: and in my name shall his horn be exalted.'),
  ('KJV', 'Psalms', 19, 89, 25, 'I will set his hand also in the sea, and his right hand in the rivers.'),
  ('KJV', 'Psalms', 19, 89, 26, 'He shall cry unto me, Thou art my father, my God, and the rock of my salvation.'),
  ('KJV', 'Psalms', 19, 89, 27, 'Also I will make him my firstborn, higher than the kings of the earth.'),
  ('KJV', 'Psalms', 19, 89, 28, 'My mercy will I keep for him for evermore, and my covenant shall stand fast with him.'),
  ('KJV', 'Psalms', 19, 89, 29, 'His seed also will I make to endure for ever, and his throne as the days of heaven.'),
  ('KJV', 'Psalms', 19, 89, 30, 'If his children forsake my law, and walk not in my judgments;'),
  ('KJV', 'Psalms', 19, 89, 31, 'If they break my statutes, and keep not my commandments;'),
  ('KJV', 'Psalms', 19, 89, 32, 'Then will I visit their transgression with the rod, and their iniquity with stripes.'),
  ('KJV', 'Psalms', 19, 89, 33, 'Nevertheless my lovingkindness will I not utterly take from him, nor suffer my faithfulness to fail.'),
  ('KJV', 'Psalms', 19, 89, 34, 'My covenant will I not break, nor alter the thing that is gone out of my lips.'),
  ('KJV', 'Psalms', 19, 89, 35, 'Once have I sworn by my holiness that I will not lie unto David.'),
  ('KJV', 'Psalms', 19, 89, 36, 'His seed shall endure for ever, and his throne as the sun before me.'),
  ('KJV', 'Psalms', 19, 89, 37, 'It shall be established for ever as the moon, and as a faithful witness in heaven. Selah.'),
  ('KJV', 'Psalms', 19, 89, 38, 'But thou hast cast off and abhorred, thou hast been wroth with thine anointed.'),
  ('KJV', 'Psalms', 19, 89, 39, 'Thou hast made void the covenant of thy servant: thou hast profaned his crown by casting it to the ground.'),
  ('KJV', 'Psalms', 19, 89, 40, 'Thou hast broken down all his hedges; thou hast brought his strong holds to ruin.'),
  ('KJV', 'Psalms', 19, 89, 41, 'All that pass by the way spoil him: he is a reproach to his neighbours.'),
  ('KJV', 'Psalms', 19, 89, 42, 'Thou hast set up the right hand of his adversaries; thou hast made all his enemies to rejoice.'),
  ('KJV', 'Psalms', 19, 89, 43, 'Thou hast also turned the edge of his sword, and hast not made him to stand in the battle.'),
  ('KJV', 'Psalms', 19, 89, 44, 'Thou hast made his glory to cease, and cast his throne down to the ground.'),
  ('KJV', 'Psalms', 19, 89, 45, 'The days of his youth hast thou shortened: thou hast covered him with shame. Selah.'),
  ('KJV', 'Psalms', 19, 89, 46, 'How long, LORD? wilt thou hide thyself for ever? shall thy wrath burn like fire?'),
  ('KJV', 'Psalms', 19, 89, 47, 'Remember how short my time is: wherefore hast thou made all men in vain?'),
  ('KJV', 'Psalms', 19, 89, 48, 'What man is he that liveth, and shall not see death? shall he deliver his soul from the hand of the grave? Selah.'),
  ('KJV', 'Psalms', 19, 89, 49, 'Lord, where are thy former lovingkindnesses, which thou swarest unto David in thy truth?'),
  ('KJV', 'Psalms', 19, 89, 50, 'Remember, Lord, the reproach of thy servants; how I do bear in my bosom the reproach of all the mighty people;'),
  ('KJV', 'Psalms', 19, 89, 51, 'Wherewith thine enemies have reproached, O LORD; wherewith they have reproached the footsteps of thine anointed.'),
  ('KJV', 'Psalms', 19, 89, 52, 'Blessed be the LORD for evermore. Amen, and Amen.'),
  ('KJV', 'Psalms', 19, 90, 1, 'A Prayer of Moses the man of God. Lord, thou hast been our dwelling place in all generations.'),
  ('KJV', 'Psalms', 19, 90, 2, 'Before the mountains were brought forth, or ever thou hadst formed the earth and the world, even from everlasting to everlasting, thou art God.'),
  ('KJV', 'Psalms', 19, 90, 3, 'Thou turnest man to destruction; and sayest, Return, ye children of men.'),
  ('KJV', 'Psalms', 19, 90, 4, 'For a thousand years in thy sight are but as yesterday when it is past, and as a watch in the night.'),
  ('KJV', 'Psalms', 19, 90, 5, 'Thou carriest them away as with a flood; they are as a sleep: in the morning they are like grass which groweth up.'),
  ('KJV', 'Psalms', 19, 90, 6, 'In the morning it flourisheth, and groweth up; in the evening it is cut down, and withereth.'),
  ('KJV', 'Psalms', 19, 90, 7, 'For we are consumed by thine anger, and by thy wrath are we troubled.'),
  ('KJV', 'Psalms', 19, 90, 8, 'Thou hast set our iniquities before thee, our secret sins in the light of thy countenance.'),
  ('KJV', 'Psalms', 19, 90, 9, 'For all our days are passed away in thy wrath: we spend our years as a tale that is told.'),
  ('KJV', 'Psalms', 19, 90, 10, 'The days of our years are threescore years and ten; and if by reason of strength they be fourscore years, yet is their strength labour and sorrow; for it is soon cut off, and we fly away.'),
  ('KJV', 'Psalms', 19, 90, 11, 'Who knoweth the power of thine anger? even according to thy fear, so is thy wrath.'),
  ('KJV', 'Psalms', 19, 90, 12, 'So teach us to number our days, that we may apply our hearts unto wisdom.'),
  ('KJV', 'Psalms', 19, 90, 13, 'Return, O LORD, how long? and let it repent thee concerning thy servants.'),
  ('KJV', 'Psalms', 19, 90, 14, 'O satisfy us early with thy mercy; that we may rejoice and be glad all our days.'),
  ('KJV', 'Psalms', 19, 90, 15, 'Make us glad according to the days wherein thou hast afflicted us, and the years wherein we have seen evil.'),
  ('KJV', 'Psalms', 19, 90, 16, 'Let thy work appear unto thy servants, and thy glory unto their children.'),
  ('KJV', 'Psalms', 19, 90, 17, 'And let the beauty of the LORD our God be upon us: and establish thou the work of our hands upon us; yea, the work of our hands establish thou it.'),
  ('KJV', 'Psalms', 19, 91, 1, 'He that dwelleth in the secret place of the most High shall abide under the shadow of the Almighty.'),
  ('KJV', 'Psalms', 19, 91, 2, 'I will say of the LORD, He is my refuge and my fortress: my God; in him will I trust.'),
  ('KJV', 'Psalms', 19, 91, 3, 'Surely he shall deliver thee from the snare of the fowler, and from the noisome pestilence.'),
  ('KJV', 'Psalms', 19, 91, 4, 'He shall cover thee with his feathers, and under his wings shalt thou trust: his truth shall be thy shield and buckler.'),
  ('KJV', 'Psalms', 19, 91, 5, 'Thou shalt not be afraid for the terror by night; nor for the arrow that flieth by day;'),
  ('KJV', 'Psalms', 19, 91, 6, 'Nor for the pestilence that walketh in darkness; nor for the destruction that wasteth at noonday.'),
  ('KJV', 'Psalms', 19, 91, 7, 'A thousand shall fall at thy side, and ten thousand at thy right hand; but it shall not come nigh thee.'),
  ('KJV', 'Psalms', 19, 91, 8, 'Only with thine eyes shalt thou behold and see the reward of the wicked.'),
  ('KJV', 'Psalms', 19, 91, 9, 'Because thou hast made the LORD, which is my refuge, even the most High, thy habitation;'),
  ('KJV', 'Psalms', 19, 91, 10, 'There shall no evil befall thee, neither shall any plague come nigh thy dwelling.'),
  ('KJV', 'Psalms', 19, 91, 11, 'For he shall give his angels charge over thee, to keep thee in all thy ways.'),
  ('KJV', 'Psalms', 19, 91, 12, 'They shall bear thee up in their hands, lest thou dash thy foot against a stone.'),
  ('KJV', 'Psalms', 19, 91, 13, 'Thou shalt tread upon the lion and adder: the young lion and the dragon shalt thou trample under feet.'),
  ('KJV', 'Psalms', 19, 91, 14, 'Because he hath set his love upon me, therefore will I deliver him: I will set him on high, because he hath known my name.'),
  ('KJV', 'Psalms', 19, 91, 15, 'He shall call upon me, and I will answer him: I will be with him in trouble; I will deliver him, and honour him.'),
  ('KJV', 'Psalms', 19, 91, 16, 'With long life will I satisfy him, and shew him my salvation.'),
  ('KJV', 'Psalms', 19, 92, 1, 'A Psalm or Song for the sabbath day. It is a good thing to give thanks unto the LORD, and to sing praises unto thy name, O most High:'),
  ('KJV', 'Psalms', 19, 92, 2, 'To shew forth thy lovingkindness in the morning, and thy faithfulness every night,'),
  ('KJV', 'Psalms', 19, 92, 3, 'Upon an instrument of ten strings, and upon the psaltery; upon the harp with a solemn sound.'),
  ('KJV', 'Psalms', 19, 92, 4, 'For thou, LORD, hast made me glad through thy work: I will triumph in the works of thy hands.'),
  ('KJV', 'Psalms', 19, 92, 5, 'O LORD, how great are thy works! and thy thoughts are very deep.'),
  ('KJV', 'Psalms', 19, 92, 6, 'A brutish man knoweth not; neither doth a fool understand this.'),
  ('KJV', 'Psalms', 19, 92, 7, 'When the wicked spring as the grass, and when all the workers of iniquity do flourish; it is that they shall be destroyed for ever:'),
  ('KJV', 'Psalms', 19, 92, 8, 'But thou, LORD, art most high for evermore.'),
  ('KJV', 'Psalms', 19, 92, 9, 'For, lo, thine enemies, O LORD, for, lo, thine enemies shall perish; all the workers of iniquity shall be scattered.'),
  ('KJV', 'Psalms', 19, 92, 10, 'But my horn shalt thou exalt like the horn of an unicorn: I shall be anointed with fresh oil.'),
  ('KJV', 'Psalms', 19, 92, 11, 'Mine eye also shall see my desire on mine enemies, and mine ears shall hear my desire of the wicked that rise up against me.'),
  ('KJV', 'Psalms', 19, 92, 12, 'The righteous shall flourish like the palm tree: he shall grow like a cedar in Lebanon.'),
  ('KJV', 'Psalms', 19, 92, 13, 'Those that be planted in the house of the LORD shall flourish in the courts of our God.'),
  ('KJV', 'Psalms', 19, 92, 14, 'They shall still bring forth fruit in old age; they shall be fat and flourishing;'),
  ('KJV', 'Psalms', 19, 92, 15, 'To shew that the LORD is upright: he is my rock, and there is no unrighteousness in him.'),
  ('KJV', 'Psalms', 19, 93, 1, 'The LORD reigneth, he is clothed with majesty; the LORD is clothed with strength, wherewith he hath girded himself: the world also is stablished, that it cannot be moved.'),
  ('KJV', 'Psalms', 19, 93, 2, 'Thy throne is established of old: thou art from everlasting.'),
  ('KJV', 'Psalms', 19, 93, 3, 'The floods have lifted up, O LORD, the floods have lifted up their voice; the floods lift up their waves.'),
  ('KJV', 'Psalms', 19, 93, 4, 'The LORD on high is mightier than the noise of many waters, yea, than the mighty waves of the sea.'),
  ('KJV', 'Psalms', 19, 93, 5, 'Thy testimonies are very sure: holiness becometh thine house, O LORD, for ever.'),
  ('KJV', 'Psalms', 19, 94, 1, 'O LORD God, to whom vengeance belongeth; O God, to whom vengeance belongeth, shew thyself.'),
  ('KJV', 'Psalms', 19, 94, 2, 'Lift up thyself, thou judge of the earth: render a reward to the proud.'),
  ('KJV', 'Psalms', 19, 94, 3, 'LORD, how long shall the wicked, how long shall the wicked triumph?'),
  ('KJV', 'Psalms', 19, 94, 4, 'How long shall they utter and speak hard things? and all the workers of iniquity boast themselves?'),
  ('KJV', 'Psalms', 19, 94, 5, 'They break in pieces thy people, O LORD, and afflict thine heritage.'),
  ('KJV', 'Psalms', 19, 94, 6, 'They slay the widow and the stranger, and murder the fatherless.'),
  ('KJV', 'Psalms', 19, 94, 7, 'Yet they say, The LORD shall not see, neither shall the God of Jacob regard it.'),
  ('KJV', 'Psalms', 19, 94, 8, 'Understand, ye brutish among the people: and ye fools, when will ye be wise?'),
  ('KJV', 'Psalms', 19, 94, 9, 'He that planted the ear, shall he not hear? he that formed the eye, shall he not see?'),
  ('KJV', 'Psalms', 19, 94, 10, 'He that chastiseth the heathen, shall not he correct? he that teacheth man knowledge, shall not he know?'),
  ('KJV', 'Psalms', 19, 94, 11, 'The LORD knoweth the thoughts of man, that they are vanity.'),
  ('KJV', 'Psalms', 19, 94, 12, 'Blessed is the man whom thou chastenest, O LORD, and teachest him out of thy law;'),
  ('KJV', 'Psalms', 19, 94, 13, 'That thou mayest give him rest from the days of adversity, until the pit be digged for the wicked.'),
  ('KJV', 'Psalms', 19, 94, 14, 'For the LORD will not cast off his people, neither will he forsake his inheritance.'),
  ('KJV', 'Psalms', 19, 94, 15, 'But judgment shall return unto righteousness: and all the upright in heart shall follow it.'),
  ('KJV', 'Psalms', 19, 94, 16, 'Who will rise up for me against the evildoers? or who will stand up for me against the workers of iniquity?'),
  ('KJV', 'Psalms', 19, 94, 17, 'Unless the LORD had been my help, my soul had almost dwelt in silence.'),
  ('KJV', 'Psalms', 19, 94, 18, 'When I said, My foot slippeth; thy mercy, O LORD, held me up.'),
  ('KJV', 'Psalms', 19, 94, 19, 'In the multitude of my thoughts within me thy comforts delight my soul.'),
  ('KJV', 'Psalms', 19, 94, 20, 'Shall the throne of iniquity have fellowship with thee, which frameth mischief by a law?'),
  ('KJV', 'Psalms', 19, 94, 21, 'They gather themselves together against the soul of the righteous, and condemn the innocent blood.'),
  ('KJV', 'Psalms', 19, 94, 22, 'But the LORD is my defence; and my God is the rock of my refuge.'),
  ('KJV', 'Psalms', 19, 94, 23, 'And he shall bring upon them their own iniquity, and shall cut them off in their own wickedness; yea, the LORD our God shall cut them off.'),
  ('KJV', 'Psalms', 19, 95, 1, 'O come, let us sing unto the LORD: let us make a joyful noise to the rock of our salvation.'),
  ('KJV', 'Psalms', 19, 95, 2, 'Let us come before his presence with thanksgiving, and make a joyful noise unto him with psalms.'),
  ('KJV', 'Psalms', 19, 95, 3, 'For the LORD is a great God, and a great King above all gods.'),
  ('KJV', 'Psalms', 19, 95, 4, 'In his hand are the deep places of the earth: the strength of the hills is his also.'),
  ('KJV', 'Psalms', 19, 95, 5, 'The sea is his, and he made it: and his hands formed the dry land.'),
  ('KJV', 'Psalms', 19, 95, 6, 'O come, let us worship and bow down: let us kneel before the LORD our maker.'),
  ('KJV', 'Psalms', 19, 95, 7, 'For he is our God; and we are the people of his pasture, and the sheep of his hand. To day if ye will hear his voice,'),
  ('KJV', 'Psalms', 19, 95, 8, 'Harden not your heart, as in the provocation, and as in the day of temptation in the wilderness:'),
  ('KJV', 'Psalms', 19, 95, 9, 'When your fathers tempted me, proved me, and saw my work.'),
  ('KJV', 'Psalms', 19, 95, 10, 'Forty years long was I grieved with this generation, and said, It is a people that do err in their heart, and they have not known my ways:'),
  ('KJV', 'Psalms', 19, 95, 11, 'Unto whom I sware in my wrath that they should not enter into my rest.'),
  ('KJV', 'Psalms', 19, 96, 1, 'O sing unto the LORD a new song: sing unto the LORD, all the earth.'),
  ('KJV', 'Psalms', 19, 96, 2, 'Sing unto the LORD, bless his name; shew forth his salvation from day to day.'),
  ('KJV', 'Psalms', 19, 96, 3, 'Declare his glory among the heathen, his wonders among all people.'),
  ('KJV', 'Psalms', 19, 96, 4, 'For the LORD is great, and greatly to be praised: he is to be feared above all gods.'),
  ('KJV', 'Psalms', 19, 96, 5, 'For all the gods of the nations are idols: but the LORD made the heavens.'),
  ('KJV', 'Psalms', 19, 96, 6, 'Honour and majesty are before him: strength and beauty are in his sanctuary.'),
  ('KJV', 'Psalms', 19, 96, 7, 'Give unto the LORD, O ye kindreds of the people, give unto the LORD glory and strength.'),
  ('KJV', 'Psalms', 19, 96, 8, 'Give unto the LORD the glory due unto his name: bring an offering, and come into his courts.'),
  ('KJV', 'Psalms', 19, 96, 9, 'O worship the LORD in the beauty of holiness: fear before him, all the earth.'),
  ('KJV', 'Psalms', 19, 96, 10, 'Say among the heathen that the LORD reigneth: the world also shall be established that it shall not be moved: he shall judge the people righteously.'),
  ('KJV', 'Psalms', 19, 96, 11, 'Let the heavens rejoice, and let the earth be glad; let the sea roar, and the fulness thereof.'),
  ('KJV', 'Psalms', 19, 96, 12, 'Let the field be joyful, and all that is therein: then shall all the trees of the wood rejoice'),
  ('KJV', 'Psalms', 19, 96, 13, 'Before the LORD: for he cometh, for he cometh to judge the earth: he shall judge the world with righteousness, and the people with his truth.'),
  ('KJV', 'Psalms', 19, 97, 1, 'The LORD reigneth; let the earth rejoice; let the multitude of isles be glad thereof.'),
  ('KJV', 'Psalms', 19, 97, 2, 'Clouds and darkness are round about him: righteousness and judgment are the habitation of his throne.'),
  ('KJV', 'Psalms', 19, 97, 3, 'A fire goeth before him, and burneth up his enemies round about.'),
  ('KJV', 'Psalms', 19, 97, 4, 'His lightnings enlightened the world: the earth saw, and trembled.'),
  ('KJV', 'Psalms', 19, 97, 5, 'The hills melted like wax at the presence of the LORD, at the presence of the Lord of the whole earth.'),
  ('KJV', 'Psalms', 19, 97, 6, 'The heavens declare his righteousness, and all the people see his glory.'),
  ('KJV', 'Psalms', 19, 97, 7, 'Confounded be all they that serve graven images, that boast themselves of idols: worship him, all ye gods.'),
  ('KJV', 'Psalms', 19, 97, 8, 'Zion heard, and was glad; and the daughters of Judah rejoiced because of thy judgments, O LORD.'),
  ('KJV', 'Psalms', 19, 97, 9, 'For thou, LORD, art high above all the earth: thou art exalted far above all gods.'),
  ('KJV', 'Psalms', 19, 97, 10, 'Ye that love the LORD, hate evil: he preserveth the souls of his saints; he delivereth them out of the hand of the wicked.'),
  ('KJV', 'Psalms', 19, 97, 11, 'Light is sown for the righteous, and gladness for the upright in heart.'),
  ('KJV', 'Psalms', 19, 97, 12, 'Rejoice in the LORD, ye righteous; and give thanks at the remembrance of his holiness.'),
  ('KJV', 'Psalms', 19, 98, 1, 'A Psalm. O sing unto the LORD a new song; for he hath done marvellous things: his right hand, and his holy arm, hath gotten him the victory.'),
  ('KJV', 'Psalms', 19, 98, 2, 'The LORD hath made known his salvation: his righteousness hath he openly shewed in the sight of the heathen.'),
  ('KJV', 'Psalms', 19, 98, 3, 'He hath remembered his mercy and his truth toward the house of Israel: all the ends of the earth have seen the salvation of our God.'),
  ('KJV', 'Psalms', 19, 98, 4, 'Make a joyful noise unto the LORD, all the earth: make a loud noise, and rejoice, and sing praise.'),
  ('KJV', 'Psalms', 19, 98, 5, 'Sing unto the LORD with the harp; with the harp, and the voice of a psalm.'),
  ('KJV', 'Psalms', 19, 98, 6, 'With trumpets and sound of cornet make a joyful noise before the LORD, the King.'),
  ('KJV', 'Psalms', 19, 98, 7, 'Let the sea roar, and the fulness thereof; the world, and they that dwell therein.'),
  ('KJV', 'Psalms', 19, 98, 8, 'Let the floods clap their hands: let the hills be joyful together'),
  ('KJV', 'Psalms', 19, 98, 9, 'Before the LORD; for he cometh to judge the earth: with righteousness shall he judge the world, and the people with equity.')
insert into control_room_bible (version, book, book_num, chapter, verse, text) values
  ('KJV', 'Psalms', 19, 99, 1, 'The LORD reigneth; let the people tremble: he sitteth between the cherubims; let the earth be moved.'),
  ('KJV', 'Psalms', 19, 99, 2, 'The LORD is great in Zion; and he is high above all the people.'),
  ('KJV', 'Psalms', 19, 99, 3, 'Let them praise thy great and terrible name; for it is holy.'),
  ('KJV', 'Psalms', 19, 99, 4, 'The king''s strength also loveth judgment; thou dost establish equity, thou executest judgment and righteousness in Jacob.'),
  ('KJV', 'Psalms', 19, 99, 5, 'Exalt ye the LORD our God, and worship at his footstool; for he is holy.'),
  ('KJV', 'Psalms', 19, 99, 6, 'Moses and Aaron among his priests, and Samuel among them that call upon his name; they called upon the LORD, and he answered them.'),
  ('KJV', 'Psalms', 19, 99, 7, 'He spake unto them in the cloudy pillar: they kept his testimonies, and the ordinance that he gave them.'),
  ('KJV', 'Psalms', 19, 99, 8, 'Thou answeredst them, O LORD our God: thou wast a God that forgavest them, though thou tookest vengeance of their inventions.'),
  ('KJV', 'Psalms', 19, 99, 9, 'Exalt the LORD our God, and worship at his holy hill; for the LORD our God is holy.'),
  ('KJV', 'Psalms', 19, 100, 1, 'A Psalm of praise. Make a joyful noise unto the LORD, all ye lands.'),
  ('KJV', 'Psalms', 19, 100, 2, 'Serve the LORD with gladness: come before his presence with singing.'),
  ('KJV', 'Psalms', 19, 100, 3, 'Know ye that the LORD he is God: it is he that hath made us, and not we ourselves; we are his people, and the sheep of his pasture.'),
  ('KJV', 'Psalms', 19, 100, 4, 'Enter into his gates with thanksgiving, and into his courts with praise: be thankful unto him, and bless his name.'),
  ('KJV', 'Psalms', 19, 100, 5, 'For the LORD is good; his mercy is everlasting; and his truth endureth to all generations.'),
  ('KJV', 'Psalms', 19, 101, 1, 'A Psalm of David. I will sing of mercy and judgment: unto thee, O LORD, will I sing.'),
  ('KJV', 'Psalms', 19, 101, 2, 'I will behave myself wisely in a perfect way. O when wilt thou come unto me? I will walk within my house with a perfect heart.'),
  ('KJV', 'Psalms', 19, 101, 3, 'I will set no wicked thing before mine eyes: I hate the work of them that turn aside; it shall not cleave to me.'),
  ('KJV', 'Psalms', 19, 101, 4, 'A froward heart shall depart from me: I will not know a wicked person.'),
  ('KJV', 'Psalms', 19, 101, 5, 'Whoso privily slandereth his neighbour, him will I cut off: him that hath an high look and a proud heart will not I suffer.'),
  ('KJV', 'Psalms', 19, 101, 6, 'Mine eyes shall be upon the faithful of the land, that they may dwell with me: he that walketh in a perfect way, he shall serve me.'),
  ('KJV', 'Psalms', 19, 101, 7, 'He that worketh deceit shall not dwell within my house: he that telleth lies shall not tarry in my sight.'),
  ('KJV', 'Psalms', 19, 101, 8, 'I will early destroy all the wicked of the land; that I may cut off all wicked doers from the city of the LORD.'),
  ('KJV', 'Psalms', 19, 102, 1, 'A Prayer of the afflicted, when he is overwhelmed, and poureth out his complaint before the LORD. Hear my prayer, O LORD, and let my cry come unto thee.'),
  ('KJV', 'Psalms', 19, 102, 2, 'Hide not thy face from me in the day when I am in trouble; incline thine ear unto me: in the day when I call answer me speedily.'),
  ('KJV', 'Psalms', 19, 102, 3, 'For my days are consumed like smoke, and my bones are burned as an hearth.'),
  ('KJV', 'Psalms', 19, 102, 4, 'My heart is smitten, and withered like grass; so that I forget to eat my bread.'),
  ('KJV', 'Psalms', 19, 102, 5, 'By reason of the voice of my groaning my bones cleave to my skin.'),
  ('KJV', 'Psalms', 19, 102, 6, 'I am like a pelican of the wilderness: I am like an owl of the desert.'),
  ('KJV', 'Psalms', 19, 102, 7, 'I watch, and am as a sparrow alone upon the house top.'),
  ('KJV', 'Psalms', 19, 102, 8, 'Mine enemies reproach me all the day; and they that are mad against me are sworn against me.'),
  ('KJV', 'Psalms', 19, 102, 9, 'For I have eaten ashes like bread, and mingled my drink with weeping,'),
  ('KJV', 'Psalms', 19, 102, 10, 'Because of thine indignation and thy wrath: for thou hast lifted me up, and cast me down.'),
  ('KJV', 'Psalms', 19, 102, 11, 'My days are like a shadow that declineth; and I am withered like grass.'),
  ('KJV', 'Psalms', 19, 102, 12, 'But thou, O LORD, shalt endure for ever; and thy remembrance unto all generations.'),
  ('KJV', 'Psalms', 19, 102, 13, 'Thou shalt arise, and have mercy upon Zion: for the time to favour her, yea, the set time, is come.'),
  ('KJV', 'Psalms', 19, 102, 14, 'For thy servants take pleasure in her stones, and favour the dust thereof.'),
  ('KJV', 'Psalms', 19, 102, 15, 'So the heathen shall fear the name of the LORD, and all the kings of the earth thy glory.'),
  ('KJV', 'Psalms', 19, 102, 16, 'When the LORD shall build up Zion, he shall appear in his glory.'),
  ('KJV', 'Psalms', 19, 102, 17, 'He will regard the prayer of the destitute, and not despise their prayer.'),
  ('KJV', 'Psalms', 19, 102, 18, 'This shall be written for the generation to come: and the people which shall be created shall praise the LORD.'),
  ('KJV', 'Psalms', 19, 102, 19, 'For he hath looked down from the height of his sanctuary; from heaven did the LORD behold the earth;'),
  ('KJV', 'Psalms', 19, 102, 20, 'To hear the groaning of the prisoner; to loose those that are appointed to death;'),
  ('KJV', 'Psalms', 19, 102, 21, 'To declare the name of the LORD in Zion, and his praise in Jerusalem;'),
  ('KJV', 'Psalms', 19, 102, 22, 'When the people are gathered together, and the kingdoms, to serve the LORD.'),
  ('KJV', 'Psalms', 19, 102, 23, 'He weakened my strength in the way; he shortened my days.'),
  ('KJV', 'Psalms', 19, 102, 24, 'I said, O my God, take me not away in the midst of my days: thy years are throughout all generations.'),
  ('KJV', 'Psalms', 19, 102, 25, 'Of old hast thou laid the foundation of the earth: and the heavens are the work of thy hands.'),
  ('KJV', 'Psalms', 19, 102, 26, 'They shall perish, but thou shalt endure: yea, all of them shall wax old like a garment; as a vesture shalt thou change them, and they shall be changed:'),
  ('KJV', 'Psalms', 19, 102, 27, 'But thou art the same, and thy years shall have no end.'),
  ('KJV', 'Psalms', 19, 102, 28, 'The children of thy servants shall continue, and their seed shall be established before thee.'),
  ('KJV', 'Psalms', 19, 103, 1, 'A Psalm of David. Bless the LORD, O my soul: and all that is within me, bless his holy name.'),
  ('KJV', 'Psalms', 19, 103, 2, 'Bless the LORD, O my soul, and forget not all his benefits:'),
  ('KJV', 'Psalms', 19, 103, 3, 'Who forgiveth all thine iniquities; who healeth all thy diseases;'),
  ('KJV', 'Psalms', 19, 103, 4, 'Who redeemeth thy life from destruction; who crowneth thee with lovingkindness and tender mercies;'),
  ('KJV', 'Psalms', 19, 103, 5, 'Who satisfieth thy mouth with good things; so that thy youth is renewed like the eagle''s.'),
  ('KJV', 'Psalms', 19, 103, 6, 'The LORD executeth righteousness and judgment for all that are oppressed.'),
  ('KJV', 'Psalms', 19, 103, 7, 'He made known his ways unto Moses, his acts unto the children of Israel.'),
  ('KJV', 'Psalms', 19, 103, 8, 'The LORD is merciful and gracious, slow to anger, and plenteous in mercy.'),
  ('KJV', 'Psalms', 19, 103, 9, 'He will not always chide: neither will he keep his anger for ever.'),
  ('KJV', 'Psalms', 19, 103, 10, 'He hath not dealt with us after our sins; nor rewarded us according to our iniquities.'),
  ('KJV', 'Psalms', 19, 103, 11, 'For as the heaven is high above the earth, so great is his mercy toward them that fear him.'),
  ('KJV', 'Psalms', 19, 103, 12, 'As far as the east is from the west, so far hath he removed our transgressions from us.'),
  ('KJV', 'Psalms', 19, 103, 13, 'Like as a father pitieth his children, so the LORD pitieth them that fear him.'),
  ('KJV', 'Psalms', 19, 103, 14, 'For he knoweth our frame; he remembereth that we are dust.'),
  ('KJV', 'Psalms', 19, 103, 15, 'As for man, his days are as grass: as a flower of the field, so he flourisheth.'),
  ('KJV', 'Psalms', 19, 103, 16, 'For the wind passeth over it, and it is gone; and the place thereof shall know it no more.'),
  ('KJV', 'Psalms', 19, 103, 17, 'But the mercy of the LORD is from everlasting to everlasting upon them that fear him, and his righteousness unto children''s children;'),
  ('KJV', 'Psalms', 19, 103, 18, 'To such as keep his covenant, and to those that remember his commandments to do them.'),
  ('KJV', 'Psalms', 19, 103, 19, 'The LORD hath prepared his throne in the heavens; and his kingdom ruleth over all.'),
  ('KJV', 'Psalms', 19, 103, 20, 'Bless the LORD, ye his angels, that excel in strength, that do his commandments, hearkening unto the voice of his word.'),
  ('KJV', 'Psalms', 19, 103, 21, 'Bless ye the LORD, all ye his hosts; ye ministers of his, that do his pleasure.'),
  ('KJV', 'Psalms', 19, 103, 22, 'Bless the LORD, all his works in all places of his dominion: bless the LORD, O my soul.'),
  ('KJV', 'Psalms', 19, 104, 1, 'Bless the LORD, O my soul. O LORD my God, thou art very great; thou art clothed with honour and majesty.'),
  ('KJV', 'Psalms', 19, 104, 2, 'Who coverest thyself with light as with a garment: who stretchest out the heavens like a curtain:'),
  ('KJV', 'Psalms', 19, 104, 3, 'Who layeth the beams of his chambers in the waters: who maketh the clouds his chariot: who walketh upon the wings of the wind:'),
  ('KJV', 'Psalms', 19, 104, 4, 'Who maketh his angels spirits; his ministers a flaming fire:'),
  ('KJV', 'Psalms', 19, 104, 5, 'Who laid the foundations of the earth, that it should not be removed for ever.'),
  ('KJV', 'Psalms', 19, 104, 6, 'Thou coveredst it with the deep as with a garment: the waters stood above the mountains.'),
  ('KJV', 'Psalms', 19, 104, 7, 'At thy rebuke they fled; at the voice of thy thunder they hasted away.'),
  ('KJV', 'Psalms', 19, 104, 8, 'They go up by the mountains; they go down by the valleys unto the place which thou hast founded for them.'),
  ('KJV', 'Psalms', 19, 104, 9, 'Thou hast set a bound that they may not pass over; that they turn not again to cover the earth.'),
  ('KJV', 'Psalms', 19, 104, 10, 'He sendeth the springs into the valleys, which run among the hills.'),
  ('KJV', 'Psalms', 19, 104, 11, 'They give drink to every beast of the field: the wild asses quench their thirst.'),
  ('KJV', 'Psalms', 19, 104, 12, 'By them shall the fowls of the heaven have their habitation, which sing among the branches.'),
  ('KJV', 'Psalms', 19, 104, 13, 'He watereth the hills from his chambers: the earth is satisfied with the fruit of thy works.'),
  ('KJV', 'Psalms', 19, 104, 14, 'He causeth the grass to grow for the cattle, and herb for the service of man: that he may bring forth food out of the earth;'),
  ('KJV', 'Psalms', 19, 104, 15, 'And wine that maketh glad the heart of man, and oil to make his face to shine, and bread which strengtheneth man''s heart.'),
  ('KJV', 'Psalms', 19, 104, 16, 'The trees of the LORD are full of sap; the cedars of Lebanon, which he hath planted;'),
  ('KJV', 'Psalms', 19, 104, 17, 'Where the birds make their nests: as for the stork, the fir trees are her house.'),
  ('KJV', 'Psalms', 19, 104, 18, 'The high hills are a refuge for the wild goats; and the rocks for the conies.'),
  ('KJV', 'Psalms', 19, 104, 19, 'He appointed the moon for seasons: the sun knoweth his going down.'),
  ('KJV', 'Psalms', 19, 104, 20, 'Thou makest darkness, and it is night: wherein all the beasts of the forest do creep forth.'),
  ('KJV', 'Psalms', 19, 104, 21, 'The young lions roar after their prey, and seek their meat from God.'),
  ('KJV', 'Psalms', 19, 104, 22, 'The sun ariseth, they gather themselves together, and lay them down in their dens.'),
  ('KJV', 'Psalms', 19, 104, 23, 'Man goeth forth unto his work and to his labour until the evening.'),
  ('KJV', 'Psalms', 19, 104, 24, 'O LORD, how manifold are thy works! in wisdom hast thou made them all: the earth is full of thy riches.'),
  ('KJV', 'Psalms', 19, 104, 25, 'So is this great and wide sea, wherein are things creeping innumerable, both small and great beasts.'),
  ('KJV', 'Psalms', 19, 104, 26, 'There go the ships: there is that leviathan, whom thou hast made to play therein.'),
  ('KJV', 'Psalms', 19, 104, 27, 'These wait all upon thee; that thou mayest give them their meat in due season.'),
  ('KJV', 'Psalms', 19, 104, 28, 'That thou givest them they gather: thou openest thine hand, they are filled with good.'),
  ('KJV', 'Psalms', 19, 104, 29, 'Thou hidest thy face, they are troubled: thou takest away their breath, they die, and return to their dust.'),
  ('KJV', 'Psalms', 19, 104, 30, 'Thou sendest forth thy spirit, they are created: and thou renewest the face of the earth.'),
  ('KJV', 'Psalms', 19, 104, 31, 'The glory of the LORD shall endure for ever: the LORD shall rejoice in his works.'),
  ('KJV', 'Psalms', 19, 104, 32, 'He looketh on the earth, and it trembleth: he toucheth the hills, and they smoke.'),
  ('KJV', 'Psalms', 19, 104, 33, 'I will sing unto the LORD as long as I live: I will sing praise to my God while I have my being.'),
  ('KJV', 'Psalms', 19, 104, 34, 'My meditation of him shall be sweet: I will be glad in the LORD.'),
  ('KJV', 'Psalms', 19, 104, 35, 'Let the sinners be consumed out of the earth, and let the wicked be no more. Bless thou the LORD, O my soul. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 105, 1, 'O give thanks unto the LORD; call upon his name: make known his deeds among the people.'),
  ('KJV', 'Psalms', 19, 105, 2, 'Sing unto him, sing psalms unto him: talk ye of all his wondrous works.'),
  ('KJV', 'Psalms', 19, 105, 3, 'Glory ye in his holy name: let the heart of them rejoice that seek the LORD.'),
  ('KJV', 'Psalms', 19, 105, 4, 'Seek the LORD, and his strength: seek his face evermore.'),
  ('KJV', 'Psalms', 19, 105, 5, 'Remember his marvellous works that he hath done; his wonders, and the judgments of his mouth;'),
  ('KJV', 'Psalms', 19, 105, 6, 'O ye seed of Abraham his servant, ye children of Jacob his chosen.'),
  ('KJV', 'Psalms', 19, 105, 7, 'He is the LORD our God: his judgments are in all the earth.'),
  ('KJV', 'Psalms', 19, 105, 8, 'He hath remembered his covenant for ever, the word which he commanded to a thousand generations.'),
  ('KJV', 'Psalms', 19, 105, 9, 'Which covenant he made with Abraham, and his oath unto Isaac;'),
  ('KJV', 'Psalms', 19, 105, 10, 'And confirmed the same unto Jacob for a law, and to Israel for an everlasting covenant:'),
  ('KJV', 'Psalms', 19, 105, 11, 'Saying, Unto thee will I give the land of Canaan, the lot of your inheritance:'),
  ('KJV', 'Psalms', 19, 105, 12, 'When they were but a few men in number; yea, very few, and strangers in it.'),
  ('KJV', 'Psalms', 19, 105, 13, 'When they went from one nation to another, from one kingdom to another people;'),
  ('KJV', 'Psalms', 19, 105, 14, 'He suffered no man to do them wrong: yea, he reproved kings for their sakes;'),
  ('KJV', 'Psalms', 19, 105, 15, 'Saying, Touch not mine anointed, and do my prophets no harm.'),
  ('KJV', 'Psalms', 19, 105, 16, 'Moreover he called for a famine upon the land: he brake the whole staff of bread.'),
  ('KJV', 'Psalms', 19, 105, 17, 'He sent a man before them, even Joseph, who was sold for a servant:'),
  ('KJV', 'Psalms', 19, 105, 18, 'Whose feet they hurt with fetters: he was laid in iron:'),
  ('KJV', 'Psalms', 19, 105, 19, 'Until the time that his word came: the word of the LORD tried him.'),
  ('KJV', 'Psalms', 19, 105, 20, 'The king sent and loosed him; even the ruler of the people, and let him go free.'),
  ('KJV', 'Psalms', 19, 105, 21, 'He made him lord of his house, and ruler of all his substance:'),
  ('KJV', 'Psalms', 19, 105, 22, 'To bind his princes at his pleasure; and teach his senators wisdom.'),
  ('KJV', 'Psalms', 19, 105, 23, 'Israel also came into Egypt; and Jacob sojourned in the land of Ham.'),
  ('KJV', 'Psalms', 19, 105, 24, 'And he increased his people greatly; and made them stronger than their enemies.'),
  ('KJV', 'Psalms', 19, 105, 25, 'He turned their heart to hate his people, to deal subtilly with his servants.'),
  ('KJV', 'Psalms', 19, 105, 26, 'He sent Moses his servant; and Aaron whom he had chosen.'),
  ('KJV', 'Psalms', 19, 105, 27, 'They shewed his signs among them, and wonders in the land of Ham.'),
  ('KJV', 'Psalms', 19, 105, 28, 'He sent darkness, and made it dark; and they rebelled not against his word.'),
  ('KJV', 'Psalms', 19, 105, 29, 'He turned their waters into blood, and slew their fish.'),
  ('KJV', 'Psalms', 19, 105, 30, 'Their land brought forth frogs in abundance, in the chambers of their kings.'),
  ('KJV', 'Psalms', 19, 105, 31, 'He spake, and there came divers sorts of flies, and lice in all their coasts.'),
  ('KJV', 'Psalms', 19, 105, 32, 'He gave them hail for rain, and flaming fire in their land.'),
  ('KJV', 'Psalms', 19, 105, 33, 'He smote their vines also and their fig trees; and brake the trees of their coasts.'),
  ('KJV', 'Psalms', 19, 105, 34, 'He spake, and the locusts came, and caterpillers, and that without number,'),
  ('KJV', 'Psalms', 19, 105, 35, 'And did eat up all the herbs in their land, and devoured the fruit of their ground.'),
  ('KJV', 'Psalms', 19, 105, 36, 'He smote also all the firstborn in their land, the chief of all their strength.'),
  ('KJV', 'Psalms', 19, 105, 37, 'He brought them forth also with silver and gold: and there was not one feeble person among their tribes.'),
  ('KJV', 'Psalms', 19, 105, 38, 'Egypt was glad when they departed: for the fear of them fell upon them.'),
  ('KJV', 'Psalms', 19, 105, 39, 'He spread a cloud for a covering; and fire to give light in the night.'),
  ('KJV', 'Psalms', 19, 105, 40, 'The people asked, and he brought quails, and satisfied them with the bread of heaven.'),
  ('KJV', 'Psalms', 19, 105, 41, 'He opened the rock, and the waters gushed out; they ran in the dry places like a river.'),
  ('KJV', 'Psalms', 19, 105, 42, 'For he remembered his holy promise, and Abraham his servant.'),
  ('KJV', 'Psalms', 19, 105, 43, 'And he brought forth his people with joy, and his chosen with gladness:'),
  ('KJV', 'Psalms', 19, 105, 44, 'And gave them the lands of the heathen: and they inherited the labour of the people;'),
  ('KJV', 'Psalms', 19, 105, 45, 'That they might observe his statutes, and keep his laws. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 106, 1, 'Praise ye the LORD. O give thanks unto the LORD; for he is good: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 106, 2, 'Who can utter the mighty acts of the LORD? who can shew forth all his praise?'),
  ('KJV', 'Psalms', 19, 106, 3, 'Blessed are they that keep judgment, and he that doeth righteousness at all times.'),
  ('KJV', 'Psalms', 19, 106, 4, 'Remember me, O LORD, with the favour that thou bearest unto thy people: O visit me with thy salvation;'),
  ('KJV', 'Psalms', 19, 106, 5, 'That I may see the good of thy chosen, that I may rejoice in the gladness of thy nation, that I may glory with thine inheritance.'),
  ('KJV', 'Psalms', 19, 106, 6, 'We have sinned with our fathers, we have committed iniquity, we have done wickedly.'),
  ('KJV', 'Psalms', 19, 106, 7, 'Our fathers understood not thy wonders in Egypt; they remembered not the multitude of thy mercies; but provoked him at the sea, even at the Red sea.'),
  ('KJV', 'Psalms', 19, 106, 8, 'Nevertheless he saved them for his name''s sake, that he might make his mighty power to be known.'),
  ('KJV', 'Psalms', 19, 106, 9, 'He rebuked the Red sea also, and it was dried up: so he led them through the depths, as through the wilderness.'),
  ('KJV', 'Psalms', 19, 106, 10, 'And he saved them from the hand of him that hated them, and redeemed them from the hand of the enemy.'),
  ('KJV', 'Psalms', 19, 106, 11, 'And the waters covered their enemies: there was not one of them left.'),
  ('KJV', 'Psalms', 19, 106, 12, 'Then believed they his words; they sang his praise.'),
  ('KJV', 'Psalms', 19, 106, 13, 'They soon forgat his works; they waited not for his counsel:'),
  ('KJV', 'Psalms', 19, 106, 14, 'But lusted exceedingly in the wilderness, and tempted God in the desert.'),
  ('KJV', 'Psalms', 19, 106, 15, 'And he gave them their request; but sent leanness into their soul.'),
  ('KJV', 'Psalms', 19, 106, 16, 'They envied Moses also in the camp, and Aaron the saint of the LORD.'),
  ('KJV', 'Psalms', 19, 106, 17, 'The earth opened and swallowed up Dathan, and covered the company of Abiram.'),
  ('KJV', 'Psalms', 19, 106, 18, 'And a fire was kindled in their company; the flame burned up the wicked.'),
  ('KJV', 'Psalms', 19, 106, 19, 'They made a calf in Horeb, and worshipped the molten image.'),
  ('KJV', 'Psalms', 19, 106, 20, 'Thus they changed their glory into the similitude of an ox that eateth grass.'),
  ('KJV', 'Psalms', 19, 106, 21, 'They forgat God their saviour, which had done great things in Egypt;'),
  ('KJV', 'Psalms', 19, 106, 22, 'Wondrous works in the land of Ham, and terrible things by the Red sea.'),
  ('KJV', 'Psalms', 19, 106, 23, 'Therefore he said that he would destroy them, had not Moses his chosen stood before him in the breach, to turn away his wrath, lest he should destroy them.'),
  ('KJV', 'Psalms', 19, 106, 24, 'Yea, they despised the pleasant land, they believed not his word:'),
  ('KJV', 'Psalms', 19, 106, 25, 'But murmured in their tents, and hearkened not unto the voice of the LORD.'),
  ('KJV', 'Psalms', 19, 106, 26, 'Therefore he lifted up his hand against them, to overthrow them in the wilderness:'),
  ('KJV', 'Psalms', 19, 106, 27, 'To overthrow their seed also among the nations, and to scatter them in the lands.'),
  ('KJV', 'Psalms', 19, 106, 28, 'They joined themselves also unto Baalpeor, and ate the sacrifices of the dead.'),
  ('KJV', 'Psalms', 19, 106, 29, 'Thus they provoked him to anger with their inventions: and the plague brake in upon them.'),
  ('KJV', 'Psalms', 19, 106, 30, 'Then stood up Phinehas, and executed judgment: and so the plague was stayed.'),
  ('KJV', 'Psalms', 19, 106, 31, 'And that was counted unto him for righteousness unto all generations for evermore.'),
  ('KJV', 'Psalms', 19, 106, 32, 'They angered him also at the waters of strife, so that it went ill with Moses for their sakes:'),
  ('KJV', 'Psalms', 19, 106, 33, 'Because they provoked his spirit, so that he spake unadvisedly with his lips.'),
  ('KJV', 'Psalms', 19, 106, 34, 'They did not destroy the nations, concerning whom the LORD commanded them:'),
  ('KJV', 'Psalms', 19, 106, 35, 'But were mingled among the heathen, and learned their works.'),
  ('KJV', 'Psalms', 19, 106, 36, 'And they served their idols: which were a snare unto them.'),
  ('KJV', 'Psalms', 19, 106, 37, 'Yea, they sacrificed their sons and their daughters unto devils,'),
  ('KJV', 'Psalms', 19, 106, 38, 'And shed innocent blood, even the blood of their sons and of their daughters, whom they sacrificed unto the idols of Canaan: and the land was polluted with blood.'),
  ('KJV', 'Psalms', 19, 106, 39, 'Thus were they defiled with their own works, and went a whoring with their own inventions.'),
  ('KJV', 'Psalms', 19, 106, 40, 'Therefore was the wrath of the LORD kindled against his people, insomuch that he abhorred his own inheritance.'),
  ('KJV', 'Psalms', 19, 106, 41, 'And he gave them into the hand of the heathen; and they that hated them ruled over them.'),
  ('KJV', 'Psalms', 19, 106, 42, 'Their enemies also oppressed them, and they were brought into subjection under their hand.'),
  ('KJV', 'Psalms', 19, 106, 43, 'Many times did he deliver them; but they provoked him with their counsel, and were brought low for their iniquity.'),
  ('KJV', 'Psalms', 19, 106, 44, 'Nevertheless he regarded their affliction, when he heard their cry:'),
  ('KJV', 'Psalms', 19, 106, 45, 'And he remembered for them his covenant, and repented according to the multitude of his mercies.'),
  ('KJV', 'Psalms', 19, 106, 46, 'He made them also to be pitied of all those that carried them captives.'),
  ('KJV', 'Psalms', 19, 106, 47, 'Save us, O LORD our God, and gather us from among the heathen, to give thanks unto thy holy name, and to triumph in thy praise.'),
  ('KJV', 'Psalms', 19, 106, 48, 'Blessed be the LORD God of Israel from everlasting to everlasting: and let all the people say, Amen. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 107, 1, 'O give thanks unto the LORD, for he is good: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 107, 2, 'Let the redeemed of the LORD say so, whom he hath redeemed from the hand of the enemy;'),
  ('KJV', 'Psalms', 19, 107, 3, 'And gathered them out of the lands, from the east, and from the west, from the north, and from the south.'),
  ('KJV', 'Psalms', 19, 107, 4, 'They wandered in the wilderness in a solitary way; they found no city to dwell in.'),
  ('KJV', 'Psalms', 19, 107, 5, 'Hungry and thirsty, their soul fainted in them.'),
  ('KJV', 'Psalms', 19, 107, 6, 'Then they cried unto the LORD in their trouble, and he delivered them out of their distresses.'),
  ('KJV', 'Psalms', 19, 107, 7, 'And he led them forth by the right way, that they might go to a city of habitation.'),
  ('KJV', 'Psalms', 19, 107, 8, 'Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!'),
  ('KJV', 'Psalms', 19, 107, 9, 'For he satisfieth the longing soul, and filleth the hungry soul with goodness.'),
  ('KJV', 'Psalms', 19, 107, 10, 'Such as sit in darkness and in the shadow of death, being bound in affliction and iron;'),
  ('KJV', 'Psalms', 19, 107, 11, 'Because they rebelled against the words of God, and contemned the counsel of the most High:'),
  ('KJV', 'Psalms', 19, 107, 12, 'Therefore he brought down their heart with labour; they fell down, and there was none to help.'),
  ('KJV', 'Psalms', 19, 107, 13, 'Then they cried unto the LORD in their trouble, and he saved them out of their distresses.'),
  ('KJV', 'Psalms', 19, 107, 14, 'He brought them out of darkness and the shadow of death, and brake their bands in sunder.'),
  ('KJV', 'Psalms', 19, 107, 15, 'Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!'),
  ('KJV', 'Psalms', 19, 107, 16, 'For he hath broken the gates of brass, and cut the bars of iron in sunder.'),
  ('KJV', 'Psalms', 19, 107, 17, 'Fools because of their transgression, and because of their iniquities, are afflicted.'),
  ('KJV', 'Psalms', 19, 107, 18, 'Their soul abhorreth all manner of meat; and they draw near unto the gates of death.'),
  ('KJV', 'Psalms', 19, 107, 19, 'Then they cry unto the LORD in their trouble, and he saveth them out of their distresses.'),
  ('KJV', 'Psalms', 19, 107, 20, 'He sent his word, and healed them, and delivered them from their destructions.'),
  ('KJV', 'Psalms', 19, 107, 21, 'Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!'),
  ('KJV', 'Psalms', 19, 107, 22, 'And let them sacrifice the sacrifices of thanksgiving, and declare his works with rejoicing.'),
  ('KJV', 'Psalms', 19, 107, 23, 'They that go down to the sea in ships, that do business in great waters;'),
  ('KJV', 'Psalms', 19, 107, 24, 'These see the works of the LORD, and his wonders in the deep.'),
  ('KJV', 'Psalms', 19, 107, 25, 'For he commandeth, and raiseth the stormy wind, which lifteth up the waves thereof.'),
  ('KJV', 'Psalms', 19, 107, 26, 'They mount up to the heaven, they go down again to the depths: their soul is melted because of trouble.'),
  ('KJV', 'Psalms', 19, 107, 27, 'They reel to and fro, and stagger like a drunken man, and are at their wits'' end.'),
  ('KJV', 'Psalms', 19, 107, 28, 'Then they cry unto the LORD in their trouble, and he bringeth them out of their distresses.'),
  ('KJV', 'Psalms', 19, 107, 29, 'He maketh the storm a calm, so that the waves thereof are still.'),
  ('KJV', 'Psalms', 19, 107, 30, 'Then are they glad because they be quiet; so he bringeth them unto their desired haven.'),
  ('KJV', 'Psalms', 19, 107, 31, 'Oh that men would praise the LORD for his goodness, and for his wonderful works to the children of men!'),
  ('KJV', 'Psalms', 19, 107, 32, 'Let them exalt him also in the congregation of the people, and praise him in the assembly of the elders.'),
  ('KJV', 'Psalms', 19, 107, 33, 'He turneth rivers into a wilderness, and the watersprings into dry ground;'),
  ('KJV', 'Psalms', 19, 107, 34, 'A fruitful land into barrenness, for the wickedness of them that dwell therein.'),
  ('KJV', 'Psalms', 19, 107, 35, 'He turneth the wilderness into a standing water, and dry ground into watersprings.'),
  ('KJV', 'Psalms', 19, 107, 36, 'And there he maketh the hungry to dwell, that they may prepare a city for habitation;'),
  ('KJV', 'Psalms', 19, 107, 37, 'And sow the fields, and plant vineyards, which may yield fruits of increase.'),
  ('KJV', 'Psalms', 19, 107, 38, 'He blesseth them also, so that they are multiplied greatly; and suffereth not their cattle to decrease.'),
  ('KJV', 'Psalms', 19, 107, 39, 'Again, they are minished and brought low through oppression, affliction, and sorrow.'),
  ('KJV', 'Psalms', 19, 107, 40, 'He poureth contempt upon princes, and causeth them to wander in the wilderness, where there is no way.'),
  ('KJV', 'Psalms', 19, 107, 41, 'Yet setteth he the poor on high from affliction, and maketh him families like a flock.'),
  ('KJV', 'Psalms', 19, 107, 42, 'The righteous shall see it, and rejoice: and all iniquity shall stop her mouth.'),
  ('KJV', 'Psalms', 19, 107, 43, 'Whoso is wise, and will observe these things, even they shall understand the lovingkindness of the LORD.'),
  ('KJV', 'Psalms', 19, 108, 1, 'A Song or Psalm of David. O God, my heart is fixed; I will sing and give praise, even with my glory.'),
  ('KJV', 'Psalms', 19, 108, 2, 'Awake, psaltery and harp: I myself will awake early.'),
  ('KJV', 'Psalms', 19, 108, 3, 'I will praise thee, O LORD, among the people: and I will sing praises unto thee among the nations.'),
  ('KJV', 'Psalms', 19, 108, 4, 'For thy mercy is great above the heavens: and thy truth reacheth unto the clouds.'),
  ('KJV', 'Psalms', 19, 108, 5, 'Be thou exalted, O God, above the heavens: and thy glory above all the earth;'),
  ('KJV', 'Psalms', 19, 108, 6, 'That thy beloved may be delivered: save with thy right hand, and answer me.'),
  ('KJV', 'Psalms', 19, 108, 7, 'God hath spoken in his holiness; I will rejoice, I will divide Shechem, and mete out the valley of Succoth.'),
  ('KJV', 'Psalms', 19, 108, 8, 'Gilead is mine; Manasseh is mine; Ephraim also is the strength of mine head; Judah is my lawgiver;'),
  ('KJV', 'Psalms', 19, 108, 9, 'Moab is my washpot; over Edom will I cast out my shoe; over Philistia will I triumph.'),
  ('KJV', 'Psalms', 19, 108, 10, 'Who will bring me into the strong city? who will lead me into Edom?'),
  ('KJV', 'Psalms', 19, 108, 11, 'Wilt not thou, O God, who hast cast us off? and wilt not thou, O God, go forth with our hosts?'),
  ('KJV', 'Psalms', 19, 108, 12, 'Give us help from trouble: for vain is the help of man.'),
  ('KJV', 'Psalms', 19, 108, 13, 'Through God we shall do valiantly: for he it is that shall tread down our enemies.'),
  ('KJV', 'Psalms', 19, 109, 1, 'To the chief Musician, A Psalm of David. Hold not thy peace, O God of my praise;'),
  ('KJV', 'Psalms', 19, 109, 2, 'For the mouth of the wicked and the mouth of the deceitful are opened against me: they have spoken against me with a lying tongue.'),
  ('KJV', 'Psalms', 19, 109, 3, 'They compassed me about also with words of hatred; and fought against me without a cause.'),
  ('KJV', 'Psalms', 19, 109, 4, 'For my love they are my adversaries: but I give myself unto prayer.'),
  ('KJV', 'Psalms', 19, 109, 5, 'And they have rewarded me evil for good, and hatred for my love.'),
  ('KJV', 'Psalms', 19, 109, 6, 'Set thou a wicked man over him: and let Satan stand at his right hand.'),
  ('KJV', 'Psalms', 19, 109, 7, 'When he shall be judged, let him be condemned: and let his prayer become sin.'),
  ('KJV', 'Psalms', 19, 109, 8, 'Let his days be few; and let another take his office.'),
  ('KJV', 'Psalms', 19, 109, 9, 'Let his children be fatherless, and his wife a widow.'),
  ('KJV', 'Psalms', 19, 109, 10, 'Let his children be continually vagabonds, and beg: let them seek their bread also out of their desolate places.'),
  ('KJV', 'Psalms', 19, 109, 11, 'Let the extortioner catch all that he hath; and let the strangers spoil his labour.'),
  ('KJV', 'Psalms', 19, 109, 12, 'Let there be none to extend mercy unto him: neither let there be any to favour his fatherless children.'),
  ('KJV', 'Psalms', 19, 109, 13, 'Let his posterity be cut off; and in the generation following let their name be blotted out.'),
  ('KJV', 'Psalms', 19, 109, 14, 'Let the iniquity of his fathers be remembered with the LORD; and let not the sin of his mother be blotted out.'),
  ('KJV', 'Psalms', 19, 109, 15, 'Let them be before the LORD continually, that he may cut off the memory of them from the earth.'),
  ('KJV', 'Psalms', 19, 109, 16, 'Because that he remembered not to shew mercy, but persecuted the poor and needy man, that he might even slay the broken in heart.'),
  ('KJV', 'Psalms', 19, 109, 17, 'As he loved cursing, so let it come unto him: as he delighted not in blessing, so let it be far from him.'),
  ('KJV', 'Psalms', 19, 109, 18, 'As he clothed himself with cursing like as with his garment, so let it come into his bowels like water, and like oil into his bones.'),
  ('KJV', 'Psalms', 19, 109, 19, 'Let it be unto him as the garment which covereth him, and for a girdle wherewith he is girded continually.'),
  ('KJV', 'Psalms', 19, 109, 20, 'Let this be the reward of mine adversaries from the LORD, and of them that speak evil against my soul.'),
  ('KJV', 'Psalms', 19, 109, 21, 'But do thou for me, O GOD the Lord, for thy name''s sake: because thy mercy is good, deliver thou me.'),
  ('KJV', 'Psalms', 19, 109, 22, 'For I am poor and needy, and my heart is wounded within me.'),
  ('KJV', 'Psalms', 19, 109, 23, 'I am gone like the shadow when it declineth: I am tossed up and down as the locust.'),
  ('KJV', 'Psalms', 19, 109, 24, 'My knees are weak through fasting; and my flesh faileth of fatness.'),
  ('KJV', 'Psalms', 19, 109, 25, 'I became also a reproach unto them: when they looked upon me they shaked their heads.'),
  ('KJV', 'Psalms', 19, 109, 26, 'Help me, O LORD my God: O save me according to thy mercy:'),
  ('KJV', 'Psalms', 19, 109, 27, 'That they may know that this is thy hand; that thou, LORD, hast done it.'),
  ('KJV', 'Psalms', 19, 109, 28, 'Let them curse, but bless thou: when they arise, let them be ashamed; but let thy servant rejoice.'),
  ('KJV', 'Psalms', 19, 109, 29, 'Let mine adversaries be clothed with shame, and let them cover themselves with their own confusion, as with a mantle.'),
  ('KJV', 'Psalms', 19, 109, 30, 'I will greatly praise the LORD with my mouth; yea, I will praise him among the multitude.'),
  ('KJV', 'Psalms', 19, 109, 31, 'For he shall stand at the right hand of the poor, to save him from those that condemn his soul.'),
  ('KJV', 'Psalms', 19, 110, 1, 'A Psalm of David. The LORD said unto my Lord, Sit thou at my right hand, until I make thine enemies thy footstool.'),
  ('KJV', 'Psalms', 19, 110, 2, 'The LORD shall send the rod of thy strength out of Zion: rule thou in the midst of thine enemies.'),
  ('KJV', 'Psalms', 19, 110, 3, 'Thy people shall be willing in the day of thy power, in the beauties of holiness from the womb of the morning: thou hast the dew of thy youth.'),
  ('KJV', 'Psalms', 19, 110, 4, 'The LORD hath sworn, and will not repent, Thou art a priest for ever after the order of Melchizedek.'),
  ('KJV', 'Psalms', 19, 110, 5, 'The Lord at thy right hand shall strike through kings in the day of his wrath.'),
  ('KJV', 'Psalms', 19, 110, 6, 'He shall judge among the heathen, he shall fill the places with the dead bodies; he shall wound the heads over many countries.'),
  ('KJV', 'Psalms', 19, 110, 7, 'He shall drink of the brook in the way: therefore shall he lift up the head.'),
  ('KJV', 'Psalms', 19, 111, 1, 'Praise ye the LORD. I will praise the LORD with my whole heart, in the assembly of the upright, and in the congregation.'),
  ('KJV', 'Psalms', 19, 111, 2, 'The works of the LORD are great, sought out of all them that have pleasure therein.'),
  ('KJV', 'Psalms', 19, 111, 3, 'His work is honourable and glorious: and his righteousness endureth for ever.'),
  ('KJV', 'Psalms', 19, 111, 4, 'He hath made his wonderful works to be remembered: the LORD is gracious and full of compassion.'),
  ('KJV', 'Psalms', 19, 111, 5, 'He hath given meat unto them that fear him: he will ever be mindful of his covenant.'),
  ('KJV', 'Psalms', 19, 111, 6, 'He hath shewed his people the power of his works, that he may give them the heritage of the heathen.'),
  ('KJV', 'Psalms', 19, 111, 7, 'The works of his hands are verity and judgment; all his commandments are sure.'),
  ('KJV', 'Psalms', 19, 111, 8, 'They stand fast for ever and ever, and are done in truth and uprightness.'),
  ('KJV', 'Psalms', 19, 111, 9, 'He sent redemption unto his people: he hath commanded his covenant for ever: holy and reverend is his name.'),
  ('KJV', 'Psalms', 19, 111, 10, 'The fear of the LORD is the beginning of wisdom: a good understanding have all they that do his commandments: his praise endureth for ever.'),
  ('KJV', 'Psalms', 19, 112, 1, 'Praise ye the LORD. Blessed is the man that feareth the LORD, that delighteth greatly in his commandments.'),
  ('KJV', 'Psalms', 19, 112, 2, 'His seed shall be mighty upon earth: the generation of the upright shall be blessed.'),
  ('KJV', 'Psalms', 19, 112, 3, 'Wealth and riches shall be in his house: and his righteousness endureth for ever.'),
  ('KJV', 'Psalms', 19, 112, 4, 'Unto the upright there ariseth light in the darkness: he is gracious, and full of compassion, and righteous.'),
  ('KJV', 'Psalms', 19, 112, 5, 'A good man sheweth favour, and lendeth: he will guide his affairs with discretion.'),
  ('KJV', 'Psalms', 19, 112, 6, 'Surely he shall not be moved for ever: the righteous shall be in everlasting remembrance.'),
  ('KJV', 'Psalms', 19, 112, 7, 'He shall not be afraid of evil tidings: his heart is fixed, trusting in the LORD.'),
  ('KJV', 'Psalms', 19, 112, 8, 'His heart is established, he shall not be afraid, until he see his desire upon his enemies.'),
  ('KJV', 'Psalms', 19, 112, 9, 'He hath dispersed, he hath given to the poor; his righteousness endureth for ever; his horn shall be exalted with honour.'),
  ('KJV', 'Psalms', 19, 112, 10, 'The wicked shall see it, and be grieved; he shall gnash with his teeth, and melt away: the desire of the wicked shall perish.'),
  ('KJV', 'Psalms', 19, 113, 1, 'Praise ye the LORD. Praise, O ye servants of the LORD, praise the name of the LORD.'),
  ('KJV', 'Psalms', 19, 113, 2, 'Blessed be the name of the LORD from this time forth and for evermore.'),
  ('KJV', 'Psalms', 19, 113, 3, 'From the rising of the sun unto the going down of the same the LORD''S name is to be praised.'),
  ('KJV', 'Psalms', 19, 113, 4, 'The LORD is high above all nations, and his glory above the heavens.'),
  ('KJV', 'Psalms', 19, 113, 5, 'Who is like unto the LORD our God, who dwelleth on high,'),
  ('KJV', 'Psalms', 19, 113, 6, 'Who humbleth himself to behold the things that are in heaven, and in the earth!'),
  ('KJV', 'Psalms', 19, 113, 7, 'He raiseth up the poor out of the dust, and lifteth the needy out of the dunghill;'),
  ('KJV', 'Psalms', 19, 113, 8, 'That he may set him with princes, even with the princes of his people.'),
  ('KJV', 'Psalms', 19, 113, 9, 'He maketh the barren woman to keep house, and to be a joyful mother of children. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 114, 1, 'When Israel went out of Egypt, the house of Jacob from a people of strange language;'),
  ('KJV', 'Psalms', 19, 114, 2, 'Judah was his sanctuary, and Israel his dominion.'),
  ('KJV', 'Psalms', 19, 114, 3, 'The sea saw it, and fled: Jordan was driven back.'),
  ('KJV', 'Psalms', 19, 114, 4, 'The mountains skipped like rams, and the little hills like lambs.'),
  ('KJV', 'Psalms', 19, 114, 5, 'What ailed thee, O thou sea, that thou fleddest? thou Jordan, that thou wast driven back?'),
  ('KJV', 'Psalms', 19, 114, 6, 'Ye mountains, that ye skipped like rams; and ye little hills, like lambs?'),
  ('KJV', 'Psalms', 19, 114, 7, 'Tremble, thou earth, at the presence of the Lord, at the presence of the God of Jacob;'),
  ('KJV', 'Psalms', 19, 114, 8, 'Which turned the rock into a standing water, the flint into a fountain of waters.'),
  ('KJV', 'Psalms', 19, 115, 1, 'Not unto us, O LORD, not unto us, but unto thy name give glory, for thy mercy, and for thy truth''s sake.'),
  ('KJV', 'Psalms', 19, 115, 2, 'Wherefore should the heathen say, Where is now their God?'),
  ('KJV', 'Psalms', 19, 115, 3, 'But our God is in the heavens: he hath done whatsoever he hath pleased.'),
  ('KJV', 'Psalms', 19, 115, 4, 'Their idols are silver and gold, the work of men''s hands.'),
  ('KJV', 'Psalms', 19, 115, 5, 'They have mouths, but they speak not: eyes have they, but they see not:'),
  ('KJV', 'Psalms', 19, 115, 6, 'They have ears, but they hear not: noses have they, but they smell not:'),
  ('KJV', 'Psalms', 19, 115, 7, 'They have hands, but they handle not: feet have they, but they walk not: neither speak they through their throat.'),
  ('KJV', 'Psalms', 19, 115, 8, 'They that make them are like unto them; so is every one that trusteth in them.'),
  ('KJV', 'Psalms', 19, 115, 9, 'O Israel, trust thou in the LORD: he is their help and their shield.'),
  ('KJV', 'Psalms', 19, 115, 10, 'O house of Aaron, trust in the LORD: he is their help and their shield.'),
  ('KJV', 'Psalms', 19, 115, 11, 'Ye that fear the LORD, trust in the LORD: he is their help and their shield.'),
  ('KJV', 'Psalms', 19, 115, 12, 'The LORD hath been mindful of us: he will bless us; he will bless the house of Israel; he will bless the house of Aaron.'),
  ('KJV', 'Psalms', 19, 115, 13, 'He will bless them that fear the LORD, both small and great.'),
  ('KJV', 'Psalms', 19, 115, 14, 'The LORD shall increase you more and more, you and your children.'),
  ('KJV', 'Psalms', 19, 115, 15, 'Ye are blessed of the LORD which made heaven and earth.'),
  ('KJV', 'Psalms', 19, 115, 16, 'The heaven, even the heavens, are the LORD''S: but the earth hath he given to the children of men.'),
  ('KJV', 'Psalms', 19, 115, 17, 'The dead praise not the LORD, neither any that go down into silence.'),
  ('KJV', 'Psalms', 19, 115, 18, 'But we will bless the LORD from this time forth and for evermore. Praise the LORD.'),
  ('KJV', 'Psalms', 19, 116, 1, 'I love the LORD, because he hath heard my voice and my supplications.'),
  ('KJV', 'Psalms', 19, 116, 2, 'Because he hath inclined his ear unto me, therefore will I call upon him as long as I live.'),
  ('KJV', 'Psalms', 19, 116, 3, 'The sorrows of death compassed me, and the pains of hell gat hold upon me: I found trouble and sorrow.'),
  ('KJV', 'Psalms', 19, 116, 4, 'Then called I upon the name of the LORD; O LORD, I beseech thee, deliver my soul.'),
  ('KJV', 'Psalms', 19, 116, 5, 'Gracious is the LORD, and righteous; yea, our God is merciful.'),
  ('KJV', 'Psalms', 19, 116, 6, 'The LORD preserveth the simple: I was brought low, and he helped me.'),
  ('KJV', 'Psalms', 19, 116, 7, 'Return unto thy rest, O my soul; for the LORD hath dealt bountifully with thee.'),
  ('KJV', 'Psalms', 19, 116, 8, 'For thou hast delivered my soul from death, mine eyes from tears, and my feet from falling.'),
  ('KJV', 'Psalms', 19, 116, 9, 'I will walk before the LORD in the land of the living.'),
  ('KJV', 'Psalms', 19, 116, 10, 'I believed, therefore have I spoken: I was greatly afflicted:'),
  ('KJV', 'Psalms', 19, 116, 11, 'I said in my haste, All men are liars.'),
  ('KJV', 'Psalms', 19, 116, 12, 'What shall I render unto the LORD for all his benefits toward me?'),
  ('KJV', 'Psalms', 19, 116, 13, 'I will take the cup of salvation, and call upon the name of the LORD.'),
  ('KJV', 'Psalms', 19, 116, 14, 'I will pay my vows unto the LORD now in the presence of all his people.'),
  ('KJV', 'Psalms', 19, 116, 15, 'Precious in the sight of the LORD is the death of his saints.'),
  ('KJV', 'Psalms', 19, 116, 16, 'O LORD, truly I am thy servant; I am thy servant, and the son of thine handmaid: thou hast loosed my bonds.'),
  ('KJV', 'Psalms', 19, 116, 17, 'I will offer to thee the sacrifice of thanksgiving, and will call upon the name of the LORD.'),
  ('KJV', 'Psalms', 19, 116, 18, 'I will pay my vows unto the LORD now in the presence of all his people,'),
  ('KJV', 'Psalms', 19, 116, 19, 'In the courts of the LORD''S house, in the midst of thee, O Jerusalem. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 117, 1, 'O praise the LORD, all ye nations: praise him, all ye people.'),
  ('KJV', 'Psalms', 19, 117, 2, 'For his merciful kindness is great toward us: and the truth of the LORD endureth for ever. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 118, 1, 'O give thanks unto the LORD; for he is good: because his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 118, 2, 'Let Israel now say, that his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 118, 3, 'Let the house of Aaron now say, that his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 118, 4, 'Let them now that fear the LORD say, that his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 118, 5, 'I called upon the LORD in distress: the LORD answered me, and set me in a large place.'),
  ('KJV', 'Psalms', 19, 118, 6, 'The LORD is on my side; I will not fear: what can man do unto me?'),
  ('KJV', 'Psalms', 19, 118, 7, 'The LORD taketh my part with them that help me: therefore shall I see my desire upon them that hate me.'),
  ('KJV', 'Psalms', 19, 118, 8, 'It is better to trust in the LORD than to put confidence in man.'),
  ('KJV', 'Psalms', 19, 118, 9, 'It is better to trust in the LORD than to put confidence in princes.'),
  ('KJV', 'Psalms', 19, 118, 10, 'All nations compassed me about: but in the name of the LORD will I destroy them.'),
  ('KJV', 'Psalms', 19, 118, 11, 'They compassed me about; yea, they compassed me about: but in the name of the LORD I will destroy them.'),
  ('KJV', 'Psalms', 19, 118, 12, 'They compassed me about like bees; they are quenched as the fire of thorns: for in the name of the LORD I will destroy them.'),
  ('KJV', 'Psalms', 19, 118, 13, 'Thou hast thrust sore at me that I might fall: but the LORD helped me.'),
  ('KJV', 'Psalms', 19, 118, 14, 'The LORD is my strength and song, and is become my salvation.'),
  ('KJV', 'Psalms', 19, 118, 15, 'The voice of rejoicing and salvation is in the tabernacles of the righteous: the right hand of the LORD doeth valiantly.'),
  ('KJV', 'Psalms', 19, 118, 16, 'The right hand of the LORD is exalted: the right hand of the LORD doeth valiantly.'),
  ('KJV', 'Psalms', 19, 118, 17, 'I shall not die, but live, and declare the works of the LORD.'),
  ('KJV', 'Psalms', 19, 118, 18, 'The LORD hath chastened me sore: but he hath not given me over unto death.'),
  ('KJV', 'Psalms', 19, 118, 19, 'Open to me the gates of righteousness: I will go into them, and I will praise the LORD:'),
  ('KJV', 'Psalms', 19, 118, 20, 'This gate of the LORD, into which the righteous shall enter.'),
  ('KJV', 'Psalms', 19, 118, 21, 'I will praise thee: for thou hast heard me, and art become my salvation.'),
  ('KJV', 'Psalms', 19, 118, 22, 'The stone which the builders refused is become the head stone of the corner.'),
  ('KJV', 'Psalms', 19, 118, 23, 'This is the LORD''S doing; it is marvellous in our eyes.'),
  ('KJV', 'Psalms', 19, 118, 24, 'This is the day which the LORD hath made; we will rejoice and be glad in it.'),
  ('KJV', 'Psalms', 19, 118, 25, 'Save now, I beseech thee, O LORD: O LORD, I beseech thee, send now prosperity.'),
  ('KJV', 'Psalms', 19, 118, 26, 'Blessed be he that cometh in the name of the LORD: we have blessed you out of the house of the LORD.'),
  ('KJV', 'Psalms', 19, 118, 27, 'God is the LORD, which hath shewed us light: bind the sacrifice with cords, even unto the horns of the altar.'),
  ('KJV', 'Psalms', 19, 118, 28, 'Thou art my God, and I will praise thee: thou art my God, I will exalt thee.'),
  ('KJV', 'Psalms', 19, 118, 29, 'O give thanks unto the LORD; for he is good: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 119, 1, 'ALEPH. Blessed are the undefiled in the way, who walk in the law of the LORD.'),
  ('KJV', 'Psalms', 19, 119, 2, 'Blessed are they that keep his testimonies, and that seek him with the whole heart.'),
  ('KJV', 'Psalms', 19, 119, 3, 'They also do no iniquity: they walk in his ways.'),
  ('KJV', 'Psalms', 19, 119, 4, 'Thou hast commanded us to keep thy precepts diligently.'),
  ('KJV', 'Psalms', 19, 119, 5, 'O that my ways were directed to keep thy statutes!'),
  ('KJV', 'Psalms', 19, 119, 6, 'Then shall I not be ashamed, when I have respect unto all thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 7, 'I will praise thee with uprightness of heart, when I shall have learned thy righteous judgments.'),
  ('KJV', 'Psalms', 19, 119, 8, 'I will keep thy statutes: O forsake me not utterly.'),
  ('KJV', 'Psalms', 19, 119, 9, 'BETH. Wherewithal shall a young man cleanse his way? by taking heed thereto according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 10, 'With my whole heart have I sought thee: O let me not wander from thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 11, 'Thy word have I hid in mine heart, that I might not sin against thee.'),
  ('KJV', 'Psalms', 19, 119, 12, 'Blessed art thou, O LORD: teach me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 13, 'With my lips have I declared all the judgments of thy mouth.'),
  ('KJV', 'Psalms', 19, 119, 14, 'I have rejoiced in the way of thy testimonies, as much as in all riches.'),
  ('KJV', 'Psalms', 19, 119, 15, 'I will meditate in thy precepts, and have respect unto thy ways.'),
  ('KJV', 'Psalms', 19, 119, 16, 'I will delight myself in thy statutes: I will not forget thy word.'),
  ('KJV', 'Psalms', 19, 119, 17, 'GIMEL. Deal bountifully with thy servant, that I may live, and keep thy word.'),
  ('KJV', 'Psalms', 19, 119, 18, 'Open thou mine eyes, that I may behold wondrous things out of thy law.'),
  ('KJV', 'Psalms', 19, 119, 19, 'I am a stranger in the earth: hide not thy commandments from me.'),
  ('KJV', 'Psalms', 19, 119, 20, 'My soul breaketh for the longing that it hath unto thy judgments at all times.'),
  ('KJV', 'Psalms', 19, 119, 21, 'Thou hast rebuked the proud that are cursed, which do err from thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 22, 'Remove from me reproach and contempt; for I have kept thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 23, 'Princes also did sit and speak against me: but thy servant did meditate in thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 24, 'Thy testimonies also are my delight and my counsellors.'),
  ('KJV', 'Psalms', 19, 119, 25, 'DALETH. My soul cleaveth unto the dust: quicken thou me according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 26, 'I have declared my ways, and thou heardest me: teach me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 27, 'Make me to understand the way of thy precepts: so shall I talk of thy wondrous works.'),
  ('KJV', 'Psalms', 19, 119, 28, 'My soul melteth for heaviness: strengthen thou me according unto thy word.'),
  ('KJV', 'Psalms', 19, 119, 29, 'Remove from me the way of lying: and grant me thy law graciously.'),
  ('KJV', 'Psalms', 19, 119, 30, 'I have chosen the way of truth: thy judgments have I laid before me.'),
  ('KJV', 'Psalms', 19, 119, 31, 'I have stuck unto thy testimonies: O LORD, put me not to shame.'),
  ('KJV', 'Psalms', 19, 119, 32, 'I will run the way of thy commandments, when thou shalt enlarge my heart.'),
  ('KJV', 'Psalms', 19, 119, 33, 'HE. Teach me, O LORD, the way of thy statutes; and I shall keep it unto the end.'),
  ('KJV', 'Psalms', 19, 119, 34, 'Give me understanding, and I shall keep thy law; yea, I shall observe it with my whole heart.'),
  ('KJV', 'Psalms', 19, 119, 35, 'Make me to go in the path of thy commandments; for therein do I delight.'),
  ('KJV', 'Psalms', 19, 119, 36, 'Incline my heart unto thy testimonies, and not to covetousness.'),
  ('KJV', 'Psalms', 19, 119, 37, 'Turn away mine eyes from beholding vanity; and quicken thou me in thy way.'),
  ('KJV', 'Psalms', 19, 119, 38, 'Stablish thy word unto thy servant, who is devoted to thy fear.'),
  ('KJV', 'Psalms', 19, 119, 39, 'Turn away my reproach which I fear: for thy judgments are good.'),
  ('KJV', 'Psalms', 19, 119, 40, 'Behold, I have longed after thy precepts: quicken me in thy righteousness.'),
  ('KJV', 'Psalms', 19, 119, 41, 'VAU. Let thy mercies come also unto me, O LORD, even thy salvation, according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 42, 'So shall I have wherewith to answer him that reproacheth me: for I trust in thy word.'),
  ('KJV', 'Psalms', 19, 119, 43, 'And take not the word of truth utterly out of my mouth; for I have hoped in thy judgments.'),
  ('KJV', 'Psalms', 19, 119, 44, 'So shall I keep thy law continually for ever and ever.'),
  ('KJV', 'Psalms', 19, 119, 45, 'And I will walk at liberty: for I seek thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 46, 'I will speak of thy testimonies also before kings, and will not be ashamed.'),
  ('KJV', 'Psalms', 19, 119, 47, 'And I will delight myself in thy commandments, which I have loved.'),
  ('KJV', 'Psalms', 19, 119, 48, 'My hands also will I lift up unto thy commandments, which I have loved; and I will meditate in thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 49, 'ZAIN. Remember the word unto thy servant, upon which thou hast caused me to hope.'),
  ('KJV', 'Psalms', 19, 119, 50, 'This is my comfort in my affliction: for thy word hath quickened me.'),
  ('KJV', 'Psalms', 19, 119, 51, 'The proud have had me greatly in derision: yet have I not declined from thy law.'),
  ('KJV', 'Psalms', 19, 119, 52, 'I remembered thy judgments of old, O LORD; and have comforted myself.'),
  ('KJV', 'Psalms', 19, 119, 53, 'Horror hath taken hold upon me because of the wicked that forsake thy law.'),
  ('KJV', 'Psalms', 19, 119, 54, 'Thy statutes have been my songs in the house of my pilgrimage.'),
  ('KJV', 'Psalms', 19, 119, 55, 'I have remembered thy name, O LORD, in the night, and have kept thy law.'),
  ('KJV', 'Psalms', 19, 119, 56, 'This I had, because I kept thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 57, 'CHETH. Thou art my portion, O LORD: I have said that I would keep thy words.'),
  ('KJV', 'Psalms', 19, 119, 58, 'I intreated thy favour with my whole heart: be merciful unto me according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 59, 'I thought on my ways, and turned my feet unto thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 60, 'I made haste, and delayed not to keep thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 61, 'The bands of the wicked have robbed me: but I have not forgotten thy law.'),
  ('KJV', 'Psalms', 19, 119, 62, 'At midnight I will rise to give thanks unto thee because of thy righteous judgments.'),
  ('KJV', 'Psalms', 19, 119, 63, 'I am a companion of all them that fear thee, and of them that keep thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 64, 'The earth, O LORD, is full of thy mercy: teach me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 65, 'TETH. Thou hast dealt well with thy servant, O LORD, according unto thy word.'),
  ('KJV', 'Psalms', 19, 119, 66, 'Teach me good judgment and knowledge: for I have believed thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 67, 'Before I was afflicted I went astray: but now have I kept thy word.'),
  ('KJV', 'Psalms', 19, 119, 68, 'Thou art good, and doest good; teach me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 69, 'The proud have forged a lie against me: but I will keep thy precepts with my whole heart.'),
  ('KJV', 'Psalms', 19, 119, 70, 'Their heart is as fat as grease; but I delight in thy law.'),
  ('KJV', 'Psalms', 19, 119, 71, 'It is good for me that I have been afflicted; that I might learn thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 72, 'The law of thy mouth is better unto me than thousands of gold and silver.'),
  ('KJV', 'Psalms', 19, 119, 73, 'JOD. Thy hands have made me and fashioned me: give me understanding, that I may learn thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 74, 'They that fear thee will be glad when they see me; because I have hoped in thy word.'),
  ('KJV', 'Psalms', 19, 119, 75, 'I know, O LORD, that thy judgments are right, and that thou in faithfulness hast afflicted me.'),
  ('KJV', 'Psalms', 19, 119, 76, 'Let, I pray thee, thy merciful kindness be for my comfort, according to thy word unto thy servant.'),
  ('KJV', 'Psalms', 19, 119, 77, 'Let thy tender mercies come unto me, that I may live: for thy law is my delight.'),
  ('KJV', 'Psalms', 19, 119, 78, 'Let the proud be ashamed; for they dealt perversely with me without a cause: but I will meditate in thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 79, 'Let those that fear thee turn unto me, and those that have known thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 80, 'Let my heart be sound in thy statutes; that I be not ashamed.'),
  ('KJV', 'Psalms', 19, 119, 81, 'CAPH. My soul fainteth for thy salvation: but I hope in thy word.'),
  ('KJV', 'Psalms', 19, 119, 82, 'Mine eyes fail for thy word, saying, When wilt thou comfort me?'),
  ('KJV', 'Psalms', 19, 119, 83, 'For I am become like a bottle in the smoke; yet do I not forget thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 84, 'How many are the days of thy servant? when wilt thou execute judgment on them that persecute me?'),
  ('KJV', 'Psalms', 19, 119, 85, 'The proud have digged pits for me, which are not after thy law.'),
  ('KJV', 'Psalms', 19, 119, 86, 'All thy commandments are faithful: they persecute me wrongfully; help thou me.'),
  ('KJV', 'Psalms', 19, 119, 87, 'They had almost consumed me upon earth; but I forsook not thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 88, 'Quicken me after thy lovingkindness; so shall I keep the testimony of thy mouth.'),
  ('KJV', 'Psalms', 19, 119, 89, 'LAMED. For ever, O LORD, thy word is settled in heaven.'),
  ('KJV', 'Psalms', 19, 119, 90, 'Thy faithfulness is unto all generations: thou hast established the earth, and it abideth.'),
  ('KJV', 'Psalms', 19, 119, 91, 'They continue this day according to thine ordinances: for all are thy servants.'),
  ('KJV', 'Psalms', 19, 119, 92, 'Unless thy law had been my delights, I should then have perished in mine affliction.'),
  ('KJV', 'Psalms', 19, 119, 93, 'I will never forget thy precepts: for with them thou hast quickened me.'),
  ('KJV', 'Psalms', 19, 119, 94, 'I am thine, save me; for I have sought thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 95, 'The wicked have waited for me to destroy me: but I will consider thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 96, 'I have seen an end of all perfection: but thy commandment is exceeding broad.'),
  ('KJV', 'Psalms', 19, 119, 97, 'MEM. O how love I thy law! it is my meditation all the day.'),
  ('KJV', 'Psalms', 19, 119, 98, 'Thou through thy commandments hast made me wiser than mine enemies: for they are ever with me.'),
  ('KJV', 'Psalms', 19, 119, 99, 'I have more understanding than all my teachers: for thy testimonies are my meditation.'),
  ('KJV', 'Psalms', 19, 119, 100, 'I understand more than the ancients, because I keep thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 101, 'I have refrained my feet from every evil way, that I might keep thy word.')
insert into control_room_bible (version, book, book_num, chapter, verse, text) values
  ('KJV', 'Psalms', 19, 119, 102, 'I have not departed from thy judgments: for thou hast taught me.'),
  ('KJV', 'Psalms', 19, 119, 103, 'How sweet are thy words unto my taste! yea, sweeter than honey to my mouth!'),
  ('KJV', 'Psalms', 19, 119, 104, 'Through thy precepts I get understanding: therefore I hate every false way.'),
  ('KJV', 'Psalms', 19, 119, 105, 'NUN. Thy word is a lamp unto my feet, and a light unto my path.'),
  ('KJV', 'Psalms', 19, 119, 106, 'I have sworn, and I will perform it, that I will keep thy righteous judgments.'),
  ('KJV', 'Psalms', 19, 119, 107, 'I am afflicted very much: quicken me, O LORD, according unto thy word.'),
  ('KJV', 'Psalms', 19, 119, 108, 'Accept, I beseech thee, the freewill offerings of my mouth, O LORD, and teach me thy judgments.'),
  ('KJV', 'Psalms', 19, 119, 109, 'My soul is continually in my hand: yet do I not forget thy law.'),
  ('KJV', 'Psalms', 19, 119, 110, 'The wicked have laid a snare for me: yet I erred not from thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 111, 'Thy testimonies have I taken as an heritage for ever: for they are the rejoicing of my heart.'),
  ('KJV', 'Psalms', 19, 119, 112, 'I have inclined mine heart to perform thy statutes alway, even unto the end.'),
  ('KJV', 'Psalms', 19, 119, 113, 'SAMECH. I hate vain thoughts: but thy law do I love.'),
  ('KJV', 'Psalms', 19, 119, 114, 'Thou art my hiding place and my shield: I hope in thy word.'),
  ('KJV', 'Psalms', 19, 119, 115, 'Depart from me, ye evildoers: for I will keep the commandments of my God.'),
  ('KJV', 'Psalms', 19, 119, 116, 'Uphold me according unto thy word, that I may live: and let me not be ashamed of my hope.'),
  ('KJV', 'Psalms', 19, 119, 117, 'Hold thou me up, and I shall be safe: and I will have respect unto thy statutes continually.'),
  ('KJV', 'Psalms', 19, 119, 118, 'Thou hast trodden down all them that err from thy statutes: for their deceit is falsehood.'),
  ('KJV', 'Psalms', 19, 119, 119, 'Thou puttest away all the wicked of the earth like dross: therefore I love thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 120, 'My flesh trembleth for fear of thee; and I am afraid of thy judgments.'),
  ('KJV', 'Psalms', 19, 119, 121, 'AIN. I have done judgment and justice: leave me not to mine oppressors.'),
  ('KJV', 'Psalms', 19, 119, 122, 'Be surety for thy servant for good: let not the proud oppress me.'),
  ('KJV', 'Psalms', 19, 119, 123, 'Mine eyes fail for thy salvation, and for the word of thy righteousness.'),
  ('KJV', 'Psalms', 19, 119, 124, 'Deal with thy servant according unto thy mercy, and teach me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 125, 'I am thy servant; give me understanding, that I may know thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 126, 'It is time for thee, LORD, to work: for they have made void thy law.'),
  ('KJV', 'Psalms', 19, 119, 127, 'Therefore I love thy commandments above gold; yea, above fine gold.'),
  ('KJV', 'Psalms', 19, 119, 128, 'Therefore I esteem all thy precepts concerning all things to be right; and I hate every false way.'),
  ('KJV', 'Psalms', 19, 119, 129, 'PE. Thy testimonies are wonderful: therefore doth my soul keep them.'),
  ('KJV', 'Psalms', 19, 119, 130, 'The entrance of thy words giveth light; it giveth understanding unto the simple.'),
  ('KJV', 'Psalms', 19, 119, 131, 'I opened my mouth, and panted: for I longed for thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 132, 'Look thou upon me, and be merciful unto me, as thou usest to do unto those that love thy name.'),
  ('KJV', 'Psalms', 19, 119, 133, 'Order my steps in thy word: and let not any iniquity have dominion over me.'),
  ('KJV', 'Psalms', 19, 119, 134, 'Deliver me from the oppression of man: so will I keep thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 135, 'Make thy face to shine upon thy servant; and teach me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 136, 'Rivers of waters run down mine eyes, because they keep not thy law.'),
  ('KJV', 'Psalms', 19, 119, 137, 'TZADDI. Righteous art thou, O LORD, and upright are thy judgments.'),
  ('KJV', 'Psalms', 19, 119, 138, 'Thy testimonies that thou hast commanded are righteous and very faithful.'),
  ('KJV', 'Psalms', 19, 119, 139, 'My zeal hath consumed me, because mine enemies have forgotten thy words.'),
  ('KJV', 'Psalms', 19, 119, 140, 'Thy word is very pure: therefore thy servant loveth it.'),
  ('KJV', 'Psalms', 19, 119, 141, 'I am small and despised: yet do not I forget thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 142, 'Thy righteousness is an everlasting righteousness, and thy law is the truth.'),
  ('KJV', 'Psalms', 19, 119, 143, 'Trouble and anguish have taken hold on me: yet thy commandments are my delights.'),
  ('KJV', 'Psalms', 19, 119, 144, 'The righteousness of thy testimonies is everlasting: give me understanding, and I shall live.'),
  ('KJV', 'Psalms', 19, 119, 145, 'KOPH. I cried with my whole heart; hear me, O LORD: I will keep thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 146, 'I cried unto thee; save me, and I shall keep thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 147, 'I prevented the dawning of the morning, and cried: I hoped in thy word.'),
  ('KJV', 'Psalms', 19, 119, 148, 'Mine eyes prevent the night watches, that I might meditate in thy word.'),
  ('KJV', 'Psalms', 19, 119, 149, 'Hear my voice according unto thy lovingkindness: O LORD, quicken me according to thy judgment.'),
  ('KJV', 'Psalms', 19, 119, 150, 'They draw nigh that follow after mischief: they are far from thy law.'),
  ('KJV', 'Psalms', 19, 119, 151, 'Thou art near, O LORD; and all thy commandments are truth.'),
  ('KJV', 'Psalms', 19, 119, 152, 'Concerning thy testimonies, I have known of old that thou hast founded them for ever.'),
  ('KJV', 'Psalms', 19, 119, 153, 'RESH. Consider mine affliction, and deliver me: for I do not forget thy law.'),
  ('KJV', 'Psalms', 19, 119, 154, 'Plead my cause, and deliver me: quicken me according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 155, 'Salvation is far from the wicked: for they seek not thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 156, 'Great are thy tender mercies, O LORD: quicken me according to thy judgments.'),
  ('KJV', 'Psalms', 19, 119, 157, 'Many are my persecutors and mine enemies; yet do I not decline from thy testimonies.'),
  ('KJV', 'Psalms', 19, 119, 158, 'I beheld the transgressors, and was grieved; because they kept not thy word.'),
  ('KJV', 'Psalms', 19, 119, 159, 'Consider how I love thy precepts: quicken me, O LORD, according to thy lovingkindness.'),
  ('KJV', 'Psalms', 19, 119, 160, 'Thy word is true from the beginning: and every one of thy righteous judgments endureth for ever.'),
  ('KJV', 'Psalms', 19, 119, 161, 'SCHIN. Princes have persecuted me without a cause: but my heart standeth in awe of thy word.'),
  ('KJV', 'Psalms', 19, 119, 162, 'I rejoice at thy word, as one that findeth great spoil.'),
  ('KJV', 'Psalms', 19, 119, 163, 'I hate and abhor lying: but thy law do I love.'),
  ('KJV', 'Psalms', 19, 119, 164, 'Seven times a day do I praise thee because of thy righteous judgments.'),
  ('KJV', 'Psalms', 19, 119, 165, 'Great peace have they which love thy law: and nothing shall offend them.'),
  ('KJV', 'Psalms', 19, 119, 166, 'LORD, I have hoped for thy salvation, and done thy commandments.'),
  ('KJV', 'Psalms', 19, 119, 167, 'My soul hath kept thy testimonies; and I love them exceedingly.'),
  ('KJV', 'Psalms', 19, 119, 168, 'I have kept thy precepts and thy testimonies: for all my ways are before thee.'),
  ('KJV', 'Psalms', 19, 119, 169, 'TAU. Let my cry come near before thee, O LORD: give me understanding according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 170, 'Let my supplication come before thee: deliver me according to thy word.'),
  ('KJV', 'Psalms', 19, 119, 171, 'My lips shall utter praise, when thou hast taught me thy statutes.'),
  ('KJV', 'Psalms', 19, 119, 172, 'My tongue shall speak of thy word: for all thy commandments are righteousness.'),
  ('KJV', 'Psalms', 19, 119, 173, 'Let thine hand help me; for I have chosen thy precepts.'),
  ('KJV', 'Psalms', 19, 119, 174, 'I have longed for thy salvation, O LORD; and thy law is my delight.'),
  ('KJV', 'Psalms', 19, 119, 175, 'Let my soul live, and it shall praise thee; and let thy judgments help me.'),
  ('KJV', 'Psalms', 19, 119, 176, 'I have gone astray like a lost sheep; seek thy servant; for I do not forget thy commandments.'),
  ('KJV', 'Psalms', 19, 120, 1, 'A Song of degrees. In my distress I cried unto the LORD, and he heard me.'),
  ('KJV', 'Psalms', 19, 120, 2, 'Deliver my soul, O LORD, from lying lips, and from a deceitful tongue.'),
  ('KJV', 'Psalms', 19, 120, 3, 'What shall be given unto thee? or what shall be done unto thee, thou false tongue?'),
  ('KJV', 'Psalms', 19, 120, 4, 'Sharp arrows of the mighty, with coals of juniper.'),
  ('KJV', 'Psalms', 19, 120, 5, 'Woe is me, that I sojourn in Mesech, that I dwell in the tents of Kedar!'),
  ('KJV', 'Psalms', 19, 120, 6, 'My soul hath long dwelt with him that hateth peace.'),
  ('KJV', 'Psalms', 19, 120, 7, 'I am for peace: but when I speak, they are for war.'),
  ('KJV', 'Psalms', 19, 121, 1, 'A Song of degrees. I will lift up mine eyes unto the hills, from whence cometh my help.'),
  ('KJV', 'Psalms', 19, 121, 2, 'My help cometh from the LORD, which made heaven and earth.'),
  ('KJV', 'Psalms', 19, 121, 3, 'He will not suffer thy foot to be moved: he that keepeth thee will not slumber.'),
  ('KJV', 'Psalms', 19, 121, 4, 'Behold, he that keepeth Israel shall neither slumber nor sleep.'),
  ('KJV', 'Psalms', 19, 121, 5, 'The LORD is thy keeper: the LORD is thy shade upon thy right hand.'),
  ('KJV', 'Psalms', 19, 121, 6, 'The sun shall not smite thee by day, nor the moon by night.'),
  ('KJV', 'Psalms', 19, 121, 7, 'The LORD shall preserve thee from all evil: he shall preserve thy soul.'),
  ('KJV', 'Psalms', 19, 121, 8, 'The LORD shall preserve thy going out and thy coming in from this time forth, and even for evermore.'),
  ('KJV', 'Psalms', 19, 122, 1, 'A Song of degrees of David. I was glad when they said unto me, Let us go into the house of the LORD.'),
  ('KJV', 'Psalms', 19, 122, 2, 'Our feet shall stand within thy gates, O Jerusalem.'),
  ('KJV', 'Psalms', 19, 122, 3, 'Jerusalem is builded as a city that is compact together:'),
  ('KJV', 'Psalms', 19, 122, 4, 'Whither the tribes go up, the tribes of the LORD, unto the testimony of Israel, to give thanks unto the name of the LORD.'),
  ('KJV', 'Psalms', 19, 122, 5, 'For there are set thrones of judgment, the thrones of the house of David.'),
  ('KJV', 'Psalms', 19, 122, 6, 'Pray for the peace of Jerusalem: they shall prosper that love thee.'),
  ('KJV', 'Psalms', 19, 122, 7, 'Peace be within thy walls, and prosperity within thy palaces.'),
  ('KJV', 'Psalms', 19, 122, 8, 'For my brethren and companions'' sakes, I will now say, Peace be within thee.'),
  ('KJV', 'Psalms', 19, 122, 9, 'Because of the house of the LORD our God I will seek thy good.'),
  ('KJV', 'Psalms', 19, 123, 1, 'A Song of degrees. Unto thee lift I up mine eyes, O thou that dwellest in the heavens.'),
  ('KJV', 'Psalms', 19, 123, 2, 'Behold, as the eyes of servants look unto the hand of their masters, and as the eyes of a maiden unto the hand of her mistress; so our eyes wait upon the LORD our God, until that he have mercy upon us.'),
  ('KJV', 'Psalms', 19, 123, 3, 'Have mercy upon us, O LORD, have mercy upon us: for we are exceedingly filled with contempt.'),
  ('KJV', 'Psalms', 19, 123, 4, 'Our soul is exceedingly filled with the scorning of those that are at ease, and with the contempt of the proud.'),
  ('KJV', 'Psalms', 19, 124, 1, 'A Song of degrees of David. If it had not been the LORD who was on our side, now may Israel say;'),
  ('KJV', 'Psalms', 19, 124, 2, 'If it had not been the LORD who was on our side, when men rose up against us:'),
  ('KJV', 'Psalms', 19, 124, 3, 'Then they had swallowed us up quick, when their wrath was kindled against us:'),
  ('KJV', 'Psalms', 19, 124, 4, 'Then the waters had overwhelmed us, the stream had gone over our soul:'),
  ('KJV', 'Psalms', 19, 124, 5, 'Then the proud waters had gone over our soul.'),
  ('KJV', 'Psalms', 19, 124, 6, 'Blessed be the LORD, who hath not given us as a prey to their teeth.'),
  ('KJV', 'Psalms', 19, 124, 7, 'Our soul is escaped as a bird out of the snare of the fowlers: the snare is broken, and we are escaped.'),
  ('KJV', 'Psalms', 19, 124, 8, 'Our help is in the name of the LORD, who made heaven and earth.'),
  ('KJV', 'Psalms', 19, 125, 1, 'A Song of degrees. They that trust in the LORD shall be as mount Zion, which cannot be removed, but abideth for ever.'),
  ('KJV', 'Psalms', 19, 125, 2, 'As the mountains are round about Jerusalem, so the LORD is round about his people from henceforth even for ever.'),
  ('KJV', 'Psalms', 19, 125, 3, 'For the rod of the wicked shall not rest upon the lot of the righteous; lest the righteous put forth their hands unto iniquity.'),
  ('KJV', 'Psalms', 19, 125, 4, 'Do good, O LORD, unto those that be good, and to them that are upright in their hearts.'),
  ('KJV', 'Psalms', 19, 125, 5, 'As for such as turn aside unto their crooked ways, the LORD shall lead them forth with the workers of iniquity: but peace shall be upon Israel.'),
  ('KJV', 'Psalms', 19, 126, 1, 'A Song of degrees. When the LORD turned again the captivity of Zion, we were like them that dream.'),
  ('KJV', 'Psalms', 19, 126, 2, 'Then was our mouth filled with laughter, and our tongue with singing: then said they among the heathen, The LORD hath done great things for them.'),
  ('KJV', 'Psalms', 19, 126, 3, 'The LORD hath done great things for us; whereof we are glad.'),
  ('KJV', 'Psalms', 19, 126, 4, 'Turn again our captivity, O LORD, as the streams in the south.'),
  ('KJV', 'Psalms', 19, 126, 5, 'They that sow in tears shall reap in joy.'),
  ('KJV', 'Psalms', 19, 126, 6, 'He that goeth forth and weepeth, bearing precious seed, shall doubtless come again with rejoicing, bringing his sheaves with him.'),
  ('KJV', 'Psalms', 19, 127, 1, 'A Song of degrees for Solomon. Except the LORD build the house, they labour in vain that build it: except the LORD keep the city, the watchman waketh but in vain.'),
  ('KJV', 'Psalms', 19, 127, 2, 'It is vain for you to rise up early, to sit up late, to eat the bread of sorrows: for so he giveth his beloved sleep.'),
  ('KJV', 'Psalms', 19, 127, 3, 'Lo, children are an heritage of the LORD: and the fruit of the womb is his reward.'),
  ('KJV', 'Psalms', 19, 127, 4, 'As arrows are in the hand of a mighty man; so are children of the youth.'),
  ('KJV', 'Psalms', 19, 127, 5, 'Happy is the man that hath his quiver full of them: they shall not be ashamed, but they shall speak with the enemies in the gate.'),
  ('KJV', 'Psalms', 19, 128, 1, 'A Song of degrees. Blessed is every one that feareth the LORD; that walketh in his ways.'),
  ('KJV', 'Psalms', 19, 128, 2, 'For thou shalt eat the labour of thine hands: happy shalt thou be, and it shall be well with thee.'),
  ('KJV', 'Psalms', 19, 128, 3, 'Thy wife shall be as a fruitful vine by the sides of thine house: thy children like olive plants round about thy table.'),
  ('KJV', 'Psalms', 19, 128, 4, 'Behold, that thus shall the man be blessed that feareth the LORD.'),
  ('KJV', 'Psalms', 19, 128, 5, 'The LORD shall bless thee out of Zion: and thou shalt see the good of Jerusalem all the days of thy life.'),
  ('KJV', 'Psalms', 19, 128, 6, 'Yea, thou shalt see thy children''s children, and peace upon Israel.'),
  ('KJV', 'Psalms', 19, 129, 1, 'A Song of degrees. Many a time have they afflicted me from my youth, may Israel now say:'),
  ('KJV', 'Psalms', 19, 129, 2, 'Many a time have they afflicted me from my youth: yet they have not prevailed against me.'),
  ('KJV', 'Psalms', 19, 129, 3, 'The plowers plowed upon my back: they made long their furrows.'),
  ('KJV', 'Psalms', 19, 129, 4, 'The LORD is righteous: he hath cut asunder the cords of the wicked.'),
  ('KJV', 'Psalms', 19, 129, 5, 'Let them all be confounded and turned back that hate Zion.'),
  ('KJV', 'Psalms', 19, 129, 6, 'Let them be as the grass upon the housetops, which withereth afore it groweth up:'),
  ('KJV', 'Psalms', 19, 129, 7, 'Wherewith the mower filleth not his hand; nor he that bindeth sheaves his bosom.'),
  ('KJV', 'Psalms', 19, 129, 8, 'Neither do they which go by say, The blessing of the LORD be upon you: we bless you in the name of the LORD.'),
  ('KJV', 'Psalms', 19, 130, 1, 'A Song of degrees. Out of the depths have I cried unto thee, O LORD.'),
  ('KJV', 'Psalms', 19, 130, 2, 'Lord, hear my voice: let thine ears be attentive to the voice of my supplications.'),
  ('KJV', 'Psalms', 19, 130, 3, 'If thou, LORD, shouldest mark iniquities, O Lord, who shall stand?'),
  ('KJV', 'Psalms', 19, 130, 4, 'But there is forgiveness with thee, that thou mayest be feared.'),
  ('KJV', 'Psalms', 19, 130, 5, 'I wait for the LORD, my soul doth wait, and in his word do I hope.'),
  ('KJV', 'Psalms', 19, 130, 6, 'My soul waiteth for the Lord more than they that watch for the morning: I say, more than they that watch for the morning.'),
  ('KJV', 'Psalms', 19, 130, 7, 'Let Israel hope in the LORD: for with the LORD there is mercy, and with him is plenteous redemption.'),
  ('KJV', 'Psalms', 19, 130, 8, 'And he shall redeem Israel from all his iniquities.'),
  ('KJV', 'Psalms', 19, 131, 1, 'A Song of degrees of David. LORD, my heart is not haughty, nor mine eyes lofty: neither do I exercise myself in great matters, or in things too high for me.'),
  ('KJV', 'Psalms', 19, 131, 2, 'Surely I have behaved and quieted myself, as a child that is weaned of his mother: my soul is even as a weaned child.'),
  ('KJV', 'Psalms', 19, 131, 3, 'Let Israel hope in the LORD from henceforth and for ever.'),
  ('KJV', 'Psalms', 19, 132, 1, 'A Song of degrees. LORD, remember David, and all his afflictions:'),
  ('KJV', 'Psalms', 19, 132, 2, 'How he sware unto the LORD, and vowed unto the mighty God of Jacob;'),
  ('KJV', 'Psalms', 19, 132, 3, 'Surely I will not come into the tabernacle of my house, nor go up into my bed;'),
  ('KJV', 'Psalms', 19, 132, 4, 'I will not give sleep to mine eyes, or slumber to mine eyelids,'),
  ('KJV', 'Psalms', 19, 132, 5, 'Until I find out a place for the LORD, an habitation for the mighty God of Jacob.'),
  ('KJV', 'Psalms', 19, 132, 6, 'Lo, we heard of it at Ephratah: we found it in the fields of the wood.'),
  ('KJV', 'Psalms', 19, 132, 7, 'We will go into his tabernacles: we will worship at his footstool.'),
  ('KJV', 'Psalms', 19, 132, 8, 'Arise, O LORD, into thy rest; thou, and the ark of thy strength.'),
  ('KJV', 'Psalms', 19, 132, 9, 'Let thy priests be clothed with righteousness; and let thy saints shout for joy.'),
  ('KJV', 'Psalms', 19, 132, 10, 'For thy servant David''s sake turn not away the face of thine anointed.'),
  ('KJV', 'Psalms', 19, 132, 11, 'The LORD hath sworn in truth unto David; he will not turn from it; Of the fruit of thy body will I set upon thy throne.'),
  ('KJV', 'Psalms', 19, 132, 12, 'If thy children will keep my covenant and my testimony that I shall teach them, their children shall also sit upon thy throne for evermore.'),
  ('KJV', 'Psalms', 19, 132, 13, 'For the LORD hath chosen Zion; he hath desired it for his habitation.'),
  ('KJV', 'Psalms', 19, 132, 14, 'This is my rest for ever: here will I dwell; for I have desired it.'),
  ('KJV', 'Psalms', 19, 132, 15, 'I will abundantly bless her provision: I will satisfy her poor with bread.'),
  ('KJV', 'Psalms', 19, 132, 16, 'I will also clothe her priests with salvation: and her saints shall shout aloud for joy.'),
  ('KJV', 'Psalms', 19, 132, 17, 'There will I make the horn of David to bud: I have ordained a lamp for mine anointed.'),
  ('KJV', 'Psalms', 19, 132, 18, 'His enemies will I clothe with shame: but upon himself shall his crown flourish.'),
  ('KJV', 'Psalms', 19, 133, 1, 'A Song of degrees of David. Behold, how good and how pleasant it is for brethren to dwell together in unity!'),
  ('KJV', 'Psalms', 19, 133, 2, 'It is like the precious ointment upon the head, that ran down upon the beard, even Aaron''s beard: that went down to the skirts of his garments;'),
  ('KJV', 'Psalms', 19, 133, 3, 'As the dew of Hermon, and as the dew that descended upon the mountains of Zion: for there the LORD commanded the blessing, even life for evermore.'),
  ('KJV', 'Psalms', 19, 134, 1, 'A Song of degrees. Behold, bless ye the LORD, all ye servants of the LORD, which by night stand in the house of the LORD.'),
  ('KJV', 'Psalms', 19, 134, 2, 'Lift up your hands in the sanctuary, and bless the LORD.'),
  ('KJV', 'Psalms', 19, 134, 3, 'The LORD that made heaven and earth bless thee out of Zion.'),
  ('KJV', 'Psalms', 19, 135, 1, 'Praise ye the LORD. Praise ye the name of the LORD; praise him, O ye servants of the LORD.'),
  ('KJV', 'Psalms', 19, 135, 2, 'Ye that stand in the house of the LORD, in the courts of the house of our God,'),
  ('KJV', 'Psalms', 19, 135, 3, 'Praise the LORD; for the LORD is good: sing praises unto his name; for it is pleasant.'),
  ('KJV', 'Psalms', 19, 135, 4, 'For the LORD hath chosen Jacob unto himself, and Israel for his peculiar treasure.'),
  ('KJV', 'Psalms', 19, 135, 5, 'For I know that the LORD is great, and that our Lord is above all gods.'),
  ('KJV', 'Psalms', 19, 135, 6, 'Whatsoever the LORD pleased, that did he in heaven, and in earth, in the seas, and all deep places.'),
  ('KJV', 'Psalms', 19, 135, 7, 'He causeth the vapours to ascend from the ends of the earth; he maketh lightnings for the rain; he bringeth the wind out of his treasuries.'),
  ('KJV', 'Psalms', 19, 135, 8, 'Who smote the firstborn of Egypt, both of man and beast.'),
  ('KJV', 'Psalms', 19, 135, 9, 'Who sent tokens and wonders into the midst of thee, O Egypt, upon Pharaoh, and upon all his servants.'),
  ('KJV', 'Psalms', 19, 135, 10, 'Who smote great nations, and slew mighty kings;'),
  ('KJV', 'Psalms', 19, 135, 11, 'Sihon king of the Amorites, and Og king of Bashan, and all the kingdoms of Canaan:'),
  ('KJV', 'Psalms', 19, 135, 12, 'And gave their land for an heritage, an heritage unto Israel his people.'),
  ('KJV', 'Psalms', 19, 135, 13, 'Thy name, O LORD, endureth for ever; and thy memorial, O LORD, throughout all generations.'),
  ('KJV', 'Psalms', 19, 135, 14, 'For the LORD will judge his people, and he will repent himself concerning his servants.'),
  ('KJV', 'Psalms', 19, 135, 15, 'The idols of the heathen are silver and gold, the work of men''s hands.'),
  ('KJV', 'Psalms', 19, 135, 16, 'They have mouths, but they speak not; eyes have they, but they see not;'),
  ('KJV', 'Psalms', 19, 135, 17, 'They have ears, but they hear not; neither is there any breath in their mouths.'),
  ('KJV', 'Psalms', 19, 135, 18, 'They that make them are like unto them: so is every one that trusteth in them.'),
  ('KJV', 'Psalms', 19, 135, 19, 'Bless the LORD, O house of Israel: bless the LORD, O house of Aaron:'),
  ('KJV', 'Psalms', 19, 135, 20, 'Bless the LORD, O house of Levi: ye that fear the LORD, bless the LORD.'),
  ('KJV', 'Psalms', 19, 135, 21, 'Blessed be the LORD out of Zion, which dwelleth at Jerusalem. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 136, 1, 'O give thanks unto the LORD; for he is good: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 2, 'O give thanks unto the God of gods: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 3, 'O give thanks to the Lord of lords: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 4, 'To him who alone doeth great wonders: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 5, 'To him that by wisdom made the heavens: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 6, 'To him that stretched out the earth above the waters: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 7, 'To him that made great lights: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 8, 'The sun to rule by day: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 9, 'The moon and stars to rule by night: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 10, 'To him that smote Egypt in their firstborn: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 11, 'And brought out Israel from among them: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 12, 'With a strong hand, and with a stretched out arm: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 13, 'To him which divided the Red sea into parts: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 14, 'And made Israel to pass through the midst of it: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 15, 'But overthrew Pharaoh and his host in the Red sea: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 16, 'To him which led his people through the wilderness: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 17, 'To him which smote great kings: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 18, 'And slew famous kings: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 19, 'Sihon king of the Amorites: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 20, 'And Og the king of Bashan: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 21, 'And gave their land for an heritage: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 22, 'Even an heritage unto Israel his servant: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 23, 'Who remembered us in our low estate: for his mercy endureth for ever:'),
  ('KJV', 'Psalms', 19, 136, 24, 'And hath redeemed us from our enemies: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 25, 'Who giveth food to all flesh: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 136, 26, 'O give thanks unto the God of heaven: for his mercy endureth for ever.'),
  ('KJV', 'Psalms', 19, 137, 1, 'By the rivers of Babylon, there we sat down, yea, we wept, when we remembered Zion.'),
  ('KJV', 'Psalms', 19, 137, 2, 'We hanged our harps upon the willows in the midst thereof.'),
  ('KJV', 'Psalms', 19, 137, 3, 'For there they that carried us away captive required of us a song; and they that wasted us required of us mirth, saying, Sing us one of the songs of Zion.'),
  ('KJV', 'Psalms', 19, 137, 4, 'How shall we sing the LORD''S song in a strange land?'),
  ('KJV', 'Psalms', 19, 137, 5, 'If I forget thee, O Jerusalem, let my right hand forget her cunning.'),
  ('KJV', 'Psalms', 19, 137, 6, 'If I do not remember thee, let my tongue cleave to the roof of my mouth; if I prefer not Jerusalem above my chief joy.'),
  ('KJV', 'Psalms', 19, 137, 7, 'Remember, O LORD, the children of Edom in the day of Jerusalem; who said, Rase it, rase it, even to the foundation thereof.'),
  ('KJV', 'Psalms', 19, 137, 8, 'O daughter of Babylon, who art to be destroyed; happy shall he be, that rewardeth thee as thou hast served us.'),
  ('KJV', 'Psalms', 19, 137, 9, 'Happy shall he be, that taketh and dasheth thy little ones against the stones.'),
  ('KJV', 'Psalms', 19, 138, 1, 'A Psalm of David. I will praise thee with my whole heart: before the gods will I sing praise unto thee.'),
  ('KJV', 'Psalms', 19, 138, 2, 'I will worship toward thy holy temple, and praise thy name for thy lovingkindness and for thy truth: for thou hast magnified thy word above all thy name.'),
  ('KJV', 'Psalms', 19, 138, 3, 'In the day when I cried thou answeredst me, and strengthenedst me with strength in my soul.'),
  ('KJV', 'Psalms', 19, 138, 4, 'All the kings of the earth shall praise thee, O LORD, when they hear the words of thy mouth.'),
  ('KJV', 'Psalms', 19, 138, 5, 'Yea, they shall sing in the ways of the LORD: for great is the glory of the LORD.'),
  ('KJV', 'Psalms', 19, 138, 6, 'Though the LORD be high, yet hath he respect unto the lowly: but the proud he knoweth afar off.'),
  ('KJV', 'Psalms', 19, 138, 7, 'Though I walk in the midst of trouble, thou wilt revive me: thou shalt stretch forth thine hand against the wrath of mine enemies, and thy right hand shall save me.'),
  ('KJV', 'Psalms', 19, 138, 8, 'The LORD will perfect that which concerneth me: thy mercy, O LORD, endureth for ever: forsake not the works of thine own hands.'),
  ('KJV', 'Psalms', 19, 139, 1, 'To the chief Musician, A Psalm of David. O LORD, thou hast searched me, and known me.'),
  ('KJV', 'Psalms', 19, 139, 2, 'Thou knowest my downsitting and mine uprising, thou understandest my thought afar off.'),
  ('KJV', 'Psalms', 19, 139, 3, 'Thou compassest my path and my lying down, and art acquainted with all my ways.'),
  ('KJV', 'Psalms', 19, 139, 4, 'For there is not a word in my tongue, but, lo, O LORD, thou knowest it altogether.'),
  ('KJV', 'Psalms', 19, 139, 5, 'Thou hast beset me behind and before, and laid thine hand upon me.'),
  ('KJV', 'Psalms', 19, 139, 6, 'Such knowledge is too wonderful for me; it is high, I cannot attain unto it.'),
  ('KJV', 'Psalms', 19, 139, 7, 'Whither shall I go from thy spirit? or whither shall I flee from thy presence?'),
  ('KJV', 'Psalms', 19, 139, 8, 'If I ascend up into heaven, thou art there: if I make my bed in hell, behold, thou art there.'),
  ('KJV', 'Psalms', 19, 139, 9, 'If I take the wings of the morning, and dwell in the uttermost parts of the sea;'),
  ('KJV', 'Psalms', 19, 139, 10, 'Even there shall thy hand lead me, and thy right hand shall hold me.'),
  ('KJV', 'Psalms', 19, 139, 11, 'If I say, Surely the darkness shall cover me; even the night shall be light about me.'),
  ('KJV', 'Psalms', 19, 139, 12, 'Yea, the darkness hideth not from thee; but the night shineth as the day: the darkness and the light are both alike to thee.'),
  ('KJV', 'Psalms', 19, 139, 13, 'For thou hast possessed my reins: thou hast covered me in my mother''s womb.'),
  ('KJV', 'Psalms', 19, 139, 14, 'I will praise thee; for I am fearfully and wonderfully made: marvellous are thy works; and that my soul knoweth right well.'),
  ('KJV', 'Psalms', 19, 139, 15, 'My substance was not hid from thee, when I was made in secret, and curiously wrought in the lowest parts of the earth.'),
  ('KJV', 'Psalms', 19, 139, 16, 'Thine eyes did see my substance, yet being unperfect; and in thy book all my members were written, which in continuance were fashioned, when as yet there was none of them.'),
  ('KJV', 'Psalms', 19, 139, 17, 'How precious also are thy thoughts unto me, O God! how great is the sum of them!'),
  ('KJV', 'Psalms', 19, 139, 18, 'If I should count them, they are more in number than the sand: when I awake, I am still with thee.'),
  ('KJV', 'Psalms', 19, 139, 19, 'Surely thou wilt slay the wicked, O God: depart from me therefore, ye bloody men.'),
  ('KJV', 'Psalms', 19, 139, 20, 'For they speak against thee wickedly, and thine enemies take thy name in vain.'),
  ('KJV', 'Psalms', 19, 139, 21, 'Do not I hate them, O LORD, that hate thee? and am not I grieved with those that rise up against thee?'),
  ('KJV', 'Psalms', 19, 139, 22, 'I hate them with perfect hatred: I count them mine enemies.'),
  ('KJV', 'Psalms', 19, 139, 23, 'Search me, O God, and know my heart: try me, and know my thoughts:'),
  ('KJV', 'Psalms', 19, 139, 24, 'And see if there be any wicked way in me, and lead me in the way everlasting.'),
  ('KJV', 'Psalms', 19, 140, 1, 'To the chief Musician, A Psalm of David. Deliver me, O LORD, from the evil man: preserve me from the violent man;'),
  ('KJV', 'Psalms', 19, 140, 2, 'Which imagine mischiefs in their heart; continually are they gathered together for war.'),
  ('KJV', 'Psalms', 19, 140, 3, 'They have sharpened their tongues like a serpent; adders'' poison is under their lips. Selah.'),
  ('KJV', 'Psalms', 19, 140, 4, 'Keep me, O LORD, from the hands of the wicked; preserve me from the violent man; who have purposed to overthrow my goings.'),
  ('KJV', 'Psalms', 19, 140, 5, 'The proud have hid a snare for me, and cords; they have spread a net by the wayside; they have set gins for me. Selah.'),
  ('KJV', 'Psalms', 19, 140, 6, 'I said unto the LORD, Thou art my God: hear the voice of my supplications, O LORD.'),
  ('KJV', 'Psalms', 19, 140, 7, 'O GOD the Lord, the strength of my salvation, thou hast covered my head in the day of battle.'),
  ('KJV', 'Psalms', 19, 140, 8, 'Grant not, O LORD, the desires of the wicked: further not his wicked device; lest they exalt themselves. Selah.'),
  ('KJV', 'Psalms', 19, 140, 9, 'As for the head of those that compass me about, let the mischief of their own lips cover them.'),
  ('KJV', 'Psalms', 19, 140, 10, 'Let burning coals fall upon them: let them be cast into the fire; into deep pits, that they rise not up again.'),
  ('KJV', 'Psalms', 19, 140, 11, 'Let not an evil speaker be established in the earth: evil shall hunt the violent man to overthrow him.'),
  ('KJV', 'Psalms', 19, 140, 12, 'I know that the LORD will maintain the cause of the afflicted, and the right of the poor.'),
  ('KJV', 'Psalms', 19, 140, 13, 'Surely the righteous shall give thanks unto thy name: the upright shall dwell in thy presence.'),
  ('KJV', 'Psalms', 19, 141, 1, 'A Psalm of David. LORD, I cry unto thee: make haste unto me; give ear unto my voice, when I cry unto thee.'),
  ('KJV', 'Psalms', 19, 141, 2, 'Let my prayer be set forth before thee as incense; and the lifting up of my hands as the evening sacrifice.'),
  ('KJV', 'Psalms', 19, 141, 3, 'Set a watch, O LORD, before my mouth; keep the door of my lips.'),
  ('KJV', 'Psalms', 19, 141, 4, 'Incline not my heart to any evil thing, to practise wicked works with men that work iniquity: and let me not eat of their dainties.'),
  ('KJV', 'Psalms', 19, 141, 5, 'Let the righteous smite me; it shall be a kindness: and let him reprove me; it shall be an excellent oil, which shall not break my head: for yet my prayer also shall be in their calamities.'),
  ('KJV', 'Psalms', 19, 141, 6, 'When their judges are overthrown in stony places, they shall hear my words; for they are sweet.'),
  ('KJV', 'Psalms', 19, 141, 7, 'Our bones are scattered at the grave''s mouth, as when one cutteth and cleaveth wood upon the earth.'),
  ('KJV', 'Psalms', 19, 141, 8, 'But mine eyes are unto thee, O GOD the Lord: in thee is my trust; leave not my soul destitute.'),
  ('KJV', 'Psalms', 19, 141, 9, 'Keep me from the snares which they have laid for me, and the gins of the workers of iniquity.'),
  ('KJV', 'Psalms', 19, 141, 10, 'Let the wicked fall into their own nets, whilst that I withal escape.'),
  ('KJV', 'Psalms', 19, 142, 1, 'Maschil of David; A Prayer when he was in the cave. I cried unto the LORD with my voice; with my voice unto the LORD did I make my supplication.'),
  ('KJV', 'Psalms', 19, 142, 2, 'I poured out my complaint before him; I shewed before him my trouble.'),
  ('KJV', 'Psalms', 19, 142, 3, 'When my spirit was overwhelmed within me, then thou knewest my path. In the way wherein I walked have they privily laid a snare for me.'),
  ('KJV', 'Psalms', 19, 142, 4, 'I looked on my right hand, and beheld, but there was no man that would know me: refuge failed me; no man cared for my soul.'),
  ('KJV', 'Psalms', 19, 142, 5, 'I cried unto thee, O LORD: I said, Thou art my refuge and my portion in the land of the living.'),
  ('KJV', 'Psalms', 19, 142, 6, 'Attend unto my cry; for I am brought very low: deliver me from my persecutors; for they are stronger than I.'),
  ('KJV', 'Psalms', 19, 142, 7, 'Bring my soul out of prison, that I may praise thy name: the righteous shall compass me about; for thou shalt deal bountifully with me.'),
  ('KJV', 'Psalms', 19, 143, 1, 'A Psalm of David. Hear my prayer, O LORD, give ear to my supplications: in thy faithfulness answer me, and in thy righteousness.'),
  ('KJV', 'Psalms', 19, 143, 2, 'And enter not into judgment with thy servant: for in thy sight shall no man living be justified.'),
  ('KJV', 'Psalms', 19, 143, 3, 'For the enemy hath persecuted my soul; he hath smitten my life down to the ground; he hath made me to dwell in darkness, as those that have been long dead.'),
  ('KJV', 'Psalms', 19, 143, 4, 'Therefore is my spirit overwhelmed within me; my heart within me is desolate.'),
  ('KJV', 'Psalms', 19, 143, 5, 'I remember the days of old; I meditate on all thy works; I muse on the work of thy hands.'),
  ('KJV', 'Psalms', 19, 143, 6, 'I stretch forth my hands unto thee: my soul thirsteth after thee, as a thirsty land. Selah.'),
  ('KJV', 'Psalms', 19, 143, 7, 'Hear me speedily, O LORD: my spirit faileth: hide not thy face from me, lest I be like unto them that go down into the pit.'),
  ('KJV', 'Psalms', 19, 143, 8, 'Cause me to hear thy lovingkindness in the morning; for in thee do I trust: cause me to know the way wherein I should walk; for I lift up my soul unto thee.'),
  ('KJV', 'Psalms', 19, 143, 9, 'Deliver me, O LORD, from mine enemies: I flee unto thee to hide me.'),
  ('KJV', 'Psalms', 19, 143, 10, 'Teach me to do thy will; for thou art my God: thy spirit is good; lead me into the land of uprightness.'),
  ('KJV', 'Psalms', 19, 143, 11, 'Quicken me, O LORD, for thy name''s sake: for thy righteousness'' sake bring my soul out of trouble.'),
  ('KJV', 'Psalms', 19, 143, 12, 'And of thy mercy cut off mine enemies, and destroy all them that afflict my soul: for I am thy servant.'),
  ('KJV', 'Psalms', 19, 144, 1, 'A Psalm of David. Blessed be the LORD my strength, which teacheth my hands to war, and my fingers to fight:'),
  ('KJV', 'Psalms', 19, 144, 2, 'My goodness, and my fortress; my high tower, and my deliverer; my shield, and he in whom I trust; who subdueth my people under me.'),
  ('KJV', 'Psalms', 19, 144, 3, 'LORD, what is man, that thou takest knowledge of him! or the son of man, that thou makest account of him!'),
  ('KJV', 'Psalms', 19, 144, 4, 'Man is like to vanity: his days are as a shadow that passeth away.'),
  ('KJV', 'Psalms', 19, 144, 5, 'Bow thy heavens, O LORD, and come down: touch the mountains, and they shall smoke.'),
  ('KJV', 'Psalms', 19, 144, 6, 'Cast forth lightning, and scatter them: shoot out thine arrows, and destroy them.'),
  ('KJV', 'Psalms', 19, 144, 7, 'Send thine hand from above; rid me, and deliver me out of great waters, from the hand of strange children;'),
  ('KJV', 'Psalms', 19, 144, 8, 'Whose mouth speaketh vanity, and their right hand is a right hand of falsehood.'),
  ('KJV', 'Psalms', 19, 144, 9, 'I will sing a new song unto thee, O God: upon a psaltery and an instrument of ten strings will I sing praises unto thee.'),
  ('KJV', 'Psalms', 19, 144, 10, 'It is he that giveth salvation unto kings: who delivereth David his servant from the hurtful sword.'),
  ('KJV', 'Psalms', 19, 144, 11, 'Rid me, and deliver me from the hand of strange children, whose mouth speaketh vanity, and their right hand is a right hand of falsehood:'),
  ('KJV', 'Psalms', 19, 144, 12, 'That our sons may be as plants grown up in their youth; that our daughters may be as corner stones, polished after the similitude of a palace:'),
  ('KJV', 'Psalms', 19, 144, 13, 'That our garners may be full, affording all manner of store: that our sheep may bring forth thousands and ten thousands in our streets:'),
  ('KJV', 'Psalms', 19, 144, 14, 'That our oxen may be strong to labour; that there be no breaking in, nor going out; that there be no complaining in our streets.'),
  ('KJV', 'Psalms', 19, 144, 15, 'Happy is that people, that is in such a case: yea, happy is that people, whose God is the LORD.'),
  ('KJV', 'Psalms', 19, 145, 1, 'David''s Psalm of praise. I will extol thee, my God, O king; and I will bless thy name for ever and ever.'),
  ('KJV', 'Psalms', 19, 145, 2, 'Every day will I bless thee; and I will praise thy name for ever and ever.'),
  ('KJV', 'Psalms', 19, 145, 3, 'Great is the LORD, and greatly to be praised; and his greatness is unsearchable.'),
  ('KJV', 'Psalms', 19, 145, 4, 'One generation shall praise thy works to another, and shall declare thy mighty acts.'),
  ('KJV', 'Psalms', 19, 145, 5, 'I will speak of the glorious honour of thy majesty, and of thy wondrous works.'),
  ('KJV', 'Psalms', 19, 145, 6, 'And men shall speak of the might of thy terrible acts: and I will declare thy greatness.'),
  ('KJV', 'Psalms', 19, 145, 7, 'They shall abundantly utter the memory of thy great goodness, and shall sing of thy righteousness.'),
  ('KJV', 'Psalms', 19, 145, 8, 'The LORD is gracious, and full of compassion; slow to anger, and of great mercy.'),
  ('KJV', 'Psalms', 19, 145, 9, 'The LORD is good to all: and his tender mercies are over all his works.'),
  ('KJV', 'Psalms', 19, 145, 10, 'All thy works shall praise thee, O LORD; and thy saints shall bless thee.'),
  ('KJV', 'Psalms', 19, 145, 11, 'They shall speak of the glory of thy kingdom, and talk of thy power;'),
  ('KJV', 'Psalms', 19, 145, 12, 'To make known to the sons of men his mighty acts, and the glorious majesty of his kingdom.'),
  ('KJV', 'Psalms', 19, 145, 13, 'Thy kingdom is an everlasting kingdom, and thy dominion endureth throughout all generations.'),
  ('KJV', 'Psalms', 19, 145, 14, 'The LORD upholdeth all that fall, and raiseth up all those that be bowed down.'),
  ('KJV', 'Psalms', 19, 145, 15, 'The eyes of all wait upon thee; and thou givest them their meat in due season.'),
  ('KJV', 'Psalms', 19, 145, 16, 'Thou openest thine hand, and satisfiest the desire of every living thing.'),
  ('KJV', 'Psalms', 19, 145, 17, 'The LORD is righteous in all his ways, and holy in all his works.'),
  ('KJV', 'Psalms', 19, 145, 18, 'The LORD is nigh unto all them that call upon him, to all that call upon him in truth.'),
  ('KJV', 'Psalms', 19, 145, 19, 'He will fulfil the desire of them that fear him: he also will hear their cry, and will save them.'),
  ('KJV', 'Psalms', 19, 145, 20, 'The LORD preserveth all them that love him: but all the wicked will he destroy.'),
  ('KJV', 'Psalms', 19, 145, 21, 'My mouth shall speak the praise of the LORD: and let all flesh bless his holy name for ever and ever.'),
  ('KJV', 'Psalms', 19, 146, 1, 'Praise ye the LORD. Praise the LORD, O my soul.'),
  ('KJV', 'Psalms', 19, 146, 2, 'While I live will I praise the LORD: I will sing praises unto my God while I have any being.'),
  ('KJV', 'Psalms', 19, 146, 3, 'Put not your trust in princes, nor in the son of man, in whom there is no help.'),
  ('KJV', 'Psalms', 19, 146, 4, 'His breath goeth forth, he returneth to his earth; in that very day his thoughts perish.'),
  ('KJV', 'Psalms', 19, 146, 5, 'Happy is he that hath the God of Jacob for his help, whose hope is in the LORD his God:'),
  ('KJV', 'Psalms', 19, 146, 6, 'Which made heaven, and earth, the sea, and all that therein is: which keepeth truth for ever:'),
  ('KJV', 'Psalms', 19, 146, 7, 'Which executeth judgment for the oppressed: which giveth food to the hungry. The LORD looseth the prisoners:'),
  ('KJV', 'Psalms', 19, 146, 8, 'The LORD openeth the eyes of the blind: the LORD raiseth them that are bowed down: the LORD loveth the righteous:'),
  ('KJV', 'Psalms', 19, 146, 9, 'The LORD preserveth the strangers; he relieveth the fatherless and widow: but the way of the wicked he turneth upside down.'),
  ('KJV', 'Psalms', 19, 146, 10, 'The LORD shall reign for ever, even thy God, O Zion, unto all generations. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 147, 1, 'Praise ye the LORD: for it is good to sing praises unto our God; for it is pleasant; and praise is comely.'),
  ('KJV', 'Psalms', 19, 147, 2, 'The LORD doth build up Jerusalem: he gathereth together the outcasts of Israel.'),
  ('KJV', 'Psalms', 19, 147, 3, 'He healeth the broken in heart, and bindeth up their wounds.'),
  ('KJV', 'Psalms', 19, 147, 4, 'He telleth the number of the stars; he calleth them all by their names.'),
  ('KJV', 'Psalms', 19, 147, 5, 'Great is our Lord, and of great power: his understanding is infinite.'),
  ('KJV', 'Psalms', 19, 147, 6, 'The LORD lifteth up the meek: he casteth the wicked down to the ground.'),
  ('KJV', 'Psalms', 19, 147, 7, 'Sing unto the LORD with thanksgiving; sing praise upon the harp unto our God:'),
  ('KJV', 'Psalms', 19, 147, 8, 'Who covereth the heaven with clouds, who prepareth rain for the earth, who maketh grass to grow upon the mountains.'),
  ('KJV', 'Psalms', 19, 147, 9, 'He giveth to the beast his food, and to the young ravens which cry.'),
  ('KJV', 'Psalms', 19, 147, 10, 'He delighteth not in the strength of the horse: he taketh not pleasure in the legs of a man.'),
  ('KJV', 'Psalms', 19, 147, 11, 'The LORD taketh pleasure in them that fear him, in those that hope in his mercy.'),
  ('KJV', 'Psalms', 19, 147, 12, 'Praise the LORD, O Jerusalem; praise thy God, O Zion.'),
  ('KJV', 'Psalms', 19, 147, 13, 'For he hath strengthened the bars of thy gates; he hath blessed thy children within thee.'),
  ('KJV', 'Psalms', 19, 147, 14, 'He maketh peace in thy borders, and filleth thee with the finest of the wheat.'),
  ('KJV', 'Psalms', 19, 147, 15, 'He sendeth forth his commandment upon earth: his word runneth very swiftly.'),
  ('KJV', 'Psalms', 19, 147, 16, 'He giveth snow like wool: he scattereth the hoarfrost like ashes.'),
  ('KJV', 'Psalms', 19, 147, 17, 'He casteth forth his ice like morsels: who can stand before his cold?'),
  ('KJV', 'Psalms', 19, 147, 18, 'He sendeth out his word, and melteth them: he causeth his wind to blow, and the waters flow.'),
  ('KJV', 'Psalms', 19, 147, 19, 'He sheweth his word unto Jacob, his statutes and his judgments unto Israel.'),
  ('KJV', 'Psalms', 19, 147, 20, 'He hath not dealt so with any nation: and as for his judgments, they have not known them. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 148, 1, 'Praise ye the LORD. Praise ye the LORD from the heavens: praise him in the heights.'),
  ('KJV', 'Psalms', 19, 148, 2, 'Praise ye him, all his angels: praise ye him, all his hosts.'),
  ('KJV', 'Psalms', 19, 148, 3, 'Praise ye him, sun and moon: praise him, all ye stars of light.'),
  ('KJV', 'Psalms', 19, 148, 4, 'Praise him, ye heavens of heavens, and ye waters that be above the heavens.'),
  ('KJV', 'Psalms', 19, 148, 5, 'Let them praise the name of the LORD: for he commanded, and they were created.'),
  ('KJV', 'Psalms', 19, 148, 6, 'He hath also stablished them for ever and ever: he hath made a decree which shall not pass.'),
  ('KJV', 'Psalms', 19, 148, 7, 'Praise the LORD from the earth, ye dragons, and all deeps:'),
  ('KJV', 'Psalms', 19, 148, 8, 'Fire, and hail; snow, and vapour; stormy wind fulfilling his word:'),
  ('KJV', 'Psalms', 19, 148, 9, 'Mountains, and all hills; fruitful trees, and all cedars:'),
  ('KJV', 'Psalms', 19, 148, 10, 'Beasts, and all cattle; creeping things, and flying fowl:'),
  ('KJV', 'Psalms', 19, 148, 11, 'Kings of the earth, and all people; princes, and all judges of the earth:'),
  ('KJV', 'Psalms', 19, 148, 12, 'Both young men, and maidens; old men, and children:'),
  ('KJV', 'Psalms', 19, 148, 13, 'Let them praise the name of the LORD: for his name alone is excellent; his glory is above the earth and heaven.'),
  ('KJV', 'Psalms', 19, 148, 14, 'He also exalteth the horn of his people, the praise of all his saints; even of the children of Israel, a people near unto him. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 149, 1, 'Praise ye the LORD. Sing unto the LORD a new song, and his praise in the congregation of saints.'),
  ('KJV', 'Psalms', 19, 149, 2, 'Let Israel rejoice in him that made him: let the children of Zion be joyful in their King.'),
  ('KJV', 'Psalms', 19, 149, 3, 'Let them praise his name in the dance: let them sing praises unto him with the timbrel and harp.'),
  ('KJV', 'Psalms', 19, 149, 4, 'For the LORD taketh pleasure in his people: he will beautify the meek with salvation.'),
  ('KJV', 'Psalms', 19, 149, 5, 'Let the saints be joyful in glory: let them sing aloud upon their beds.'),
  ('KJV', 'Psalms', 19, 149, 6, 'Let the high praises of God be in their mouth, and a twoedged sword in their hand;'),
  ('KJV', 'Psalms', 19, 149, 7, 'To execute vengeance upon the heathen, and punishments upon the people;'),
  ('KJV', 'Psalms', 19, 149, 8, 'To bind their kings with chains, and their nobles with fetters of iron;'),
  ('KJV', 'Psalms', 19, 149, 9, 'To execute upon them the judgment written: this honour have all his saints. Praise ye the LORD.'),
  ('KJV', 'Psalms', 19, 150, 1, 'Praise ye the LORD. Praise God in his sanctuary: praise him in the firmament of his power.'),
  ('KJV', 'Psalms', 19, 150, 2, 'Praise him for his mighty acts: praise him according to his excellent greatness.'),
  ('KJV', 'Psalms', 19, 150, 3, 'Praise him with the sound of the trumpet: praise him with the psaltery and harp.'),
  ('KJV', 'Psalms', 19, 150, 4, 'Praise him with the timbrel and dance: praise him with stringed instruments and organs.'),
  ('KJV', 'Psalms', 19, 150, 5, 'Praise him upon the loud cymbals: praise him upon the high sounding cymbals.'),
  ('KJV', 'Psalms', 19, 150, 6, 'Let every thing that hath breath praise the LORD. Praise ye the LORD.'),
  ('KJV', 'Proverbs', 20, 1, 1, 'The proverbs of Solomon the son of David, king of Israel;'),
  ('KJV', 'Proverbs', 20, 1, 2, 'To know wisdom and instruction; to perceive the words of understanding;'),
  ('KJV', 'Proverbs', 20, 1, 3, 'To receive the instruction of wisdom, justice, and judgment, and equity;'),
  ('KJV', 'Proverbs', 20, 1, 4, 'To give subtilty to the simple, to the young man knowledge and discretion.'),
  ('KJV', 'Proverbs', 20, 1, 5, 'A wise man will hear, and will increase learning; and a man of understanding shall attain unto wise counsels:'),
  ('KJV', 'Proverbs', 20, 1, 6, 'To understand a proverb, and the interpretation; the words of the wise, and their dark sayings.'),
  ('KJV', 'Proverbs', 20, 1, 7, 'The fear of the LORD is the beginning of knowledge: but fools despise wisdom and instruction.'),
  ('KJV', 'Proverbs', 20, 1, 8, 'My son, hear the instruction of thy father, and forsake not the law of thy mother:'),
  ('KJV', 'Proverbs', 20, 1, 9, 'For they shall be an ornament of grace unto thy head, and chains about thy neck.'),
  ('KJV', 'Proverbs', 20, 1, 10, 'My son, if sinners entice thee, consent thou not.'),
  ('KJV', 'Proverbs', 20, 1, 11, 'If they say, Come with us, let us lay wait for blood, let us lurk privily for the innocent without cause:'),
  ('KJV', 'Proverbs', 20, 1, 12, 'Let us swallow them up alive as the grave; and whole, as those that go down into the pit:'),
  ('KJV', 'Proverbs', 20, 1, 13, 'We shall find all precious substance, we shall fill our houses with spoil:'),
  ('KJV', 'Proverbs', 20, 1, 14, 'Cast in thy lot among us; let us all have one purse:'),
  ('KJV', 'Proverbs', 20, 1, 15, 'My son, walk not thou in the way with them; refrain thy foot from their path:'),
  ('KJV', 'Proverbs', 20, 1, 16, 'For their feet run to evil, and make haste to shed blood.'),
  ('KJV', 'Proverbs', 20, 1, 17, 'Surely in vain the net is spread in the sight of any bird.'),
  ('KJV', 'Proverbs', 20, 1, 18, 'And they lay wait for their own blood; they lurk privily for their own lives.'),
  ('KJV', 'Proverbs', 20, 1, 19, 'So are the ways of every one that is greedy of gain; which taketh away the life of the owners thereof.'),
  ('KJV', 'Proverbs', 20, 1, 20, 'Wisdom crieth without; she uttereth her voice in the streets:'),
  ('KJV', 'Proverbs', 20, 1, 21, 'She crieth in the chief place of concourse, in the openings of the gates: in the city she uttereth her words, saying,'),
  ('KJV', 'Proverbs', 20, 1, 22, 'How long, ye simple ones, will ye love simplicity? and the scorners delight in their scorning, and fools hate knowledge?'),
  ('KJV', 'Proverbs', 20, 1, 23, 'Turn you at my reproof: behold, I will pour out my spirit unto you, I will make known my words unto you.'),
  ('KJV', 'Proverbs', 20, 1, 24, 'Because I have called, and ye refused; I have stretched out my hand, and no man regarded;'),
  ('KJV', 'Proverbs', 20, 1, 25, 'But ye have set at nought all my counsel, and would none of my reproof:'),
  ('KJV', 'Proverbs', 20, 1, 26, 'I also will laugh at your calamity; I will mock when your fear cometh;'),
  ('KJV', 'Proverbs', 20, 1, 27, 'When your fear cometh as desolation, and your destruction cometh as a whirlwind; when distress and anguish cometh upon you.'),
  ('KJV', 'Proverbs', 20, 1, 28, 'Then shall they call upon me, but I will not answer; they shall seek me early, but they shall not find me:'),
  ('KJV', 'Proverbs', 20, 1, 29, 'For that they hated knowledge, and did not choose the fear of the LORD:'),
  ('KJV', 'Proverbs', 20, 1, 30, 'They would none of my counsel: they despised all my reproof.'),
  ('KJV', 'Proverbs', 20, 1, 31, 'Therefore shall they eat of the fruit of their own way, and be filled with their own devices.'),
  ('KJV', 'Proverbs', 20, 1, 32, 'For the turning away of the simple shall slay them, and the prosperity of fools shall destroy them.'),
  ('KJV', 'Proverbs', 20, 1, 33, 'But whoso hearkeneth unto me shall dwell safely, and shall be quiet from fear of evil.'),
  ('KJV', 'Proverbs', 20, 2, 1, 'My son, if thou wilt receive my words, and hide my commandments with thee;'),
  ('KJV', 'Proverbs', 20, 2, 2, 'So that thou incline thine ear unto wisdom, and apply thine heart to understanding;'),
  ('KJV', 'Proverbs', 20, 2, 3, 'Yea, if thou criest after knowledge, and liftest up thy voice for understanding;'),
  ('KJV', 'Proverbs', 20, 2, 4, 'If thou seekest her as silver, and searchest for her as for hid treasures;'),
  ('KJV', 'Proverbs', 20, 2, 5, 'Then shalt thou understand the fear of the LORD, and find the knowledge of God.'),
  ('KJV', 'Proverbs', 20, 2, 6, 'For the LORD giveth wisdom: out of his mouth cometh knowledge and understanding.'),
  ('KJV', 'Proverbs', 20, 2, 7, 'He layeth up sound wisdom for the righteous: he is a buckler to them that walk uprightly.'),
  ('KJV', 'Proverbs', 20, 2, 8, 'He keepeth the paths of judgment, and preserveth the way of his saints.'),
  ('KJV', 'Proverbs', 20, 2, 9, 'Then shalt thou understand righteousness, and judgment, and equity; yea, every good path.'),
  ('KJV', 'Proverbs', 20, 2, 10, 'When wisdom entereth into thine heart, and knowledge is pleasant unto thy soul;'),
  ('KJV', 'Proverbs', 20, 2, 11, 'Discretion shall preserve thee, understanding shall keep thee:'),
  ('KJV', 'Proverbs', 20, 2, 12, 'To deliver thee from the way of the evil man, from the man that speaketh froward things;'),
  ('KJV', 'Proverbs', 20, 2, 13, 'Who leave the paths of uprightness, to walk in the ways of darkness;'),
  ('KJV', 'Proverbs', 20, 2, 14, 'Who rejoice to do evil, and delight in the frowardness of the wicked;'),
  ('KJV', 'Proverbs', 20, 2, 15, 'Whose ways are crooked, and they froward in their paths:'),
  ('KJV', 'Proverbs', 20, 2, 16, 'To deliver thee from the strange woman, even from the stranger which flattereth with her words;'),
  ('KJV', 'Proverbs', 20, 2, 17, 'Which forsaketh the guide of her youth, and forgetteth the covenant of her God.'),
  ('KJV', 'Proverbs', 20, 2, 18, 'For her house inclineth unto death, and her paths unto the dead.'),
  ('KJV', 'Proverbs', 20, 2, 19, 'None that go unto her return again, neither take they hold of the paths of life.'),
  ('KJV', 'Proverbs', 20, 2, 20, 'That thou mayest walk in the way of good men, and keep the paths of the righteous.'),
  ('KJV', 'Proverbs', 20, 2, 21, 'For the upright shall dwell in the land, and the perfect shall remain in it.'),
  ('KJV', 'Proverbs', 20, 2, 22, 'But the wicked shall be cut off from the earth, and the transgressors shall be rooted out of it.'),
  ('KJV', 'Proverbs', 20, 3, 1, 'My son, forget not my law; but let thine heart keep my commandments:'),
  ('KJV', 'Proverbs', 20, 3, 2, 'For length of days, and long life, and peace, shall they add to thee.'),
  ('KJV', 'Proverbs', 20, 3, 3, 'Let not mercy and truth forsake thee: bind them about thy neck; write them upon the table of thine heart:'),
  ('KJV', 'Proverbs', 20, 3, 4, 'So shalt thou find favour and good understanding in the sight of God and man.'),
  ('KJV', 'Proverbs', 20, 3, 5, 'Trust in the LORD with all thine heart; and lean not unto thine own understanding.'),
  ('KJV', 'Proverbs', 20, 3, 6, 'In all thy ways acknowledge him, and he shall direct thy paths.'),
  ('KJV', 'Proverbs', 20, 3, 7, 'Be not wise in thine own eyes: fear the LORD, and depart from evil.'),
  ('KJV', 'Proverbs', 20, 3, 8, 'It shall be health to thy navel, and marrow to thy bones.'),
  ('KJV', 'Proverbs', 20, 3, 9, 'Honour the LORD with thy substance, and with the firstfruits of all thine increase:'),
  ('KJV', 'Proverbs', 20, 3, 10, 'So shall thy barns be filled with plenty, and thy presses shall burst out with new wine.'),
  ('KJV', 'Proverbs', 20, 3, 11, 'My son, despise not the chastening of the LORD; neither be weary of his correction:'),
  ('KJV', 'Proverbs', 20, 3, 12, 'For whom the LORD loveth he correcteth; even as a father the son in whom he delighteth.'),
  ('KJV', 'Proverbs', 20, 3, 13, 'Happy is the man that findeth wisdom, and the man that getteth understanding.'),
  ('KJV', 'Proverbs', 20, 3, 14, 'For the merchandise of it is better than the merchandise of silver, and the gain thereof than fine gold.'),
  ('KJV', 'Proverbs', 20, 3, 15, 'She is more precious than rubies: and all the things thou canst desire are not to be compared unto her.'),
  ('KJV', 'Proverbs', 20, 3, 16, 'Length of days is in her right hand; and in her left hand riches and honour.'),
  ('KJV', 'Proverbs', 20, 3, 17, 'Her ways are ways of pleasantness, and all her paths are peace.'),
  ('KJV', 'Proverbs', 20, 3, 18, 'She is a tree of life to them that lay hold upon her: and happy is every one that retaineth her.'),
  ('KJV', 'Proverbs', 20, 3, 19, 'The LORD by wisdom hath founded the earth; by understanding hath he established the heavens.'),
  ('KJV', 'Proverbs', 20, 3, 20, 'By his knowledge the depths are broken up, and the clouds drop down the dew.'),
  ('KJV', 'Proverbs', 20, 3, 21, 'My son, let not them depart from thine eyes: keep sound wisdom and discretion:'),
  ('KJV', 'Proverbs', 20, 3, 22, 'So shall they be life unto thy soul, and grace to thy neck.'),
  ('KJV', 'Proverbs', 20, 3, 23, 'Then shalt thou walk in thy way safely, and thy foot shall not stumble.'),
  ('KJV', 'Proverbs', 20, 3, 24, 'When thou liest down, thou shalt not be afraid: yea, thou shalt lie down, and thy sleep shall be sweet.'),
  ('KJV', 'Proverbs', 20, 3, 25, 'Be not afraid of sudden fear, neither of the desolation of the wicked, when it cometh.'),
  ('KJV', 'Proverbs', 20, 3, 26, 'For the LORD shall be thy confidence, and shall keep thy foot from being taken.'),
  ('KJV', 'Proverbs', 20, 3, 27, 'Withhold not good from them to whom it is due, when it is in the power of thine hand to do it.'),
  ('KJV', 'Proverbs', 20, 3, 28, 'Say not unto thy neighbour, Go, and come again, and to morrow I will give; when thou hast it by thee.'),
  ('KJV', 'Proverbs', 20, 3, 29, 'Devise not evil against thy neighbour, seeing he dwelleth securely by thee.'),
  ('KJV', 'Proverbs', 20, 3, 30, 'Strive not with a man without cause, if he have done thee no harm.'),
  ('KJV', 'Proverbs', 20, 3, 31, 'Envy thou not the oppressor, and choose none of his ways.'),
  ('KJV', 'Proverbs', 20, 3, 32, 'For the froward is abomination to the LORD: but his secret is with the righteous.'),
  ('KJV', 'Proverbs', 20, 3, 33, 'The curse of the LORD is in the house of the wicked: but he blesseth the habitation of the just.'),
  ('KJV', 'Proverbs', 20, 3, 34, 'Surely he scorneth the scorners: but he giveth grace unto the lowly.'),
  ('KJV', 'Proverbs', 20, 3, 35, 'The wise shall inherit glory: but shame shall be the promotion of fools.'),
  ('KJV', 'Proverbs', 20, 4, 1, 'Hear, ye children, the instruction of a father, and attend to know understanding.'),
  ('KJV', 'Proverbs', 20, 4, 2, 'For I give you good doctrine, forsake ye not my law.'),
  ('KJV', 'Proverbs', 20, 4, 3, 'For I was my father''s son, tender and only beloved in the sight of my mother.'),
  ('KJV', 'Proverbs', 20, 4, 4, 'He taught me also, and said unto me, Let thine heart retain my words: keep my commandments, and live.'),
  ('KJV', 'Proverbs', 20, 4, 5, 'Get wisdom, get understanding: forget it not; neither decline from the words of my mouth.'),
  ('KJV', 'Proverbs', 20, 4, 6, 'Forsake her not, and she shall preserve thee: love her, and she shall keep thee.'),
  ('KJV', 'Proverbs', 20, 4, 7, 'Wisdom is the principal thing; therefore get wisdom: and with all thy getting get understanding.'),
  ('KJV', 'Proverbs', 20, 4, 8, 'Exalt her, and she shall promote thee: she shall bring thee to honour, when thou dost embrace her.'),
  ('KJV', 'Proverbs', 20, 4, 9, 'She shall give to thine head an ornament of grace: a crown of glory shall she deliver to thee.')
insert into control_room_bible (version, book, book_num, chapter, verse, text) values
  ('KJV', 'Proverbs', 20, 4, 10, 'Hear, O my son, and receive my sayings; and the years of thy life shall be many.'),
  ('KJV', 'Proverbs', 20, 4, 11, 'I have taught thee in the way of wisdom; I have led thee in right paths.'),
  ('KJV', 'Proverbs', 20, 4, 12, 'When thou goest, thy steps shall not be straitened; and when thou runnest, thou shalt not stumble.'),
  ('KJV', 'Proverbs', 20, 4, 13, 'Take fast hold of instruction; let her not go: keep her; for she is thy life.'),
  ('KJV', 'Proverbs', 20, 4, 14, 'Enter not into the path of the wicked, and go not in the way of evil men.'),
  ('KJV', 'Proverbs', 20, 4, 15, 'Avoid it, pass not by it, turn from it, and pass away.'),
  ('KJV', 'Proverbs', 20, 4, 16, 'For they sleep not, except they have done mischief; and their sleep is taken away, unless they cause some to fall.'),
  ('KJV', 'Proverbs', 20, 4, 17, 'For they eat the bread of wickedness, and drink the wine of violence.'),
  ('KJV', 'Proverbs', 20, 4, 18, 'But the path of the just is as the shining light, that shineth more and more unto the perfect day.'),
  ('KJV', 'Proverbs', 20, 4, 19, 'The way of the wicked is as darkness: they know not at what they stumble.'),
  ('KJV', 'Proverbs', 20, 4, 20, 'My son, attend to my words; incline thine ear unto my sayings.'),
  ('KJV', 'Proverbs', 20, 4, 21, 'Let them not depart from thine eyes; keep them in the midst of thine heart.'),
  ('KJV', 'Proverbs', 20, 4, 22, 'For they are life unto those that find them, and health to all their flesh.'),
  ('KJV', 'Proverbs', 20, 4, 23, 'Keep thy heart with all diligence; for out of it are the issues of life.'),
  ('KJV', 'Proverbs', 20, 4, 24, 'Put away from thee a froward mouth, and perverse lips put far from thee.'),
  ('KJV', 'Proverbs', 20, 4, 25, 'Let thine eyes look right on, and let thine eyelids look straight before thee.'),
  ('KJV', 'Proverbs', 20, 4, 26, 'Ponder the path of thy feet, and let all thy ways be established.'),
  ('KJV', 'Proverbs', 20, 4, 27, 'Turn not to the right hand nor to the left: remove thy foot from evil.'),
  ('KJV', 'Proverbs', 20, 5, 1, 'My son, attend unto my wisdom, and bow thine ear to my understanding:'),
  ('KJV', 'Proverbs', 20, 5, 2, 'That thou mayest regard discretion, and that thy lips may keep knowledge.'),
  ('KJV', 'Proverbs', 20, 5, 3, 'For the lips of a strange woman drop as an honeycomb, and her mouth is smoother than oil:'),
  ('KJV', 'Proverbs', 20, 5, 4, 'But her end is bitter as wormwood, sharp as a twoedged sword.'),
  ('KJV', 'Proverbs', 20, 5, 5, 'Her feet go down to death; her steps take hold on hell.'),
  ('KJV', 'Proverbs', 20, 5, 6, 'Lest thou shouldest ponder the path of life, her ways are moveable, that thou canst not know them.'),
  ('KJV', 'Proverbs', 20, 5, 7, 'Hear me now therefore, O ye children, and depart not from the words of my mouth.'),
  ('KJV', 'Proverbs', 20, 5, 8, 'Remove thy way far from her, and come not nigh the door of her house:'),
  ('KJV', 'Proverbs', 20, 5, 9, 'Lest thou give thine honour unto others, and thy years unto the cruel:'),
  ('KJV', 'Proverbs', 20, 5, 10, 'Lest strangers be filled with thy wealth; and thy labours be in the house of a stranger;'),
  ('KJV', 'Proverbs', 20, 5, 11, 'And thou mourn at the last, when thy flesh and thy body are consumed,'),
  ('KJV', 'Proverbs', 20, 5, 12, 'And say, How have I hated instruction, and my heart despised reproof;'),
  ('KJV', 'Proverbs', 20, 5, 13, 'And have not obeyed the voice of my teachers, nor inclined mine ear to them that instructed me!'),
  ('KJV', 'Proverbs', 20, 5, 14, 'I was almost in all evil in the midst of the congregation and assembly.'),
  ('KJV', 'Proverbs', 20, 5, 15, 'Drink waters out of thine own cistern, and running waters out of thine own well.'),
  ('KJV', 'Proverbs', 20, 5, 16, 'Let thy fountains be dispersed abroad, and rivers of waters in the streets.'),
  ('KJV', 'Proverbs', 20, 5, 17, 'Let them be only thine own, and not strangers'' with thee.'),
  ('KJV', 'Proverbs', 20, 5, 18, 'Let thy fountain be blessed: and rejoice with the wife of thy youth.'),
  ('KJV', 'Proverbs', 20, 5, 19, 'Let her be as the loving hind and pleasant roe; let her breasts satisfy thee at all times; and be thou ravished always with her love.'),
  ('KJV', 'Proverbs', 20, 5, 20, 'And why wilt thou, my son, be ravished with a strange woman, and embrace the bosom of a stranger?'),
  ('KJV', 'Proverbs', 20, 5, 21, 'For the ways of man are before the eyes of the LORD, and he pondereth all his goings.'),
  ('KJV', 'Proverbs', 20, 5, 22, 'His own iniquities shall take the wicked himself, and he shall be holden with the cords of his sins.'),
  ('KJV', 'Proverbs', 20, 5, 23, 'He shall die without instruction; and in the greatness of his folly he shall go astray.'),
  ('KJV', 'Proverbs', 20, 6, 1, 'My son, if thou be surety for thy friend, if thou hast stricken thy hand with a stranger,'),
  ('KJV', 'Proverbs', 20, 6, 2, 'Thou art snared with the words of thy mouth, thou art taken with the words of thy mouth.'),
  ('KJV', 'Proverbs', 20, 6, 3, 'Do this now, my son, and deliver thyself, when thou art come into the hand of thy friend; go, humble thyself, and make sure thy friend.'),
  ('KJV', 'Proverbs', 20, 6, 4, 'Give not sleep to thine eyes, nor slumber to thine eyelids.'),
  ('KJV', 'Proverbs', 20, 6, 5, 'Deliver thyself as a roe from the hand of the hunter, and as a bird from the hand of the fowler.'),
  ('KJV', 'Proverbs', 20, 6, 6, 'Go to the ant, thou sluggard; consider her ways, and be wise:'),
  ('KJV', 'Proverbs', 20, 6, 7, 'Which having no guide, overseer, or ruler,'),
  ('KJV', 'Proverbs', 20, 6, 8, 'Provideth her meat in the summer, and gathereth her food in the harvest.'),
  ('KJV', 'Proverbs', 20, 6, 9, 'How long wilt thou sleep, O sluggard? when wilt thou arise out of thy sleep?'),
  ('KJV', 'Proverbs', 20, 6, 10, 'Yet a little sleep, a little slumber, a little folding of the hands to sleep:'),
  ('KJV', 'Proverbs', 20, 6, 11, 'So shall thy poverty come as one that travelleth, and thy want as an armed man.'),
  ('KJV', 'Proverbs', 20, 6, 12, 'A naughty person, a wicked man, walketh with a froward mouth.'),
  ('KJV', 'Proverbs', 20, 6, 13, 'He winketh with his eyes, he speaketh with his feet, he teacheth with his fingers;'),
  ('KJV', 'Proverbs', 20, 6, 14, 'Frowardness is in his heart, he deviseth mischief continually; he soweth discord.'),
  ('KJV', 'Proverbs', 20, 6, 15, 'Therefore shall his calamity come suddenly; suddenly shall he be broken without remedy.'),
  ('KJV', 'Proverbs', 20, 6, 16, 'These six things doth the LORD hate: yea, seven are an abomination unto him:'),
  ('KJV', 'Proverbs', 20, 6, 17, 'A proud look, a lying tongue, and hands that shed innocent blood,'),
  ('KJV', 'Proverbs', 20, 6, 18, 'An heart that deviseth wicked imaginations, feet that be swift in running to mischief,'),
  ('KJV', 'Proverbs', 20, 6, 19, 'A false witness that speaketh lies, and he that soweth discord among brethren.'),
  ('KJV', 'Proverbs', 20, 6, 20, 'My son, keep thy father''s commandment, and forsake not the law of thy mother:'),
  ('KJV', 'Proverbs', 20, 6, 21, 'Bind them continually upon thine heart, and tie them about thy neck.'),
  ('KJV', 'Proverbs', 20, 6, 22, 'When thou goest, it shall lead thee; when thou sleepest, it shall keep thee; and when thou awakest, it shall talk with thee.'),
  ('KJV', 'Proverbs', 20, 6, 23, 'For the commandment is a lamp; and the law is light; and reproofs of instruction are the way of life:'),
  ('KJV', 'Proverbs', 20, 6, 24, 'To keep thee from the evil woman, from the flattery of the tongue of a strange woman.'),
  ('KJV', 'Proverbs', 20, 6, 25, 'Lust not after her beauty in thine heart; neither let her take thee with her eyelids.'),
  ('KJV', 'Proverbs', 20, 6, 26, 'For by means of a whorish woman a man is brought to a piece of bread: and the adulteress will hunt for the precious life.'),
  ('KJV', 'Proverbs', 20, 6, 27, 'Can a man take fire in his bosom, and his clothes not be burned?'),
  ('KJV', 'Proverbs', 20, 6, 28, 'Can one go upon hot coals, and his feet not be burned?'),
  ('KJV', 'Proverbs', 20, 6, 29, 'So he that goeth in to his neighbour''s wife; whosoever toucheth her shall not be innocent.'),
  ('KJV', 'Proverbs', 20, 6, 30, 'Men do not despise a thief, if he steal to satisfy his soul when he is hungry;'),
  ('KJV', 'Proverbs', 20, 6, 31, 'But if he be found, he shall restore sevenfold; he shall give all the substance of his house.'),
  ('KJV', 'Proverbs', 20, 6, 32, 'But whoso committeth adultery with a woman lacketh understanding: he that doeth it destroyeth his own soul.'),
  ('KJV', 'Proverbs', 20, 6, 33, 'A wound and dishonour shall he get; and his reproach shall not be wiped away.'),
  ('KJV', 'Proverbs', 20, 6, 34, 'For jealousy is the rage of a man: therefore he will not spare in the day of vengeance.'),
  ('KJV', 'Proverbs', 20, 6, 35, 'He will not regard any ransom; neither will he rest content, though thou givest many gifts.'),
  ('KJV', 'Proverbs', 20, 7, 1, 'My son, keep my words, and lay up my commandments with thee.'),
  ('KJV', 'Proverbs', 20, 7, 2, 'Keep my commandments, and live; and my law as the apple of thine eye.'),
  ('KJV', 'Proverbs', 20, 7, 3, 'Bind them upon thy fingers, write them upon the table of thine heart.'),
  ('KJV', 'Proverbs', 20, 7, 4, 'Say unto wisdom, Thou art my sister; and call understanding thy kinswoman:'),
  ('KJV', 'Proverbs', 20, 7, 5, 'That they may keep thee from the strange woman, from the stranger which flattereth with her words.'),
  ('KJV', 'Proverbs', 20, 7, 6, 'For at the window of my house I looked through my casement,'),
  ('KJV', 'Proverbs', 20, 7, 7, 'And beheld among the simple ones, I discerned among the youths, a young man void of understanding,'),
  ('KJV', 'Proverbs', 20, 7, 8, 'Passing through the street near her corner; and he went the way to her house,'),
  ('KJV', 'Proverbs', 20, 7, 9, 'In the twilight, in the evening, in the black and dark night:'),
  ('KJV', 'Proverbs', 20, 7, 10, 'And, behold, there met him a woman with the attire of an harlot, and subtil of heart.'),
  ('KJV', 'Proverbs', 20, 7, 11, '(She is loud and stubborn; her feet abide not in her house:'),
  ('KJV', 'Proverbs', 20, 7, 12, 'Now is she without, now in the streets, and lieth in wait at every corner.)'),
  ('KJV', 'Proverbs', 20, 7, 13, 'So she caught him, and kissed him, and with an impudent face said unto him,'),
  ('KJV', 'Proverbs', 20, 7, 14, 'I have peace offerings with me; this day have I payed my vows.'),
  ('KJV', 'Proverbs', 20, 7, 15, 'Therefore came I forth to meet thee, diligently to seek thy face, and I have found thee.'),
  ('KJV', 'Proverbs', 20, 7, 16, 'I have decked my bed with coverings of tapestry, with carved works, with fine linen of Egypt.'),
  ('KJV', 'Proverbs', 20, 7, 17, 'I have perfumed my bed with myrrh, aloes, and cinnamon.'),
  ('KJV', 'Proverbs', 20, 7, 18, 'Come, let us take our fill of love until the morning: let us solace ourselves with loves.'),
  ('KJV', 'Proverbs', 20, 7, 19, 'For the goodman is not at home, he is gone a long journey:'),
  ('KJV', 'Proverbs', 20, 7, 20, 'He hath taken a bag of money with him, and will come home at the day appointed.'),
  ('KJV', 'Proverbs', 20, 7, 21, 'With her much fair speech she caused him to yield, with the flattering of her lips she forced him.'),
  ('KJV', 'Proverbs', 20, 7, 22, 'He goeth after her straightway, as an ox goeth to the slaughter, or as a fool to the correction of the stocks;'),
  ('KJV', 'Proverbs', 20, 7, 23, 'Till a dart strike through his liver; as a bird hasteth to the snare, and knoweth not that it is for his life.'),
  ('KJV', 'Proverbs', 20, 7, 24, 'Hearken unto me now therefore, O ye children, and attend to the words of my mouth.'),
  ('KJV', 'Proverbs', 20, 7, 25, 'Let not thine heart decline to her ways, go not astray in her paths.'),
  ('KJV', 'Proverbs', 20, 7, 26, 'For she hath cast down many wounded: yea, many strong men have been slain by her.'),
  ('KJV', 'Proverbs', 20, 7, 27, 'Her house is the way to hell, going down to the chambers of death.'),
  ('KJV', 'Proverbs', 20, 8, 1, 'Doth not wisdom cry? and understanding put forth her voice?'),
  ('KJV', 'Proverbs', 20, 8, 2, 'She standeth in the top of high places, by the way in the places of the paths.'),
  ('KJV', 'Proverbs', 20, 8, 3, 'She crieth at the gates, at the entry of the city, at the coming in at the doors.'),
  ('KJV', 'Proverbs', 20, 8, 4, 'Unto you, O men, I call; and my voice is to the sons of man.'),
  ('KJV', 'Proverbs', 20, 8, 5, 'O ye simple, understand wisdom: and, ye fools, be ye of an understanding heart.'),
  ('KJV', 'Proverbs', 20, 8, 6, 'Hear; for I will speak of excellent things; and the opening of my lips shall be right things.'),
  ('KJV', 'Proverbs', 20, 8, 7, 'For my mouth shall speak truth; and wickedness is an abomination to my lips.'),
  ('KJV', 'Proverbs', 20, 8, 8, 'All the words of my mouth are in righteousness; there is nothing froward or perverse in them.'),
  ('KJV', 'Proverbs', 20, 8, 9, 'They are all plain to him that understandeth, and right to them that find knowledge.'),
  ('KJV', 'Proverbs', 20, 8, 10, 'Receive my instruction, and not silver; and knowledge rather than choice gold.'),
  ('KJV', 'Proverbs', 20, 8, 11, 'For wisdom is better than rubies; and all the things that may be desired are not to be compared to it.'),
  ('KJV', 'Proverbs', 20, 8, 12, 'I wisdom dwell with prudence, and find out knowledge of witty inventions.'),
  ('KJV', 'Proverbs', 20, 8, 13, 'The fear of the LORD is to hate evil: pride, and arrogancy, and the evil way, and the froward mouth, do I hate.'),
  ('KJV', 'Proverbs', 20, 8, 14, 'Counsel is mine, and sound wisdom: I am understanding; I have strength.'),
  ('KJV', 'Proverbs', 20, 8, 15, 'By me kings reign, and princes decree justice.'),
  ('KJV', 'Proverbs', 20, 8, 16, 'By me princes rule, and nobles, even all the judges of the earth.'),
  ('KJV', 'Proverbs', 20, 8, 17, 'I love them that love me; and those that seek me early shall find me.'),
  ('KJV', 'Proverbs', 20, 8, 18, 'Riches and honour are with me; yea, durable riches and righteousness.'),
  ('KJV', 'Proverbs', 20, 8, 19, 'My fruit is better than gold, yea, than fine gold; and my revenue than choice silver.'),
  ('KJV', 'Proverbs', 20, 8, 20, 'I lead in the way of righteousness, in the midst of the paths of judgment:'),
  ('KJV', 'Proverbs', 20, 8, 21, 'That I may cause those that love me to inherit substance; and I will fill their treasures.'),
  ('KJV', 'Proverbs', 20, 8, 22, 'The LORD possessed me in the beginning of his way, before his works of old.'),
  ('KJV', 'Proverbs', 20, 8, 23, 'I was set up from everlasting, from the beginning, or ever the earth was.'),
  ('KJV', 'Proverbs', 20, 8, 24, 'When there were no depths, I was brought forth; when there were no fountains abounding with water.'),
  ('KJV', 'Proverbs', 20, 8, 25, 'Before the mountains were settled, before the hills was I brought forth:'),
  ('KJV', 'Proverbs', 20, 8, 26, 'While as yet he had not made the earth, nor the fields, nor the highest part of the dust of the world.'),
  ('KJV', 'Proverbs', 20, 8, 27, 'When he prepared the heavens, I was there: when he set a compass upon the face of the depth:'),
  ('KJV', 'Proverbs', 20, 8, 28, 'When he established the clouds above: when he strengthened the fountains of the deep:'),
  ('KJV', 'Proverbs', 20, 8, 29, 'When he gave to the sea his decree, that the waters should not pass his commandment: when he appointed the foundations of the earth:'),
  ('KJV', 'Proverbs', 20, 8, 30, 'Then I was by him, as one brought up with him: and I was daily his delight, rejoicing always before him;'),
  ('KJV', 'Proverbs', 20, 8, 31, 'Rejoicing in the habitable part of his earth; and my delights were with the sons of men.'),
  ('KJV', 'Proverbs', 20, 8, 32, 'Now therefore hearken unto me, O ye children: for blessed are they that keep my ways.'),
  ('KJV', 'Proverbs', 20, 8, 33, 'Hear instruction, and be wise, and refuse it not.'),
  ('KJV', 'Proverbs', 20, 8, 34, 'Blessed is the man that heareth me, watching daily at my gates, waiting at the posts of my doors.'),
  ('KJV', 'Proverbs', 20, 8, 35, 'For whoso findeth me findeth life, and shall obtain favour of the LORD.'),
  ('KJV', 'Proverbs', 20, 8, 36, 'But he that sinneth against me wrongeth his own soul: all they that hate me love death.'),
  ('KJV', 'Proverbs', 20, 9, 1, 'Wisdom hath builded her house, she hath hewn out her seven pillars:'),
  ('KJV', 'Proverbs', 20, 9, 2, 'She hath killed her beasts; she hath mingled her wine; she hath also furnished her table.'),
  ('KJV', 'Proverbs', 20, 9, 3, 'She hath sent forth her maidens: she crieth upon the highest places of the city,'),
  ('KJV', 'Proverbs', 20, 9, 4, 'Whoso is simple, let him turn in hither: as for him that wanteth understanding, she saith to him,'),
  ('KJV', 'Proverbs', 20, 9, 5, 'Come, eat of my bread, and drink of the wine which I have mingled.'),
  ('KJV', 'Proverbs', 20, 9, 6, 'Forsake the foolish, and live; and go in the way of understanding.'),
  ('KJV', 'Proverbs', 20, 9, 7, 'He that reproveth a scorner getteth to himself shame: and he that rebuketh a wicked man getteth himself a blot.'),
  ('KJV', 'Proverbs', 20, 9, 8, 'Reprove not a scorner, lest he hate thee: rebuke a wise man, and he will love thee.'),
  ('KJV', 'Proverbs', 20, 9, 9, 'Give instruction to a wise man, and he will be yet wiser: teach a just man, and he will increase in learning.'),
  ('KJV', 'Proverbs', 20, 9, 10, 'The fear of the LORD is the beginning of wisdom: and the knowledge of the holy is understanding.'),
  ('KJV', 'Proverbs', 20, 9, 11, 'For by me thy days shall be multiplied, and the years of thy life shall be increased.'),
  ('KJV', 'Proverbs', 20, 9, 12, 'If thou be wise, thou shalt be wise for thyself: but if thou scornest, thou alone shalt bear it.'),
  ('KJV', 'Proverbs', 20, 9, 13, 'A foolish woman is clamorous: she is simple, and knoweth nothing.'),
  ('KJV', 'Proverbs', 20, 9, 14, 'For she sitteth at the door of her house, on a seat in the high places of the city,'),
  ('KJV', 'Proverbs', 20, 9, 15, 'To call passengers who go right on their ways:'),
  ('KJV', 'Proverbs', 20, 9, 16, 'Whoso is simple, let him turn in hither: and as for him that wanteth understanding, she saith to him,'),
  ('KJV', 'Proverbs', 20, 9, 17, 'Stolen waters are sweet, and bread eaten in secret is pleasant.'),
  ('KJV', 'Proverbs', 20, 9, 18, 'But he knoweth not that the dead are there; and that her guests are in the depths of hell.'),
  ('KJV', 'Proverbs', 20, 10, 1, 'The proverbs of Solomon. A wise son maketh a glad father: but a foolish son is the heaviness of his mother.'),
  ('KJV', 'Proverbs', 20, 10, 2, 'Treasures of wickedness profit nothing: but righteousness delivereth from death.'),
  ('KJV', 'Proverbs', 20, 10, 3, 'The LORD will not suffer the soul of the righteous to famish: but he casteth away the substance of the wicked.'),
  ('KJV', 'Proverbs', 20, 10, 4, 'He becometh poor that dealeth with a slack hand: but the hand of the diligent maketh rich.'),
  ('KJV', 'Proverbs', 20, 10, 5, 'He that gathereth in summer is a wise son: but he that sleepeth in harvest is a son that causeth shame.'),
  ('KJV', 'Proverbs', 20, 10, 6, 'Blessings are upon the head of the just: but violence covereth the mouth of the wicked.'),
  ('KJV', 'Proverbs', 20, 10, 7, 'The memory of the just is blessed: but the name of the wicked shall rot.'),
  ('KJV', 'Proverbs', 20, 10, 8, 'The wise in heart will receive commandments: but a prating fool shall fall.'),
  ('KJV', 'Proverbs', 20, 10, 9, 'He that walketh uprightly walketh surely: but he that perverteth his ways shall be known.'),
  ('KJV', 'Proverbs', 20, 10, 10, 'He that winketh with the eye causeth sorrow: but a prating fool shall fall.'),
  ('KJV', 'Proverbs', 20, 10, 11, 'The mouth of a righteous man is a well of life: but violence covereth the mouth of the wicked.'),
  ('KJV', 'Proverbs', 20, 10, 12, 'Hatred stirreth up strifes: but love covereth all sins.'),
  ('KJV', 'Proverbs', 20, 10, 13, 'In the lips of him that hath understanding wisdom is found: but a rod is for the back of him that is void of understanding.'),
  ('KJV', 'Proverbs', 20, 10, 14, 'Wise men lay up knowledge: but the mouth of the foolish is near destruction.'),
  ('KJV', 'Proverbs', 20, 10, 15, 'The rich man''s wealth is his strong city: the destruction of the poor is their poverty.'),
  ('KJV', 'Proverbs', 20, 10, 16, 'The labour of the righteous tendeth to life: the fruit of the wicked to sin.'),
  ('KJV', 'Proverbs', 20, 10, 17, 'He is in the way of life that keepeth instruction: but he that refuseth reproof erreth.'),
  ('KJV', 'Proverbs', 20, 10, 18, 'He that hideth hatred with lying lips, and he that uttereth a slander, is a fool.'),
  ('KJV', 'Proverbs', 20, 10, 19, 'In the multitude of words there wanteth not sin: but he that refraineth his lips is wise.'),
  ('KJV', 'Proverbs', 20, 10, 20, 'The tongue of the just is as choice silver: the heart of the wicked is little worth.'),
  ('KJV', 'Proverbs', 20, 10, 21, 'The lips of the righteous feed many: but fools die for want of wisdom.'),
  ('KJV', 'Proverbs', 20, 10, 22, 'The blessing of the LORD, it maketh rich, and he addeth no sorrow with it.'),
  ('KJV', 'Proverbs', 20, 10, 23, 'It is as sport to a fool to do mischief: but a man of understanding hath wisdom.'),
  ('KJV', 'Proverbs', 20, 10, 24, 'The fear of the wicked, it shall come upon him: but the desire of the righteous shall be granted.'),
  ('KJV', 'Proverbs', 20, 10, 25, 'As the whirlwind passeth, so is the wicked no more: but the righteous is an everlasting foundation.'),
  ('KJV', 'Proverbs', 20, 10, 26, 'As vinegar to the teeth, and as smoke to the eyes, so is the sluggard to them that send him.'),
  ('KJV', 'Proverbs', 20, 10, 27, 'The fear of the LORD prolongeth days: but the years of the wicked shall be shortened.'),
  ('KJV', 'Proverbs', 20, 10, 28, 'The hope of the righteous shall be gladness: but the expectation of the wicked shall perish.'),
  ('KJV', 'Proverbs', 20, 10, 29, 'The way of the LORD is strength to the upright: but destruction shall be to the workers of iniquity.'),
  ('KJV', 'Proverbs', 20, 10, 30, 'The righteous shall never be removed: but the wicked shall not inhabit the earth.'),
  ('KJV', 'Proverbs', 20, 10, 31, 'The mouth of the just bringeth forth wisdom: but the froward tongue shall be cut out.'),
  ('KJV', 'Proverbs', 20, 10, 32, 'The lips of the righteous know what is acceptable: but the mouth of the wicked speaketh frowardness.'),
  ('KJV', 'Proverbs', 20, 11, 1, 'A false balance is abomination to the LORD: but a just weight is his delight.'),
  ('KJV', 'Proverbs', 20, 11, 2, 'When pride cometh, then cometh shame: but with the lowly is wisdom.'),
  ('KJV', 'Proverbs', 20, 11, 3, 'The integrity of the upright shall guide them: but the perverseness of transgressors shall destroy them.'),
  ('KJV', 'Proverbs', 20, 11, 4, 'Riches profit not in the day of wrath: but righteousness delivereth from death.'),
  ('KJV', 'Proverbs', 20, 11, 5, 'The righteousness of the perfect shall direct his way: but the wicked shall fall by his own wickedness.'),
  ('KJV', 'Proverbs', 20, 11, 6, 'The righteousness of the upright shall deliver them: but transgressors shall be taken in their own naughtiness.'),
  ('KJV', 'Proverbs', 20, 11, 7, 'When a wicked man dieth, his expectation shall perish: and the hope of unjust men perisheth.'),
  ('KJV', 'Proverbs', 20, 11, 8, 'The righteous is delivered out of trouble, and the wicked cometh in his stead.'),
  ('KJV', 'Proverbs', 20, 11, 9, 'An hypocrite with his mouth destroyeth his neighbour: but through knowledge shall the just be delivered.'),
  ('KJV', 'Proverbs', 20, 11, 10, 'When it goeth well with the righteous, the city rejoiceth: and when the wicked perish, there is shouting.'),
  ('KJV', 'Proverbs', 20, 11, 11, 'By the blessing of the upright the city is exalted: but it is overthrown by the mouth of the wicked.'),
  ('KJV', 'Proverbs', 20, 11, 12, 'He that is void of wisdom despiseth his neighbour: but a man of understanding holdeth his peace.'),
  ('KJV', 'Proverbs', 20, 11, 13, 'A talebearer revealeth secrets: but he that is of a faithful spirit concealeth the matter.'),
  ('KJV', 'Proverbs', 20, 11, 14, 'Where no counsel is, the people fall: but in the multitude of counsellors there is safety.'),
  ('KJV', 'Proverbs', 20, 11, 15, 'He that is surety for a stranger shall smart for it: and he that hateth suretiship is sure.'),
  ('KJV', 'Proverbs', 20, 11, 16, 'A gracious woman retaineth honour: and strong men retain riches.'),
  ('KJV', 'Proverbs', 20, 11, 17, 'The merciful man doeth good to his own soul: but he that is cruel troubleth his own flesh.'),
  ('KJV', 'Proverbs', 20, 11, 18, 'The wicked worketh a deceitful work: but to him that soweth righteousness shall be a sure reward.'),
  ('KJV', 'Proverbs', 20, 11, 19, 'As righteousness tendeth to life: so he that pursueth evil pursueth it to his own death.'),
  ('KJV', 'Proverbs', 20, 11, 20, 'They that are of a froward heart are abomination to the LORD: but such as are upright in their way are his delight.'),
  ('KJV', 'Proverbs', 20, 11, 21, 'Though hand join in hand, the wicked shall not be unpunished: but the seed of the righteous shall be delivered.'),
  ('KJV', 'Proverbs', 20, 11, 22, 'As a jewel of gold in a swine''s snout, so is a fair woman which is without discretion.'),
  ('KJV', 'Proverbs', 20, 11, 23, 'The desire of the righteous is only good: but the expectation of the wicked is wrath.'),
  ('KJV', 'Proverbs', 20, 11, 24, 'There is that scattereth, and yet increaseth; and there is that withholdeth more than is meet, but it tendeth to poverty.'),
  ('KJV', 'Proverbs', 20, 11, 25, 'The liberal soul shall be made fat: and he that watereth shall be watered also himself.'),
  ('KJV', 'Proverbs', 20, 11, 26, 'He that withholdeth corn, the people shall curse him: but blessing shall be upon the head of him that selleth it.'),
  ('KJV', 'Proverbs', 20, 11, 27, 'He that diligently seeketh good procureth favour: but he that seeketh mischief, it shall come unto him.'),
  ('KJV', 'Proverbs', 20, 11, 28, 'He that trusteth in his riches shall fall: but the righteous shall flourish as a branch.'),
  ('KJV', 'Proverbs', 20, 11, 29, 'He that troubleth his own house shall inherit the wind: and the fool shall be servant to the wise of heart.'),
  ('KJV', 'Proverbs', 20, 11, 30, 'The fruit of the righteous is a tree of life; and he that winneth souls is wise.'),
  ('KJV', 'Proverbs', 20, 11, 31, 'Behold, the righteous shall be recompensed in the earth: much more the wicked and the sinner.'),
  ('KJV', 'Proverbs', 20, 12, 1, 'Whoso loveth instruction loveth knowledge: but he that hateth reproof is brutish.'),
  ('KJV', 'Proverbs', 20, 12, 2, 'A good man obtaineth favour of the LORD: but a man of wicked devices will he condemn.'),
  ('KJV', 'Proverbs', 20, 12, 3, 'A man shall not be established by wickedness: but the root of the righteous shall not be moved.'),
  ('KJV', 'Proverbs', 20, 12, 4, 'A virtuous woman is a crown to her husband: but she that maketh ashamed is as rottenness in his bones.'),
  ('KJV', 'Proverbs', 20, 12, 5, 'The thoughts of the righteous are right: but the counsels of the wicked are deceit.'),
  ('KJV', 'Proverbs', 20, 12, 6, 'The words of the wicked are to lie in wait for blood: but the mouth of the upright shall deliver them.'),
  ('KJV', 'Proverbs', 20, 12, 7, 'The wicked are overthrown, and are not: but the house of the righteous shall stand.'),
  ('KJV', 'Proverbs', 20, 12, 8, 'A man shall be commended according to his wisdom: but he that is of a perverse heart shall be despised.'),
  ('KJV', 'Proverbs', 20, 12, 9, 'He that is despised, and hath a servant, is better than he that honoureth himself, and lacketh bread.'),
  ('KJV', 'Proverbs', 20, 12, 10, 'A righteous man regardeth the life of his beast: but the tender mercies of the wicked are cruel.'),
  ('KJV', 'Proverbs', 20, 12, 11, 'He that tilleth his land shall be satisfied with bread: but he that followeth vain persons is void of understanding.'),
  ('KJV', 'Proverbs', 20, 12, 12, 'The wicked desireth the net of evil men: but the root of the righteous yieldeth fruit.'),
  ('KJV', 'Proverbs', 20, 12, 13, 'The wicked is snared by the transgression of his lips: but the just shall come out of trouble.'),
  ('KJV', 'Proverbs', 20, 12, 14, 'A man shall be satisfied with good by the fruit of his mouth: and the recompence of a man''s hands shall be rendered unto him.'),
  ('KJV', 'Proverbs', 20, 12, 15, 'The way of a fool is right in his own eyes: but he that hearkeneth unto counsel is wise.'),
  ('KJV', 'Proverbs', 20, 12, 16, 'A fool''s wrath is presently known: but a prudent man covereth shame.'),
  ('KJV', 'Proverbs', 20, 12, 17, 'He that speaketh truth sheweth forth righteousness: but a false witness deceit.'),
  ('KJV', 'Proverbs', 20, 12, 18, 'There is that speaketh like the piercings of a sword: but the tongue of the wise is health.'),
  ('KJV', 'Proverbs', 20, 12, 19, 'The lip of truth shall be established for ever: but a lying tongue is but for a moment.'),
  ('KJV', 'Proverbs', 20, 12, 20, 'Deceit is in the heart of them that imagine evil: but to the counsellors of peace is joy.'),
  ('KJV', 'Proverbs', 20, 12, 21, 'There shall no evil happen to the just: but the wicked shall be filled with mischief.'),
  ('KJV', 'Proverbs', 20, 12, 22, 'Lying lips are abomination to the LORD: but they that deal truly are his delight.'),
  ('KJV', 'Proverbs', 20, 12, 23, 'A prudent man concealeth knowledge: but the heart of fools proclaimeth foolishness.'),
  ('KJV', 'Proverbs', 20, 12, 24, 'The hand of the diligent shall bear rule: but the slothful shall be under tribute.'),
  ('KJV', 'Proverbs', 20, 12, 25, 'Heaviness in the heart of man maketh it stoop: but a good word maketh it glad.'),
  ('KJV', 'Proverbs', 20, 12, 26, 'The righteous is more excellent than his neighbour: but the way of the wicked seduceth them.'),
  ('KJV', 'Proverbs', 20, 12, 27, 'The slothful man roasteth not that which he took in hunting: but the substance of a diligent man is precious.'),
  ('KJV', 'Proverbs', 20, 12, 28, 'In the way of righteousness is life; and in the pathway thereof there is no death.'),
  ('KJV', 'Proverbs', 20, 13, 1, 'A wise son heareth his father''s instruction: but a scorner heareth not rebuke.'),
  ('KJV', 'Proverbs', 20, 13, 2, 'A man shall eat good by the fruit of his mouth: but the soul of the transgressors shall eat violence.'),
  ('KJV', 'Proverbs', 20, 13, 3, 'He that keepeth his mouth keepeth his life: but he that openeth wide his lips shall have destruction.'),
  ('KJV', 'Proverbs', 20, 13, 4, 'The soul of the sluggard desireth, and hath nothing: but the soul of the diligent shall be made fat.'),
  ('KJV', 'Proverbs', 20, 13, 5, 'A righteous man hateth lying: but a wicked man is loathsome, and cometh to shame.'),
  ('KJV', 'Proverbs', 20, 13, 6, 'Righteousness keepeth him that is upright in the way: but wickedness overthroweth the sinner.'),
  ('KJV', 'Proverbs', 20, 13, 7, 'There is that maketh himself rich, yet hath nothing: there is that maketh himself poor, yet hath great riches.'),
  ('KJV', 'Proverbs', 20, 13, 8, 'The ransom of a man''s life are his riches: but the poor heareth not rebuke.'),
  ('KJV', 'Proverbs', 20, 13, 9, 'The light of the righteous rejoiceth: but the lamp of the wicked shall be put out.'),
  ('KJV', 'Proverbs', 20, 13, 10, 'Only by pride cometh contention: but with the well advised is wisdom.'),
  ('KJV', 'Proverbs', 20, 13, 11, 'Wealth gotten by vanity shall be diminished: but he that gathereth by labour shall increase.'),
  ('KJV', 'Proverbs', 20, 13, 12, 'Hope deferred maketh the heart sick: but when the desire cometh, it is a tree of life.'),
  ('KJV', 'Proverbs', 20, 13, 13, 'Whoso despiseth the word shall be destroyed: but he that feareth the commandment shall be rewarded.'),
  ('KJV', 'Proverbs', 20, 13, 14, 'The law of the wise is a fountain of life, to depart from the snares of death.'),
  ('KJV', 'Proverbs', 20, 13, 15, 'Good understanding giveth favour: but the way of transgressors is hard.'),
  ('KJV', 'Proverbs', 20, 13, 16, 'Every prudent man dealeth with knowledge: but a fool layeth open his folly.'),
  ('KJV', 'Proverbs', 20, 13, 17, 'A wicked messenger falleth into mischief: but a faithful ambassador is health.'),
  ('KJV', 'Proverbs', 20, 13, 18, 'Poverty and shame shall be to him that refuseth instruction: but he that regardeth reproof shall be honoured.'),
  ('KJV', 'Proverbs', 20, 13, 19, 'The desire accomplished is sweet to the soul: but it is abomination to fools to depart from evil.'),
  ('KJV', 'Proverbs', 20, 13, 20, 'He that walketh with wise men shall be wise: but a companion of fools shall be destroyed.'),
  ('KJV', 'Proverbs', 20, 13, 21, 'Evil pursueth sinners: but to the righteous good shall be repayed.'),
  ('KJV', 'Proverbs', 20, 13, 22, 'A good man leaveth an inheritance to his children''s children: and the wealth of the sinner is laid up for the just.'),
  ('KJV', 'Proverbs', 20, 13, 23, 'Much food is in the tillage of the poor: but there is that is destroyed for want of judgment.'),
  ('KJV', 'Proverbs', 20, 13, 24, 'He that spareth his rod hateth his son: but he that loveth him chasteneth him betimes.'),
  ('KJV', 'Proverbs', 20, 13, 25, 'The righteous eateth to the satisfying of his soul: but the belly of the wicked shall want.'),
  ('KJV', 'Proverbs', 20, 14, 1, 'Every wise woman buildeth her house: but the foolish plucketh it down with her hands.'),
  ('KJV', 'Proverbs', 20, 14, 2, 'He that walketh in his uprightness feareth the LORD: but he that is perverse in his ways despiseth him.'),
  ('KJV', 'Proverbs', 20, 14, 3, 'In the mouth of the foolish is a rod of pride: but the lips of the wise shall preserve them.'),
  ('KJV', 'Proverbs', 20, 14, 4, 'Where no oxen are, the crib is clean: but much increase is by the strength of the ox.'),
  ('KJV', 'Proverbs', 20, 14, 5, 'A faithful witness will not lie: but a false witness will utter lies.'),
  ('KJV', 'Proverbs', 20, 14, 6, 'A scorner seeketh wisdom, and findeth it not: but knowledge is easy unto him that understandeth.'),
  ('KJV', 'Proverbs', 20, 14, 7, 'Go from the presence of a foolish man, when thou perceivest not in him the lips of knowledge.'),
  ('KJV', 'Proverbs', 20, 14, 8, 'The wisdom of the prudent is to understand his way: but the folly of fools is deceit.'),
  ('KJV', 'Proverbs', 20, 14, 9, 'Fools make a mock at sin: but among the righteous there is favour.'),
  ('KJV', 'Proverbs', 20, 14, 10, 'The heart knoweth his own bitterness; and a stranger doth not intermeddle with his joy.'),
  ('KJV', 'Proverbs', 20, 14, 11, 'The house of the wicked shall be overthrown: but the tabernacle of the upright shall flourish.'),
  ('KJV', 'Proverbs', 20, 14, 12, 'There is a way which seemeth right unto a man, but the end thereof are the ways of death.'),
  ('KJV', 'Proverbs', 20, 14, 13, 'Even in laughter the heart is sorrowful; and the end of that mirth is heaviness.'),
  ('KJV', 'Proverbs', 20, 14, 14, 'The backslider in heart shall be filled with his own ways: and a good man shall be satisfied from himself.'),
  ('KJV', 'Proverbs', 20, 14, 15, 'The simple believeth every word: but the prudent man looketh well to his going.'),
  ('KJV', 'Proverbs', 20, 14, 16, 'A wise man feareth, and departeth from evil: but the fool rageth, and is confident.'),
  ('KJV', 'Proverbs', 20, 14, 17, 'He that is soon angry dealeth foolishly: and a man of wicked devices is hated.'),
  ('KJV', 'Proverbs', 20, 14, 18, 'The simple inherit folly: but the prudent are crowned with knowledge.'),
  ('KJV', 'Proverbs', 20, 14, 19, 'The evil bow before the good; and the wicked at the gates of the righteous.'),
  ('KJV', 'Proverbs', 20, 14, 20, 'The poor is hated even of his own neighbour: but the rich hath many friends.'),
  ('KJV', 'Proverbs', 20, 14, 21, 'He that despiseth his neighbour sinneth: but he that hath mercy on the poor, happy is he.'),
  ('KJV', 'Proverbs', 20, 14, 22, 'Do they not err that devise evil? but mercy and truth shall be to them that devise good.'),
  ('KJV', 'Proverbs', 20, 14, 23, 'In all labour there is profit: but the talk of the lips tendeth only to penury.'),
  ('KJV', 'Proverbs', 20, 14, 24, 'The crown of the wise is their riches: but the foolishness of fools is folly.'),
  ('KJV', 'Proverbs', 20, 14, 25, 'A true witness delivereth souls: but a deceitful witness speaketh lies.'),
  ('KJV', 'Proverbs', 20, 14, 26, 'In the fear of the LORD is strong confidence: and his children shall have a place of refuge.'),
  ('KJV', 'Proverbs', 20, 14, 27, 'The fear of the LORD is a fountain of life, to depart from the snares of death.'),
  ('KJV', 'Proverbs', 20, 14, 28, 'In the multitude of people is the king''s honour: but in the want of people is the destruction of the prince.'),
  ('KJV', 'Proverbs', 20, 14, 29, 'He that is slow to wrath is of great understanding: but he that is hasty of spirit exalteth folly.'),
  ('KJV', 'Proverbs', 20, 14, 30, 'A sound heart is the life of the flesh: but envy the rottenness of the bones.'),
  ('KJV', 'Proverbs', 20, 14, 31, 'He that oppresseth the poor reproacheth his Maker: but he that honoureth him hath mercy on the poor.'),
  ('KJV', 'Proverbs', 20, 14, 32, 'The wicked is driven away in his wickedness: but the righteous hath hope in his death.'),
  ('KJV', 'Proverbs', 20, 14, 33, 'Wisdom resteth in the heart of him that hath understanding: but that which is in the midst of fools is made known.'),
  ('KJV', 'Proverbs', 20, 14, 34, 'Righteousness exalteth a nation: but sin is a reproach to any people.'),
  ('KJV', 'Proverbs', 20, 14, 35, 'The king''s favour is toward a wise servant: but his wrath is against him that causeth shame.'),
  ('KJV', 'Proverbs', 20, 15, 1, 'A soft answer turneth away wrath: but grievous words stir up anger.'),
  ('KJV', 'Proverbs', 20, 15, 2, 'The tongue of the wise useth knowledge aright: but the mouth of fools poureth out foolishness.'),
  ('KJV', 'Proverbs', 20, 15, 3, 'The eyes of the LORD are in every place, beholding the evil and the good.'),
  ('KJV', 'Proverbs', 20, 15, 4, 'A wholesome tongue is a tree of life: but perverseness therein is a breach in the spirit.'),
  ('KJV', 'Proverbs', 20, 15, 5, 'A fool despiseth his father''s instruction: but he that regardeth reproof is prudent.'),
  ('KJV', 'Proverbs', 20, 15, 6, 'In the house of the righteous is much treasure: but in the revenues of the wicked is trouble.'),
  ('KJV', 'Proverbs', 20, 15, 7, 'The lips of the wise disperse knowledge: but the heart of the foolish doeth not so.'),
  ('KJV', 'Proverbs', 20, 15, 8, 'The sacrifice of the wicked is an abomination to the LORD: but the prayer of the upright is his delight.'),
  ('KJV', 'Proverbs', 20, 15, 9, 'The way of the wicked is an abomination unto the LORD: but he loveth him that followeth after righteousness.'),
  ('KJV', 'Proverbs', 20, 15, 10, 'Correction is grievous unto him that forsaketh the way: and he that hateth reproof shall die.'),
  ('KJV', 'Proverbs', 20, 15, 11, 'Hell and destruction are before the LORD: how much more then the hearts of the children of men?'),
  ('KJV', 'Proverbs', 20, 15, 12, 'A scorner loveth not one that reproveth him: neither will he go unto the wise.'),
  ('KJV', 'Proverbs', 20, 15, 13, 'A merry heart maketh a cheerful countenance: but by sorrow of the heart the spirit is broken.'),
  ('KJV', 'Proverbs', 20, 15, 14, 'The heart of him that hath understanding seeketh knowledge: but the mouth of fools feedeth on foolishness.'),
  ('KJV', 'Proverbs', 20, 15, 15, 'All the days of the afflicted are evil: but he that is of a merry heart hath a continual feast.'),
  ('KJV', 'Proverbs', 20, 15, 16, 'Better is little with the fear of the LORD than great treasure and trouble therewith.'),
  ('KJV', 'Proverbs', 20, 15, 17, 'Better is a dinner of herbs where love is, than a stalled ox and hatred therewith.'),
  ('KJV', 'Proverbs', 20, 15, 18, 'A wrathful man stirreth up strife: but he that is slow to anger appeaseth strife.'),
  ('KJV', 'Proverbs', 20, 15, 19, 'The way of the slothful man is as an hedge of thorns: but the way of the righteous is made plain.'),
  ('KJV', 'Proverbs', 20, 15, 20, 'A wise son maketh a glad father: but a foolish man despiseth his mother.'),
  ('KJV', 'Proverbs', 20, 15, 21, 'Folly is joy to him that is destitute of wisdom: but a man of understanding walketh uprightly.'),
  ('KJV', 'Proverbs', 20, 15, 22, 'Without counsel purposes are disappointed: but in the multitude of counsellors they are established.'),
  ('KJV', 'Proverbs', 20, 15, 23, 'A man hath joy by the answer of his mouth: and a word spoken in due season, how good is it!'),
  ('KJV', 'Proverbs', 20, 15, 24, 'The way of life is above to the wise, that he may depart from hell beneath.'),
  ('KJV', 'Proverbs', 20, 15, 25, 'The LORD will destroy the house of the proud: but he will establish the border of the widow.'),
  ('KJV', 'Proverbs', 20, 15, 26, 'The thoughts of the wicked are an abomination to the LORD: but the words of the pure are pleasant words.'),
  ('KJV', 'Proverbs', 20, 15, 27, 'He that is greedy of gain troubleth his own house; but he that hateth gifts shall live.'),
  ('KJV', 'Proverbs', 20, 15, 28, 'The heart of the righteous studieth to answer: but the mouth of the wicked poureth out evil things.'),
  ('KJV', 'Proverbs', 20, 15, 29, 'The LORD is far from the wicked: but he heareth the prayer of the righteous.'),
  ('KJV', 'Proverbs', 20, 15, 30, 'The light of the eyes rejoiceth the heart: and a good report maketh the bones fat.'),
  ('KJV', 'Proverbs', 20, 15, 31, 'The ear that heareth the reproof of life abideth among the wise.'),
  ('KJV', 'Proverbs', 20, 15, 32, 'He that refuseth instruction despiseth his own soul: but he that heareth reproof getteth understanding.'),
  ('KJV', 'Proverbs', 20, 15, 33, 'The fear of the LORD is the instruction of wisdom; and before honour is humility.'),
  ('KJV', 'Proverbs', 20, 16, 1, 'The preparations of the heart in man, and the answer of the tongue, is from the LORD.'),
  ('KJV', 'Proverbs', 20, 16, 2, 'All the ways of a man are clean in his own eyes; but the LORD weigheth the spirits.'),
  ('KJV', 'Proverbs', 20, 16, 3, 'Commit thy works unto the LORD, and thy thoughts shall be established.'),
  ('KJV', 'Proverbs', 20, 16, 4, 'The LORD hath made all things for himself: yea, even the wicked for the day of evil.'),
  ('KJV', 'Proverbs', 20, 16, 5, 'Every one that is proud in heart is an abomination to the LORD: though hand join in hand, he shall not be unpunished.'),
  ('KJV', 'Proverbs', 20, 16, 6, 'By mercy and truth iniquity is purged: and by the fear of the LORD men depart from evil.'),
  ('KJV', 'Proverbs', 20, 16, 7, 'When a man''s ways please the LORD, he maketh even his enemies to be at peace with him.'),
  ('KJV', 'Proverbs', 20, 16, 8, 'Better is a little with righteousness than great revenues without right.'),
  ('KJV', 'Proverbs', 20, 16, 9, 'A man''s heart deviseth his way: but the LORD directeth his steps.'),
  ('KJV', 'Proverbs', 20, 16, 10, 'A divine sentence is in the lips of the king: his mouth transgresseth not in judgment.'),
  ('KJV', 'Proverbs', 20, 16, 11, 'A just weight and balance are the LORD''S: all the weights of the bag are his work.'),
  ('KJV', 'Proverbs', 20, 16, 12, 'It is an abomination to kings to commit wickedness: for the throne is established by righteousness.'),
  ('KJV', 'Proverbs', 20, 16, 13, 'Righteous lips are the delight of kings; and they love him that speaketh right.'),
  ('KJV', 'Proverbs', 20, 16, 14, 'The wrath of a king is as messengers of death: but a wise man will pacify it.'),
  ('KJV', 'Proverbs', 20, 16, 15, 'In the light of the king''s countenance is life; and his favour is as a cloud of the latter rain.'),
  ('KJV', 'Proverbs', 20, 16, 16, 'How much better is it to get wisdom than gold! and to get understanding rather to be chosen than silver!'),
  ('KJV', 'Proverbs', 20, 16, 17, 'The highway of the upright is to depart from evil: he that keepeth his way preserveth his soul.'),
  ('KJV', 'Proverbs', 20, 16, 18, 'Pride goeth before destruction, and an haughty spirit before a fall.'),
  ('KJV', 'Proverbs', 20, 16, 19, 'Better it is to be of an humble spirit with the lowly, than to divide the spoil with the proud.'),
  ('KJV', 'Proverbs', 20, 16, 20, 'He that handleth a matter wisely shall find good: and whoso trusteth in the LORD, happy is he.'),
  ('KJV', 'Proverbs', 20, 16, 21, 'The wise in heart shall be called prudent: and the sweetness of the lips increaseth learning.'),
  ('KJV', 'Proverbs', 20, 16, 22, 'Understanding is a wellspring of life unto him that hath it: but the instruction of fools is folly.'),
  ('KJV', 'Proverbs', 20, 16, 23, 'The heart of the wise teacheth his mouth, and addeth learning to his lips.'),
  ('KJV', 'Proverbs', 20, 16, 24, 'Pleasant words are as an honeycomb, sweet to the soul, and health to the bones.'),
  ('KJV', 'Proverbs', 20, 16, 25, 'There is a way that seemeth right unto a man, but the end thereof are the ways of death.'),
  ('KJV', 'Proverbs', 20, 16, 26, 'He that laboureth laboureth for himself; for his mouth craveth it of him.'),
  ('KJV', 'Proverbs', 20, 16, 27, 'An ungodly man diggeth up evil: and in his lips there is as a burning fire.'),
  ('KJV', 'Proverbs', 20, 16, 28, 'A froward man soweth strife: and a whisperer separateth chief friends.'),
  ('KJV', 'Proverbs', 20, 16, 29, 'A violent man enticeth his neighbour, and leadeth him into the way that is not good.'),
  ('KJV', 'Proverbs', 20, 16, 30, 'He shutteth his eyes to devise froward things: moving his lips he bringeth evil to pass.'),
  ('KJV', 'Proverbs', 20, 16, 31, 'The hoary head is a crown of glory, if it be found in the way of righteousness.'),
  ('KJV', 'Proverbs', 20, 16, 32, 'He that is slow to anger is better than the mighty; and he that ruleth his spirit than he that taketh a city.'),
  ('KJV', 'Proverbs', 20, 16, 33, 'The lot is cast into the lap; but the whole disposing thereof is of the LORD.'),
  ('KJV', 'Proverbs', 20, 17, 1, 'Better is a dry morsel, and quietness therewith, than an house full of sacrifices with strife.'),
  ('KJV', 'Proverbs', 20, 17, 2, 'A wise servant shall have rule over a son that causeth shame, and shall have part of the inheritance among the brethren.'),
  ('KJV', 'Proverbs', 20, 17, 3, 'The fining pot is for silver, and the furnace for gold: but the LORD trieth the hearts.'),
  ('KJV', 'Proverbs', 20, 17, 4, 'A wicked doer giveth heed to false lips; and a liar giveth ear to a naughty tongue.'),
  ('KJV', 'Proverbs', 20, 17, 5, 'Whoso mocketh the poor reproacheth his Maker: and he that is glad at calamities shall not be unpunished.'),
  ('KJV', 'Proverbs', 20, 17, 6, 'Children''s children are the crown of old men; and the glory of children are their fathers.'),
  ('KJV', 'Proverbs', 20, 17, 7, 'Excellent speech becometh not a fool: much less do lying lips a prince.'),
  ('KJV', 'Proverbs', 20, 17, 8, 'A gift is as a precious stone in the eyes of him that hath it: whithersoever it turneth, it prospereth.'),
  ('KJV', 'Proverbs', 20, 17, 9, 'He that covereth a transgression seeketh love; but he that repeateth a matter separateth very friends.'),
  ('KJV', 'Proverbs', 20, 17, 10, 'A reproof entereth more into a wise man than an hundred stripes into a fool.'),
  ('KJV', 'Proverbs', 20, 17, 11, 'An evil man seeketh only rebellion: therefore a cruel messenger shall be sent against him.'),
  ('KJV', 'Proverbs', 20, 17, 12, 'Let a bear robbed of her whelps meet a man, rather than a fool in his folly.'),
  ('KJV', 'Proverbs', 20, 17, 13, 'Whoso rewardeth evil for good, evil shall not depart from his house.'),
  ('KJV', 'Proverbs', 20, 17, 14, 'The beginning of strife is as when one letteth out water: therefore leave off contention, before it be meddled with.'),
  ('KJV', 'Proverbs', 20, 17, 15, 'He that justifieth the wicked, and he that condemneth the just, even they both are abomination to the LORD.'),
  ('KJV', 'Proverbs', 20, 17, 16, 'Wherefore is there a price in the hand of a fool to get wisdom, seeing he hath no heart to it?'),
  ('KJV', 'Proverbs', 20, 17, 17, 'A friend loveth at all times, and a brother is born for adversity.'),
  ('KJV', 'Proverbs', 20, 17, 18, 'A man void of understanding striketh hands, and becometh surety in the presence of his friend.'),
  ('KJV', 'Proverbs', 20, 17, 19, 'He loveth transgression that loveth strife: and he that exalteth his gate seeketh destruction.'),
  ('KJV', 'Proverbs', 20, 17, 20, 'He that hath a froward heart findeth no good: and he that hath a perverse tongue falleth into mischief.'),
  ('KJV', 'Proverbs', 20, 17, 21, 'He that begetteth a fool doeth it to his sorrow: and the father of a fool hath no joy.'),
  ('KJV', 'Proverbs', 20, 17, 22, 'A merry heart doeth good like a medicine: but a broken spirit drieth the bones.'),
  ('KJV', 'Proverbs', 20, 17, 23, 'A wicked man taketh a gift out of the bosom to pervert the ways of judgment.'),
  ('KJV', 'Proverbs', 20, 17, 24, 'Wisdom is before him that hath understanding; but the eyes of a fool are in the ends of the earth.'),
  ('KJV', 'Proverbs', 20, 17, 25, 'A foolish son is a grief to his father, and bitterness to her that bare him.'),
  ('KJV', 'Proverbs', 20, 17, 26, 'Also to punish the just is not good, nor to strike princes for equity.'),
  ('KJV', 'Proverbs', 20, 17, 27, 'He that hath knowledge spareth his words: and a man of understanding is of an excellent spirit.'),
  ('KJV', 'Proverbs', 20, 17, 28, 'Even a fool, when he holdeth his peace, is counted wise: and he that shutteth his lips is esteemed a man of understanding.'),
  ('KJV', 'Proverbs', 20, 18, 1, 'Through desire a man, having separated himself, seeketh and intermeddleth with all wisdom.'),
  ('KJV', 'Proverbs', 20, 18, 2, 'A fool hath no delight in understanding, but that his heart may discover itself.'),
  ('KJV', 'Proverbs', 20, 18, 3, 'When the wicked cometh, then cometh also contempt, and with ignominy reproach.'),
  ('KJV', 'Proverbs', 20, 18, 4, 'The words of a man''s mouth are as deep waters, and the wellspring of wisdom as a flowing brook.'),
  ('KJV', 'Proverbs', 20, 18, 5, 'It is not good to accept the person of the wicked, to overthrow the righteous in judgment.'),
  ('KJV', 'Proverbs', 20, 18, 6, 'A fool''s lips enter into contention, and his mouth calleth for strokes.'),
  ('KJV', 'Proverbs', 20, 18, 7, 'A fool''s mouth is his destruction, and his lips are the snare of his soul.'),
  ('KJV', 'Proverbs', 20, 18, 8, 'The words of a talebearer are as wounds, and they go down into the innermost parts of the belly.'),
  ('KJV', 'Proverbs', 20, 18, 9, 'He also that is slothful in his work is brother to him that is a great waster.'),
  ('KJV', 'Proverbs', 20, 18, 10, 'The name of the LORD is a strong tower: the righteous runneth into it, and is safe.'),
  ('KJV', 'Proverbs', 20, 18, 11, 'The rich man''s wealth is his strong city, and as an high wall in his own conceit.'),
  ('KJV', 'Proverbs', 20, 18, 12, 'Before destruction the heart of man is haughty, and before honour is humility.'),
  ('KJV', 'Proverbs', 20, 18, 13, 'He that answereth a matter before he heareth it, it is folly and shame unto him.'),
  ('KJV', 'Proverbs', 20, 18, 14, 'The spirit of a man will sustain his infirmity; but a wounded spirit who can bear?'),
  ('KJV', 'Proverbs', 20, 18, 15, 'The heart of the prudent getteth knowledge; and the ear of the wise seeketh knowledge.'),
  ('KJV', 'Proverbs', 20, 18, 16, 'A man''s gift maketh room for him, and bringeth him before great men.'),
  ('KJV', 'Proverbs', 20, 18, 17, 'He that is first in his own cause seemeth just; but his neighbour cometh and searcheth him.'),
  ('KJV', 'Proverbs', 20, 18, 18, 'The lot causeth contentions to cease, and parteth between the mighty.'),
  ('KJV', 'Proverbs', 20, 18, 19, 'A brother offended is harder to be won than a strong city: and their contentions are like the bars of a castle.'),
  ('KJV', 'Proverbs', 20, 18, 20, 'A man''s belly shall be satisfied with the fruit of his mouth; and with the increase of his lips shall he be filled.'),
  ('KJV', 'Proverbs', 20, 18, 21, 'Death and life are in the power of the tongue: and they that love it shall eat the fruit thereof.'),
  ('KJV', 'Proverbs', 20, 18, 22, 'Whoso findeth a wife findeth a good thing, and obtaineth favour of the LORD.'),
  ('KJV', 'Proverbs', 20, 18, 23, 'The poor useth intreaties; but the rich answereth roughly.'),
  ('KJV', 'Proverbs', 20, 18, 24, 'A man that hath friends must shew himself friendly: and there is a friend that sticketh closer than a brother.'),
  ('KJV', 'Proverbs', 20, 19, 1, 'Better is the poor that walketh in his integrity, than he that is perverse in his lips, and is a fool.'),
  ('KJV', 'Proverbs', 20, 19, 2, 'Also, that the soul be without knowledge, it is not good; and he that hasteth with his feet sinneth.'),
  ('KJV', 'Proverbs', 20, 19, 3, 'The foolishness of man perverteth his way: and his heart fretteth against the LORD.'),
  ('KJV', 'Proverbs', 20, 19, 4, 'Wealth maketh many friends; but the poor is separated from his neighbour.'),
  ('KJV', 'Proverbs', 20, 19, 5, 'A false witness shall not be unpunished, and he that speaketh lies shall not escape.'),
  ('KJV', 'Proverbs', 20, 19, 6, 'Many will intreat the favour of the prince: and every man is a friend to him that giveth gifts.'),
  ('KJV', 'Proverbs', 20, 19, 7, 'All the brethren of the poor do hate him: how much more do his friends go far from him? he pursueth them with words, yet they are wanting to him.'),
  ('KJV', 'Proverbs', 20, 19, 8, 'He that getteth wisdom loveth his own soul: he that keepeth understanding shall find good.'),
  ('KJV', 'Proverbs', 20, 19, 9, 'A false witness shall not be unpunished, and he that speaketh lies shall perish.'),
  ('KJV', 'Proverbs', 20, 19, 10, 'Delight is not seemly for a fool; much less for a servant to have rule over princes.'),
  ('KJV', 'Proverbs', 20, 19, 11, 'The discretion of a man deferreth his anger; and it is his glory to pass over a transgression.'),
  ('KJV', 'Proverbs', 20, 19, 12, 'The king''s wrath is as the roaring of a lion; but his favour is as dew upon the grass.'),
  ('KJV', 'Proverbs', 20, 19, 13, 'A foolish son is the calamity of his father: and the contentions of a wife are a continual dropping.'),
  ('KJV', 'Proverbs', 20, 19, 14, 'House and riches are the inheritance of fathers: and a prudent wife is from the LORD.'),
  ('KJV', 'Proverbs', 20, 19, 15, 'Slothfulness casteth into a deep sleep; and an idle soul shall suffer hunger.'),
  ('KJV', 'Proverbs', 20, 19, 16, 'He that keepeth the commandment keepeth his own soul; but he that despiseth his ways shall die.'),
  ('KJV', 'Proverbs', 20, 19, 17, 'He that hath pity upon the poor lendeth unto the LORD; and that which he hath given will he pay him again.'),
  ('KJV', 'Proverbs', 20, 19, 18, 'Chasten thy son while there is hope, and let not thy soul spare for his crying.'),
  ('KJV', 'Proverbs', 20, 19, 19, 'A man of great wrath shall suffer punishment: for if thou deliver him, yet thou must do it again.'),
  ('KJV', 'Proverbs', 20, 19, 20, 'Hear counsel, and receive instruction, that thou mayest be wise in thy latter end.'),
  ('KJV', 'Proverbs', 20, 19, 21, 'There are many devices in a man''s heart; nevertheless the counsel of the LORD, that shall stand.'),
  ('KJV', 'Proverbs', 20, 19, 22, 'The desire of a man is his kindness: and a poor man is better than a liar.'),
  ('KJV', 'Proverbs', 20, 19, 23, 'The fear of the LORD tendeth to life: and he that hath it shall abide satisfied; he shall not be visited with evil.'),
  ('KJV', 'Proverbs', 20, 19, 24, 'A slothful man hideth his hand in his bosom, and will not so much as bring it to his mouth again.'),
  ('KJV', 'Proverbs', 20, 19, 25, 'Smite a scorner, and the simple will beware: and reprove one that hath understanding, and he will understand knowledge.'),
  ('KJV', 'Proverbs', 20, 19, 26, 'He that wasteth his father, and chaseth away his mother, is a son that causeth shame, and bringeth reproach.'),
  ('KJV', 'Proverbs', 20, 19, 27, 'Cease, my son, to hear the instruction that causeth to err from the words of knowledge.'),
  ('KJV', 'Proverbs', 20, 19, 28, 'An ungodly witness scorneth judgment: and the mouth of the wicked devoureth iniquity.'),
  ('KJV', 'Proverbs', 20, 19, 29, 'Judgments are prepared for scorners, and stripes for the back of fools.'),
  ('KJV', 'Proverbs', 20, 20, 1, 'Wine is a mocker, strong drink is raging: and whosoever is deceived thereby is not wise.'),
  ('KJV', 'Proverbs', 20, 20, 2, 'The fear of a king is as the roaring of a lion: whoso provoketh him to anger sinneth against his own soul.'),
  ('KJV', 'Proverbs', 20, 20, 3, 'It is an honour for a man to cease from strife: but every fool will be meddling.'),
  ('KJV', 'Proverbs', 20, 20, 4, 'The sluggard will not plow by reason of the cold; therefore shall he beg in harvest, and have nothing.'),
  ('KJV', 'Proverbs', 20, 20, 5, 'Counsel in the heart of man is like deep water; but a man of understanding will draw it out.'),
  ('KJV', 'Proverbs', 20, 20, 6, 'Most men will proclaim every one his own goodness: but a faithful man who can find?'),
  ('KJV', 'Proverbs', 20, 20, 7, 'The just man walketh in his integrity: his children are blessed after him.'),
  ('KJV', 'Proverbs', 20, 20, 8, 'A king that sitteth in the throne of judgment scattereth away all evil with his eyes.'),
  ('KJV', 'Proverbs', 20, 20, 9, 'Who can say, I have made my heart clean, I am pure from my sin?'),
  ('KJV', 'Proverbs', 20, 20, 10, 'Divers weights, and divers measures, both of them are alike abomination to the LORD.'),
  ('KJV', 'Proverbs', 20, 20, 11, 'Even a child is known by his doings, whether his work be pure, and whether it be right.'),
  ('KJV', 'Proverbs', 20, 20, 12, 'The hearing ear, and the seeing eye, the LORD hath made even both of them.'),
  ('KJV', 'Proverbs', 20, 20, 13, 'Love not sleep, lest thou come to poverty; open thine eyes, and thou shalt be satisfied with bread.'),
  ('KJV', 'Proverbs', 20, 20, 14, 'It is naught, it is naught, saith the buyer: but when he is gone his way, then he boasteth.'),
  ('KJV', 'Proverbs', 20, 20, 15, 'There is gold, and a multitude of rubies: but the lips of knowledge are a precious jewel.'),
  ('KJV', 'Proverbs', 20, 20, 16, 'Take his garment that is surety for a stranger: and take a pledge of him for a strange woman.'),
  ('KJV', 'Proverbs', 20, 20, 17, 'Bread of deceit is sweet to a man; but afterwards his mouth shall be filled with gravel.'),
  ('KJV', 'Proverbs', 20, 20, 18, 'Every purpose is established by counsel: and with good advice make war.'),
  ('KJV', 'Proverbs', 20, 20, 19, 'He that goeth about as a talebearer revealeth secrets: therefore meddle not with him that flattereth with his lips.'),
  ('KJV', 'Proverbs', 20, 20, 20, 'Whoso curseth his father or his mother, his lamp shall be put out in obscure darkness.'),
  ('KJV', 'Proverbs', 20, 20, 21, 'An inheritance may be gotten hastily at the beginning; but the end thereof shall not be blessed.'),
  ('KJV', 'Proverbs', 20, 20, 22, 'Say not thou, I will recompense evil; but wait on the LORD, and he shall save thee.'),
  ('KJV', 'Proverbs', 20, 20, 23, 'Divers weights are an abomination unto the LORD; and a false balance is not good.'),
  ('KJV', 'Proverbs', 20, 20, 24, 'Man''s goings are of the LORD; how can a man then understand his own way?'),
  ('KJV', 'Proverbs', 20, 20, 25, 'It is a snare to the man who devoureth that which is holy, and after vows to make enquiry.'),
  ('KJV', 'Proverbs', 20, 20, 26, 'A wise king scattereth the wicked, and bringeth the wheel over them.'),
  ('KJV', 'Proverbs', 20, 20, 27, 'The spirit of man is the candle of the LORD, searching all the inward parts of the belly.'),
  ('KJV', 'Proverbs', 20, 20, 28, 'Mercy and truth preserve the king: and his throne is upholden by mercy.'),
  ('KJV', 'Proverbs', 20, 20, 29, 'The glory of young men is their strength: and the beauty of old men is the gray head.'),
  ('KJV', 'Proverbs', 20, 20, 30, 'The blueness of a wound cleanseth away evil: so do stripes the inward parts of the belly.'),
  ('KJV', 'Proverbs', 20, 21, 1, 'The king''s heart is in the hand of the LORD, as the rivers of water: he turneth it whithersoever he will.'),
  ('KJV', 'Proverbs', 20, 21, 2, 'Every way of a man is right in his own eyes: but the LORD pondereth the hearts.'),
  ('KJV', 'Proverbs', 20, 21, 3, 'To do justice and judgment is more acceptable to the LORD than sacrifice.'),
  ('KJV', 'Proverbs', 20, 21, 4, 'An high look, and a proud heart, and the plowing of the wicked, is sin.'),
  ('KJV', 'Proverbs', 20, 21, 5, 'The thoughts of the diligent tend only to plenteousness; but of every one that is hasty only to want.'),
  ('KJV', 'Proverbs', 20, 21, 6, 'The getting of treasures by a lying tongue is a vanity tossed to and fro of them that seek death.'),
  ('KJV', 'Proverbs', 20, 21, 7, 'The robbery of the wicked shall destroy them; because they refuse to do judgment.'),
  ('KJV', 'Proverbs', 20, 21, 8, 'The way of man is froward and strange: but as for the pure, his work is right.'),
  ('KJV', 'Proverbs', 20, 21, 9, 'It is better to dwell in a corner of the housetop, than with a brawling woman in a wide house.'),
  ('KJV', 'Proverbs', 20, 21, 10, 'The soul of the wicked desireth evil: his neighbour findeth no favour in his eyes.'),
  ('KJV', 'Proverbs', 20, 21, 11, 'When the scorner is punished, the simple is made wise: and when the wise is instructed, he receiveth knowledge.'),
  ('KJV', 'Proverbs', 20, 21, 12, 'The righteous man wisely considereth the house of the wicked: but God overthroweth the wicked for their wickedness.'),
  ('KJV', 'Proverbs', 20, 21, 13, 'Whoso stoppeth his ears at the cry of the poor, he also shall cry himself, but shall not be heard.'),
  ('KJV', 'Proverbs', 20, 21, 14, 'A gift in secret pacifieth anger: and a reward in the bosom strong wrath.'),
  ('KJV', 'Proverbs', 20, 21, 15, 'It is joy to the just to do judgment: but destruction shall be to the workers of iniquity.')
insert into control_room_bible (version, book, book_num, chapter, verse, text) values
  ('KJV', 'Proverbs', 20, 21, 16, 'The man that wandereth out of the way of understanding shall remain in the congregation of the dead.'),
  ('KJV', 'Proverbs', 20, 21, 17, 'He that loveth pleasure shall be a poor man: he that loveth wine and oil shall not be rich.'),
  ('KJV', 'Proverbs', 20, 21, 18, 'The wicked shall be a ransom for the righteous, and the transgressor for the upright.'),
  ('KJV', 'Proverbs', 20, 21, 19, 'It is better to dwell in the wilderness, than with a contentious and an angry woman.'),
  ('KJV', 'Proverbs', 20, 21, 20, 'There is treasure to be desired and oil in the dwelling of the wise; but a foolish man spendeth it up.'),
  ('KJV', 'Proverbs', 20, 21, 21, 'He that followeth after righteousness and mercy findeth life, righteousness, and honour.'),
  ('KJV', 'Proverbs', 20, 21, 22, 'A wise man scaleth the city of the mighty, and casteth down the strength of the confidence thereof.'),
  ('KJV', 'Proverbs', 20, 21, 23, 'Whoso keepeth his mouth and his tongue keepeth his soul from troubles.'),
  ('KJV', 'Proverbs', 20, 21, 24, 'Proud and haughty scorner is his name, who dealeth in proud wrath.'),
  ('KJV', 'Proverbs', 20, 21, 25, 'The desire of the slothful killeth him; for his hands refuse to labour.'),
  ('KJV', 'Proverbs', 20, 21, 26, 'He coveteth greedily all the day long: but the righteous giveth and spareth not.'),
  ('KJV', 'Proverbs', 20, 21, 27, 'The sacrifice of the wicked is abomination: how much more, when he bringeth it with a wicked mind?'),
  ('KJV', 'Proverbs', 20, 21, 28, 'A false witness shall perish: but the man that heareth speaketh constantly.'),
  ('KJV', 'Proverbs', 20, 21, 29, 'A wicked man hardeneth his face: but as for the upright, he directeth his way.'),
  ('KJV', 'Proverbs', 20, 21, 30, 'There is no wisdom nor understanding nor counsel against the LORD.'),
  ('KJV', 'Proverbs', 20, 21, 31, 'The horse is prepared against the day of battle: but safety is of the LORD.'),
  ('KJV', 'Proverbs', 20, 22, 1, 'A good name is rather to be chosen than great riches, and loving favour rather than silver and gold.'),
  ('KJV', 'Proverbs', 20, 22, 2, 'The rich and poor meet together: the LORD is the maker of them all.'),
  ('KJV', 'Proverbs', 20, 22, 3, 'A prudent man foreseeth the evil, and hideth himself: but the simple pass on, and are punished.'),
  ('KJV', 'Proverbs', 20, 22, 4, 'By humility and the fear of the LORD are riches, and honour, and life.'),
  ('KJV', 'Proverbs', 20, 22, 5, 'Thorns and snares are in the way of the froward: he that doth keep his soul shall be far from them.'),
  ('KJV', 'Proverbs', 20, 22, 6, 'Train up a child in the way he should go: and when he is old, he will not depart from it.'),
  ('KJV', 'Proverbs', 20, 22, 7, 'The rich ruleth over the poor, and the borrower is servant to the lender.'),
  ('KJV', 'Proverbs', 20, 22, 8, 'He that soweth iniquity shall reap vanity: and the rod of his anger shall fail.'),
  ('KJV', 'Proverbs', 20, 22, 9, 'He that hath a bountiful eye shall be blessed; for he giveth of his bread to the poor.'),
  ('KJV', 'Proverbs', 20, 22, 10, 'Cast out the scorner, and contention shall go out; yea, strife and reproach shall cease.'),
  ('KJV', 'Proverbs', 20, 22, 11, 'He that loveth pureness of heart, for the grace of his lips the king shall be his friend.'),
  ('KJV', 'Proverbs', 20, 22, 12, 'The eyes of the LORD preserve knowledge, and he overthroweth the words of the transgressor.'),
  ('KJV', 'Proverbs', 20, 22, 13, 'The slothful man saith, There is a lion without, I shall be slain in the streets.'),
  ('KJV', 'Proverbs', 20, 22, 14, 'The mouth of strange women is a deep pit: he that is abhorred of the LORD shall fall therein.'),
  ('KJV', 'Proverbs', 20, 22, 15, 'Foolishness is bound in the heart of a child; but the rod of correction shall drive it far from him.'),
  ('KJV', 'Proverbs', 20, 22, 16, 'He that oppresseth the poor to increase his riches, and he that giveth to the rich, shall surely come to want.'),
  ('KJV', 'Proverbs', 20, 22, 17, 'Bow down thine ear, and hear the words of the wise, and apply thine heart unto my knowledge.'),
  ('KJV', 'Proverbs', 20, 22, 18, 'For it is a pleasant thing if thou keep them within thee; they shall withal be fitted in thy lips.'),
  ('KJV', 'Proverbs', 20, 22, 19, 'That thy trust may be in the LORD, I have made known to thee this day, even to thee.'),
  ('KJV', 'Proverbs', 20, 22, 20, 'Have not I written to thee excellent things in counsels and knowledge,'),
  ('KJV', 'Proverbs', 20, 22, 21, 'That I might make thee know the certainty of the words of truth; that thou mightest answer the words of truth to them that send unto thee?'),
  ('KJV', 'Proverbs', 20, 22, 22, 'Rob not the poor, because he is poor: neither oppress the afflicted in the gate:'),
  ('KJV', 'Proverbs', 20, 22, 23, 'For the LORD will plead their cause, and spoil the soul of those that spoiled them.'),
  ('KJV', 'Proverbs', 20, 22, 24, 'Make no friendship with an angry man; and with a furious man thou shalt not go:'),
  ('KJV', 'Proverbs', 20, 22, 25, 'Lest thou learn his ways, and get a snare to thy soul.'),
  ('KJV', 'Proverbs', 20, 22, 26, 'Be not thou one of them that strike hands, or of them that are sureties for debts.'),
  ('KJV', 'Proverbs', 20, 22, 27, 'If thou hast nothing to pay, why should he take away thy bed from under thee?'),
  ('KJV', 'Proverbs', 20, 22, 28, 'Remove not the ancient landmark, which thy fathers have set.'),
  ('KJV', 'Proverbs', 20, 22, 29, 'Seest thou a man diligent in his business? he shall stand before kings; he shall not stand before mean men.'),
  ('KJV', 'Proverbs', 20, 23, 1, 'When thou sittest to eat with a ruler, consider diligently what is before thee:'),
  ('KJV', 'Proverbs', 20, 23, 2, 'And put a knife to thy throat, if thou be a man given to appetite.'),
  ('KJV', 'Proverbs', 20, 23, 3, 'Be not desirous of his dainties: for they are deceitful meat.'),
  ('KJV', 'Proverbs', 20, 23, 4, 'Labour not to be rich: cease from thine own wisdom.'),
  ('KJV', 'Proverbs', 20, 23, 5, 'Wilt thou set thine eyes upon that which is not? for riches certainly make themselves wings; they fly away as an eagle toward heaven.'),
  ('KJV', 'Proverbs', 20, 23, 6, 'Eat thou not the bread of him that hath an evil eye, neither desire thou his dainty meats:'),
  ('KJV', 'Proverbs', 20, 23, 7, 'For as he thinketh in his heart, so is he: Eat and drink, saith he to thee; but his heart is not with thee.'),
  ('KJV', 'Proverbs', 20, 23, 8, 'The morsel which thou hast eaten shalt thou vomit up, and lose thy sweet words.'),
  ('KJV', 'Proverbs', 20, 23, 9, 'Speak not in the ears of a fool: for he will despise the wisdom of thy words.'),
  ('KJV', 'Proverbs', 20, 23, 10, 'Remove not the old landmark; and enter not into the fields of the fatherless:'),
  ('KJV', 'Proverbs', 20, 23, 11, 'For their redeemer is mighty; he shall plead their cause with thee.'),
  ('KJV', 'Proverbs', 20, 23, 12, 'Apply thine heart unto instruction, and thine ears to the words of knowledge.'),
  ('KJV', 'Proverbs', 20, 23, 13, 'Withhold not correction from the child: for if thou beatest him with the rod, he shall not die.'),
  ('KJV', 'Proverbs', 20, 23, 14, 'Thou shalt beat him with the rod, and shalt deliver his soul from hell.'),
  ('KJV', 'Proverbs', 20, 23, 15, 'My son, if thine heart be wise, my heart shall rejoice, even mine.'),
  ('KJV', 'Proverbs', 20, 23, 16, 'Yea, my reins shall rejoice, when thy lips speak right things.'),
  ('KJV', 'Proverbs', 20, 23, 17, 'Let not thine heart envy sinners: but be thou in the fear of the LORD all the day long.'),
  ('KJV', 'Proverbs', 20, 23, 18, 'For surely there is an end; and thine expectation shall not be cut off.'),
  ('KJV', 'Proverbs', 20, 23, 19, 'Hear thou, my son, and be wise, and guide thine heart in the way.'),
  ('KJV', 'Proverbs', 20, 23, 20, 'Be not among winebibbers; among riotous eaters of flesh:'),
  ('KJV', 'Proverbs', 20, 23, 21, 'For the drunkard and the glutton shall come to poverty: and drowsiness shall clothe a man with rags.'),
  ('KJV', 'Proverbs', 20, 23, 22, 'Hearken unto thy father that begat thee, and despise not thy mother when she is old.'),
  ('KJV', 'Proverbs', 20, 23, 23, 'Buy the truth, and sell it not; also wisdom, and instruction, and understanding.'),
  ('KJV', 'Proverbs', 20, 23, 24, 'The father of the righteous shall greatly rejoice: and he that begetteth a wise child shall have joy of him.'),
  ('KJV', 'Proverbs', 20, 23, 25, 'Thy father and thy mother shall be glad, and she that bare thee shall rejoice.'),
  ('KJV', 'Proverbs', 20, 23, 26, 'My son, give me thine heart, and let thine eyes observe my ways.'),
  ('KJV', 'Proverbs', 20, 23, 27, 'For a whore is a deep ditch; and a strange woman is a narrow pit.'),
  ('KJV', 'Proverbs', 20, 23, 28, 'She also lieth in wait as for a prey, and increaseth the transgressors among men.'),
  ('KJV', 'Proverbs', 20, 23, 29, 'Who hath woe? who hath sorrow? who hath contentions? who hath babbling? who hath wounds without cause? who hath redness of eyes?'),
  ('KJV', 'Proverbs', 20, 23, 30, 'They that tarry long at the wine; they that go to seek mixed wine.'),
  ('KJV', 'Proverbs', 20, 23, 31, 'Look not thou upon the wine when it is red, when it giveth his colour in the cup, when it moveth itself aright.'),
  ('KJV', 'Proverbs', 20, 23, 32, 'At the last it biteth like a serpent, and stingeth like an adder.'),
  ('KJV', 'Proverbs', 20, 23, 33, 'Thine eyes shall behold strange women, and thine heart shall utter perverse things.'),
  ('KJV', 'Proverbs', 20, 23, 34, 'Yea, thou shalt be as he that lieth down in the midst of the sea, or as he that lieth upon the top of a mast.'),
  ('KJV', 'Proverbs', 20, 23, 35, 'They have stricken me, shalt thou say, and I was not sick; they have beaten me, and I felt it not: when shall I awake? I will seek it yet again.'),
  ('KJV', 'Proverbs', 20, 24, 1, 'Be not thou envious against evil men, neither desire to be with them.'),
  ('KJV', 'Proverbs', 20, 24, 2, 'For their heart studieth destruction, and their lips talk of mischief.'),
  ('KJV', 'Proverbs', 20, 24, 3, 'Through wisdom is an house builded; and by understanding it is established:'),
  ('KJV', 'Proverbs', 20, 24, 4, 'And by knowledge shall the chambers be filled with all precious and pleasant riches.'),
  ('KJV', 'Proverbs', 20, 24, 5, 'A wise man is strong; yea, a man of knowledge increaseth strength.'),
  ('KJV', 'Proverbs', 20, 24, 6, 'For by wise counsel thou shalt make thy war: and in multitude of counsellors there is safety.'),
  ('KJV', 'Proverbs', 20, 24, 7, 'Wisdom is too high for a fool: he openeth not his mouth in the gate.'),
  ('KJV', 'Proverbs', 20, 24, 8, 'He that deviseth to do evil shall be called a mischievous person.'),
  ('KJV', 'Proverbs', 20, 24, 9, 'The thought of foolishness is sin: and the scorner is an abomination to men.'),
  ('KJV', 'Proverbs', 20, 24, 10, 'If thou faint in the day of adversity, thy strength is small.'),
  ('KJV', 'Proverbs', 20, 24, 11, 'If thou forbear to deliver them that are drawn unto death, and those that are ready to be slain;'),
  ('KJV', 'Proverbs', 20, 24, 12, 'If thou sayest, Behold, we knew it not; doth not he that pondereth the heart consider it? and he that keepeth thy soul, doth not he know it? and shall not he render to every man according to his works?'),
  ('KJV', 'Proverbs', 20, 24, 13, 'My son, eat thou honey, because it is good; and the honeycomb, which is sweet to thy taste:'),
  ('KJV', 'Proverbs', 20, 24, 14, 'So shall the knowledge of wisdom be unto thy soul: when thou hast found it, then there shall be a reward, and thy expectation shall not be cut off.'),
  ('KJV', 'Proverbs', 20, 24, 15, 'Lay not wait, O wicked man, against the dwelling of the righteous; spoil not his resting place:'),
  ('KJV', 'Proverbs', 20, 24, 16, 'For a just man falleth seven times, and riseth up again: but the wicked shall fall into mischief.'),
  ('KJV', 'Proverbs', 20, 24, 17, 'Rejoice not when thine enemy falleth, and let not thine heart be glad when he stumbleth:'),
  ('KJV', 'Proverbs', 20, 24, 18, 'Lest the LORD see it, and it displease him, and he turn away his wrath from him.'),
  ('KJV', 'Proverbs', 20, 24, 19, 'Fret not thyself because of evil men, neither be thou envious at the wicked;'),
  ('KJV', 'Proverbs', 20, 24, 20, 'For there shall be no reward to the evil man; the candle of the wicked shall be put out.'),
  ('KJV', 'Proverbs', 20, 24, 21, 'My son, fear thou the LORD and the king: and meddle not with them that are given to change:'),
  ('KJV', 'Proverbs', 20, 24, 22, 'For their calamity shall rise suddenly; and who knoweth the ruin of them both?'),
  ('KJV', 'Proverbs', 20, 24, 23, 'These things also belong to the wise. It is not good to have respect of persons in judgment.'),
  ('KJV', 'Proverbs', 20, 24, 24, 'He that saith unto the wicked, Thou art righteous; him shall the people curse, nations shall abhor him:'),
  ('KJV', 'Proverbs', 20, 24, 25, 'But to them that rebuke him shall be delight, and a good blessing shall come upon them.'),
  ('KJV', 'Proverbs', 20, 24, 26, 'Every man shall kiss his lips that giveth a right answer.'),
  ('KJV', 'Proverbs', 20, 24, 27, 'Prepare thy work without, and make it fit for thyself in the field; and afterwards build thine house.'),
  ('KJV', 'Proverbs', 20, 24, 28, 'Be not a witness against thy neighbour without cause; and deceive not with thy lips.'),
  ('KJV', 'Proverbs', 20, 24, 29, 'Say not, I will do so to him as he hath done to me: I will render to the man according to his work.'),
  ('KJV', 'Proverbs', 20, 24, 30, 'I went by the field of the slothful, and by the vineyard of the man void of understanding;'),
  ('KJV', 'Proverbs', 20, 24, 31, 'And, lo, it was all grown over with thorns, and nettles had covered the face thereof, and the stone wall thereof was broken down.'),
  ('KJV', 'Proverbs', 20, 24, 32, 'Then I saw, and considered it well: I looked upon it, and received instruction.'),
  ('KJV', 'Proverbs', 20, 24, 33, 'Yet a little sleep, a little slumber, a little folding of the hands to sleep:'),
  ('KJV', 'Proverbs', 20, 24, 34, 'So shall thy poverty come as one that travelleth; and thy want as an armed man.'),
  ('KJV', 'Proverbs', 20, 25, 1, 'These are also proverbs of Solomon, which the men of Hezekiah king of Judah copied out.'),
  ('KJV', 'Proverbs', 20, 25, 2, 'It is the glory of God to conceal a thing: but the honour of kings is to search out a matter.'),
  ('KJV', 'Proverbs', 20, 25, 3, 'The heaven for height, and the earth for depth, and the heart of kings is unsearchable.'),
  ('KJV', 'Proverbs', 20, 25, 4, 'Take away the dross from the silver, and there shall come forth a vessel for the finer.'),
  ('KJV', 'Proverbs', 20, 25, 5, 'Take away the wicked from before the king, and his throne shall be established in righteousness.'),
  ('KJV', 'Proverbs', 20, 25, 6, 'Put not forth thyself in the presence of the king, and stand not in the place of great men:'),
  ('KJV', 'Proverbs', 20, 25, 7, 'For better it is that it be said unto thee, Come up hither; than that thou shouldest be put lower in the presence of the prince whom thine eyes have seen.'),
  ('KJV', 'Proverbs', 20, 25, 8, 'Go not forth hastily to strive, lest thou know not what to do in the end thereof, when thy neighbour hath put thee to shame.'),
  ('KJV', 'Proverbs', 20, 25, 9, 'Debate thy cause with thy neighbour himself; and discover not a secret to another:'),
  ('KJV', 'Proverbs', 20, 25, 10, 'Lest he that heareth it put thee to shame, and thine infamy turn not away.'),
  ('KJV', 'Proverbs', 20, 25, 11, 'A word fitly spoken is like apples of gold in pictures of silver.'),
  ('KJV', 'Proverbs', 20, 25, 12, 'As an earring of gold, and an ornament of fine gold, so is a wise reprover upon an obedient ear.'),
  ('KJV', 'Proverbs', 20, 25, 13, 'As the cold of snow in the time of harvest, so is a faithful messenger to them that send him: for he refresheth the soul of his masters.'),
  ('KJV', 'Proverbs', 20, 25, 14, 'Whoso boasteth himself of a false gift is like clouds and wind without rain.'),
  ('KJV', 'Proverbs', 20, 25, 15, 'By long forbearing is a prince persuaded, and a soft tongue breaketh the bone.'),
  ('KJV', 'Proverbs', 20, 25, 16, 'Hast thou found honey? eat so much as is sufficient for thee, lest thou be filled therewith, and vomit it.'),
  ('KJV', 'Proverbs', 20, 25, 17, 'Withdraw thy foot from thy neighbour''s house; lest he be weary of thee, and so hate thee.'),
  ('KJV', 'Proverbs', 20, 25, 18, 'A man that beareth false witness against his neighbour is a maul, and a sword, and a sharp arrow.'),
  ('KJV', 'Proverbs', 20, 25, 19, 'Confidence in an unfaithful man in time of trouble is like a broken tooth, and a foot out of joint.'),
  ('KJV', 'Proverbs', 20, 25, 20, 'As he that taketh away a garment in cold weather, and as vinegar upon nitre, so is he that singeth songs to an heavy heart.'),
  ('KJV', 'Proverbs', 20, 25, 21, 'If thine enemy be hungry, give him bread to eat; and if he be thirsty, give him water to drink:'),
  ('KJV', 'Proverbs', 20, 25, 22, 'For thou shalt heap coals of fire upon his head, and the LORD shall reward thee.'),
  ('KJV', 'Proverbs', 20, 25, 23, 'The north wind driveth away rain: so doth an angry countenance a backbiting tongue.'),
  ('KJV', 'Proverbs', 20, 25, 24, 'It is better to dwell in the corner of the housetop, than with a brawling woman and in a wide house.'),
  ('KJV', 'Proverbs', 20, 25, 25, 'As cold waters to a thirsty soul, so is good news from a far country.'),
  ('KJV', 'Proverbs', 20, 25, 26, 'A righteous man falling down before the wicked is as a troubled fountain, and a corrupt spring.'),
  ('KJV', 'Proverbs', 20, 25, 27, 'It is not good to eat much honey: so for men to search their own glory is not glory.'),
  ('KJV', 'Proverbs', 20, 25, 28, 'He that hath no rule over his own spirit is like a city that is broken down, and without walls.'),
  ('KJV', 'Proverbs', 20, 26, 1, 'As snow in summer, and as rain in harvest, so honour is not seemly for a fool.'),
  ('KJV', 'Proverbs', 20, 26, 2, 'As the bird by wandering, as the swallow by flying, so the curse causeless shall not come.'),
  ('KJV', 'Proverbs', 20, 26, 3, 'A whip for the horse, a bridle for the ass, and a rod for the fool''s back.'),
  ('KJV', 'Proverbs', 20, 26, 4, 'Answer not a fool according to his folly, lest thou also be like unto him.'),
  ('KJV', 'Proverbs', 20, 26, 5, 'Answer a fool according to his folly, lest he be wise in his own conceit.'),
  ('KJV', 'Proverbs', 20, 26, 6, 'He that sendeth a message by the hand of a fool cutteth off the feet, and drinketh damage.'),
  ('KJV', 'Proverbs', 20, 26, 7, 'The legs of the lame are not equal: so is a parable in the mouth of fools.'),
  ('KJV', 'Proverbs', 20, 26, 8, 'As he that bindeth a stone in a sling, so is he that giveth honour to a fool.'),
  ('KJV', 'Proverbs', 20, 26, 9, 'As a thorn goeth up into the hand of a drunkard, so is a parable in the mouth of fools.'),
  ('KJV', 'Proverbs', 20, 26, 10, 'The great God that formed all things both rewardeth the fool, and rewardeth transgressors.'),
  ('KJV', 'Proverbs', 20, 26, 11, 'As a dog returneth to his vomit, so a fool returneth to his folly.'),
  ('KJV', 'Proverbs', 20, 26, 12, 'Seest thou a man wise in his own conceit? there is more hope of a fool than of him.'),
  ('KJV', 'Proverbs', 20, 26, 13, 'The slothful man saith, There is a lion in the way; a lion is in the streets.'),
  ('KJV', 'Proverbs', 20, 26, 14, 'As the door turneth upon his hinges, so doth the slothful upon his bed.'),
  ('KJV', 'Proverbs', 20, 26, 15, 'The slothful hideth his hand in his bosom; it grieveth him to bring it again to his mouth.'),
  ('KJV', 'Proverbs', 20, 26, 16, 'The sluggard is wiser in his own conceit than seven men that can render a reason.'),
  ('KJV', 'Proverbs', 20, 26, 17, 'He that passeth by, and meddleth with strife belonging not to him, is like one that taketh a dog by the ears.'),
  ('KJV', 'Proverbs', 20, 26, 18, 'As a mad man who casteth firebrands, arrows, and death,'),
  ('KJV', 'Proverbs', 20, 26, 19, 'So is the man that deceiveth his neighbour, and saith, Am not I in sport?'),
  ('KJV', 'Proverbs', 20, 26, 20, 'Where no wood is, there the fire goeth out: so where there is no talebearer, the strife ceaseth.'),
  ('KJV', 'Proverbs', 20, 26, 21, 'As coals are to burning coals, and wood to fire; so is a contentious man to kindle strife.'),
  ('KJV', 'Proverbs', 20, 26, 22, 'The words of a talebearer are as wounds, and they go down into the innermost parts of the belly.'),
  ('KJV', 'Proverbs', 20, 26, 23, 'Burning lips and a wicked heart are like a potsherd covered with silver dross.'),
  ('KJV', 'Proverbs', 20, 26, 24, 'He that hateth dissembleth with his lips, and layeth up deceit within him;'),
  ('KJV', 'Proverbs', 20, 26, 25, 'When he speaketh fair, believe him not: for there are seven abominations in his heart.'),
  ('KJV', 'Proverbs', 20, 26, 26, 'Whose hatred is covered by deceit, his wickedness shall be shewed before the whole congregation.'),
  ('KJV', 'Proverbs', 20, 26, 27, 'Whoso diggeth a pit shall fall therein: and he that rolleth a stone, it will return upon him.'),
  ('KJV', 'Proverbs', 20, 26, 28, 'A lying tongue hateth those that are afflicted by it; and a flattering mouth worketh ruin.'),
  ('KJV', 'Proverbs', 20, 27, 1, 'Boast not thyself of to morrow; for thou knowest not what a day may bring forth.'),
  ('KJV', 'Proverbs', 20, 27, 2, 'Let another man praise thee, and not thine own mouth; a stranger, and not thine own lips.'),
  ('KJV', 'Proverbs', 20, 27, 3, 'A stone is heavy, and the sand weighty; but a fool''s wrath is heavier than them both.'),
  ('KJV', 'Proverbs', 20, 27, 4, 'Wrath is cruel, and anger is outrageous; but who is able to stand before envy?'),
  ('KJV', 'Proverbs', 20, 27, 5, 'Open rebuke is better than secret love.'),
  ('KJV', 'Proverbs', 20, 27, 6, 'Faithful are the wounds of a friend; but the kisses of an enemy are deceitful.'),
  ('KJV', 'Proverbs', 20, 27, 7, 'The full soul loatheth an honeycomb; but to the hungry soul every bitter thing is sweet.'),
  ('KJV', 'Proverbs', 20, 27, 8, 'As a bird that wandereth from her nest, so is a man that wandereth from his place.'),
  ('KJV', 'Proverbs', 20, 27, 9, 'Ointment and perfume rejoice the heart: so doth the sweetness of a man''s friend by hearty counsel.'),
  ('KJV', 'Proverbs', 20, 27, 10, 'Thine own friend, and thy father''s friend, forsake not; neither go into thy brother''s house in the day of thy calamity: for better is a neighbour that is near than a brother far off.'),
  ('KJV', 'Proverbs', 20, 27, 11, 'My son, be wise, and make my heart glad, that I may answer him that reproacheth me.'),
  ('KJV', 'Proverbs', 20, 27, 12, 'A prudent man foreseeth the evil, and hideth himself; but the simple pass on, and are punished.'),
  ('KJV', 'Proverbs', 20, 27, 13, 'Take his garment that is surety for a stranger, and take a pledge of him for a strange woman.'),
  ('KJV', 'Proverbs', 20, 27, 14, 'He that blesseth his friend with a loud voice, rising early in the morning, it shall be counted a curse to him.'),
  ('KJV', 'Proverbs', 20, 27, 15, 'A continual dropping in a very rainy day and a contentious woman are alike.'),
  ('KJV', 'Proverbs', 20, 27, 16, 'Whosoever hideth her hideth the wind, and the ointment of his right hand, which bewrayeth itself.'),
  ('KJV', 'Proverbs', 20, 27, 17, 'Iron sharpeneth iron; so a man sharpeneth the countenance of his friend.'),
  ('KJV', 'Proverbs', 20, 27, 18, 'Whoso keepeth the fig tree shall eat the fruit thereof: so he that waiteth on his master shall be honoured.'),
  ('KJV', 'Proverbs', 20, 27, 19, 'As in water face answereth to face, so the heart of man to man.'),
  ('KJV', 'Proverbs', 20, 27, 20, 'Hell and destruction are never full; so the eyes of man are never satisfied.'),
  ('KJV', 'Proverbs', 20, 27, 21, 'As the fining pot for silver, and the furnace for gold; so is a man to his praise.'),
  ('KJV', 'Proverbs', 20, 27, 22, 'Though thou shouldest bray a fool in a mortar among wheat with a pestle, yet will not his foolishness depart from him.'),
  ('KJV', 'Proverbs', 20, 27, 23, 'Be thou diligent to know the state of thy flocks, and look well to thy herds.'),
  ('KJV', 'Proverbs', 20, 27, 24, 'For riches are not for ever: and doth the crown endure to every generation?'),
  ('KJV', 'Proverbs', 20, 27, 25, 'The hay appeareth, and the tender grass sheweth itself, and herbs of the mountains are gathered.'),
  ('KJV', 'Proverbs', 20, 27, 26, 'The lambs are for thy clothing, and the goats are the price of the field.'),
  ('KJV', 'Proverbs', 20, 27, 27, 'And thou shalt have goats'' milk enough for thy food, for the food of thy household, and for the maintenance for thy maidens.'),
  ('KJV', 'Proverbs', 20, 28, 1, 'The wicked flee when no man pursueth: but the righteous are bold as a lion.'),
  ('KJV', 'Proverbs', 20, 28, 2, 'For the transgression of a land many are the princes thereof: but by a man of understanding and knowledge the state thereof shall be prolonged.'),
  ('KJV', 'Proverbs', 20, 28, 3, 'A poor man that oppresseth the poor is like a sweeping rain which leaveth no food.'),
  ('KJV', 'Proverbs', 20, 28, 4, 'They that forsake the law praise the wicked: but such as keep the law contend with them.'),
  ('KJV', 'Proverbs', 20, 28, 5, 'Evil men understand not judgment: but they that seek the LORD understand all things.'),
  ('KJV', 'Proverbs', 20, 28, 6, 'Better is the poor that walketh in his uprightness, than he that is perverse in his ways, though he be rich.'),
  ('KJV', 'Proverbs', 20, 28, 7, 'Whoso keepeth the law is a wise son: but he that is a companion of riotous men shameth his father.'),
  ('KJV', 'Proverbs', 20, 28, 8, 'He that by usury and unjust gain increaseth his substance, he shall gather it for him that will pity the poor.'),
  ('KJV', 'Proverbs', 20, 28, 9, 'He that turneth away his ear from hearing the law, even his prayer shall be abomination.'),
  ('KJV', 'Proverbs', 20, 28, 10, 'Whoso causeth the righteous to go astray in an evil way, he shall fall himself into his own pit: but the upright shall have good things in possession.'),
  ('KJV', 'Proverbs', 20, 28, 11, 'The rich man is wise in his own conceit; but the poor that hath understanding searcheth him out.'),
  ('KJV', 'Proverbs', 20, 28, 12, 'When righteous men do rejoice, there is great glory: but when the wicked rise, a man is hidden.'),
  ('KJV', 'Proverbs', 20, 28, 13, 'He that covereth his sins shall not prosper: but whoso confesseth and forsaketh them shall have mercy.'),
  ('KJV', 'Proverbs', 20, 28, 14, 'Happy is the man that feareth alway: but he that hardeneth his heart shall fall into mischief.'),
  ('KJV', 'Proverbs', 20, 28, 15, 'As a roaring lion, and a ranging bear; so is a wicked ruler over the poor people.'),
  ('KJV', 'Proverbs', 20, 28, 16, 'The prince that wanteth understanding is also a great oppressor: but he that hateth covetousness shall prolong his days.'),
  ('KJV', 'Proverbs', 20, 28, 17, 'A man that doeth violence to the blood of any person shall flee to the pit; let no man stay him.'),
  ('KJV', 'Proverbs', 20, 28, 18, 'Whoso walketh uprightly shall be saved: but he that is perverse in his ways shall fall at once.'),
  ('KJV', 'Proverbs', 20, 28, 19, 'He that tilleth his land shall have plenty of bread: but he that followeth after vain persons shall have poverty enough.'),
  ('KJV', 'Proverbs', 20, 28, 20, 'A faithful man shall abound with blessings: but he that maketh haste to be rich shall not be innocent.'),
  ('KJV', 'Proverbs', 20, 28, 21, 'To have respect of persons is not good: for for a piece of bread that man will transgress.'),
  ('KJV', 'Proverbs', 20, 28, 22, 'He that hasteth to be rich hath an evil eye, and considereth not that poverty shall come upon him.'),
  ('KJV', 'Proverbs', 20, 28, 23, 'He that rebuketh a man afterwards shall find more favour than he that flattereth with the tongue.'),
  ('KJV', 'Proverbs', 20, 28, 24, 'Whoso robbeth his father or his mother, and saith, It is no transgression; the same is the companion of a destroyer.'),
  ('KJV', 'Proverbs', 20, 28, 25, 'He that is of a proud heart stirreth up strife: but he that putteth his trust in the LORD shall be made fat.'),
  ('KJV', 'Proverbs', 20, 28, 26, 'He that trusteth in his own heart is a fool: but whoso walketh wisely, he shall be delivered.'),
  ('KJV', 'Proverbs', 20, 28, 27, 'He that giveth unto the poor shall not lack: but he that hideth his eyes shall have many a curse.'),
  ('KJV', 'Proverbs', 20, 28, 28, 'When the wicked rise, men hide themselves: but when they perish, the righteous increase.'),
  ('KJV', 'Proverbs', 20, 29, 1, 'He, that being often reproved hardeneth his neck, shall suddenly be destroyed, and that without remedy.'),
  ('KJV', 'Proverbs', 20, 29, 2, 'When the righteous are in authority, the people rejoice: but when the wicked beareth rule, the people mourn.'),
  ('KJV', 'Proverbs', 20, 29, 3, 'Whoso loveth wisdom rejoiceth his father: but he that keepeth company with harlots spendeth his substance.'),
  ('KJV', 'Proverbs', 20, 29, 4, 'The king by judgment establisheth the land: but he that receiveth gifts overthroweth it.'),
  ('KJV', 'Proverbs', 20, 29, 5, 'A man that flattereth his neighbour spreadeth a net for his feet.'),
  ('KJV', 'Proverbs', 20, 29, 6, 'In the transgression of an evil man there is a snare: but the righteous doth sing and rejoice.'),
  ('KJV', 'Proverbs', 20, 29, 7, 'The righteous considereth the cause of the poor: but the wicked regardeth not to know it.'),
  ('KJV', 'Proverbs', 20, 29, 8, 'Scornful men bring a city into a snare: but wise men turn away wrath.'),
  ('KJV', 'Proverbs', 20, 29, 9, 'If a wise man contendeth with a foolish man, whether he rage or laugh, there is no rest.'),
  ('KJV', 'Proverbs', 20, 29, 10, 'The bloodthirsty hate the upright: but the just seek his soul.'),
  ('KJV', 'Proverbs', 20, 29, 11, 'A fool uttereth all his mind: but a wise man keepeth it in till afterwards.'),
  ('KJV', 'Proverbs', 20, 29, 12, 'If a ruler hearken to lies, all his servants are wicked.'),
  ('KJV', 'Proverbs', 20, 29, 13, 'The poor and the deceitful man meet together: the LORD lighteneth both their eyes.'),
  ('KJV', 'Proverbs', 20, 29, 14, 'The king that faithfully judgeth the poor, his throne shall be established for ever.'),
  ('KJV', 'Proverbs', 20, 29, 15, 'The rod and reproof give wisdom: but a child left to himself bringeth his mother to shame.'),
  ('KJV', 'Proverbs', 20, 29, 16, 'When the wicked are multiplied, transgression increaseth: but the righteous shall see their fall.'),
  ('KJV', 'Proverbs', 20, 29, 17, 'Correct thy son, and he shall give thee rest; yea, he shall give delight unto thy soul.'),
  ('KJV', 'Proverbs', 20, 29, 18, 'Where there is no vision, the people perish: but he that keepeth the law, happy is he.'),
  ('KJV', 'Proverbs', 20, 29, 19, 'A servant will not be corrected by words: for though he understand he will not answer.'),
  ('KJV', 'Proverbs', 20, 29, 20, 'Seest thou a man that is hasty in his words? there is more hope of a fool than of him.'),
  ('KJV', 'Proverbs', 20, 29, 21, 'He that delicately bringeth up his servant from a child shall have him become his son at the length.'),
  ('KJV', 'Proverbs', 20, 29, 22, 'An angry man stirreth up strife, and a furious man aboundeth in transgression.'),
  ('KJV', 'Proverbs', 20, 29, 23, 'A man''s pride shall bring him low: but honour shall uphold the humble in spirit.'),
  ('KJV', 'Proverbs', 20, 29, 24, 'Whoso is partner with a thief hateth his own soul: he heareth cursing, and bewrayeth it not.'),
  ('KJV', 'Proverbs', 20, 29, 25, 'The fear of man bringeth a snare: but whoso putteth his trust in the LORD shall be safe.'),
  ('KJV', 'Proverbs', 20, 29, 26, 'Many seek the ruler''s favour; but every man''s judgment cometh from the LORD.'),
  ('KJV', 'Proverbs', 20, 29, 27, 'An unjust man is an abomination to the just: and he that is upright in the way is abomination to the wicked.'),
  ('KJV', 'Proverbs', 20, 30, 1, 'The words of Agur the son of Jakeh, even the prophecy: the man spake unto Ithiel, even unto Ithiel and Ucal,'),
  ('KJV', 'Proverbs', 20, 30, 2, 'Surely I am more brutish than any man, and have not the understanding of a man.'),
  ('KJV', 'Proverbs', 20, 30, 3, 'I neither learned wisdom, nor have the knowledge of the holy.'),
  ('KJV', 'Proverbs', 20, 30, 4, 'Who hath ascended up into heaven, or descended? who hath gathered the wind in his fists? who hath bound the waters in a garment? who hath established all the ends of the earth? what is his name, and what is his son''s name, if thou canst tell?'),
  ('KJV', 'Proverbs', 20, 30, 5, 'Every word of God is pure: he is a shield unto them that put their trust in him.'),
  ('KJV', 'Proverbs', 20, 30, 6, 'Add thou not unto his words, lest he reprove thee, and thou be found a liar.'),
  ('KJV', 'Proverbs', 20, 30, 7, 'Two things have I required of thee; deny me them not before I die:'),
  ('KJV', 'Proverbs', 20, 30, 8, 'Remove far from me vanity and lies: give me neither poverty nor riches; feed me with food convenient for me:'),
  ('KJV', 'Proverbs', 20, 30, 9, 'Lest I be full, and deny thee, and say, Who is the LORD? or lest I be poor, and steal, and take the name of my God in vain.'),
  ('KJV', 'Proverbs', 20, 30, 10, 'Accuse not a servant unto his master, lest he curse thee, and thou be found guilty.'),
  ('KJV', 'Proverbs', 20, 30, 11, 'There is a generation that curseth their father, and doth not bless their mother.'),
  ('KJV', 'Proverbs', 20, 30, 12, 'There is a generation that are pure in their own eyes, and yet is not washed from their filthiness.'),
  ('KJV', 'Proverbs', 20, 30, 13, 'There is a generation, O how lofty are their eyes! and their eyelids are lifted up.'),
  ('KJV', 'Proverbs', 20, 30, 14, 'There is a generation, whose teeth are as swords, and their jaw teeth as knives, to devour the poor from off the earth, and the needy from among men.'),
  ('KJV', 'Proverbs', 20, 30, 15, 'The horseleach hath two daughters, crying, Give, give. There are three things that are never satisfied, yea, four things say not, It is enough:'),
  ('KJV', 'Proverbs', 20, 30, 16, 'The grave; and the barren womb; the earth that is not filled with water; and the fire that saith not, It is enough.'),
  ('KJV', 'Proverbs', 20, 30, 17, 'The eye that mocketh at his father, and despiseth to obey his mother, the ravens of the valley shall pick it out, and the young eagles shall eat it.'),
  ('KJV', 'Proverbs', 20, 30, 18, 'There be three things which are too wonderful for me, yea, four which I know not:'),
  ('KJV', 'Proverbs', 20, 30, 19, 'The way of an eagle in the air; the way of a serpent upon a rock; the way of a ship in the midst of the sea; and the way of a man with a maid.'),
  ('KJV', 'Proverbs', 20, 30, 20, 'Such is the way of an adulterous woman; she eateth, and wipeth her mouth, and saith, I have done no wickedness.'),
  ('KJV', 'Proverbs', 20, 30, 21, 'For three things the earth is disquieted, and for four which it cannot bear:'),
  ('KJV', 'Proverbs', 20, 30, 22, 'For a servant when he reigneth; and a fool when he is filled with meat;'),
  ('KJV', 'Proverbs', 20, 30, 23, 'For an odious woman when she is married; and an handmaid that is heir to her mistress.'),
  ('KJV', 'Proverbs', 20, 30, 24, 'There be four things which are little upon the earth, but they are exceeding wise:'),
  ('KJV', 'Proverbs', 20, 30, 25, 'The ants are a people not strong, yet they prepare their meat in the summer;'),
  ('KJV', 'Proverbs', 20, 30, 26, 'The conies are but a feeble folk, yet make they their houses in the rocks;'),
  ('KJV', 'Proverbs', 20, 30, 27, 'The locusts have no king, yet go they forth all of them by bands;'),
  ('KJV', 'Proverbs', 20, 30, 28, 'The spider taketh hold with her hands, and is in kings'' palaces.'),
  ('KJV', 'Proverbs', 20, 30, 29, 'There be three things which go well, yea, four are comely in going:'),
  ('KJV', 'Proverbs', 20, 30, 30, 'A lion which is strongest among beasts, and turneth not away for any;'),
  ('KJV', 'Proverbs', 20, 30, 31, 'A greyhound; an he goat also; and a king, against whom there is no rising up.'),
  ('KJV', 'Proverbs', 20, 30, 32, 'If thou hast done foolishly in lifting up thyself, or if thou hast thought evil, lay thine hand upon thy mouth.'),
  ('KJV', 'Proverbs', 20, 30, 33, 'Surely the churning of milk bringeth forth butter, and the wringing of the nose bringeth forth blood: so the forcing of wrath bringeth forth strife.'),
  ('KJV', 'Proverbs', 20, 31, 1, 'The words of king Lemuel, the prophecy that his mother taught him.'),
  ('KJV', 'Proverbs', 20, 31, 2, 'What, my son? and what, the son of my womb? and what, the son of my vows?'),
  ('KJV', 'Proverbs', 20, 31, 3, 'Give not thy strength unto women, nor thy ways to that which destroyeth kings.'),
  ('KJV', 'Proverbs', 20, 31, 4, 'It is not for kings, O Lemuel, it is not for kings to drink wine; nor for princes strong drink:'),
  ('KJV', 'Proverbs', 20, 31, 5, 'Lest they drink, and forget the law, and pervert the judgment of any of the afflicted.'),
  ('KJV', 'Proverbs', 20, 31, 6, 'Give strong drink unto him that is ready to perish, and wine unto those that be of heavy hearts.'),
  ('KJV', 'Proverbs', 20, 31, 7, 'Let him drink, and forget his poverty, and remember his misery no more.'),
  ('KJV', 'Proverbs', 20, 31, 8, 'Open thy mouth for the dumb in the cause of all such as are appointed to destruction.'),
  ('KJV', 'Proverbs', 20, 31, 9, 'Open thy mouth, judge righteously, and plead the cause of the poor and needy.'),
  ('KJV', 'Proverbs', 20, 31, 10, 'Who can find a virtuous woman? for her price is far above rubies.'),
  ('KJV', 'Proverbs', 20, 31, 11, 'The heart of her husband doth safely trust in her, so that he shall have no need of spoil.'),
  ('KJV', 'Proverbs', 20, 31, 12, 'She will do him good and not evil all the days of her life.'),
  ('KJV', 'Proverbs', 20, 31, 13, 'She seeketh wool, and flax, and worketh willingly with her hands.'),
  ('KJV', 'Proverbs', 20, 31, 14, 'She is like the merchants'' ships; she bringeth her food from afar.'),
  ('KJV', 'Proverbs', 20, 31, 15, 'She riseth also while it is yet night, and giveth meat to her household, and a portion to her maidens.'),
  ('KJV', 'Proverbs', 20, 31, 16, 'She considereth a field, and buyeth it: with the fruit of her hands she planteth a vineyard.'),
  ('KJV', 'Proverbs', 20, 31, 17, 'She girdeth her loins with strength, and strengtheneth her arms.'),
  ('KJV', 'Proverbs', 20, 31, 18, 'She perceiveth that her merchandise is good: her candle goeth not out by night.'),
  ('KJV', 'Proverbs', 20, 31, 19, 'She layeth her hands to the spindle, and her hands hold the distaff.'),
  ('KJV', 'Proverbs', 20, 31, 20, 'She stretcheth out her hand to the poor; yea, she reacheth forth her hands to the needy.'),
  ('KJV', 'Proverbs', 20, 31, 21, 'She is not afraid of the snow for her household: for all her household are clothed with scarlet.'),
  ('KJV', 'Proverbs', 20, 31, 22, 'She maketh herself coverings of tapestry; her clothing is silk and purple.'),
  ('KJV', 'Proverbs', 20, 31, 23, 'Her husband is known in the gates, when he sitteth among the elders of the land.'),
  ('KJV', 'Proverbs', 20, 31, 24, 'She maketh fine linen, and selleth it; and delivereth girdles unto the merchant.'),
  ('KJV', 'Proverbs', 20, 31, 25, 'Strength and honour are her clothing; and she shall rejoice in time to come.'),
  ('KJV', 'Proverbs', 20, 31, 26, 'She openeth her mouth with wisdom; and in her tongue is the law of kindness.'),
  ('KJV', 'Proverbs', 20, 31, 27, 'She looketh well to the ways of her household, and eateth not the bread of idleness.'),
  ('KJV', 'Proverbs', 20, 31, 28, 'Her children arise up, and call her blessed; her husband also, and he praiseth her.'),
  ('KJV', 'Proverbs', 20, 31, 29, 'Many daughters have done virtuously, but thou excellest them all.'),
  ('KJV', 'Proverbs', 20, 31, 30, 'Favour is deceitful, and beauty is vain: but a woman that feareth the LORD, she shall be praised.'),
  ('KJV', 'Proverbs', 20, 31, 31, 'Give her of the fruit of her hands; and let her own works praise her in the gates.'),
  ('KJV', 'Ecclesiastes', 21, 1, 1, 'The words of the Preacher, the son of David, king in Jerusalem.'),
  ('KJV', 'Ecclesiastes', 21, 1, 2, 'Vanity of vanities, saith the Preacher, vanity of vanities; all is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 1, 3, 'What profit hath a man of all his labour which he taketh under the sun?'),
  ('KJV', 'Ecclesiastes', 21, 1, 4, 'One generation passeth away, and another generation cometh: but the earth abideth for ever.'),
  ('KJV', 'Ecclesiastes', 21, 1, 5, 'The sun also ariseth, and the sun goeth down, and hasteth to his place where he arose.'),
  ('KJV', 'Ecclesiastes', 21, 1, 6, 'The wind goeth toward the south, and turneth about unto the north; it whirleth about continually, and the wind returneth again according to his circuits.'),
  ('KJV', 'Ecclesiastes', 21, 1, 7, 'All the rivers run into the sea; yet the sea is not full; unto the place from whence the rivers come, thither they return again.'),
  ('KJV', 'Ecclesiastes', 21, 1, 8, 'All things are full of labour; man cannot utter it: the eye is not satisfied with seeing, nor the ear filled with hearing.'),
  ('KJV', 'Ecclesiastes', 21, 1, 9, 'The thing that hath been, it is that which shall be; and that which is done is that which shall be done: and there is no new thing under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 1, 10, 'Is there any thing whereof it may be said, See, this is new? it hath been already of old time, which was before us.'),
  ('KJV', 'Ecclesiastes', 21, 1, 11, 'There is no remembrance of former things; neither shall there be any remembrance of things that are to come with those that shall come after.'),
  ('KJV', 'Ecclesiastes', 21, 1, 12, 'I the Preacher was king over Israel in Jerusalem.'),
  ('KJV', 'Ecclesiastes', 21, 1, 13, 'And I gave my heart to seek and search out by wisdom concerning all things that are done under heaven: this sore travail hath God given to the sons of man to be exercised therewith.'),
  ('KJV', 'Ecclesiastes', 21, 1, 14, 'I have seen all the works that are done under the sun; and, behold, all is vanity and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 1, 15, 'That which is crooked cannot be made straight: and that which is wanting cannot be numbered.'),
  ('KJV', 'Ecclesiastes', 21, 1, 16, 'I communed with mine own heart, saying, Lo, I am come to great estate, and have gotten more wisdom than all they that have been before me in Jerusalem: yea, my heart had great experience of wisdom and knowledge.'),
  ('KJV', 'Ecclesiastes', 21, 1, 17, 'And I gave my heart to know wisdom, and to know madness and folly: I perceived that this also is vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 1, 18, 'For in much wisdom is much grief: and he that increaseth knowledge increaseth sorrow.'),
  ('KJV', 'Ecclesiastes', 21, 2, 1, 'I said in mine heart, Go to now, I will prove thee with mirth, therefore enjoy pleasure: and, behold, this also is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 2, 2, 'I said of laughter, It is mad: and of mirth, What doeth it?'),
  ('KJV', 'Ecclesiastes', 21, 2, 3, 'I sought in mine heart to give myself unto wine, yet acquainting mine heart with wisdom; and to lay hold on folly, till I might see what was that good for the sons of men, which they should do under the heaven all the days of their life.'),
  ('KJV', 'Ecclesiastes', 21, 2, 4, 'I made me great works; I builded me houses; I planted me vineyards:'),
  ('KJV', 'Ecclesiastes', 21, 2, 5, 'I made me gardens and orchards, and I planted trees in them of all kind of fruits:'),
  ('KJV', 'Ecclesiastes', 21, 2, 6, 'I made me pools of water, to water therewith the wood that bringeth forth trees:'),
  ('KJV', 'Ecclesiastes', 21, 2, 7, 'I got me servants and maidens, and had servants born in my house; also I had great possessions of great and small cattle above all that were in Jerusalem before me:'),
  ('KJV', 'Ecclesiastes', 21, 2, 8, 'I gathered me also silver and gold, and the peculiar treasure of kings and of the provinces: I gat me men singers and women singers, and the delights of the sons of men, as musical instruments, and that of all sorts.'),
  ('KJV', 'Ecclesiastes', 21, 2, 9, 'So I was great, and increased more than all that were before me in Jerusalem: also my wisdom remained with me.'),
  ('KJV', 'Ecclesiastes', 21, 2, 10, 'And whatsoever mine eyes desired I kept not from them, I withheld not my heart from any joy; for my heart rejoiced in all my labour: and this was my portion of all my labour.'),
  ('KJV', 'Ecclesiastes', 21, 2, 11, 'Then I looked on all the works that my hands had wrought, and on the labour that I had laboured to do: and, behold, all was vanity and vexation of spirit, and there was no profit under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 2, 12, 'And I turned myself to behold wisdom, and madness, and folly: for what can the man do that cometh after the king? even that which hath been already done.'),
  ('KJV', 'Ecclesiastes', 21, 2, 13, 'Then I saw that wisdom excelleth folly, as far as light excelleth darkness.'),
  ('KJV', 'Ecclesiastes', 21, 2, 14, 'The wise man''s eyes are in his head; but the fool walketh in darkness: and I myself perceived also that one event happeneth to them all.'),
  ('KJV', 'Ecclesiastes', 21, 2, 15, 'Then said I in my heart, As it happeneth to the fool, so it happeneth even to me; and why was I then more wise? Then I said in my heart, that this also is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 2, 16, 'For there is no remembrance of the wise more than of the fool for ever; seeing that which now is in the days to come shall all be forgotten. And how dieth the wise man? as the fool.'),
  ('KJV', 'Ecclesiastes', 21, 2, 17, 'Therefore I hated life; because the work that is wrought under the sun is grievous unto me: for all is vanity and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 2, 18, 'Yea, I hated all my labour which I had taken under the sun: because I should leave it unto the man that shall be after me.'),
  ('KJV', 'Ecclesiastes', 21, 2, 19, 'And who knoweth whether he shall be a wise man or a fool? yet shall he have rule over all my labour wherein I have laboured, and wherein I have shewed myself wise under the sun. This is also vanity.'),
  ('KJV', 'Ecclesiastes', 21, 2, 20, 'Therefore I went about to cause my heart to despair of all the labour which I took under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 2, 21, 'For there is a man whose labour is in wisdom, and in knowledge, and in equity; yet to a man that hath not laboured therein shall he leave it for his portion. This also is vanity and a great evil.'),
  ('KJV', 'Ecclesiastes', 21, 2, 22, 'For what hath man of all his labour, and of the vexation of his heart, wherein he hath laboured under the sun?'),
  ('KJV', 'Ecclesiastes', 21, 2, 23, 'For all his days are sorrows, and his travail grief; yea, his heart taketh not rest in the night. This is also vanity.'),
  ('KJV', 'Ecclesiastes', 21, 2, 24, 'There is nothing better for a man, than that he should eat and drink, and that he should make his soul enjoy good in his labour. This also I saw, that it was from the hand of God.'),
  ('KJV', 'Ecclesiastes', 21, 2, 25, 'For who can eat, or who else can hasten hereunto, more than I?'),
  ('KJV', 'Ecclesiastes', 21, 2, 26, 'For God giveth to a man that is good in his sight wisdom, and knowledge, and joy: but to the sinner he giveth travail, to gather and to heap up, that he may give to him that is good before God. This also is vanity and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 3, 1, 'To every thing there is a season, and a time to every purpose under the heaven:'),
  ('KJV', 'Ecclesiastes', 21, 3, 2, 'A time to be born, and a time to die; a time to plant, and a time to pluck up that which is planted;'),
  ('KJV', 'Ecclesiastes', 21, 3, 3, 'A time to kill, and a time to heal; a time to break down, and a time to build up;'),
  ('KJV', 'Ecclesiastes', 21, 3, 4, 'A time to weep, and a time to laugh; a time to mourn, and a time to dance;'),
  ('KJV', 'Ecclesiastes', 21, 3, 5, 'A time to cast away stones, and a time to gather stones together; a time to embrace, and a time to refrain from embracing;'),
  ('KJV', 'Ecclesiastes', 21, 3, 6, 'A time to get, and a time to lose; a time to keep, and a time to cast away;'),
  ('KJV', 'Ecclesiastes', 21, 3, 7, 'A time to rend, and a time to sew; a time to keep silence, and a time to speak;'),
  ('KJV', 'Ecclesiastes', 21, 3, 8, 'A time to love, and a time to hate; a time of war, and a time of peace.'),
  ('KJV', 'Ecclesiastes', 21, 3, 9, 'What profit hath he that worketh in that wherein he laboureth?'),
  ('KJV', 'Ecclesiastes', 21, 3, 10, 'I have seen the travail, which God hath given to the sons of men to be exercised in it.'),
  ('KJV', 'Ecclesiastes', 21, 3, 11, 'He hath made every thing beautiful in his time: also he hath set the world in their heart, so that no man can find out the work that God maketh from the beginning to the end.'),
  ('KJV', 'Ecclesiastes', 21, 3, 12, 'I know that there is no good in them, but for a man to rejoice, and to do good in his life.'),
  ('KJV', 'Ecclesiastes', 21, 3, 13, 'And also that every man should eat and drink, and enjoy the good of all his labour, it is the gift of God.'),
  ('KJV', 'Ecclesiastes', 21, 3, 14, 'I know that, whatsoever God doeth, it shall be for ever: nothing can be put to it, nor any thing taken from it: and God doeth it, that men should fear before him.'),
  ('KJV', 'Ecclesiastes', 21, 3, 15, 'That which hath been is now; and that which is to be hath already been; and God requireth that which is past.'),
  ('KJV', 'Ecclesiastes', 21, 3, 16, 'And moreover I saw under the sun the place of judgment, that wickedness was there; and the place of righteousness, that iniquity was there.'),
  ('KJV', 'Ecclesiastes', 21, 3, 17, 'I said in mine heart, God shall judge the righteous and the wicked: for there is a time there for every purpose and for every work.'),
  ('KJV', 'Ecclesiastes', 21, 3, 18, 'I said in mine heart concerning the estate of the sons of men, that God might manifest them, and that they might see that they themselves are beasts.'),
  ('KJV', 'Ecclesiastes', 21, 3, 19, 'For that which befalleth the sons of men befalleth beasts; even one thing befalleth them: as the one dieth, so dieth the other; yea, they have all one breath; so that a man hath no preeminence above a beast: for all is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 3, 20, 'All go unto one place; all are of the dust, and all turn to dust again.'),
  ('KJV', 'Ecclesiastes', 21, 3, 21, 'Who knoweth the spirit of man that goeth upward, and the spirit of the beast that goeth downward to the earth?'),
  ('KJV', 'Ecclesiastes', 21, 3, 22, 'Wherefore I perceive that there is nothing better, than that a man should rejoice in his own works; for that is his portion: for who shall bring him to see what shall be after him?'),
  ('KJV', 'Ecclesiastes', 21, 4, 1, 'So I returned, and considered all the oppressions that are done under the sun: and behold the tears of such as were oppressed, and they had no comforter; and on the side of their oppressors there was power; but they had no comforter.'),
  ('KJV', 'Ecclesiastes', 21, 4, 2, 'Wherefore I praised the dead which are already dead more than the living which are yet alive.'),
  ('KJV', 'Ecclesiastes', 21, 4, 3, 'Yea, better is he than both they, which hath not yet been, who hath not seen the evil work that is done under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 4, 4, 'Again, I considered all travail, and every right work, that for this a man is envied of his neighbour. This is also vanity and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 4, 5, 'The fool foldeth his hands together, and eateth his own flesh.'),
  ('KJV', 'Ecclesiastes', 21, 4, 6, 'Better is an handful with quietness, than both the hands full with travail and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 4, 7, 'Then I returned, and I saw vanity under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 4, 8, 'There is one alone, and there is not a second; yea, he hath neither child nor brother: yet is there no end of all his labour; neither is his eye satisfied with riches; neither saith he, For whom do I labour, and bereave my soul of good? This is also vanity, yea, it is a sore travail.'),
  ('KJV', 'Ecclesiastes', 21, 4, 9, 'Two are better than one; because they have a good reward for their labour.'),
  ('KJV', 'Ecclesiastes', 21, 4, 10, 'For if they fall, the one will lift up his fellow: but woe to him that is alone when he falleth; for he hath not another to help him up.'),
  ('KJV', 'Ecclesiastes', 21, 4, 11, 'Again, if two lie together, then they have heat: but how can one be warm alone?'),
  ('KJV', 'Ecclesiastes', 21, 4, 12, 'And if one prevail against him, two shall withstand him; and a threefold cord is not quickly broken.'),
  ('KJV', 'Ecclesiastes', 21, 4, 13, 'Better is a poor and a wise child than an old and foolish king, who will no more be admonished.'),
  ('KJV', 'Ecclesiastes', 21, 4, 14, 'For out of prison he cometh to reign; whereas also he that is born in his kingdom becometh poor.'),
  ('KJV', 'Ecclesiastes', 21, 4, 15, 'I considered all the living which walk under the sun, with the second child that shall stand up in his stead.'),
  ('KJV', 'Ecclesiastes', 21, 4, 16, 'There is no end of all the people, even of all that have been before them: they also that come after shall not rejoice in him. Surely this also is vanity and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 5, 1, 'Keep thy foot when thou goest to the house of God, and be more ready to hear, than to give the sacrifice of fools: for they consider not that they do evil.'),
  ('KJV', 'Ecclesiastes', 21, 5, 2, 'Be not rash with thy mouth, and let not thine heart be hasty to utter any thing before God: for God is in heaven, and thou upon earth: therefore let thy words be few.'),
  ('KJV', 'Ecclesiastes', 21, 5, 3, 'For a dream cometh through the multitude of business; and a fool''s voice is known by multitude of words.'),
  ('KJV', 'Ecclesiastes', 21, 5, 4, 'When thou vowest a vow unto God, defer not to pay it; for he hath no pleasure in fools: pay that which thou hast vowed.'),
  ('KJV', 'Ecclesiastes', 21, 5, 5, 'Better is it that thou shouldest not vow, than that thou shouldest vow and not pay.'),
  ('KJV', 'Ecclesiastes', 21, 5, 6, 'Suffer not thy mouth to cause thy flesh to sin; neither say thou before the angel, that it was an error: wherefore should God be angry at thy voice, and destroy the work of thine hands?'),
  ('KJV', 'Ecclesiastes', 21, 5, 7, 'For in the multitude of dreams and many words there are also divers vanities: but fear thou God.'),
  ('KJV', 'Ecclesiastes', 21, 5, 8, 'If thou seest the oppression of the poor, and violent perverting of judgment and justice in a province, marvel not at the matter: for he that is higher than the highest regardeth; and there be higher than they.'),
  ('KJV', 'Ecclesiastes', 21, 5, 9, 'Moreover the profit of the earth is for all: the king himself is served by the field.'),
  ('KJV', 'Ecclesiastes', 21, 5, 10, 'He that loveth silver shall not be satisfied with silver; nor he that loveth abundance with increase: this is also vanity.'),
  ('KJV', 'Ecclesiastes', 21, 5, 11, 'When goods increase, they are increased that eat them: and what good is there to the owners thereof, saving the beholding of them with their eyes?'),
  ('KJV', 'Ecclesiastes', 21, 5, 12, 'The sleep of a labouring man is sweet, whether he eat little or much: but the abundance of the rich will not suffer him to sleep.'),
  ('KJV', 'Ecclesiastes', 21, 5, 13, 'There is a sore evil which I have seen under the sun, namely, riches kept for the owners thereof to their hurt.'),
  ('KJV', 'Ecclesiastes', 21, 5, 14, 'But those riches perish by evil travail: and he begetteth a son, and there is nothing in his hand.'),
  ('KJV', 'Ecclesiastes', 21, 5, 15, 'As he came forth of his mother''s womb, naked shall he return to go as he came, and shall take nothing of his labour, which he may carry away in his hand.'),
  ('KJV', 'Ecclesiastes', 21, 5, 16, 'And this also is a sore evil, that in all points as he came, so shall he go: and what profit hath he that hath laboured for the wind?'),
  ('KJV', 'Ecclesiastes', 21, 5, 17, 'All his days also he eateth in darkness, and he hath much sorrow and wrath with his sickness.'),
  ('KJV', 'Ecclesiastes', 21, 5, 18, 'Behold that which I have seen: it is good and comely for one to eat and to drink, and to enjoy the good of all his labour that he taketh under the sun all the days of his life, which God giveth him: for it is his portion.'),
  ('KJV', 'Ecclesiastes', 21, 5, 19, 'Every man also to whom God hath given riches and wealth, and hath given him power to eat thereof, and to take his portion, and to rejoice in his labour; this is the gift of God.'),
  ('KJV', 'Ecclesiastes', 21, 5, 20, 'For he shall not much remember the days of his life; because God answereth him in the joy of his heart.'),
  ('KJV', 'Ecclesiastes', 21, 6, 1, 'There is an evil which I have seen under the sun, and it is common among men:'),
  ('KJV', 'Ecclesiastes', 21, 6, 2, 'A man to whom God hath given riches, wealth, and honour, so that he wanteth nothing for his soul of all that he desireth, yet God giveth him not power to eat thereof, but a stranger eateth it: this is vanity, and it is an evil disease.'),
  ('KJV', 'Ecclesiastes', 21, 6, 3, 'If a man beget an hundred children, and live many years, so that the days of his years be many, and his soul be not filled with good, and also that he have no burial; I say, that an untimely birth is better than he.'),
  ('KJV', 'Ecclesiastes', 21, 6, 4, 'For he cometh in with vanity, and departeth in darkness, and his name shall be covered with darkness.'),
  ('KJV', 'Ecclesiastes', 21, 6, 5, 'Moreover he hath not seen the sun, nor known any thing: this hath more rest than the other.'),
  ('KJV', 'Ecclesiastes', 21, 6, 6, 'Yea, though he live a thousand years twice told, yet hath he seen no good: do not all go to one place?'),
  ('KJV', 'Ecclesiastes', 21, 6, 7, 'All the labour of man is for his mouth, and yet the appetite is not filled.'),
  ('KJV', 'Ecclesiastes', 21, 6, 8, 'For what hath the wise more than the fool? what hath the poor, that knoweth to walk before the living?'),
  ('KJV', 'Ecclesiastes', 21, 6, 9, 'Better is the sight of the eyes than the wandering of the desire: this is also vanity and vexation of spirit.'),
  ('KJV', 'Ecclesiastes', 21, 6, 10, 'That which hath been is named already, and it is known that it is man: neither may he contend with him that is mightier than he.'),
  ('KJV', 'Ecclesiastes', 21, 6, 11, 'Seeing there be many things that increase vanity, what is man the better?'),
  ('KJV', 'Ecclesiastes', 21, 6, 12, 'For who knoweth what is good for man in this life, all the days of his vain life which he spendeth as a shadow? for who can tell a man what shall be after him under the sun?'),
  ('KJV', 'Ecclesiastes', 21, 7, 1, 'A good name is better than precious ointment; and the day of death than the day of one''s birth.'),
  ('KJV', 'Ecclesiastes', 21, 7, 2, 'It is better to go to the house of mourning, than to go to the house of feasting: for that is the end of all men; and the living will lay it to his heart.'),
  ('KJV', 'Ecclesiastes', 21, 7, 3, 'Sorrow is better than laughter: for by the sadness of the countenance the heart is made better.'),
  ('KJV', 'Ecclesiastes', 21, 7, 4, 'The heart of the wise is in the house of mourning; but the heart of fools is in the house of mirth.'),
  ('KJV', 'Ecclesiastes', 21, 7, 5, 'It is better to hear the rebuke of the wise, than for a man to hear the song of fools.'),
  ('KJV', 'Ecclesiastes', 21, 7, 6, 'For as the crackling of thorns under a pot, so is the laughter of the fool: this also is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 7, 7, 'Surely oppression maketh a wise man mad; and a gift destroyeth the heart.'),
  ('KJV', 'Ecclesiastes', 21, 7, 8, 'Better is the end of a thing than the beginning thereof: and the patient in spirit is better than the proud in spirit.'),
  ('KJV', 'Ecclesiastes', 21, 7, 9, 'Be not hasty in thy spirit to be angry: for anger resteth in the bosom of fools.'),
  ('KJV', 'Ecclesiastes', 21, 7, 10, 'Say not thou, What is the cause that the former days were better than these? for thou dost not enquire wisely concerning this.'),
  ('KJV', 'Ecclesiastes', 21, 7, 11, 'Wisdom is good with an inheritance: and by it there is profit to them that see the sun.'),
  ('KJV', 'Ecclesiastes', 21, 7, 12, 'For wisdom is a defence, and money is a defence: but the excellency of knowledge is, that wisdom giveth life to them that have it.'),
  ('KJV', 'Ecclesiastes', 21, 7, 13, 'Consider the work of God: for who can make that straight, which he hath made crooked?'),
  ('KJV', 'Ecclesiastes', 21, 7, 14, 'In the day of prosperity be joyful, but in the day of adversity consider: God also hath set the one over against the other, to the end that man should find nothing after him.'),
  ('KJV', 'Ecclesiastes', 21, 7, 15, 'All things have I seen in the days of my vanity: there is a just man that perisheth in his righteousness, and there is a wicked man that prolongeth his life in his wickedness.'),
  ('KJV', 'Ecclesiastes', 21, 7, 16, 'Be not righteous over much; neither make thyself over wise: why shouldest thou destroy thyself?'),
  ('KJV', 'Ecclesiastes', 21, 7, 17, 'Be not over much wicked, neither be thou foolish: why shouldest thou die before thy time?'),
  ('KJV', 'Ecclesiastes', 21, 7, 18, 'It is good that thou shouldest take hold of this; yea, also from this withdraw not thine hand: for he that feareth God shall come forth of them all.'),
  ('KJV', 'Ecclesiastes', 21, 7, 19, 'Wisdom strengtheneth the wise more than ten mighty men which are in the city.'),
  ('KJV', 'Ecclesiastes', 21, 7, 20, 'For there is not a just man upon earth, that doeth good, and sinneth not.'),
  ('KJV', 'Ecclesiastes', 21, 7, 21, 'Also take no heed unto all words that are spoken; lest thou hear thy servant curse thee:'),
  ('KJV', 'Ecclesiastes', 21, 7, 22, 'For oftentimes also thine own heart knoweth that thou thyself likewise hast cursed others.'),
  ('KJV', 'Ecclesiastes', 21, 7, 23, 'All this have I proved by wisdom: I said, I will be wise; but it was far from me.'),
  ('KJV', 'Ecclesiastes', 21, 7, 24, 'That which is far off, and exceeding deep, who can find it out?'),
  ('KJV', 'Ecclesiastes', 21, 7, 25, 'I applied mine heart to know, and to search, and to seek out wisdom, and the reason of things, and to know the wickedness of folly, even of foolishness and madness:'),
  ('KJV', 'Ecclesiastes', 21, 7, 26, 'And I find more bitter than death the woman, whose heart is snares and nets, and her hands as bands: whoso pleaseth God shall escape from her; but the sinner shall be taken by her.'),
  ('KJV', 'Ecclesiastes', 21, 7, 27, 'Behold, this have I found, saith the preacher, counting one by one, to find out the account:'),
  ('KJV', 'Ecclesiastes', 21, 7, 28, 'Which yet my soul seeketh, but I find not: one man among a thousand have I found; but a woman among all those have I not found.'),
  ('KJV', 'Ecclesiastes', 21, 7, 29, 'Lo, this only have I found, that God hath made man upright; but they have sought out many inventions.'),
  ('KJV', 'Ecclesiastes', 21, 8, 1, 'Who is as the wise man? and who knoweth the interpretation of a thing? a man''s wisdom maketh his face to shine, and the boldness of his face shall be changed.'),
  ('KJV', 'Ecclesiastes', 21, 8, 2, 'I counsel thee to keep the king''s commandment, and that in regard of the oath of God.'),
  ('KJV', 'Ecclesiastes', 21, 8, 3, 'Be not hasty to go out of his sight: stand not in an evil thing; for he doeth whatsoever pleaseth him.'),
  ('KJV', 'Ecclesiastes', 21, 8, 4, 'Where the word of a king is, there is power: and who may say unto him, What doest thou?'),
  ('KJV', 'Ecclesiastes', 21, 8, 5, 'Whoso keepeth the commandment shall feel no evil thing: and a wise man''s heart discerneth both time and judgment.'),
  ('KJV', 'Ecclesiastes', 21, 8, 6, 'Because to every purpose there is time and judgment, therefore the misery of man is great upon him.'),
  ('KJV', 'Ecclesiastes', 21, 8, 7, 'For he knoweth not that which shall be: for who can tell him when it shall be?'),
  ('KJV', 'Ecclesiastes', 21, 8, 8, 'There is no man that hath power over the spirit to retain the spirit; neither hath he power in the day of death: and there is no discharge in that war; neither shall wickedness deliver those that are given to it.'),
  ('KJV', 'Ecclesiastes', 21, 8, 9, 'All this have I seen, and applied my heart unto every work that is done under the sun: there is a time wherein one man ruleth over another to his own hurt.'),
  ('KJV', 'Ecclesiastes', 21, 8, 10, 'And so I saw the wicked buried, who had come and gone from the place of the holy, and they were forgotten in the city where they had so done: this is also vanity.'),
  ('KJV', 'Ecclesiastes', 21, 8, 11, 'Because sentence against an evil work is not executed speedily, therefore the heart of the sons of men is fully set in them to do evil.'),
  ('KJV', 'Ecclesiastes', 21, 8, 12, 'Though a sinner do evil an hundred times, and his days be prolonged, yet surely I know that it shall be well with them that fear God, which fear before him:'),
  ('KJV', 'Ecclesiastes', 21, 8, 13, 'But it shall not be well with the wicked, neither shall he prolong his days, which are as a shadow; because he feareth not before God.'),
  ('KJV', 'Ecclesiastes', 21, 8, 14, 'There is a vanity which is done upon the earth; that there be just men, unto whom it happeneth according to the work of the wicked; again, there be wicked men, to whom it happeneth according to the work of the righteous: I said that this also is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 8, 15, 'Then I commended mirth, because a man hath no better thing under the sun, than to eat, and to drink, and to be merry: for that shall abide with him of his labour the days of his life, which God giveth him under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 8, 16, 'When I applied mine heart to know wisdom, and to see the business that is done upon the earth: (for also there is that neither day nor night seeth sleep with his eyes:)'),
  ('KJV', 'Ecclesiastes', 21, 8, 17, 'Then I beheld all the work of God, that a man cannot find out the work that is done under the sun: because though a man labour to seek it out, yet he shall not find it; yea further; though a wise man think to know it, yet shall he not be able to find it.'),
  ('KJV', 'Ecclesiastes', 21, 9, 1, 'For all this I considered in my heart even to declare all this, that the righteous, and the wise, and their works, are in the hand of God: no man knoweth either love or hatred by all that is before them.'),
  ('KJV', 'Ecclesiastes', 21, 9, 2, 'All things come alike to all: there is one event to the righteous, and to the wicked; to the good and to the clean, and to the unclean; to him that sacrificeth, and to him that sacrificeth not: as is the good, so is the sinner; and he that sweareth, as he that feareth an oath.'),
  ('KJV', 'Ecclesiastes', 21, 9, 3, 'This is an evil among all things that are done under the sun, that there is one event unto all: yea, also the heart of the sons of men is full of evil, and madness is in their heart while they live, and after that they go to the dead.'),
  ('KJV', 'Ecclesiastes', 21, 9, 4, 'For to him that is joined to all the living there is hope: for a living dog is better than a dead lion.'),
  ('KJV', 'Ecclesiastes', 21, 9, 5, 'For the living know that they shall die: but the dead know not any thing, neither have they any more a reward; for the memory of them is forgotten.'),
  ('KJV', 'Ecclesiastes', 21, 9, 6, 'Also their love, and their hatred, and their envy, is now perished; neither have they any more a portion for ever in any thing that is done under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 9, 7, 'Go thy way, eat thy bread with joy, and drink thy wine with a merry heart; for God now accepteth thy works.'),
  ('KJV', 'Ecclesiastes', 21, 9, 8, 'Let thy garments be always white; and let thy head lack no ointment.'),
  ('KJV', 'Ecclesiastes', 21, 9, 9, 'Live joyfully with the wife whom thou lovest all the days of the life of thy vanity, which he hath given thee under the sun, all the days of thy vanity: for that is thy portion in this life, and in thy labour which thou takest under the sun.'),
  ('KJV', 'Ecclesiastes', 21, 9, 10, 'Whatsoever thy hand findeth to do, do it with thy might; for there is no work, nor device, nor knowledge, nor wisdom, in the grave, whither thou goest.'),
  ('KJV', 'Ecclesiastes', 21, 9, 11, 'I returned, and saw under the sun, that the race is not to the swift, nor the battle to the strong, neither yet bread to the wise, nor yet riches to men of understanding, nor yet favour to men of skill; but time and chance happeneth to them all.'),
  ('KJV', 'Ecclesiastes', 21, 9, 12, 'For man also knoweth not his time: as the fishes that are taken in an evil net, and as the birds that are caught in the snare; so are the sons of men snared in an evil time, when it falleth suddenly upon them.'),
  ('KJV', 'Ecclesiastes', 21, 9, 13, 'This wisdom have I seen also under the sun, and it seemed great unto me:'),
  ('KJV', 'Ecclesiastes', 21, 9, 14, 'There was a little city, and few men within it; and there came a great king against it, and besieged it, and built great bulwarks against it:'),
  ('KJV', 'Ecclesiastes', 21, 9, 15, 'Now there was found in it a poor wise man, and he by his wisdom delivered the city; yet no man remembered that same poor man.'),
  ('KJV', 'Ecclesiastes', 21, 9, 16, 'Then said I, Wisdom is better than strength: nevertheless the poor man''s wisdom is despised, and his words are not heard.'),
  ('KJV', 'Ecclesiastes', 21, 9, 17, 'The words of wise men are heard in quiet more than the cry of him that ruleth among fools.'),
  ('KJV', 'Ecclesiastes', 21, 9, 18, 'Wisdom is better than weapons of war: but one sinner destroyeth much good.'),
  ('KJV', 'Ecclesiastes', 21, 10, 1, 'Dead flies cause the ointment of the apothecary to send forth a stinking savour: so doth a little folly him that is in reputation for wisdom and honour.'),
  ('KJV', 'Ecclesiastes', 21, 10, 2, 'A wise man''s heart is at his right hand; but a fool''s heart at his left.'),
  ('KJV', 'Ecclesiastes', 21, 10, 3, 'Yea also, when he that is a fool walketh by the way, his wisdom faileth him, and he saith to every one that he is a fool.'),
  ('KJV', 'Ecclesiastes', 21, 10, 4, 'If the spirit of the ruler rise up against thee, leave not thy place; for yielding pacifieth great offences.'),
  ('KJV', 'Ecclesiastes', 21, 10, 5, 'There is an evil which I have seen under the sun, as an error which proceedeth from the ruler:'),
  ('KJV', 'Ecclesiastes', 21, 10, 6, 'Folly is set in great dignity, and the rich sit in low place.')
insert into control_room_bible (version, book, book_num, chapter, verse, text) values
  ('KJV', 'Ecclesiastes', 21, 10, 7, 'I have seen servants upon horses, and princes walking as servants upon the earth.'),
  ('KJV', 'Ecclesiastes', 21, 10, 8, 'He that diggeth a pit shall fall into it; and whoso breaketh an hedge, a serpent shall bite him.'),
  ('KJV', 'Ecclesiastes', 21, 10, 9, 'Whoso removeth stones shall be hurt therewith; and he that cleaveth wood shall be endangered thereby.'),
  ('KJV', 'Ecclesiastes', 21, 10, 10, 'If the iron be blunt, and he do not whet the edge, then must he put to more strength: but wisdom is profitable to direct.'),
  ('KJV', 'Ecclesiastes', 21, 10, 11, 'Surely the serpent will bite without enchantment; and a babbler is no better.'),
  ('KJV', 'Ecclesiastes', 21, 10, 12, 'The words of a wise man''s mouth are gracious; but the lips of a fool will swallow up himself.'),
  ('KJV', 'Ecclesiastes', 21, 10, 13, 'The beginning of the words of his mouth is foolishness: and the end of his talk is mischievous madness.'),
  ('KJV', 'Ecclesiastes', 21, 10, 14, 'A fool also is full of words: a man cannot tell what shall be; and what shall be after him, who can tell him?'),
  ('KJV', 'Ecclesiastes', 21, 10, 15, 'The labour of the foolish wearieth every one of them, because he knoweth not how to go to the city.'),
  ('KJV', 'Ecclesiastes', 21, 10, 16, 'Woe to thee, O land, when thy king is a child, and thy princes eat in the morning!'),
  ('KJV', 'Ecclesiastes', 21, 10, 17, 'Blessed art thou, O land, when thy king is the son of nobles, and thy princes eat in due season, for strength, and not for drunkenness!'),
  ('KJV', 'Ecclesiastes', 21, 10, 18, 'By much slothfulness the building decayeth; and through idleness of the hands the house droppeth through.'),
  ('KJV', 'Ecclesiastes', 21, 10, 19, 'A feast is made for laughter, and wine maketh merry: but money answereth all things.'),
  ('KJV', 'Ecclesiastes', 21, 10, 20, 'Curse not the king, no not in thy thought; and curse not the rich in thy bedchamber: for a bird of the air shall carry the voice, and that which hath wings shall tell the matter.'),
  ('KJV', 'Ecclesiastes', 21, 11, 1, 'Cast thy bread upon the waters: for thou shalt find it after many days.'),
  ('KJV', 'Ecclesiastes', 21, 11, 2, 'Give a portion to seven, and also to eight; for thou knowest not what evil shall be upon the earth.'),
  ('KJV', 'Ecclesiastes', 21, 11, 3, 'If the clouds be full of rain, they empty themselves upon the earth: and if the tree fall toward the south, or toward the north, in the place where the tree falleth, there it shall be.'),
  ('KJV', 'Ecclesiastes', 21, 11, 4, 'He that observeth the wind shall not sow; and he that regardeth the clouds shall not reap.'),
  ('KJV', 'Ecclesiastes', 21, 11, 5, 'As thou knowest not what is the way of the spirit, nor how the bones do grow in the womb of her that is with child: even so thou knowest not the works of God who maketh all.'),
  ('KJV', 'Ecclesiastes', 21, 11, 6, 'In the morning sow thy seed, and in the evening withhold not thine hand: for thou knowest not whether shall prosper, either this or that, or whether they both shall be alike good.'),
  ('KJV', 'Ecclesiastes', 21, 11, 7, 'Truly the light is sweet, and a pleasant thing it is for the eyes to behold the sun:'),
  ('KJV', 'Ecclesiastes', 21, 11, 8, 'But if a man live many years, and rejoice in them all; yet let him remember the days of darkness; for they shall be many. All that cometh is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 11, 9, 'Rejoice, O young man, in thy youth; and let thy heart cheer thee in the days of thy youth, and walk in the ways of thine heart, and in the sight of thine eyes: but know thou, that for all these things God will bring thee into judgment.'),
  ('KJV', 'Ecclesiastes', 21, 11, 10, 'Therefore remove sorrow from thy heart, and put away evil from thy flesh: for childhood and youth are vanity.'),
  ('KJV', 'Ecclesiastes', 21, 12, 1, 'Remember now thy Creator in the days of thy youth, while the evil days come not, nor the years draw nigh, when thou shalt say, I have no pleasure in them;'),
  ('KJV', 'Ecclesiastes', 21, 12, 2, 'While the sun, or the light, or the moon, or the stars, be not darkened, nor the clouds return after the rain:'),
  ('KJV', 'Ecclesiastes', 21, 12, 3, 'In the day when the keepers of the house shall tremble, and the strong men shall bow themselves, and the grinders cease because they are few, and those that look out of the windows be darkened,'),
  ('KJV', 'Ecclesiastes', 21, 12, 4, 'And the doors shall be shut in the streets, when the sound of the grinding is low, and he shall rise up at the voice of the bird, and all the daughters of musick shall be brought low;'),
  ('KJV', 'Ecclesiastes', 21, 12, 5, 'Also when they shall be afraid of that which is high, and fears shall be in the way, and the almond tree shall flourish, and the grasshopper shall be a burden, and desire shall fail: because man goeth to his long home, and the mourners go about the streets:'),
  ('KJV', 'Ecclesiastes', 21, 12, 6, 'Or ever the silver cord be loosed, or the golden bowl be broken, or the pitcher be broken at the fountain, or the wheel broken at the cistern.'),
  ('KJV', 'Ecclesiastes', 21, 12, 7, 'Then shall the dust return to the earth as it was: and the spirit shall return unto God who gave it.'),
  ('KJV', 'Ecclesiastes', 21, 12, 8, 'Vanity of vanities, saith the preacher; all is vanity.'),
  ('KJV', 'Ecclesiastes', 21, 12, 9, 'And moreover, because the preacher was wise, he still taught the people knowledge; yea, he gave good heed, and sought out, and set in order many proverbs.'),
  ('KJV', 'Ecclesiastes', 21, 12, 10, 'The preacher sought to find out acceptable words: and that which was written was upright, even words of truth.'),
  ('KJV', 'Ecclesiastes', 21, 12, 11, 'The words of the wise are as goads, and as nails fastened by the masters of assemblies, which are given from one shepherd.'),
  ('KJV', 'Ecclesiastes', 21, 12, 12, 'And further, by these, my son, be admonished: of making many books there is no end; and much study is a weariness of the flesh.'),
  ('KJV', 'Ecclesiastes', 21, 12, 13, 'Let us hear the conclusion of the whole matter: Fear God, and keep his commandments: for this is the whole duty of man.'),
  ('KJV', 'Ecclesiastes', 21, 12, 14, 'For God shall bring every work into judgment, with every secret thing, whether it be good, or whether it be evil.'),
  ('KJV', 'Song of Solomon', 22, 1, 1, 'The song of songs, which is Solomon''s.'),
  ('KJV', 'Song of Solomon', 22, 1, 2, 'Let him kiss me with the kisses of his mouth: for thy love is better than wine.'),
  ('KJV', 'Song of Solomon', 22, 1, 3, 'Because of the savour of thy good ointments thy name is as ointment poured forth, therefore do the virgins love thee.'),
  ('KJV', 'Song of Solomon', 22, 1, 4, 'Draw me, we will run after thee: the king hath brought me into his chambers: we will be glad and rejoice in thee, we will remember thy love more than wine: the upright love thee.'),
  ('KJV', 'Song of Solomon', 22, 1, 5, 'I am black, but comely, O ye daughters of Jerusalem, as the tents of Kedar, as the curtains of Solomon.'),
  ('KJV', 'Song of Solomon', 22, 1, 6, 'Look not upon me, because I am black, because the sun hath looked upon me: my mother''s children were angry with me; they made me the keeper of the vineyards; but mine own vineyard have I not kept.'),
  ('KJV', 'Song of Solomon', 22, 1, 7, 'Tell me, O thou whom my soul loveth, where thou feedest, where thou makest thy flock to rest at noon: for why should I be as one that turneth aside by the flocks of thy companions?'),
  ('KJV', 'Song of Solomon', 22, 1, 8, 'If thou know not, O thou fairest among women, go thy way forth by the footsteps of the flock, and feed thy kids beside the shepherds'' tents.'),
  ('KJV', 'Song of Solomon', 22, 1, 9, 'I have compared thee, O my love, to a company of horses in Pharaoh''s chariots.'),
  ('KJV', 'Song of Solomon', 22, 1, 10, 'Thy cheeks are comely with rows of jewels, thy neck with chains of gold.'),
  ('KJV', 'Song of Solomon', 22, 1, 11, 'We will make thee borders of gold with studs of silver.'),
  ('KJV', 'Song of Solomon', 22, 1, 12, 'While the king sitteth at his table, my spikenard sendeth forth the smell thereof.'),
  ('KJV', 'Song of Solomon', 22, 1, 13, 'A bundle of myrrh is my wellbeloved unto me; he shall lie all night betwixt my breasts.'),
  ('KJV', 'Song of Solomon', 22, 1, 14, 'My beloved is unto me as a cluster of camphire in the vineyards of Engedi.'),
  ('KJV', 'Song of Solomon', 22, 1, 15, 'Behold, thou art fair, my love; behold, thou art fair; thou hast doves'' eyes.'),
  ('KJV', 'Song of Solomon', 22, 1, 16, 'Behold, thou art fair, my beloved, yea, pleasant: also our bed is green.'),
  ('KJV', 'Song of Solomon', 22, 1, 17, 'The beams of our house are cedar, and our rafters of fir.'),
  ('KJV', 'Song of Solomon', 22, 2, 1, 'I am the rose of Sharon, and the lily of the valleys.'),
  ('KJV', 'Song of Solomon', 22, 2, 2, 'As the lily among thorns, so is my love among the daughters.'),
  ('KJV', 'Song of Solomon', 22, 2, 3, 'As the apple tree among the trees of the wood, so is my beloved among the sons. I sat down under his shadow with great delight, and his fruit was sweet to my taste.'),
  ('KJV', 'Song of Solomon', 22, 2, 4, 'He brought me to the banqueting house, and his banner over me was love.'),
  ('KJV', 'Song of Solomon', 22, 2, 5, 'Stay me with flagons, comfort me with apples: for I am sick of love.'),
  ('KJV', 'Song of Solomon', 22, 2, 6, 'His left hand is under my head, and his right hand doth embrace me.'),
  ('KJV', 'Song of Solomon', 22, 2, 7, 'I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.'),
  ('KJV', 'Song of Solomon', 22, 2, 8, 'The voice of my beloved! behold, he cometh leaping upon the mountains, skipping upon the hills.'),
  ('KJV', 'Song of Solomon', 22, 2, 9, 'My beloved is like a roe or a young hart: behold, he standeth behind our wall, he looketh forth at the windows, shewing himself through the lattice.'),
  ('KJV', 'Song of Solomon', 22, 2, 10, 'My beloved spake, and said unto me, Rise up, my love, my fair one, and come away.'),
  ('KJV', 'Song of Solomon', 22, 2, 11, 'For, lo, the winter is past, the rain is over and gone;'),
  ('KJV', 'Song of Solomon', 22, 2, 12, 'The flowers appear on the earth; the time of the singing of birds is come, and the voice of the turtle is heard in our land;'),
  ('KJV', 'Song of Solomon', 22, 2, 13, 'The fig tree putteth forth her green figs, and the vines with the tender grape give a good smell. Arise, my love, my fair one, and come away.'),
  ('KJV', 'Song of Solomon', 22, 2, 14, 'O my dove, that art in the clefts of the rock, in the secret places of the stairs, let me see thy countenance, let me hear thy voice; for sweet is thy voice, and thy countenance is comely.'),
  ('KJV', 'Song of Solomon', 22, 2, 15, 'Take us the foxes, the little foxes, that spoil the vines: for our vines have tender grapes.'),
  ('KJV', 'Song of Solomon', 22, 2, 16, 'My beloved is mine, and I am his: he feedeth among the lilies.'),
  ('KJV', 'Song of Solomon', 22, 2, 17, 'Until the day break, and the shadows flee away, turn, my beloved, and be thou like a roe or a young hart upon the mountains of Bether.'),
  ('KJV', 'Song of Solomon', 22, 3, 1, 'By night on my bed I sought him whom my soul loveth: I sought him, but I found him not.'),
  ('KJV', 'Song of Solomon', 22, 3, 2, 'I will rise now, and go about the city in the streets, and in the broad ways I will seek him whom my soul loveth: I sought him, but I found him not.'),
  ('KJV', 'Song of Solomon', 22, 3, 3, 'The watchmen that go about the city found me: to whom I said, Saw ye him whom my soul loveth?'),
  ('KJV', 'Song of Solomon', 22, 3, 4, 'It was but a little that I passed from them, but I found him whom my soul loveth: I held him, and would not let him go, until I had brought him into my mother''s house, and into the chamber of her that conceived me.'),
  ('KJV', 'Song of Solomon', 22, 3, 5, 'I charge you, O ye daughters of Jerusalem, by the roes, and by the hinds of the field, that ye stir not up, nor awake my love, till he please.'),
  ('KJV', 'Song of Solomon', 22, 3, 6, 'Who is this that cometh out of the wilderness like pillars of smoke, perfumed with myrrh and frankincense, with all powders of the merchant?'),
  ('KJV', 'Song of Solomon', 22, 3, 7, 'Behold his bed, which is Solomon''s; threescore valiant men are about it, of the valiant of Israel.'),
  ('KJV', 'Song of Solomon', 22, 3, 8, 'They all hold swords, being expert in war: every man hath his sword upon his thigh because of fear in the night.'),
  ('KJV', 'Song of Solomon', 22, 3, 9, 'King Solomon made himself a chariot of the wood of Lebanon.'),
  ('KJV', 'Song of Solomon', 22, 3, 10, 'He made the pillars thereof of silver, the bottom thereof of gold, the covering of it of purple, the midst thereof being paved with love, for the daughters of Jerusalem.'),
  ('KJV', 'Song of Solomon', 22, 3, 11, 'Go forth, O ye daughters of Zion, and behold king Solomon with the crown wherewith his mother crowned him in the day of his espousals, and in the day of the gladness of his heart.'),
  ('KJV', 'Song of Solomon', 22, 4, 1, 'Behold, thou art fair, my love; behold, thou art fair; thou hast doves'' eyes within thy locks: thy hair is as a flock of goats, that appear from mount Gilead.'),
  ('KJV', 'Song of Solomon', 22, 4, 2, 'Thy teeth are like a flock of sheep that are even shorn, which came up from the washing; whereof every one bear twins, and none is barren among them.'),
  ('KJV', 'Song of Solomon', 22, 4, 3, 'Thy lips are like a thread of scarlet, and thy speech is comely: thy temples are like a piece of a pomegranate within thy locks.'),
  ('KJV', 'Song of Solomon', 22, 4, 4, 'Thy neck is like the tower of David builded for an armoury, whereon there hang a thousand bucklers, all shields of mighty men.'),
  ('KJV', 'Song of Solomon', 22, 4, 5, 'Thy two breasts are like two young roes that are twins, which feed among the lilies.'),
  ('KJV', 'Song of Solomon', 22, 4, 6, 'Until the day break, and the shadows flee away, I will get me to the mountain of myrrh, and to the hill of frankincense.'),
  ('KJV', 'Song of Solomon', 22, 4, 7, 'Thou art all fair, my love; there is no spot in thee.'),
  ('KJV', 'Song of Solomon', 22, 4, 8, 'Come with me from Lebanon, my spouse, with me from Lebanon: look from the top of Amana, from the top of Shenir and Hermon, from the lions'' dens, from the mountains of the leopards.'),
  ('KJV', 'Song of Solomon', 22, 4, 9, 'Thou hast ravished my heart, my sister, my spouse; thou hast ravished my heart with one of thine eyes, with one chain of thy neck.'),
  ('KJV', 'Song of Solomon', 22, 4, 10, 'How fair is thy love, my sister, my spouse! how much better is thy love than wine! and the smell of thine ointments than all spices!'),
  ('KJV', 'Song of Solomon', 22, 4, 11, 'Thy lips, O my spouse, drop as the honeycomb: honey and milk are under thy tongue; and the smell of thy garments is like the smell of Lebanon.'),
  ('KJV', 'Song of Solomon', 22, 4, 12, 'A garden inclosed is my sister, my spouse; a spring shut up, a fountain sealed.'),
  ('KJV', 'Song of Solomon', 22, 4, 13, 'Thy plants are an orchard of pomegranates, with pleasant fruits; camphire, with spikenard,'),
  ('KJV', 'Song of Solomon', 22, 4, 14, 'Spikenard and saffron; calamus and cinnamon, with all trees of frankincense; myrrh and aloes, with all the chief spices:'),
  ('KJV', 'Song of Solomon', 22, 4, 15, 'A fountain of gardens, a well of living waters, and streams from Lebanon.'),
  ('KJV', 'Song of Solomon', 22, 4, 16, 'Awake, O north wind; and come, thou south; blow upon my garden, that the spices thereof may flow out. Let my beloved come into his garden, and eat his pleasant fruits.'),
  ('KJV', 'Song of Solomon', 22, 5, 1, 'I am come into my garden, my sister, my spouse: I have gathered my myrrh with my spice; I have eaten my honeycomb with my honey; I have drunk my wine with my milk: eat, O friends; drink, yea, drink abundantly, O beloved.'),
  ('KJV', 'Song of Solomon', 22, 5, 2, 'I sleep, but my heart waketh: it is the voice of my beloved that knocketh, saying, Open to me, my sister, my love, my dove, my undefiled: for my head is filled with dew, and my locks with the drops of the night.'),
  ('KJV', 'Song of Solomon', 22, 5, 3, 'I have put off my coat; how shall I put it on? I have washed my feet; how shall I defile them?'),
  ('KJV', 'Song of Solomon', 22, 5, 4, 'My beloved put in his hand by the hole of the door, and my bowels were moved for him.'),
  ('KJV', 'Song of Solomon', 22, 5, 5, 'I rose up to open to my beloved; and my hands dropped with myrrh, and my fingers with sweet smelling myrrh, upon the handles of the lock.'),
  ('KJV', 'Song of Solomon', 22, 5, 6, 'I opened to my beloved; but my beloved had withdrawn himself, and was gone: my soul failed when he spake: I sought him, but I could not find him; I called him, but he gave me no answer.'),
  ('KJV', 'Song of Solomon', 22, 5, 7, 'The watchmen that went about the city found me, they smote me, they wounded me; the keepers of the walls took away my veil from me.'),
  ('KJV', 'Song of Solomon', 22, 5, 8, 'I charge you, O daughters of Jerusalem, if ye find my beloved, that ye tell him, that I am sick of love.'),
  ('KJV', 'Song of Solomon', 22, 5, 9, 'What is thy beloved more than another beloved, O thou fairest among women? what is thy beloved more than another beloved, that thou dost so charge us?'),
  ('KJV', 'Song of Solomon', 22, 5, 10, 'My beloved is white and ruddy, the chiefest among ten thousand.'),
  ('KJV', 'Song of Solomon', 22, 5, 11, 'His head is as the most fine gold, his locks are bushy, and black as a raven.'),
  ('KJV', 'Song of Solomon', 22, 5, 12, 'His eyes are as the eyes of doves by the rivers of waters, washed with milk, and fitly set.'),
  ('KJV', 'Song of Solomon', 22, 5, 13, 'His cheeks are as a bed of spices, as sweet flowers: his lips like lilies, dropping sweet smelling myrrh.'),
  ('KJV', 'Song of Solomon', 22, 5, 14, 'His hands are as gold rings set with the beryl: his belly is as bright ivory overlaid with sapphires.'),
  ('KJV', 'Song of Solomon', 22, 5, 15, 'His legs are as pillars of marble, set upon sockets of fine gold: his countenance is as Lebanon, excellent as the cedars.'),
  ('KJV', 'Song of Solomon', 22, 5, 16, 'His mouth is most sweet: yea, he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem.'),
  ('KJV', 'Song of Solomon', 22, 6, 1, 'Whither is thy beloved gone, O thou fairest among women? whither is thy beloved turned aside? that we may seek him with thee.'),
  ('KJV', 'Song of Solomon', 22, 6, 2, 'My beloved is gone down into his garden, to the beds of spices, to feed in the gardens, and to gather lilies.'),
  ('KJV', 'Song of Solomon', 22, 6, 3, 'I am my beloved''s, and my beloved is mine: he feedeth among the lilies.'),
  ('KJV', 'Song of Solomon', 22, 6, 4, 'Thou art beautiful, O my love, as Tirzah, comely as Jerusalem, terrible as an army with banners.'),
  ('KJV', 'Song of Solomon', 22, 6, 5, 'Turn away thine eyes from me, for they have overcome me: thy hair is as a flock of goats that appear from Gilead.'),
  ('KJV', 'Song of Solomon', 22, 6, 6, 'Thy teeth are as a flock of sheep which go up from the washing, whereof every one beareth twins, and there is not one barren among them.'),
  ('KJV', 'Song of Solomon', 22, 6, 7, 'As a piece of a pomegranate are thy temples within thy locks.'),
  ('KJV', 'Song of Solomon', 22, 6, 8, 'There are threescore queens, and fourscore concubines, and virgins without number.'),
  ('KJV', 'Song of Solomon', 22, 6, 9, 'My dove, my undefiled is but one; she is the only one of her mother, she is the choice one of her that bare her. The daughters saw her, and blessed her; yea, the queens and the concubines, and they praised her.'),
  ('KJV', 'Song of Solomon', 22, 6, 10, 'Who is she that looketh forth as the morning, fair as the moon, clear as the sun, and terrible as an army with banners?'),
  ('KJV', 'Song of Solomon', 22, 6, 11, 'I went down into the garden of nuts to see the fruits of the valley, and to see whether the vine flourished, and the pomegranates budded.'),
  ('KJV', 'Song of Solomon', 22, 6, 12, 'Or ever I was aware, my soul made me like the chariots of Amminadib.'),
  ('KJV', 'Song of Solomon', 22, 6, 13, 'Return, return, O Shulamite; return, return, that we may look upon thee. What will ye see in the Shulamite? As it were the company of two armies.'),
  ('KJV', 'Song of Solomon', 22, 7, 1, 'How beautiful are thy feet with shoes, O prince''s daughter! the joints of thy thighs are like jewels, the work of the hands of a cunning workman.'),
  ('KJV', 'Song of Solomon', 22, 7, 2, 'Thy navel is like a round goblet, which wanteth not liquor: thy belly is like an heap of wheat set about with lilies.'),
  ('KJV', 'Song of Solomon', 22, 7, 3, 'Thy two breasts are like two young roes that are twins.'),
  ('KJV', 'Song of Solomon', 22, 7, 4, 'Thy neck is as a tower of ivory; thine eyes like the fishpools in Heshbon, by the gate of Bathrabbim: thy nose is as the tower of Lebanon which looketh toward Damascus.'),
  ('KJV', 'Song of Solomon', 22, 7, 5, 'Thine head upon thee is like Carmel, and the hair of thine head like purple; the king is held in the galleries.'),
  ('KJV', 'Song of Solomon', 22, 7, 6, 'How fair and how pleasant art thou, O love, for delights!'),
  ('KJV', 'Song of Solomon', 22, 7, 7, 'This thy stature is like to a palm tree, and thy breasts to clusters of grapes.'),
  ('KJV', 'Song of Solomon', 22, 7, 8, 'I said, I will go up to the palm tree, I will take hold of the boughs thereof: now also thy breasts shall be as clusters of the vine, and the smell of thy nose like apples;'),
  ('KJV', 'Song of Solomon', 22, 7, 9, 'And the roof of thy mouth like the best wine for my beloved, that goeth down sweetly, causing the lips of those that are asleep to speak.'),
  ('KJV', 'Song of Solomon', 22, 7, 10, 'I am my beloved''s, and his desire is toward me.'),
  ('KJV', 'Song of Solomon', 22, 7, 11, 'Come, my beloved, let us go forth into the field; let us lodge in the villages.'),
  ('KJV', 'Song of Solomon', 22, 7, 12, 'Let us get up early to the vineyards; let us see if the vine flourish, whether the tender grape appear, and the pomegranates bud forth: there will I give thee my loves.'),
  ('KJV', 'Song of Solomon', 22, 7, 13, 'The mandrakes give a smell, and at our gates are all manner of pleasant fruits, new and old, which I have laid up for thee, O my beloved.'),
  ('KJV', 'Song of Solomon', 22, 8, 1, 'O that thou wert as my brother, that sucked the breasts of my mother! when I should find thee without, I would kiss thee; yea, I should not be despised.'),
  ('KJV', 'Song of Solomon', 22, 8, 2, 'I would lead thee, and bring thee into my mother''s house, who would instruct me: I would cause thee to drink of spiced wine of the juice of my pomegranate.'),
  ('KJV', 'Song of Solomon', 22, 8, 3, 'His left hand should be under my head, and his right hand should embrace me.'),
  ('KJV', 'Song of Solomon', 22, 8, 4, 'I charge you, O daughters of Jerusalem, that ye stir not up, nor awake my love, until he please.'),
  ('KJV', 'Song of Solomon', 22, 8, 5, 'Who is this that cometh up from the wilderness, leaning upon her beloved? I raised thee up under the apple tree: there thy mother brought thee forth: there she brought thee forth that bare thee.'),
  ('KJV', 'Song of Solomon', 22, 8, 6, 'Set me as a seal upon thine heart, as a seal upon thine arm: for love is strong as death; jealousy is cruel as the grave: the coals thereof are coals of fire, which hath a most vehement flame.'),
  ('KJV', 'Song of Solomon', 22, 8, 7, 'Many waters cannot quench love, neither can the floods drown it: if a man would give all the substance of his house for love, it would utterly be contemned.'),
  ('KJV', 'Song of Solomon', 22, 8, 8, 'We have a little sister, and she hath no breasts: what shall we do for our sister in the day when she shall be spoken for?'),
  ('KJV', 'Song of Solomon', 22, 8, 9, 'If she be a wall, we will build upon her a palace of silver: and if she be a door, we will inclose her with boards of cedar.'),
  ('KJV', 'Song of Solomon', 22, 8, 10, 'I am a wall, and my breasts like towers: then was I in his eyes as one that found favour.'),
  ('KJV', 'Song of Solomon', 22, 8, 11, 'Solomon had a vineyard at Baalhamon; he let out the vineyard unto keepers; every one for the fruit thereof was to bring a thousand pieces of silver.'),
  ('KJV', 'Song of Solomon', 22, 8, 12, 'My vineyard, which is mine, is before me: thou, O Solomon, must have a thousand, and those that keep the fruit thereof two hundred.'),
  ('KJV', 'Song of Solomon', 22, 8, 13, 'Thou that dwellest in the gardens, the companions hearken to thy voice: cause me to hear it.'),
  ('KJV', 'Song of Solomon', 22, 8, 14, 'Make haste, my beloved, and be thou like to a roe or to a young hart upon the mountains of spices.'),
  ('KJV', 'Isaiah', 23, 1, 1, 'The vision of Isaiah the son of Amoz, which he saw concerning Judah and Jerusalem in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah.'),
  ('KJV', 'Isaiah', 23, 1, 2, 'Hear, O heavens, and give ear, O earth: for the LORD hath spoken, I have nourished and brought up children, and they have rebelled against me.'),
  ('KJV', 'Isaiah', 23, 1, 3, 'The ox knoweth his owner, and the ass his master''s crib: but Israel doth not know, my people doth not consider.'),
  ('KJV', 'Isaiah', 23, 1, 4, 'Ah sinful nation, a people laden with iniquity, a seed of evildoers, children that are corrupters: they have forsaken the LORD, they have provoked the Holy One of Israel unto anger, they are gone away backward.'),
  ('KJV', 'Isaiah', 23, 1, 5, 'Why should ye be stricken any more? ye will revolt more and more: the whole head is sick, and the whole heart faint.'),
  ('KJV', 'Isaiah', 23, 1, 6, 'From the sole of the foot even unto the head there is no soundness in it; but wounds, and bruises, and putrifying sores: they have not been closed, neither bound up, neither mollified with ointment.'),
  ('KJV', 'Isaiah', 23, 1, 7, 'Your country is desolate, your cities are burned with fire: your land, strangers devour it in your presence, and it is desolate, as overthrown by strangers.'),
  ('KJV', 'Isaiah', 23, 1, 8, 'And the daughter of Zion is left as a cottage in a vineyard, as a lodge in a garden of cucumbers, as a besieged city.'),
  ('KJV', 'Isaiah', 23, 1, 9, 'Except the LORD of hosts had left unto us a very small remnant, we should have been as Sodom, and we should have been like unto Gomorrah.'),
  ('KJV', 'Isaiah', 23, 1, 10, 'Hear the word of the LORD, ye rulers of Sodom; give ear unto the law of our God, ye people of Gomorrah.'),
  ('KJV', 'Isaiah', 23, 1, 11, 'To what purpose is the multitude of your sacrifices unto me? saith the LORD: I am full of the burnt offerings of rams, and the fat of fed beasts; and I delight not in the blood of bullocks, or of lambs, or of he goats.'),
  ('KJV', 'Isaiah', 23, 1, 12, 'When ye come to appear before me, who hath required this at your hand, to tread my courts?'),
  ('KJV', 'Isaiah', 23, 1, 13, 'Bring no more vain oblations; incense is an abomination unto me; the new moons and sabbaths, the calling of assemblies, I cannot away with; it is iniquity, even the solemn meeting.'),
  ('KJV', 'Isaiah', 23, 1, 14, 'Your new moons and your appointed feasts my soul hateth: they are a trouble unto me; I am weary to bear them.'),
  ('KJV', 'Isaiah', 23, 1, 15, 'And when ye spread forth your hands, I will hide mine eyes from you: yea, when ye make many prayers, I will not hear: your hands are full of blood.'),
  ('KJV', 'Isaiah', 23, 1, 16, 'Wash you, make you clean; put away the evil of your doings from before mine eyes; cease to do evil;'),
  ('KJV', 'Isaiah', 23, 1, 17, 'Learn to do well; seek judgment, relieve the oppressed, judge the fatherless, plead for the widow.'),
  ('KJV', 'Isaiah', 23, 1, 18, 'Come now, and let us reason together, saith the LORD: though your sins be as scarlet, they shall be as white as snow; though they be red like crimson, they shall be as wool.'),
  ('KJV', 'Isaiah', 23, 1, 19, 'If ye be willing and obedient, ye shall eat the good of the land:'),
  ('KJV', 'Isaiah', 23, 1, 20, 'But if ye refuse and rebel, ye shall be devoured with the sword: for the mouth of the LORD hath spoken it.'),
  ('KJV', 'Isaiah', 23, 1, 21, 'How is the faithful city become an harlot! it was full of judgment; righteousness lodged in it; but now murderers.'),
  ('KJV', 'Isaiah', 23, 1, 22, 'Thy silver is become dross, thy wine mixed with water:'),
  ('KJV', 'Isaiah', 23, 1, 23, 'Thy princes are rebellious, and companions of thieves: every one loveth gifts, and followeth after rewards: they judge not the fatherless, neither doth the cause of the widow come unto them.'),
  ('KJV', 'Isaiah', 23, 1, 24, 'Therefore saith the Lord, the LORD of hosts, the mighty One of Israel, Ah, I will ease me of mine adversaries, and avenge me of mine enemies:'),
  ('KJV', 'Isaiah', 23, 1, 25, 'And I will turn my hand upon thee, and purely purge away thy dross, and take away all thy tin:'),
  ('KJV', 'Isaiah', 23, 1, 26, 'And I will restore thy judges as at the first, and thy counsellors as at the beginning: afterward thou shalt be called, The city of righteousness, the faithful city.'),
  ('KJV', 'Isaiah', 23, 1, 27, 'Zion shall be redeemed with judgment, and her converts with righteousness.'),
  ('KJV', 'Isaiah', 23, 1, 28, 'And the destruction of the transgressors and of the sinners shall be together, and they that forsake the LORD shall be consumed.'),
  ('KJV', 'Isaiah', 23, 1, 29, 'For they shall be ashamed of the oaks which ye have desired, and ye shall be confounded for the gardens that ye have chosen.'),
  ('KJV', 'Isaiah', 23, 1, 30, 'For ye shall be as an oak whose leaf fadeth, and as a garden that hath no water.'),
  ('KJV', 'Isaiah', 23, 1, 31, 'And the strong shall be as tow, and the maker of it as a spark, and they shall both burn together, and none shall quench them.'),
  ('KJV', 'Isaiah', 23, 2, 1, 'The word that Isaiah the son of Amoz saw concerning Judah and Jerusalem.'),
  ('KJV', 'Isaiah', 23, 2, 2, 'And it shall come to pass in the last days, that the mountain of the LORD''S house shall be established in the top of the mountains, and shall be exalted above the hills; and all nations shall flow unto it.'),
  ('KJV', 'Isaiah', 23, 2, 3, 'And many people shall go and say, Come ye, and let us go up to the mountain of the LORD, to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for out of Zion shall go forth the law, and the word of the LORD from Jerusalem.'),
  ('KJV', 'Isaiah', 23, 2, 4, 'And he shall judge among the nations, and shall rebuke many people: and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up sword against nation, neither shall they learn war any more.'),
  ('KJV', 'Isaiah', 23, 2, 5, 'O house of Jacob, come ye, and let us walk in the light of the LORD.'),
  ('KJV', 'Isaiah', 23, 2, 6, 'Therefore thou hast forsaken thy people the house of Jacob, because they be replenished from the east, and are soothsayers like the Philistines, and they please themselves in the children of strangers.'),
  ('KJV', 'Isaiah', 23, 2, 7, 'Their land also is full of silver and gold, neither is there any end of their treasures; their land is also full of horses, neither is there any end of their chariots:'),
  ('KJV', 'Isaiah', 23, 2, 8, 'Their land also is full of idols; they worship the work of their own hands, that which their own fingers have made:'),
  ('KJV', 'Isaiah', 23, 2, 9, 'And the mean man boweth down, and the great man humbleth himself: therefore forgive them not.'),
  ('KJV', 'Isaiah', 23, 2, 10, 'Enter into the rock, and hide thee in the dust, for fear of the LORD, and for the glory of his majesty.'),
  ('KJV', 'Isaiah', 23, 2, 11, 'The lofty looks of man shall be humbled, and the haughtiness of men shall be bowed down, and the LORD alone shall be exalted in that day.'),
  ('KJV', 'Isaiah', 23, 2, 12, 'For the day of the LORD of hosts shall be upon every one that is proud and lofty, and upon every one that is lifted up; and he shall be brought low:'),
  ('KJV', 'Isaiah', 23, 2, 13, 'And upon all the cedars of Lebanon, that are high and lifted up, and upon all the oaks of Bashan,'),
  ('KJV', 'Isaiah', 23, 2, 14, 'And upon all the high mountains, and upon all the hills that are lifted up,'),
  ('KJV', 'Isaiah', 23, 2, 15, 'And upon every high tower, and upon every fenced wall,'),
  ('KJV', 'Isaiah', 23, 2, 16, 'And upon all the ships of Tarshish, and upon all pleasant pictures.'),
  ('KJV', 'Isaiah', 23, 2, 17, 'And the loftiness of man shall be bowed down, and the haughtiness of men shall be made low: and the LORD alone shall be exalted in that day.'),
  ('KJV', 'Isaiah', 23, 2, 18, 'And the idols he shall utterly abolish.'),
  ('KJV', 'Isaiah', 23, 2, 19, 'And they shall go into the holes of the rocks, and into the caves of the earth, for fear of the LORD, and for the glory of his majesty, when he ariseth to shake terribly the earth.'),
  ('KJV', 'Isaiah', 23, 2, 20, 'In that day a man shall cast his idols of silver, and his idols of gold, which they made each one for himself to worship, to the moles and to the bats;'),
  ('KJV', 'Isaiah', 23, 2, 21, 'To go into the clefts of the rocks, and into the tops of the ragged rocks, for fear of the LORD, and for the glory of his majesty, when he ariseth to shake terribly the earth.'),
  ('KJV', 'Isaiah', 23, 2, 22, 'Cease ye from man, whose breath is in his nostrils: for wherein is he to be accounted of?'),
  ('KJV', 'Isaiah', 23, 3, 1, 'For, behold, the Lord, the LORD of hosts, doth take away from Jerusalem and from Judah the stay and the staff, the whole stay of bread, and the whole stay of water,'),
  ('KJV', 'Isaiah', 23, 3, 2, 'The mighty man, and the man of war, the judge, and the prophet, and the prudent, and the ancient,'),
  ('KJV', 'Isaiah', 23, 3, 3, 'The captain of fifty, and the honourable man, and the counsellor, and the cunning artificer, and the eloquent orator.'),
  ('KJV', 'Isaiah', 23, 3, 4, 'And I will give children to be their princes, and babes shall rule over them.'),
  ('KJV', 'Isaiah', 23, 3, 5, 'And the people shall be oppressed, every one by another, and every one by his neighbour: the child shall behave himself proudly against the ancient, and the base against the honourable.'),
  ('KJV', 'Isaiah', 23, 3, 6, 'When a man shall take hold of his brother of the house of his father, saying, Thou hast clothing, be thou our ruler, and let this ruin be under thy hand:'),
  ('KJV', 'Isaiah', 23, 3, 7, 'In that day shall he swear, saying, I will not be an healer; for in my house is neither bread nor clothing: make me not a ruler of the people.'),
  ('KJV', 'Isaiah', 23, 3, 8, 'For Jerusalem is ruined, and Judah is fallen: because their tongue and their doings are against the LORD, to provoke the eyes of his glory.'),
  ('KJV', 'Isaiah', 23, 3, 9, 'The shew of their countenance doth witness against them; and they declare their sin as Sodom, they hide it not. Woe unto their soul! for they have rewarded evil unto themselves.'),
  ('KJV', 'Isaiah', 23, 3, 10, 'Say ye to the righteous, that it shall be well with him: for they shall eat the fruit of their doings.'),
  ('KJV', 'Isaiah', 23, 3, 11, 'Woe unto the wicked! it shall be ill with him: for the reward of his hands shall be given him.'),
  ('KJV', 'Isaiah', 23, 3, 12, 'As for my people, children are their oppressors, and women rule over them. O my people, they which lead thee cause thee to err, and destroy the way of thy paths.'),
  ('KJV', 'Isaiah', 23, 3, 13, 'The LORD standeth up to plead, and standeth to judge the people.'),
  ('KJV', 'Isaiah', 23, 3, 14, 'The LORD will enter into judgment with the ancients of his people, and the princes thereof: for ye have eaten up the vineyard; the spoil of the poor is in your houses.'),
  ('KJV', 'Isaiah', 23, 3, 15, 'What mean ye that ye beat my people to pieces, and grind the faces of the poor? saith the Lord GOD of hosts.'),
  ('KJV', 'Isaiah', 23, 3, 16, 'Moreover the LORD saith, Because the daughters of Zion are haughty, and walk with stretched forth necks and wanton eyes, walking and mincing as they go, and making a tinkling with their feet:'),
  ('KJV', 'Isaiah', 23, 3, 17, 'Therefore the Lord will smite with a scab the crown of the head of the daughters of Zion, and the LORD will discover their secret parts.'),
  ('KJV', 'Isaiah', 23, 3, 18, 'In that day the Lord will take away the bravery of their tinkling ornaments about their feet, and their cauls, and their round tires like the moon,'),
  ('KJV', 'Isaiah', 23, 3, 19, 'The chains, and the bracelets, and the mufflers,'),
  ('KJV', 'Isaiah', 23, 3, 20, 'The bonnets, and the ornaments of the legs, and the headbands, and the tablets, and the earrings,'),
  ('KJV', 'Isaiah', 23, 3, 21, 'The rings, and nose jewels,'),
  ('KJV', 'Isaiah', 23, 3, 22, 'The changeable suits of apparel, and the mantles, and the wimples, and the crisping pins,'),
  ('KJV', 'Isaiah', 23, 3, 23, 'The glasses, and the fine linen, and the hoods, and the vails.'),
  ('KJV', 'Isaiah', 23, 3, 24, 'And it shall come to pass, that instead of sweet smell there shall be stink; and instead of a girdle a rent; and instead of well set hair baldness; and instead of a stomacher a girding of sackcloth; and burning instead of beauty.'),
  ('KJV', 'Isaiah', 23, 3, 25, 'Thy men shall fall by the sword, and thy mighty in the war.'),
  ('KJV', 'Isaiah', 23, 3, 26, 'And her gates shall lament and mourn; and she being desolate shall sit upon the ground.'),
  ('KJV', 'Isaiah', 23, 4, 1, 'And in that day seven women shall take hold of one man, saying, We will eat our own bread, and wear our own apparel: only let us be called by thy name, to take away our reproach.'),
  ('KJV', 'Isaiah', 23, 4, 2, 'In that day shall the branch of the LORD be beautiful and glorious, and the fruit of the earth shall be excellent and comely for them that are escaped of Israel.'),
  ('KJV', 'Isaiah', 23, 4, 3, 'And it shall come to pass, that he that is left in Zion, and he that remaineth in Jerusalem, shall be called holy, even every one that is written among the living in Jerusalem:'),
  ('KJV', 'Isaiah', 23, 4, 4, 'When the Lord shall have washed away the filth of the daughters of Zion, and shall have purged the blood of Jerusalem from the midst thereof by the spirit of judgment, and by the spirit of burning.'),
  ('KJV', 'Isaiah', 23, 4, 5, 'And the LORD will create upon every dwelling place of mount Zion, and upon her assemblies, a cloud and smoke by day, and the shining of a flaming fire by night: for upon all the glory shall be a defence.'),
  ('KJV', 'Isaiah', 23, 4, 6, 'And there shall be a tabernacle for a shadow in the daytime from the heat, and for a place of refuge, and for a covert from storm and from rain.'),
  ('KJV', 'Isaiah', 23, 5, 1, 'Now will I sing to my wellbeloved a song of my beloved touching his vineyard. My wellbeloved hath a vineyard in a very fruitful hill:'),
  ('KJV', 'Isaiah', 23, 5, 2, 'And he fenced it, and gathered out the stones thereof, and planted it with the choicest vine, and built a tower in the midst of it, and also made a winepress therein: and he looked that it should bring forth grapes, and it brought forth wild grapes.'),
  ('KJV', 'Isaiah', 23, 5, 3, 'And now, O inhabitants of Jerusalem, and men of Judah, judge, I pray you, betwixt me and my vineyard.'),
  ('KJV', 'Isaiah', 23, 5, 4, 'What could have been done more to my vineyard, that I have not done in it? wherefore, when I looked that it should bring forth grapes, brought it forth wild grapes?'),
  ('KJV', 'Isaiah', 23, 5, 5, 'And now go to; I will tell you what I will do to my vineyard: I will take away the hedge thereof, and it shall be eaten up; and break down the wall thereof, and it shall be trodden down:'),
  ('KJV', 'Isaiah', 23, 5, 6, 'And I will lay it waste: it shall not be pruned, nor digged; but there shall come up briers and thorns: I will also command the clouds that they rain no rain upon it.'),
  ('KJV', 'Isaiah', 23, 5, 7, 'For the vineyard of the LORD of hosts is the house of Israel, and the men of Judah his pleasant plant: and he looked for judgment, but behold oppression; for righteousness, but behold a cry.'),
  ('KJV', 'Isaiah', 23, 5, 8, 'Woe unto them that join house to house, that lay field to field, till there be no place, that they may be placed alone in the midst of the earth!'),
  ('KJV', 'Isaiah', 23, 5, 9, 'In mine ears said the LORD of hosts, Of a truth many houses shall be desolate, even great and fair, without inhabitant.'),
  ('KJV', 'Isaiah', 23, 5, 10, 'Yea, ten acres of vineyard shall yield one bath, and the seed of an homer shall yield an ephah.'),
  ('KJV', 'Isaiah', 23, 5, 11, 'Woe unto them that rise up early in the morning, that they may follow strong drink; that continue until night, till wine inflame them!'),
  ('KJV', 'Isaiah', 23, 5, 12, 'And the harp, and the viol, the tabret, and pipe, and wine, are in their feasts: but they regard not the work of the LORD, neither consider the operation of his hands.'),
  ('KJV', 'Isaiah', 23, 5, 13, 'Therefore my people are gone into captivity, because they have no knowledge: and their honourable men are famished, and their multitude dried up with thirst.'),
  ('KJV', 'Isaiah', 23, 5, 14, 'Therefore hell hath enlarged herself, and opened her mouth without measure: and their glory, and their multitude, and their pomp, and he that rejoiceth, shall descend into it.'),
  ('KJV', 'Isaiah', 23, 5, 15, 'And the mean man shall be brought down, and the mighty man shall be humbled, and the eyes of the lofty shall be humbled:'),
  ('KJV', 'Isaiah', 23, 5, 16, 'But the LORD of hosts shall be exalted in judgment, and God that is holy shall be sanctified in righteousness.'),
  ('KJV', 'Isaiah', 23, 5, 17, 'Then shall the lambs feed after their manner, and the waste places of the fat ones shall strangers eat.'),
  ('KJV', 'Isaiah', 23, 5, 18, 'Woe unto them that draw iniquity with cords of vanity, and sin as it were with a cart rope:'),
  ('KJV', 'Isaiah', 23, 5, 19, 'That say, Let him make speed, and hasten his work, that we may see it: and let the counsel of the Holy One of Israel draw nigh and come, that we may know it!'),
  ('KJV', 'Isaiah', 23, 5, 20, 'Woe unto them that call evil good, and good evil; that put darkness for light, and light for darkness; that put bitter for sweet, and sweet for bitter!'),
  ('KJV', 'Isaiah', 23, 5, 21, 'Woe unto them that are wise in their own eyes, and prudent in their own sight!'),
  ('KJV', 'Isaiah', 23, 5, 22, 'Woe unto them that are mighty to drink wine, and men of strength to mingle strong drink:'),
  ('KJV', 'Isaiah', 23, 5, 23, 'Which justify the wicked for reward, and take away the righteousness of the righteous from him!'),
  ('KJV', 'Isaiah', 23, 5, 24, 'Therefore as the fire devoureth the stubble, and the flame consumeth the chaff, so their root shall be as rottenness, and their blossom shall go up as dust: because they have cast away the law of the LORD of hosts, and despised the word of the Holy One of Israel.'),
  ('KJV', 'Isaiah', 23, 5, 25, 'Therefore is the anger of the LORD kindled against his people, and he hath stretched forth his hand against them, and hath smitten them: and the hills did tremble, and their carcases were torn in the midst of the streets. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('KJV', 'Isaiah', 23, 5, 26, 'And he will lift up an ensign to the nations from far, and will hiss unto them from the end of the earth: and, behold, they shall come with speed swiftly:'),
  ('KJV', 'Isaiah', 23, 5, 27, 'None shall be weary nor stumble among them; none shall slumber nor sleep; neither shall the girdle of their loins be loosed, nor the latchet of their shoes be broken:'),
  ('KJV', 'Isaiah', 23, 5, 28, 'Whose arrows are sharp, and all their bows bent, their horses'' hoofs shall be counted like flint, and their wheels like a whirlwind:'),
  ('KJV', 'Isaiah', 23, 5, 29, 'Their roaring shall be like a lion, they shall roar like young lions: yea, they shall roar, and lay hold of the prey, and shall carry it away safe, and none shall deliver it.'),
  ('KJV', 'Isaiah', 23, 5, 30, 'And in that day they shall roar against them like the roaring of the sea: and if one look unto the land, behold darkness and sorrow, and the light is darkened in the heavens thereof.'),
  ('KJV', 'Isaiah', 23, 6, 1, 'In the year that king Uzziah died I saw also the Lord sitting upon a throne, high and lifted up, and his train filled the temple.'),
  ('KJV', 'Isaiah', 23, 6, 2, 'Above it stood the seraphims: each one had six wings; with twain he covered his face, and with twain he covered his feet, and with twain he did fly.'),
  ('KJV', 'Isaiah', 23, 6, 3, 'And one cried unto another, and said, Holy, holy, holy, is the LORD of hosts: the whole earth is full of his glory.'),
  ('KJV', 'Isaiah', 23, 6, 4, 'And the posts of the door moved at the voice of him that cried, and the house was filled with smoke.'),
  ('KJV', 'Isaiah', 23, 6, 5, 'Then said I, Woe is me! for I am undone; because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for mine eyes have seen the King, the LORD of hosts.'),
  ('KJV', 'Isaiah', 23, 6, 6, 'Then flew one of the seraphims unto me, having a live coal in his hand, which he had taken with the tongs from off the altar:'),
  ('KJV', 'Isaiah', 23, 6, 7, 'And he laid it upon my mouth, and said, Lo, this hath touched thy lips; and thine iniquity is taken away, and thy sin purged.'),
  ('KJV', 'Isaiah', 23, 6, 8, 'Also I heard the voice of the Lord, saying, Whom shall I send, and who will go for us? Then said I, Here am I; send me.'),
  ('KJV', 'Isaiah', 23, 6, 9, 'And he said, Go, and tell this people, Hear ye indeed, but understand not; and see ye indeed, but perceive not.'),
  ('KJV', 'Isaiah', 23, 6, 10, 'Make the heart of this people fat, and make their ears heavy, and shut their eyes; lest they see with their eyes, and hear with their ears, and understand with their heart, and convert, and be healed.'),
  ('KJV', 'Isaiah', 23, 6, 11, 'Then said I, Lord, how long? And he answered, Until the cities be wasted without inhabitant, and the houses without man, and the land be utterly desolate,'),
  ('KJV', 'Isaiah', 23, 6, 12, 'And the LORD have removed men far away, and there be a great forsaking in the midst of the land.'),
  ('KJV', 'Isaiah', 23, 6, 13, 'But yet in it shall be a tenth, and it shall return, and shall be eaten: as a teil tree, and as an oak, whose substance is in them, when they cast their leaves: so the holy seed shall be the substance thereof.'),
  ('KJV', 'Isaiah', 23, 7, 1, 'And it came to pass in the days of Ahaz the son of Jotham, the son of Uzziah, king of Judah, that Rezin the king of Syria, and Pekah the son of Remaliah, king of Israel, went up toward Jerusalem to war against it, but could not prevail against it.'),
  ('KJV', 'Isaiah', 23, 7, 2, 'And it was told the house of David, saying, Syria is confederate with Ephraim. And his heart was moved, and the heart of his people, as the trees of the wood are moved with the wind.'),
  ('KJV', 'Isaiah', 23, 7, 3, 'Then said the LORD unto Isaiah, Go forth now to meet Ahaz, thou, and Shearjashub thy son, at the end of the conduit of the upper pool in the highway of the fuller''s field;'),
  ('KJV', 'Isaiah', 23, 7, 4, 'And say unto him, Take heed, and be quiet; fear not, neither be fainthearted for the two tails of these smoking firebrands, for the fierce anger of Rezin with Syria, and of the son of Remaliah.'),
  ('KJV', 'Isaiah', 23, 7, 5, 'Because Syria, Ephraim, and the son of Remaliah, have taken evil counsel against thee, saying,'),
  ('KJV', 'Isaiah', 23, 7, 6, 'Let us go up against Judah, and vex it, and let us make a breach therein for us, and set a king in the midst of it, even the son of Tabeal:'),
  ('KJV', 'Isaiah', 23, 7, 7, 'Thus saith the Lord GOD, It shall not stand, neither shall it come to pass.'),
  ('KJV', 'Isaiah', 23, 7, 8, 'For the head of Syria is Damascus, and the head of Damascus is Rezin; and within threescore and five years shall Ephraim be broken, that it be not a people.'),
  ('KJV', 'Isaiah', 23, 7, 9, 'And the head of Ephraim is Samaria, and the head of Samaria is Remaliah''s son. If ye will not believe, surely ye shall not be established.'),
  ('KJV', 'Isaiah', 23, 7, 10, 'Moreover the LORD spake again unto Ahaz, saying,'),
  ('KJV', 'Isaiah', 23, 7, 11, 'Ask thee a sign of the LORD thy God; ask it either in the depth, or in the height above.'),
  ('KJV', 'Isaiah', 23, 7, 12, 'But Ahaz said, I will not ask, neither will I tempt the LORD.'),
  ('KJV', 'Isaiah', 23, 7, 13, 'And he said, Hear ye now, O house of David; Is it a small thing for you to weary men, but will ye weary my God also?'),
  ('KJV', 'Isaiah', 23, 7, 14, 'Therefore the Lord himself shall give you a sign; Behold, a virgin shall conceive, and bear a son, and shall call his name Immanuel.'),
  ('KJV', 'Isaiah', 23, 7, 15, 'Butter and honey shall he eat, that he may know to refuse the evil, and choose the good.'),
  ('KJV', 'Isaiah', 23, 7, 16, 'For before the child shall know to refuse the evil, and choose the good, the land that thou abhorrest shall be forsaken of both her kings.'),
  ('KJV', 'Isaiah', 23, 7, 17, 'The LORD shall bring upon thee, and upon thy people, and upon thy father''s house, days that have not come, from the day that Ephraim departed from Judah; even the king of Assyria.'),
  ('KJV', 'Isaiah', 23, 7, 18, 'And it shall come to pass in that day, that the LORD shall hiss for the fly that is in the uttermost part of the rivers of Egypt, and for the bee that is in the land of Assyria.'),
  ('KJV', 'Isaiah', 23, 7, 19, 'And they shall come, and shall rest all of them in the desolate valleys, and in the holes of the rocks, and upon all thorns, and upon all bushes.'),
  ('KJV', 'Isaiah', 23, 7, 20, 'In the same day shall the Lord shave with a razor that is hired, namely, by them beyond the river, by the king of Assyria, the head, and the hair of the feet: and it shall also consume the beard.'),
  ('KJV', 'Isaiah', 23, 7, 21, 'And it shall come to pass in that day, that a man shall nourish a young cow, and two sheep;'),
  ('KJV', 'Isaiah', 23, 7, 22, 'And it shall come to pass, for the abundance of milk that they shall give he shall eat butter: for butter and honey shall every one eat that is left in the land.'),
  ('KJV', 'Isaiah', 23, 7, 23, 'And it shall come to pass in that day, that every place shall be, where there were a thousand vines at a thousand silverlings, it shall even be for briers and thorns.'),
  ('KJV', 'Isaiah', 23, 7, 24, 'With arrows and with bows shall men come thither; because all the land shall become briers and thorns.'),
  ('KJV', 'Isaiah', 23, 7, 25, 'And on all hills that shall be digged with the mattock, there shall not come thither the fear of briers and thorns: but it shall be for the sending forth of oxen, and for the treading of lesser cattle.'),
  ('KJV', 'Isaiah', 23, 8, 1, 'Moreover the LORD said unto me, Take thee a great roll, and write in it with a man''s pen concerning Mahershalalhashbaz.'),
  ('KJV', 'Isaiah', 23, 8, 2, 'And I took unto me faithful witnesses to record, Uriah the priest, and Zechariah the son of Jeberechiah.'),
  ('KJV', 'Isaiah', 23, 8, 3, 'And I went unto the prophetess; and she conceived, and bare a son. Then said the LORD to me, Call his name Mahershalalhashbaz.'),
  ('KJV', 'Isaiah', 23, 8, 4, 'For before the child shall have knowledge to cry, My father, and my mother, the riches of Damascus and the spoil of Samaria shall be taken away before the king of Assyria.'),
  ('KJV', 'Isaiah', 23, 8, 5, 'The LORD spake also unto me again, saying,'),
  ('KJV', 'Isaiah', 23, 8, 6, 'Forasmuch as this people refuseth the waters of Shiloah that go softly, and rejoice in Rezin and Remaliah''s son;'),
  ('KJV', 'Isaiah', 23, 8, 7, 'Now therefore, behold, the Lord bringeth up upon them the waters of the river, strong and many, even the king of Assyria, and all his glory: and he shall come up over all his channels, and go over all his banks:'),
  ('KJV', 'Isaiah', 23, 8, 8, 'And he shall pass through Judah; he shall overflow and go over, he shall reach even to the neck; and the stretching out of his wings shall fill the breadth of thy land, O Immanuel.'),
  ('KJV', 'Isaiah', 23, 8, 9, 'Associate yourselves, O ye people, and ye shall be broken in pieces; and give ear, all ye of far countries: gird yourselves, and ye shall be broken in pieces; gird yourselves, and ye shall be broken in pieces.'),
  ('KJV', 'Isaiah', 23, 8, 10, 'Take counsel together, and it shall come to nought; speak the word, and it shall not stand: for God is with us.'),
  ('KJV', 'Isaiah', 23, 8, 11, 'For the LORD spake thus to me with a strong hand, and instructed me that I should not walk in the way of this people, saying,'),
  ('KJV', 'Isaiah', 23, 8, 12, 'Say ye not, A confederacy, to all them to whom this people shall say, A confederacy; neither fear ye their fear, nor be afraid.'),
  ('KJV', 'Isaiah', 23, 8, 13, 'Sanctify the LORD of hosts himself; and let him be your fear, and let him be your dread.'),
  ('KJV', 'Isaiah', 23, 8, 14, 'And he shall be for a sanctuary; but for a stone of stumbling and for a rock of offence to both the houses of Israel, for a gin and for a snare to the inhabitants of Jerusalem.'),
  ('KJV', 'Isaiah', 23, 8, 15, 'And many among them shall stumble, and fall, and be broken, and be snared, and be taken.'),
  ('KJV', 'Isaiah', 23, 8, 16, 'Bind up the testimony, seal the law among my disciples.'),
  ('KJV', 'Isaiah', 23, 8, 17, 'And I will wait upon the LORD, that hideth his face from the house of Jacob, and I will look for him.'),
  ('KJV', 'Isaiah', 23, 8, 18, 'Behold, I and the children whom the LORD hath given me are for signs and for wonders in Israel from the LORD of hosts, which dwelleth in mount Zion.'),
  ('KJV', 'Isaiah', 23, 8, 19, 'And when they shall say unto you, Seek unto them that have familiar spirits, and unto wizards that peep, and that mutter: should not a people seek unto their God? for the living to the dead?'),
  ('KJV', 'Isaiah', 23, 8, 20, 'To the law and to the testimony: if they speak not according to this word, it is because there is no light in them.'),
  ('KJV', 'Isaiah', 23, 8, 21, 'And they shall pass through it, hardly bestead and hungry: and it shall come to pass, that when they shall be hungry, they shall fret themselves, and curse their king and their God, and look upward.'),
  ('KJV', 'Isaiah', 23, 8, 22, 'And they shall look unto the earth; and behold trouble and darkness, dimness of anguish; and they shall be driven to darkness.'),
  ('KJV', 'Isaiah', 23, 9, 1, 'Nevertheless the dimness shall not be such as was in her vexation, when at the first he lightly afflicted the land of Zebulun and the land of Naphtali, and afterward did more grievously afflict her by the way of the sea, beyond Jordan, in Galilee of the nations.'),
  ('KJV', 'Isaiah', 23, 9, 2, 'The people that walked in darkness have seen a great light: they that dwell in the land of the shadow of death, upon them hath the light shined.'),
  ('KJV', 'Isaiah', 23, 9, 3, 'Thou hast multiplied the nation, and not increased the joy: they joy before thee according to the joy in harvest, and as men rejoice when they divide the spoil.'),
  ('KJV', 'Isaiah', 23, 9, 4, 'For thou hast broken the yoke of his burden, and the staff of his shoulder, the rod of his oppressor, as in the day of Midian.'),
  ('KJV', 'Isaiah', 23, 9, 5, 'For every battle of the warrior is with confused noise, and garments rolled in blood; but this shall be with burning and fuel of fire.'),
  ('KJV', 'Isaiah', 23, 9, 6, 'For unto us a child is born, unto us a son is given: and the government shall be upon his shoulder: and his name shall be called Wonderful, Counsellor, The mighty God, The everlasting Father, The Prince of Peace.'),
  ('KJV', 'Isaiah', 23, 9, 7, 'Of the increase of his government and peace there shall be no end, upon the throne of David, and upon his kingdom, to order it, and to establish it with judgment and with justice from henceforth even for ever. The zeal of the LORD of hosts will perform this.'),
  ('KJV', 'Isaiah', 23, 9, 8, 'The Lord sent a word into Jacob, and it hath lighted upon Israel.'),
  ('KJV', 'Isaiah', 23, 9, 9, 'And all the people shall know, even Ephraim and the inhabitant of Samaria, that say in the pride and stoutness of heart,'),
  ('KJV', 'Isaiah', 23, 9, 10, 'The bricks are fallen down, but we will build with hewn stones: the sycomores are cut down, but we will change them into cedars.'),
  ('KJV', 'Isaiah', 23, 9, 11, 'Therefore the LORD shall set up the adversaries of Rezin against him, and join his enemies together;'),
  ('KJV', 'Isaiah', 23, 9, 12, 'The Syrians before, and the Philistines behind; and they shall devour Israel with open mouth. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('KJV', 'Isaiah', 23, 9, 13, 'For the people turneth not unto him that smiteth them, neither do they seek the LORD of hosts.'),
  ('KJV', 'Isaiah', 23, 9, 14, 'Therefore the LORD will cut off from Israel head and tail, branch and rush, in one day.'),
  ('KJV', 'Isaiah', 23, 9, 15, 'The ancient and honourable, he is the head; and the prophet that teacheth lies, he is the tail.'),
  ('KJV', 'Isaiah', 23, 9, 16, 'For the leaders of this people cause them to err; and they that are led of them are destroyed.'),
  ('KJV', 'Isaiah', 23, 9, 17, 'Therefore the Lord shall have no joy in their young men, neither shall have mercy on their fatherless and widows: for every one is an hypocrite and an evildoer, and every mouth speaketh folly. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('KJV', 'Isaiah', 23, 9, 18, 'For wickedness burneth as the fire: it shall devour the briers and thorns, and shall kindle in the thickets of the forest, and they shall mount up like the lifting up of smoke.'),
  ('KJV', 'Isaiah', 23, 9, 19, 'Through the wrath of the LORD of hosts is the land darkened, and the people shall be as the fuel of the fire: no man shall spare his brother.'),
  ('KJV', 'Isaiah', 23, 9, 20, 'And he shall snatch on the right hand, and be hungry; and he shall eat on the left hand, and they shall not be satisfied: they shall eat every man the flesh of his own arm:'),
  ('KJV', 'Isaiah', 23, 9, 21, 'Manasseh, Ephraim; and Ephraim, Manasseh: and they together shall be against Judah. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('KJV', 'Isaiah', 23, 10, 1, 'Woe unto them that decree unrighteous decrees, and that write grievousness which they have prescribed;'),
  ('KJV', 'Isaiah', 23, 10, 2, 'To turn aside the needy from judgment, and to take away the right from the poor of my people, that widows may be their prey, and that they may rob the fatherless!'),
  ('KJV', 'Isaiah', 23, 10, 3, 'And what will ye do in the day of visitation, and in the desolation which shall come from far? to whom will ye flee for help? and where will ye leave your glory?'),
  ('KJV', 'Isaiah', 23, 10, 4, 'Without me they shall bow down under the prisoners, and they shall fall under the slain. For all this his anger is not turned away, but his hand is stretched out still.'),
  ('KJV', 'Isaiah', 23, 10, 5, 'O Assyrian, the rod of mine anger, and the staff in their hand is mine indignation.'),
  ('KJV', 'Isaiah', 23, 10, 6, 'I will send him against an hypocritical nation, and against the people of my wrath will I give him a charge, to take the spoil, and to take the prey, and to tread them down like the mire of the streets.'),
  ('KJV', 'Isaiah', 23, 10, 7, 'Howbeit he meaneth not so, neither doth his heart think so; but it is in his heart to destroy and cut off nations not a few.'),
  ('KJV', 'Isaiah', 23, 10, 8, 'For he saith, Are not my princes altogether kings?'),
  ('KJV', 'Isaiah', 23, 10, 9, 'Is not Calno as Carchemish? is not Hamath as Arpad? is not Samaria as Damascus?'),
  ('KJV', 'Isaiah', 23, 10, 10, 'As my hand hath found the kingdoms of the idols, and whose graven images did excel them of Jerusalem and of Samaria;'),
  ('KJV', 'Isaiah', 23, 10, 11, 'Shall I not, as I have done unto Samaria and her idols, so do to Jerusalem and her idols?'),
  ('KJV', 'Isaiah', 23, 10, 12, 'Wherefore it shall come to pass, that when the Lord hath performed his whole work upon mount Zion and on Jerusalem, I will punish the fruit of the stout heart of the king of Assyria, and the glory of his high looks.'),
  ('KJV', 'Isaiah', 23, 10, 13, 'For he saith, By the strength of my hand I have done it, and by my wisdom; for I am prudent: and I have removed the bounds of the people, and have robbed their treasures, and I have put down the inhabitants like a valiant man:'),
  ('KJV', 'Isaiah', 23, 10, 14, 'And my hand hath found as a nest the riches of the people: and as one gathereth eggs that are left, have I gathered all the earth; and there was none that moved the wing, or opened the mouth, or peeped.'),
  ('KJV', 'Isaiah', 23, 10, 15, 'Shall the axe boast itself against him that heweth therewith? or shall the saw magnify itself against him that shaketh it? as if the rod should shake itself against them that lift it up, or as if the staff should lift up itself, as if it were no wood.'),
  ('KJV', 'Isaiah', 23, 10, 16, 'Therefore shall the Lord, the Lord of hosts, send among his fat ones leanness; and under his glory he shall kindle a burning like the burning of a fire.'),
  ('KJV', 'Isaiah', 23, 10, 17, 'And the light of Israel shall be for a fire, and his Holy One for a flame: and it shall burn and devour his thorns and his briers in one day;'),
  ('KJV', 'Isaiah', 23, 10, 18, 'And shall consume the glory of his forest, and of his fruitful field, both soul and body: and they shall be as when a standardbearer fainteth.'),
  ('KJV', 'Isaiah', 23, 10, 19, 'And the rest of the trees of his forest shall be few, that a child may write them.'),
  ('KJV', 'Isaiah', 23, 10, 20, 'And it shall come to pass in that day, that the remnant of Israel, and such as are escaped of the house of Jacob, shall no more again stay upon him that smote them; but shall stay upon the LORD, the Holy One of Israel, in truth.'),
  ('KJV', 'Isaiah', 23, 10, 21, 'The remnant shall return, even the remnant of Jacob, unto the mighty God.'),
  ('KJV', 'Isaiah', 23, 10, 22, 'For though thy people Israel be as the sand of the sea, yet a remnant of them shall return: the consumption decreed shall overflow with righteousness.'),
  ('KJV', 'Isaiah', 23, 10, 23, 'For the Lord GOD of hosts shall make a consumption, even determined, in the midst of all the land.'),
  ('KJV', 'Isaiah', 23, 10, 24, 'Therefore thus saith the Lord GOD of hosts, O my people that dwellest in Zion, be not afraid of the Assyrian: he shall smite thee with a rod, and shall lift up his staff against thee, after the manner of Egypt.'),
  ('KJV', 'Isaiah', 23, 10, 25, 'For yet a very little while, and the indignation shall cease, and mine anger in their destruction.'),
  ('KJV', 'Isaiah', 23, 10, 26, 'And the LORD of hosts shall stir up a scourge for him according to the slaughter of Midian at the rock of Oreb: and as his rod was upon the sea, so shall he lift it up after the manner of Egypt.'),
  ('KJV', 'Isaiah', 23, 10, 27, 'And it shall come to pass in that day, that his burden shall be taken away from off thy shoulder, and his yoke from off thy neck, and the yoke shall be destroyed because of the anointing.'),
  ('KJV', 'Isaiah', 23, 10, 28, 'He is come to Aiath, he is passed to Migron; at Michmash he hath laid up his carriages:'),
  ('KJV', 'Isaiah', 23, 10, 29, 'They are gone over the passage: they have taken up their lodging at Geba; Ramah is afraid; Gibeah of Saul is fled.'),
  ('KJV', 'Isaiah', 23, 10, 30, 'Lift up thy voice, O daughter of Gallim: cause it to be heard unto Laish, O poor Anathoth.'),
  ('KJV', 'Isaiah', 23, 10, 31, 'Madmenah is removed; the inhabitants of Gebim gather themselves to flee.'),
  ('KJV', 'Isaiah', 23, 10, 32, 'As yet shall he remain at Nob that day: he shall shake his hand against the mount of the daughter of Zion, the hill of Jerusalem.'),
  ('KJV', 'Isaiah', 23, 10, 33, 'Behold, the Lord, the LORD of hosts, shall lop the bough with terror: and the high ones of stature shall be hewn down, and the haughty shall be humbled.'),
  ('KJV', 'Isaiah', 23, 10, 34, 'And he shall cut down the thickets of the forest with iron, and Lebanon shall fall by a mighty one.'),
  ('KJV', 'Isaiah', 23, 11, 1, 'And there shall come forth a rod out of the stem of Jesse, and a Branch shall grow out of his roots:'),
  ('KJV', 'Isaiah', 23, 11, 2, 'And the spirit of the LORD shall rest upon him, the spirit of wisdom and understanding, the spirit of counsel and might, the spirit of knowledge and of the fear of the LORD;'),
  ('KJV', 'Isaiah', 23, 11, 3, 'And shall make him of quick understanding in the fear of the LORD: and he shall not judge after the sight of his eyes, neither reprove after the hearing of his ears:'),
  ('KJV', 'Isaiah', 23, 11, 4, 'But with righteousness shall he judge the poor, and reprove with equity for the meek of the earth: and he shall smite the earth with the rod of his mouth, and with the breath of his lips shall he slay the wicked.'),
  ('KJV', 'Isaiah', 23, 11, 5, 'And righteousness shall be the girdle of his loins, and faithfulness the girdle of his reins.'),
  ('KJV', 'Isaiah', 23, 11, 6, 'The wolf also shall dwell with the lamb, and the leopard shall lie down with the kid; and the calf and the young lion and the fatling together; and a little child shall lead them.'),
  ('KJV', 'Isaiah', 23, 11, 7, 'And the cow and the bear shall feed; their young ones shall lie down together: and the lion shall eat straw like the ox.'),
  ('KJV', 'Isaiah', 23, 11, 8, 'And the sucking child shall play on the hole of the asp, and the weaned child shall put his hand on the cockatrice'' den.'),
  ('KJV', 'Isaiah', 23, 11, 9, 'They shall not hurt nor destroy in all my holy mountain: for the earth shall be full of the knowledge of the LORD, as the waters cover the sea.'),
  ('KJV', 'Isaiah', 23, 11, 10, 'And in that day there shall be a root of Jesse, which shall stand for an ensign of the people; to it shall the Gentiles seek: and his rest shall be glorious.'),
  ('KJV', 'Isaiah', 23, 11, 11, 'And it shall come to pass in that day, that the Lord shall set his hand again the second time to recover the remnant of his people, which shall be left, from Assyria, and from Egypt, and from Pathros, and from Cush, and from Elam, and from Shinar, and from Hamath, and from the islands of the sea.'),
  ('KJV', 'Isaiah', 23, 11, 12, 'And he shall set up an ensign for the nations, and shall assemble the outcasts of Israel, and gather together the dispersed of Judah from the four corners of the earth.'),
  ('KJV', 'Isaiah', 23, 11, 13, 'The envy also of Ephraim shall depart, and the adversaries of Judah shall be cut off: Ephraim shall not envy Judah, and Judah shall not vex Ephraim.'),
  ('KJV', 'Isaiah', 23, 11, 14, 'But they shall fly upon the shoulders of the Philistines toward the west; they shall spoil them of the east together: they shall lay their hand upon Edom and Moab; and the children of Ammon shall obey them.'),
  ('KJV', 'Isaiah', 23, 11, 15, 'And the LORD shall utterly destroy the tongue of the Egyptian sea; and with his mighty wind shall he shake his hand over the river, and shall smite it in the seven streams, and make men go over dryshod.'),
  ('KJV', 'Isaiah', 23, 11, 16, 'And there shall be an highway for the remnant of his people, which shall be left, from Assyria; like as it was to Israel in the day that he came up out of the land of Egypt.'),
  ('KJV', 'Isaiah', 23, 12, 1, 'And in that day thou shalt say, O LORD, I will praise thee: though thou wast angry with me, thine anger is turned away, and thou comfortedst me.'),
  ('KJV', 'Isaiah', 23, 12, 2, 'Behold, God is my salvation; I will trust, and not be afraid: for the LORD JEHOVAH is my strength and my song; he also is become my salvation.'),
  ('KJV', 'Isaiah', 23, 12, 3, 'Therefore with joy shall ye draw water out of the wells of salvation.'),
  ('KJV', 'Isaiah', 23, 12, 4, 'And in that day shall ye say, Praise the LORD, call upon his name, declare his doings among the people, make mention that his name is exalted.'),
  ('KJV', 'Isaiah', 23, 12, 5, 'Sing unto the LORD; for he hath done excellent things: this is known in all the earth.'),
  ('KJV', 'Isaiah', 23, 12, 6, 'Cry out and shout, thou inhabitant of Zion: for great is the Holy One of Israel in the midst of thee.'),
  ('KJV', 'Isaiah', 23, 13, 1, 'The burden of Babylon, which Isaiah the son of Amoz did see.'),
  ('KJV', 'Isaiah', 23, 13, 2, 'Lift ye up a banner upon the high mountain, exalt the voice unto them, shake the hand, that they may go into the gates of the nobles.'),
  ('KJV', 'Isaiah', 23, 13, 3, 'I have commanded my sanctified ones, I have also called my mighty ones for mine anger, even them that rejoice in my highness.'),
  ('KJV', 'Isaiah', 23, 13, 4, 'The noise of a multitude in the mountains, like as of a great people; a tumultuous noise of the kingdoms of nations gathered together: the LORD of hosts mustereth the host of the battle.'),
  ('KJV', 'Isaiah', 23, 13, 5, 'They come from a far country, from the end of heaven, even the LORD, and the weapons of his indignation, to destroy the whole land.'),
  ('KJV', 'Isaiah', 23, 13, 6, 'Howl ye; for the day of the LORD is at hand; it shall come as a destruction from the Almighty.'),
  ('KJV', 'Isaiah', 23, 13, 7, 'Therefore shall all hands be faint, and every man''s heart shall melt:'),
  ('KJV', 'Isaiah', 23, 13, 8, 'And they shall be afraid: pangs and sorrows shall take hold of them; they shall be in pain as a woman that travaileth: they shall be amazed one at another; their faces shall be as flames.'),
  ('KJV', 'Isaiah', 23, 13, 9, 'Behold, the day of the LORD cometh, cruel both with wrath and fierce anger, to lay the land desolate: and he shall destroy the sinners thereof out of it.'),
  ('KJV', 'Isaiah', 23, 13, 10, 'For the stars of heaven and the constellations thereof shall not give their light: the sun shall be darkened in his going forth, and the moon shall not cause her light to shine.'),
  ('KJV', 'Isaiah', 23, 13, 11, 'And I will punish the world for their evil, and the wicked for their iniquity; and I will cause the arrogancy of the proud to cease, and will lay low the haughtiness of the terrible.'),
  ('KJV', 'Isaiah', 23, 13, 12, 'I will make a man more precious than fine gold; even a man than the golden wedge of Ophir.'),
  ('KJV', 'Isaiah', 23, 13, 13, 'Therefore I will shake the heavens, and the earth shall remove out of her place, in the wrath of the LORD of hosts, and in the day of his fierce anger.'),
  ('KJV', 'Isaiah', 23, 13, 14, 'And it shall be as the chased roe, and as a sheep that no man taketh up: they shall every man turn to his own people, and flee every one into his own land.'),
  ('KJV', 'Isaiah', 23, 13, 15, 'Every one that is found shall be thrust through; and every one that is joined unto them shall fall by the sword.'),
  ('KJV', 'Isaiah', 23, 13, 16, 'Their children also shall be dashed to pieces before their eyes; their houses shall be spoiled, and their wives ravished.'),
  ('KJV', 'Isaiah', 23, 13, 17, 'Behold, I will stir up the Medes against them, which shall not regard silver; and as for gold, they shall not delight in it.'),
  ('KJV', 'Isaiah', 23, 13, 18, 'Their bows also shall dash the young men to pieces; and they shall have no pity on the fruit of the womb; their eye shall not spare children.'),
  ('KJV', 'Isaiah', 23, 13, 19, 'And Babylon, the glory of kingdoms, the beauty of the Chaldees'' excellency, shall be as when God overthrew Sodom and Gomorrah.'),
  ('KJV', 'Isaiah', 23, 13, 20, 'It shall never be inhabited, neither shall it be dwelt in from generation to generation: neither shall the Arabian pitch tent there; neither shall the shepherds make their fold there.'),
  ('KJV', 'Isaiah', 23, 13, 21, 'But wild beasts of the desert shall lie there; and their houses shall be full of doleful creatures; and owls shall dwell there, and satyrs shall dance there.'),
  ('KJV', 'Isaiah', 23, 13, 22, 'And the wild beasts of the islands shall cry in their desolate houses, and dragons in their pleasant palaces: and her time is near to come, and her days shall not be prolonged.'),
  ('KJV', 'Isaiah', 23, 14, 1, 'For the LORD will have mercy on Jacob, and will yet choose Israel, and set them in their own land: and the strangers shall be joined with them, and they shall cleave to the house of Jacob.'),
  ('KJV', 'Isaiah', 23, 14, 2, 'And the people shall take them, and bring them to their place: and the house of Israel shall possess them in the land of the LORD for servants and handmaids: and they shall take them captives, whose captives they were; and they shall rule over their oppressors.'),
  ('KJV', 'Isaiah', 23, 14, 3, 'And it shall come to pass in the day that the LORD shall give thee rest from thy sorrow, and from thy fear, and from the hard bondage wherein thou wast made to serve,'),
  ('KJV', 'Isaiah', 23, 14, 4, 'That thou shalt take up this proverb against the king of Babylon, and say, How hath the oppressor ceased! the golden city ceased!'),
  ('KJV', 'Isaiah', 23, 14, 5, 'The LORD hath broken the staff of the wicked, and the sceptre of the rulers.'),
  ('KJV', 'Isaiah', 23, 14, 6, 'He who smote the people in wrath with a continual stroke, he that ruled the nations in anger, is persecuted, and none hindereth.'),
  ('KJV', 'Isaiah', 23, 14, 7, 'The whole earth is at rest, and is quiet: they break forth into singing.'),
  ('KJV', 'Isaiah', 23, 14, 8, 'Yea, the fir trees rejoice at thee, and the cedars of Lebanon, saying, Since thou art laid down, no feller is come up against us.'),
  ('KJV', 'Isaiah', 23, 14, 9, 'Hell from beneath is moved for thee to meet thee at thy coming: it stirreth up the dead for thee, even all the chief ones of the earth; it hath raised up from their thrones all the kings of the nations.'),
  ('KJV', 'Isaiah', 23, 14, 10, 'All they shall speak and say unto thee, Art thou also become weak as we? art thou become like unto us?'),
  ('KJV', 'Isaiah', 23, 14, 11, 'Thy pomp is brought down to the grave, and the noise of thy viols: the worm is spread under thee, and the worms cover thee.'),
  ('KJV', 'Isaiah', 23, 14, 12, 'How art thou fallen from heaven, O Lucifer, son of the morning! how art thou cut down to the ground, which didst weaken the nations!'),
  ('KJV', 'Isaiah', 23, 14, 13, 'For thou hast said in thine heart, I will ascend into heaven, I will exalt my throne above the stars of God: I will sit also upon the mount of the congregation, in the sides of the north:'),
  ('KJV', 'Isaiah', 23, 14, 14, 'I will ascend above the heights of the clouds; I will be like the most High.'),
  ('KJV', 'Isaiah', 23, 14, 15, 'Yet thou shalt be brought down to hell, to the sides of the pit.'),
  ('KJV', 'Isaiah', 23, 14, 16, 'They that see thee shall narrowly look upon thee, and consider thee, saying, Is this the man that made the earth to tremble, that did shake kingdoms;'),
  ('KJV', 'Isaiah', 23, 14, 17, 'That made the world as a wilderness, and destroyed the cities thereof; that opened not the house of his prisoners?'),
  ('KJV', 'Isaiah', 23, 14, 18, 'All the kings of the nations, even all of them, lie in glory, every one in his own house.'),
  ('KJV', 'Isaiah', 23, 14, 19, 'But thou art cast out of thy grave like an abominable branch, and as the raiment of those that are slain, thrust through with a sword, that go down to the stones of the pit; as a carcase trodden under feet.'),
  ('KJV', 'Isaiah', 23, 14, 20, 'Thou shalt not be joined with them in burial, because thou hast destroyed thy land, and slain thy people: the seed of evildoers shall never be renowned.'),
  ('KJV', 'Isaiah', 23, 14, 21, 'Prepare slaughter for his children for the iniquity of their fathers; that they do not rise, nor possess the land, nor fill the face of the world with cities.'),
  ('KJV', 'Isaiah', 23, 14, 22, 'For I will rise up against them, saith the LORD of hosts, and cut off from Babylon the name, and remnant, and son, and nephew, saith the LORD.'),
  ('KJV', 'Isaiah', 23, 14, 23, 'I will also make it a possession for the bittern, and pools of water: and I will sweep it with the besom of destruction, saith the LORD of hosts.'),
  ('KJV', 'Isaiah', 23, 14, 24, 'The LORD of hosts hath sworn, saying, Surely as I have thought, so shall it come to pass; and as I have purposed, so shall it stand:'),
  ('KJV', 'Isaiah', 23, 14, 25, 'That I will break the Assyrian in my land, and upon my mountains tread him under foot: then shall his yoke depart from off them, and his burden depart from off their shoulders.'),
  ('KJV', 'Isaiah', 23, 14, 26, 'This is the purpose that is purposed upon the whole earth: and this is the hand that is stretched out upon all the nations.'),
  ('KJV', 'Isaiah', 23, 14, 27, 'For the LORD of hosts hath purposed, and who shall disannul it? and his hand is stretched out, and who shall turn it back?'),
  ('KJV', 'Isaiah', 23, 14, 28, 'In the year that king Ahaz died was this burden.'),
  ('KJV', 'Isaiah', 23, 14, 29, 'Rejoice not thou, whole Palestina, because the rod of him that smote thee is broken: for out of the serpent''s root shall come forth a cockatrice, and his fruit shall be a fiery flying serpent.'),
  ('KJV', 'Isaiah', 23, 14, 30, 'And the firstborn of the poor shall feed, and the needy shall lie down in safety: and I will kill thy root with famine, and he shall slay thy remnant.'),
  ('KJV', 'Isaiah', 23, 14, 31, 'Howl, O gate; cry, O city; thou, whole Palestina, art dissolved: for there shall come from the north a smoke, and none shall be alone in his appointed times.'),
  ('KJV', 'Isaiah', 23, 14, 32, 'What shall one then answer the messengers of the nation? That the LORD hath founded Zion, and the poor of his people shall trust in it.'),
  ('KJV', 'Isaiah', 23, 15, 1, 'The burden of Moab. Because in the night Ar of Moab is laid waste, and brought to silence; because in the night Kir of Moab is laid waste, and brought to silence;'),
  ('KJV', 'Isaiah', 23, 15, 2, 'He is gone up to Bajith, and to Dibon, the high places, to weep: Moab shall howl over Nebo, and over Medeba: on all their heads shall be baldness, and every beard cut off.'),
  ('KJV', 'Isaiah', 23, 15, 3, 'In their streets they shall gird themselves with sackcloth: on the tops of their houses, and in their streets, every one shall howl, weeping abundantly.'),
  ('KJV', 'Isaiah', 23, 15, 4, 'And Heshbon shall cry, and Elealeh: their voice shall be heard even unto Jahaz: therefore the armed soldiers of Moab shall cry out; his life shall be grievous unto him.'),
  ('KJV', 'Isaiah', 23, 15, 5, 'My heart shall cry out for Moab; his fugitives shall flee unto Zoar, an heifer of three years old: for by the mounting up of Luhith with weeping shall they go it up; for in the way of Horonaim they shall raise up a cry of destruction.'),
  ('KJV', 'Isaiah', 23, 15, 6, 'For the waters of Nimrim shall be desolate: for the hay is withered away, the grass faileth, there is no green thing.'),
  ('KJV', 'Isaiah', 23, 15, 7, 'Therefore the abundance they have gotten, and that which they have laid up, shall they carry away to the brook of the willows.'),
  ('KJV', 'Isaiah', 23, 15, 8, 'For the cry is gone round about the borders of Moab; the howling thereof unto Eglaim, and the howling thereof unto Beerelim.'),
  ('KJV', 'Isaiah', 23, 15, 9, 'For the waters of Dimon shall be full of blood: for I will bring more upon Dimon, lions upon him that escapeth of Moab, and upon the remnant of the land.'),
  ('KJV', 'Isaiah', 23, 16, 1, 'Send ye the lamb to the ruler of the land from Sela to the wilderness, unto the mount of the daughter of Zion.'),
  ('KJV', 'Isaiah', 23, 16, 2, 'For it shall be, that, as a wandering bird cast out of the nest, so the daughters of Moab shall be at the fords of Arnon.'),
  ('KJV', 'Isaiah', 23, 16, 3, 'Take counsel, execute judgment; make thy shadow as the night in the midst of the noonday; hide the outcasts; bewray not him that wandereth.'),
  ('KJV', 'Isaiah', 23, 16, 4, 'Let mine outcasts dwell with thee, Moab; be thou a covert to them from the face of the spoiler: for the extortioner is at an end, the spoiler ceaseth, the oppressors are consumed out of the land.'),
  ('KJV', 'Isaiah', 23, 16, 5, 'And in mercy shall the throne be established: and he shall sit upon it in truth in the tabernacle of David, judging, and seeking judgment, and hasting righteousness.'),
  ('KJV', 'Isaiah', 23, 16, 6, 'We have heard of the pride of Moab; he is very proud: even of his haughtiness, and his pride, and his wrath: but his lies shall not be so.'),
  ('KJV', 'Isaiah', 23, 16, 7, 'Therefore shall Moab howl for Moab, every one shall howl: for the foundations of Kirhareseth shall ye mourn; surely they are stricken.'),
  ('KJV', 'Isaiah', 23, 16, 8, 'For the fields of Heshbon languish, and the vine of Sibmah: the lords of the heathen have broken down the principal plants thereof, they are come even unto Jazer, they wandered through the wilderness: her branches are stretched out, they are gone over the sea.'),
  ('KJV', 'Isaiah', 23, 16, 9, 'Therefore I will bewail with the weeping of Jazer the vine of Sibmah: I will water thee with my tears, O Heshbon, and Elealeh: for the shouting for thy summer fruits and for thy harvest is fallen.'),
  ('KJV', 'Isaiah', 23, 16, 10, 'And gladness is taken away, and joy out of the plentiful field; and in the vineyards there shall be no singing, neither shall there be shouting: the treaders shall tread out no wine in their presses; I have made their vintage shouting to cease.'),
  ('KJV', 'Isaiah', 23, 16, 11, 'Wherefore my bowels shall sound like an harp for Moab, and mine inward parts for Kirharesh.'),
  ('KJV', 'Isaiah', 23, 16, 12, 'And it shall come to pass, when it is seen that Moab is weary on the high place, that he shall come to his sanctuary to pray; but he shall not prevail.'),
  ('KJV', 'Isaiah', 23, 16, 13, 'This is the word that the LORD hath spoken concerning Moab since that time.'),
  ('KJV', 'Isaiah', 23, 16, 14, 'But now the LORD hath spoken, saying, Within three years, as the years of an hireling, and the glory of Moab shall be contemned, with all that great multitude; and the remnant shall be very small and feeble.'),
  ('KJV', 'Isaiah', 23, 17, 1, 'The burden of Damascus. Behold, Damascus is taken away from being a city, and it shall be a ruinous heap.'),
  ('KJV', 'Isaiah', 23, 17, 2, 'The cities of Aroer are forsaken: they shall be for flocks, which shall lie down, and none shall make them afraid.'),
  ('KJV', 'Isaiah', 23, 17, 3, 'The fortress also shall cease from Ephraim, and the kingdom from Damascus, and the remnant of Syria: they shall be as the glory of the children of Israel, saith the LORD of hosts.'),
  ('KJV', 'Isaiah', 23, 17, 4, 'And in that day it shall come to pass, that the glory of Jacob shall be made thin, and the fatness of his flesh shall wax lean.'),
  ('KJV', 'Isaiah', 23, 17, 5, 'And it shall be as when the harvestman gathereth the corn, and reapeth the ears with his arm; and it shall be as he that gathereth ears in the valley of Rephaim.'),
  ('KJV', 'Isaiah', 23, 17, 6, 'Yet gleaning grapes shall be left in it, as the shaking of an olive tree, two or three berries in the top of the uppermost bough, four or five in the outmost fruitful branches thereof, saith the LORD God of Israel.'),
  ('KJV', 'Isaiah', 23, 17, 7, 'At that day shall a man look to his Maker, and his eyes shall have respect to the Holy One of Israel.'),
  ('KJV', 'Isaiah', 23, 17, 8, 'And he shall not look to the altars, the work of his hands, neither shall respect that which his fingers have made, either the groves, or the images.'),
  ('KJV', 'Isaiah', 23, 17, 9, 'In that day shall his strong cities be as a forsaken bough, and an uppermost branch, which they left because of the children of Israel: and there shall be desolation.'),
  ('KJV', 'Isaiah', 23, 17, 10, 'Because thou hast forgotten the God of thy salvation, and hast not been mindful of the rock of thy strength, therefore shalt thou plant pleasant plants, and shalt set it with strange slips:'),
  ('KJV', 'Isaiah', 23, 17, 11, 'In the day shalt thou make thy plant to grow, and in the morning shalt thou make thy seed to flourish: but the harvest shall be a heap in the day of grief and of desperate sorrow.'),
  ('KJV', 'Isaiah', 23, 17, 12, 'Woe to the multitude of many people, which make a noise like the noise of the seas; and to the rushing of nations, that make a rushing like the rushing of mighty waters!'),
  ('KJV', 'Isaiah', 23, 17, 13, 'The nations shall rush like the rushing of many waters: but God shall rebuke them, and they shall flee far off, and shall be chased as the chaff of the mountains before the wind, and like a rolling thing before the whirlwind.'),
  ('KJV', 'Isaiah', 23, 17, 14, 'And behold at eveningtide trouble; and before the morning he is not. This is the portion of them that spoil us, and the lot of them that rob us.'),
  ('KJV', 'Isaiah', 23, 18, 1, 'Woe to the land shadowing with wings, which is beyond the rivers of Ethiopia:'),
  ('KJV', 'Isaiah', 23, 18, 2, 'That sendeth ambassadors by the sea, even in vessels of bulrushes upon the waters, saying, Go, ye swift messengers, to a nation scattered and peeled, to a people terrible from their beginning hitherto; a nation meted out and trodden down, whose land the rivers have spoiled!')
